rticles/v2-explore-articles.js","webpack:///./blocks/v2-faq/v2-faq.js","webpack:///./blocks/v2-feature-carousel/v2-feature-carousel.js","webpack:///./blocks/v2-forms/forms/ lazy ^\\.\\/.*\\.js$ referencedExports: default, onSubmit, onSubmit, postLoad namespace object","webpack:///./blocks/v2-forms/v2-forms.js","webpack:///./blocks/v2-hero-reveal/v2-hero-reveal.js","webpack:///./blocks/v2-hero/v2-hero.js","webpack:///./blocks/v2-hotspots-spot/v2-hotspots-spot.js","webpack:///./blocks/v2-hotspots/v2-hotspots.js","webpack:///./blocks/v2-icon-cards/v2-icon-cards.js","webpack:///./blocks/v2-iframe/v2-iframe.js","webpack:///./blocks/v2-image-banner/v2-image-banner.js","webpack:///./blocks/v2-images-grid/v2-images-grid.js","webpack:///./blocks/v2-inpage-navigation/v2-inpage-navigation.js","webpack:///./blocks/v2-intro-section/v2-intro-section.js","webpack:///./blocks/v2-magazine-tabbed-carousel/v2-magazine-tabbed-carousel.js","webpack:///./blocks/v2-media-with-content/v2-media-with-content.js","webpack:///./blocks/v2-navigation-hub/v2-navigation-hub.js","webpack:///./blocks/v2-newsletter/v2-newsletter.js","webpack:///./blocks/v2-pencil-promo/v2-pencil-promo.js","webpack:///./blocks/v2-picture-tooltips/v2-picture-tooltips.js","webpack:///./blocks/v2-product-listing/v2-product-listing.js","webpack:///./blocks/v2-pull-quote/v2-pull-quote.js","webpack:///./blocks/v2-recommendations/v2-recommendations.js","webpack:///./blocks/v2-resources/v2-resources.js","webpack:///./blocks/v2-slider/v2-slider.js","webpack:///./blocks/v2-social-block/v2-social-block.js","webpack:///./blocks/v2-solutions/v2-solutions.js","webpack:///./blocks/v2-specifications/v2-specifications.js","webpack:///./blocks/v2-stories-carousel/v2-stories-carousel.js","webpack:///./blocks/v2-sub-navigation/v2-sub-navigation.js","webpack:///./blocks/v2-tabbed-carousel/v2-tabbed-carousel.js","webpack:///./blocks/v2-testimonial/v2-testimonial.js","webpack:///./blocks/v2-truck-builder/v2-truck-builder.js","webpack:///./blocks/v2-truck-features/v2-truck-features.js","webpack:///./blocks/v2-truck-lineup/v2-truck-lineup.js","webpack:///./blocks/v2-video/v2-video.js","webpack:///./blocks/vin-number/vin-number.js","webpack:///./blocks/ sync ^[^/]+\\/[^/]+\\.js$","webpack:///./common/countdown/countdown.js","webpack:///./common/custom-dropdown/custom-dropdown.js","webpack:///./common/modal/modal-component.js","webpack:///./scripts/404-entrypoint.js","webpack:///./scripts/aem.js","webpack:///./scripts/app-loader.js","webpack:///./scripts/carousel-helper.js","webpack:///./scripts/common.js","webpack:///./scripts/scripts.js","webpack:///./scripts/search-api.js","webpack:///./scripts/services/magazine.service.js","webpack:///./scripts/services/news.service.js","webpack:///./scripts/validate-countries.js","webpack:///./scripts/video-helper.js","webpack:///./templates/ lazy ^\\.\\/.*\\/.*\\.js$ referencedExports: default, default namespace object","webpack:///webpack/bootstrap","webpack:///webpack/runtime/async module","webpack:///webpack/runtime/create fake namespace object","webpack:///webpack/runtime/define property getters","webpack:///webpack/runtime/ensure chunk","webpack:///webpack/runtime/get javascript chunk filename","webpack:///webpack/runtime/get mini-css chunk filename","webpack:///webpack/runtime/hasOwnProperty shorthand","webpack:///webpack/runtime/load script","webpack:///webpack/runtime/make namespace object","webpack:///webpack/runtime/publicPath","webpack:///webpack/runtime/jsonp chunk loading","webpack:///webpack/startup"],"sourcesContent":["import { createElement } from '../../scripts/common.js';\nimport fragmentBlock from '../fragment/fragment.js';\n\n/* Function checks if the content of the provied element is just a link to other doc */\nfunction isContentLink(el) {\n  // The assumpions:\n  // 1. The content is just plain text - no HTML inside\n  // 2. The link starts from '/' and doesn't contain any white space character\n  return el.innerHTML === el.textContent && /^\\/(\\S+)$/g.test(el.innerHTML);\n}\n\nexport default async function decorate(block) {\n  const rows = [...block.querySelectorAll(':scope > div')];\n  const accordionsPromises = rows.map(async (row) => {\n    const accordionHeader = row.querySelector(\n      ':scope > div > h1, :scope > div > h2, :scope > div > h3, :scope > div > h4, :scope > div > h5, :scope > div > h6',\n    );\n    const accordionContent = row.querySelector(':scope > div:nth-child(2)');\n\n    const headerButton = createElement('button', { classes: 'accordion-header-button' });\n    const headerEl = createElement('h2', { classes: 'accordion-header' });\n    const plusEl = createElement('div', { classes: 'accordion-close' });\n    headerEl.innerHTML = accordionHeader?.innerHTML;\n    headerButton.append(headerEl, plusEl);\n\n    const contentEl = createElement('div', { classes: ['accordion-content', 'accordion-content-close'] });\n\n    if (isContentLink(accordionContent)) {\n      await fragmentBlock(accordionContent);\n    }\n\n    if (accordionContent.textContent.startsWith('#id-') && accordionContent.innerHTML === accordionContent.textContent) {\n      const pointedContent = document.querySelector(`.${accordionContent.textContent.substring(1)}`);\n\n      if (pointedContent) {\n        const prevDisaply = pointedContent.parentElement.style.display;\n        pointedContent.parentElement.style.display = 'none';\n        // lets wait for loading of the content that we want to put inside the accordion\n        new MutationObserver((_, observer) => {\n          if (pointedContent.dataset.blockStatus === 'loaded') {\n            observer.disconnect();\n            contentEl.innerHTML = '';\n            contentEl.append(pointedContent.parentElement);\n            pointedContent.parentElement.style.display = prevDisaply;\n          }\n        }).observe(pointedContent, { attributes: true });\n      }\n    }\n\n    contentEl.innerHTML = accordionContent.innerHTML;\n\n    const accordionEl = createElement('div', { classes: ['accordion-item', 'accordion-item-close'] });\n    accordionEl.append(headerButton);\n    accordionEl.append(contentEl);\n\n    headerButton.addEventListener('click', () => {\n      accordionEl.classList.toggle('accordion-item-close');\n    });\n\n    return accordionEl;\n  });\n\n  block.innerHTML = '';\n  await Promise.allSettled(accordionsPromises);\n  accordionsPromises.forEach(async (acc) => {\n    const result = await acc;\n    block.append(result);\n  });\n}\n","import { createElement } from '../../scripts/common.js';\n\nexport default function decorate(block) {\n  const breadcrumbItems = createElement('ul', { classes: 'breadcrumb-list' });\n\n  const articleUrl = window.location.href.split('/').pop();\n  const articleName = articleUrl.replaceAll('-', ' ').toLowerCase();\n  const homeUrl = `${window.location.origin}/magazine/`;\n\n  breadcrumbItems.innerHTML = `\n    <li class=\"breadcrumb breadcrumb-home\">\n      <a href='${homeUrl}'>\n        Home\n      </a>\n    </li>\n    <li class=\"breadcrumb breadcrumb-current\">\n      ${articleName}\n    </li>`;\n\n  block.textContent = '';\n  block.append(breadcrumbItems);\n}\n","import { createOptimizedPicture } from '../../scripts/aem.js';\nimport { createElement } from '../../scripts/common.js';\n\nconst updateListElements = (ul, isDarkVar = false, isCTABlock = false) => {\n  const lis = [...ul.children];\n  lis.forEach((li) => {\n    // get image for setting as background image\n    if (isDarkVar) {\n      const img = li.querySelector('img');\n      li.style.backgroundImage = `url(${img.src})`;\n      const pictureDiv = li.querySelector('.cards-card-image');\n      pictureDiv.remove();\n    }\n\n    if (isCTABlock) {\n      const buttons = li.querySelectorAll('.cards-card-body .button-container');\n      const { length } = buttons;\n      if (length === 0) {\n        return;\n      }\n      // Last button is the one we want to use at card level\n      const tempLink = [...buttons].at(-1).querySelector('a');\n      const newLink = createElement('a', {\n        props: { href: tempLink.href, title: tempLink.title },\n      });\n\n      buttons[length - 1].remove(); // remove last button\n      newLink.innerHTML = li.innerHTML;\n      li.textContent = '';\n      li.appendChild(newLink);\n    }\n  });\n};\n\nconst recalcMaxHeight = (elements, initMaxHeight) => {\n  const newMaxHeight = elements.reduce((maxHeight, el) => {\n    el.style.height = '';\n\n    return el.offsetHeight > maxHeight ? el.offsetHeight : maxHeight;\n  }, initMaxHeight);\n\n  return newMaxHeight;\n};\n\nconst setHeightForCards = (cards, height) => {\n  [...cards].forEach((c) => {\n    c.style.height = `${height}px`;\n  });\n};\n\nconst observerFallBack = (changes, observer, cards, imgMaxHeight) => {\n  changes.forEach((change) => {\n    const isAttribute = change.type === 'attributes';\n    const isStatus = isAttribute && change.attributeName === 'data-section-status';\n    const isLoaded = isStatus && change.target.dataset.sectionStatus === 'loaded';\n    if (!isLoaded) {\n      return;\n    }\n    let maxHeight = imgMaxHeight;\n    const { children } = cards;\n    [...children].forEach((card) => {\n      const height = card.offsetHeight;\n      const img = card.querySelector('img');\n      if (img && img.offsetHeight === 0) {\n        img.classList.add('scaled');\n\n        // adding height recalculation on images load\n        img.addEventListener('load', () => {\n          maxHeight = recalcMaxHeight([...children], maxHeight);\n\n          setHeightForCards(children, maxHeight);\n        });\n      }\n      if (height > maxHeight) {\n        maxHeight = height;\n      }\n    });\n    setHeightForCards(children, maxHeight);\n    observer.disconnect();\n  });\n};\n\nconst setSameHeightCards = (block, cards, imgMaxHeight) => {\n  const parentSection = block.closest('[data-section-status]');\n  const observer = new MutationObserver((changes) => observerFallBack(changes, observer, cards, imgMaxHeight));\n  observer.observe(parentSection, { attributes: true, attributeFilter: ['data-section-status'] });\n};\n\nexport default function decorate(block) {\n  const isCTABlock = block.classList.contains('cta');\n  const isDarkVar = block.classList.contains('dark');\n  let imgMaxHeight = 0;\n  /* change to ul, li */\n  const ul = document.createElement('ul');\n  [...block.children].forEach((row) => {\n    const li = document.createElement('li');\n    li.innerHTML = row.innerHTML;\n    [...li.children].forEach((div) => {\n      const hasPicture = isCTABlock ? div.querySelector('picture') : div.children.length === 1 && div.querySelector('picture');\n      if (hasPicture) {\n        div.className = 'cards-card-image';\n      } else {\n        div.className = 'cards-card-body';\n      }\n    });\n    ul.append(li);\n  });\n  ul.querySelectorAll('img').forEach((img) => {\n    if (isDarkVar) {\n      imgMaxHeight = img.height > imgMaxHeight ? img.height : imgMaxHeight;\n    }\n    img.closest('picture').replaceWith(createOptimizedPicture(img.src, img.alt, false, [{ width: '750' }]));\n  });\n\n  // add background black\n  if (isDarkVar) {\n    const cardsContainer = block.parentElement.parentElement;\n    cardsContainer.classList.add('dark-card-container');\n  }\n  block.textContent = '';\n  block.append(ul);\n\n  updateListElements(ul, isDarkVar, isCTABlock);\n\n  if (isCTABlock) {\n    setSameHeightCards(block, ul, imgMaxHeight);\n  }\n}\n","import { isVideoLink, selectVideoLink, wrapImageWithVideoLink, addVideoShowHandler } from '../../scripts/video-helper.js';\nimport { createElement } from '../../scripts/common.js';\n\nconst debounceDelay = 30;\n\nfunction isInViewport(el) {\n  const rect = el.getBoundingClientRect();\n  return (\n    rect.top >= 0 &&\n    rect.left >= 0 &&\n    rect.bottom <= (window.innerHeight || document.documentElement.clientHeight) &&\n    rect.right <= (window.innerWidth || document.documentElement.clientWidth)\n  );\n}\n\nfunction calcCarouselItemsOffset(slidesEl) {\n  const first = slidesEl.firstElementChild;\n  const second = first.nextElementSibling;\n  const scrollOffset = second.getBoundingClientRect().x - first.getBoundingClientRect().x;\n\n  return scrollOffset;\n}\n\nfunction initScroll(slidesList, onActiveItemChange) {\n  let activeIndex = 0;\n\n  slidesList.addEventListener('scroll', () => {\n    const scrollOffset = calcCarouselItemsOffset(slidesList);\n    let index = 0;\n    // how many items have scrolled out?\n    while (slidesList.scrollLeft - scrollOffset * (index + 1) > 0) {\n      index += 1;\n    }\n\n    if (activeIndex !== index) {\n      activeIndex = index;\n      onActiveItemChange(activeIndex);\n    }\n  });\n}\n\nfunction adjustWidthAndControls(block, carousel, ...controls) {\n  function toggle() {\n    const gap = parseInt(window.getComputedStyle(carousel).gap, 10);\n    const itemWidth = parseInt(window.getComputedStyle(carousel.firstElementChild).width, 10);\n    const itemsWidth = itemWidth * carousel.children.length + gap * (carousel.children.length - 1);\n    const containerWidth = parseInt(window.getComputedStyle(carousel.parentElement).width, 10);\n    const showControls = itemsWidth > containerWidth;\n    controls.forEach((ul) => (showControls ? ul.classList.remove('hidden') : ul.classList.add('hidden')));\n  }\n\n  let resizeTimeout;\n  window.addEventListener('resize', () => {\n    if (resizeTimeout) {\n      clearTimeout(resizeTimeout);\n    }\n    resizeTimeout = setTimeout(toggle, debounceDelay);\n  });\n\n  // wait for the section to be loaded before we initially resize the carousel\n  const section = block.closest('.section');\n  new MutationObserver((_, observer) => {\n    if (section.dataset.sectionStatus === 'loaded') {\n      observer.disconnect();\n      setTimeout(toggle);\n    }\n  }).observe(section, { attributes: true });\n}\n\nfunction createDesktopControls(ul) {\n  function scroll(direction) {\n    const scrollOffset = calcCarouselItemsOffset(ul);\n\n    // when no more items are on the left, scroll to the last item\n    if (isInViewport(ul.firstChild) && direction === 'left') {\n      ul.scrollTo(ul.scrollWidth, 0);\n      return;\n    }\n\n    // when no more items are on the right, scroll to the firs item\n    if (isInViewport(ul.lastChild) && direction === 'right') {\n      ul.scrollTo(0, 0);\n      return;\n    }\n\n    // otherwise scroll one item in selected direction\n    const left = direction === 'left' ? -1 * scrollOffset : scrollOffset;\n    ul.scrollBy({ top: 0, left, behavior: 'smooth' });\n  }\n\n  const desktopControls = createElement('ul', { classes: 'desktop-controls' });\n  const leftButtonContainer = createElement('li');\n  const leftButton = createElement('button', { props: { type: 'button' } });\n  leftButton.textContent = 'Left';\n  const rightButtonContainer = createElement('li');\n  const rightButton = createElement('button', { props: { type: 'button' } });\n  rightButton.textContent = 'Right';\n  leftButtonContainer.append(leftButton);\n  rightButtonContainer.append(rightButton);\n  desktopControls.append(leftButtonContainer, rightButtonContainer);\n  ul.insertAdjacentElement('beforebegin', desktopControls);\n  const [prevButton, nextButton] = desktopControls.querySelectorAll(':scope button');\n  prevButton.addEventListener('click', () => scroll('left'));\n  nextButton.addEventListener('click', () => scroll('right'));\n\n  // Check if the carousel is inside a magazine article and if NOT hide the controls\n  const isMagazineArticle = document.querySelector('.magazine');\n  if (!isMagazineArticle) {\n    desktopControls.classList.add('hidden');\n  }\n\n  return desktopControls;\n}\n\nfunction createDotControls(ul) {\n  // create carousel controls for mobile\n  const dotControls = createElement('ul', { classes: 'mobile-controls' });\n  [...ul.children].forEach((item, j) => {\n    const control = createElement('li');\n    if (!j) {\n      control.className = 'active';\n    }\n    const button = createElement('button', { props: { type: 'button' } });\n    button.textContent = j + 1;\n    control.append(button);\n    control.firstElementChild.addEventListener('click', () => {\n      dotControls.querySelector('li.active').classList.remove('active');\n      control.classList.add('active');\n\n      const left = item.offsetLeft + item.offsetWidth / 2 - (item.parentNode.offsetLeft + item.parentNode.offsetWidth / 2);\n      ul.scrollTo({ top: 0, left, behavior: 'smooth' });\n    });\n\n    dotControls.append(control);\n  });\n  ul.insertAdjacentElement('beforebegin', dotControls);\n\n  let scrollTimeout;\n  ul.addEventListener('scroll', () => {\n    if (scrollTimeout) {\n      clearTimeout(scrollTimeout);\n    }\n    scrollTimeout = setTimeout(() => {\n      const scrollOffset = calcCarouselItemsOffset(ul);\n      let index = 0;\n      // how many items have scrolled out?\n      while (ul.scrollLeft - scrollOffset * (index + 1) > 0) {\n        index += 1;\n      }\n      dotControls.querySelector('li.active').classList.remove('active');\n      dotControls.children[index].classList.add('active');\n    }, debounceDelay);\n  });\n  return dotControls;\n}\n\nfunction replaceBlockClasses(block) {\n  const classes = block.classList;\n\n  if (classes.contains('cards')) {\n    classes.remove('cards');\n    classes.add('cards-variant');\n  }\n}\n\nexport default function decorate(block) {\n  replaceBlockClasses(block);\n  const ul = createElement('ul', { classes: ['items'] });\n\n  // We support two formats:\n  // 1. Each slide in a row (can be splitted into columns)\n  // 2. All values in the first cell as a list.\n  const isList = block.querySelectorAll(':scope > div > div > ul').length;\n  const rows = [...block.querySelectorAll(isList ? ':scope > div > div > ul > li' : ':scope > div')];\n\n  rows.forEach((row) => {\n    const columns = row.querySelectorAll(':scope > div, :scope > picture');\n    columns.forEach((column) => {\n      column.classList.add('carousel-item-column');\n    });\n\n    const listItem = createElement('li', { classes: ['carousel-item'] });\n    listItem.append(...row.children);\n    ul.append(listItem);\n  });\n\n  [...ul.children].forEach((li) => {\n    // Add wrapper around the content\n    const container = createElement('div', { classes: ['carousel-content-wrapper'] });\n\n    container.innerHTML = li.innerHTML;\n    li.innerHTML = '';\n    li.append(container);\n\n    // for each column\n    li.querySelectorAll('.carousel-item-column').forEach((column) => {\n      const picture = column.querySelector('picture');\n      const links = [...column.querySelectorAll('a')];\n      const videoLinks = links.filter((link) => isVideoLink(link));\n\n      // handling image with video link\n      if (videoLinks.length && picture) {\n        const selectedVideoLink = selectVideoLink(videoLinks);\n        if (selectedVideoLink) {\n          // removing unused video links\n          videoLinks\n            .filter((videoLink) => videoLink.getAttribute('href') !== selectedVideoLink.getAttribute('href'))\n            .forEach((link) => link.remove());\n\n          wrapImageWithVideoLink(selectedVideoLink, picture);\n          addVideoShowHandler(selectedVideoLink);\n          // remove the video wrapper paragraph\n          selectedVideoLink.parentElement.replaceWith(selectedVideoLink);\n        }\n      } else if (links.length && picture) {\n        // handling image with link\n        const clone = links[0].cloneNode(false);\n        picture.replaceWith(clone);\n        clone.append(picture);\n        column.prepend(clone);\n      }\n\n      // handling heading and subheading\n      const [header, subheader] = [...column.querySelectorAll('h1, h2, h3, h4, h5, h6')].sort((h1, h2) => h1.tagName[1] - h2.tagName[1]);\n\n      if (header) {\n        const newHeader = createElement('h2', { classes: 'carousel-item-header' });\n        newHeader.innerHTML = header.innerHTML;\n        header.replaceWith(newHeader);\n      }\n      if (subheader) {\n        const newSubheader = createElement('h3', { classes: 'carousel-item-subheader' });\n        newSubheader.innerHTML = subheader.innerHTML;\n        subheader.replaceWith(newSubheader);\n      }\n\n      // removing new lines from content\n      container.querySelectorAll('br').forEach((el) => el.remove());\n      // removing empty paragraphs\n      container.querySelectorAll('p').forEach((p) => {\n        const paragraphHTML = p.innerHTML;\n        const isEmptyParagrph = !paragraphHTML.replaceAll('\\n', '').trim();\n\n        if (isEmptyParagrph) {\n          p.remove();\n        }\n      });\n\n      // warpping all paragraphs and headers\n      const textElements = column.querySelectorAll('p, h2, h3');\n      if (textElements.length) {\n        const textWrapper = createElement('div', { classes: 'carousel-item-text' });\n        textWrapper.append(...textElements);\n        column.append(textWrapper);\n      }\n    });\n\n    const carouselLink = container.querySelector('a');\n    if (carouselLink) {\n      carouselLink.classList.add('button', 'carousel-link');\n    }\n\n    block.innerHTML = '';\n    block.append(ul);\n  });\n\n  const desktopControls = createDesktopControls(ul);\n  const dotControls = createDotControls(ul);\n\n  const onActiveItemChange = (newActiveItemIndex) => {\n    const newActiveEl = ul.querySelectorAll('li')[newActiveItemIndex];\n    ul.querySelector('li.active')?.classList.remove('active');\n    newActiveEl.classList.add('active');\n  };\n\n  initScroll(ul, onActiveItemChange);\n  onActiveItemChange(0);\n\n  adjustWidthAndControls(block, ul, dotControls, desktopControls);\n}\n","import { addVideoShowHandler, isVideoLink, selectVideoLink, wrapImageWithVideoLink } from '../../scripts/video-helper.js';\nimport { createElement } from '../../scripts/common.js';\nimport { getAllElWithChildren } from '../../scripts/scripts.js';\n\nconst decorateUnderline = (col) => {\n  const hr = createElement('hr', { classes: 'column-underline' });\n  const u = col.querySelector('u');\n  if (!u) {\n    const strong = col.firstElementChild.querySelector('strong');\n    if (strong) {\n      strong.parentElement.appendChild(hr);\n    }\n    return;\n  }\n  const uText = u.textContent;\n  const p = u.closest('p');\n  u.parentElement.textContent = uText;\n  p.appendChild(hr);\n};\n\nconst removeEmptyPs = (pictureWrapper) => {\n  const Ps = pictureWrapper.querySelectorAll('p');\n  [...Ps].forEach((p) => {\n    if (p.children.length === 0) {\n      p.remove();\n    }\n  });\n};\n\nconst videoHandling = (blockEl) => {\n  const pictureWrapper = getAllElWithChildren(blockEl.querySelectorAll(':scope > div > div'), 'picture')[0];\n  const picture = pictureWrapper && pictureWrapper.querySelector('picture');\n  const links = pictureWrapper && pictureWrapper.querySelectorAll('a');\n\n  if (!picture || !links.length) {\n    return;\n  }\n\n  const videoLinks = [...links].filter((link) => isVideoLink(link));\n  const selectedVideoLink = selectVideoLink(videoLinks);\n\n  if (selectedVideoLink) {\n    videoLinks.filter((videoLink) => videoLink.getAttribute('href') !== selectedVideoLink.getAttribute('href')).forEach((link) => link.remove());\n    wrapImageWithVideoLink(selectedVideoLink, picture);\n    addVideoShowHandler(selectedVideoLink);\n    selectedVideoLink.parentElement.replaceChildren(selectedVideoLink);\n    removeEmptyPs(pictureWrapper);\n  }\n};\n\nexport default function decorate(block) {\n  const cols = [...block.firstElementChild.children];\n  block.classList.add(`columns-${cols.length}-cols`);\n  const isInfo = block.classList.contains('info');\n  const isPromo = block.classList.contains('promo');\n  if (isInfo) {\n    const hasAbsolute = block.classList.contains('absolute');\n    if (hasAbsolute) {\n      block.closest('.columns-wrapper').classList.add('info', 'absolute');\n    }\n    cols.forEach((col) => {\n      col.className = 'columns-col-wrapper';\n      decorateUnderline(col);\n    });\n  }\n  if (isPromo) {\n    const parent = block.querySelectorAll(':scope > div > div');\n    const textParent = getAllElWithChildren(parent, 'picture', true)[0];\n    const pictureParent = getAllElWithChildren(parent, 'picture')[0];\n    const imgLeft = parent[0].querySelector('picture');\n    textParent.className = 'columns-promo-text-wrapper';\n    if (pictureParent) {\n      pictureParent.className = 'columns-promo-picture-wrapper';\n    }\n    if (imgLeft) {\n      textParent.classList.add('columns-promo-img-left');\n    }\n  }\n\n  videoHandling(block);\n}\n","/**\n * OneTrust Cookies list is automatically injected into this block.\n * The OneTrust framework is loaded from delayed.js.\n * @param block\n */\nexport default function decorate(block) {\n  block.setAttribute('id', 'ot-sdk-cookie-policy');\n  block.textContent = '';\n}\n","import { createElement } from '../../scripts/common.js';\n\nexport default function decorate(block) {\n  const button = createElement('button', { classes: 'cta' });\n  button.textContent = block.textContent;\n  button.addEventListener('click', () => {\n    if (window.OneTrust) {\n      window.OneTrust.ToggleInfoDisplay();\n    }\n  });\n\n  block.textContent = '';\n  block.append(button);\n}\n","import { createElement } from '../../scripts/common.js';\n\nexport default function decorate(block) {\n  const children = [...block.children];\n\n  const downloadSpecsSection = createElement('div', { classes: 'download-specs-section' });\n  const specsTitle = children.shift().querySelector('h3');\n  const downloadSpecsList = createElement('ul', { classes: 'download-specs-list' });\n\n  children.forEach((e, idx) => {\n    const downloadItem = createElement('li', { classes: ['download-specs-item', `download-specs-item-${idx + 1}`] });\n\n    const anchorElement = createElement('a', { classes: 'anchor-element' });\n    const linkUrl = e.querySelector('a').getAttribute('href');\n    anchorElement.setAttribute('href', linkUrl);\n    anchorElement.setAttribute('target', '_blank');\n\n    const img = createElement('img', { classes: 'download-specs-icon' });\n    img.src = '/icons/pdficon.png';\n\n    const pElement = createElement('p', { classes: 'p-element' });\n    const text = e.querySelector('div').innerText;\n    pElement.textContent = text;\n\n    anchorElement.append(img, pElement);\n    downloadItem.append(anchorElement);\n    downloadSpecsList.append(downloadItem);\n  });\n  downloadSpecsSection.append(specsTitle, downloadSpecsList);\n\n  block.textContent = '';\n  block.append(downloadSpecsSection);\n}\n","import { createElement } from '../../scripts/common.js';\n\nconst buildRegularDownloadBlock = (block) => {\n  const children = [...block.children];\n\n  const downloadList = createElement('ul', { classes: 'download-list' });\n\n  children.forEach((e, idx) => {\n    const downloadItem = createElement('li', { classes: ['download-item', `download-item-${idx + 1}`] });\n\n    const image = e.querySelector('picture').innerHTML;\n\n    const allTexts = e.querySelectorAll('p');\n\n    const titleElement = allTexts[0].querySelector('a');\n    const title = titleElement.getAttribute('title');\n    const titleUrl = titleElement.getAttribute('href');\n\n    const textContent = allTexts[1].innerHTML;\n\n    const linkElement = allTexts[2].querySelector('a');\n    const linkText = linkElement.getAttribute('title');\n    const linkUrl = linkElement.getAttribute('href');\n\n    const fileExtension = linkUrl.split('.').pop();\n    const fileRoute = fileExtension === 'xlsm' ? `${window.hlx.codeBasePath}/files/${linkUrl.slice(7)}` : linkUrl;\n\n    downloadItem.innerHTML = `\n    <div class='download-card'>\n      <div class='download-image'>\n        <picture>\n          ${image}\n        </picture>\n      </div>\n      <div class='download-texts'>\n        <a href='${titleUrl}' class='download-texts-title'>\n          ${title}\n        </a>\n        <p class='download-texts-text'>\n          ${textContent}\n        </p>\n        <a href='${fileRoute}' class='download-texts-link' target='_blank' title='${linkText}'>\n          ${linkText}\n        </a>\n      </div>\n    </div>`;\n    downloadList.append(downloadItem);\n  });\n  block.textContent = '';\n  block.append(downloadList);\n};\n\nconst buildNewDownloadBlock = (block) => {\n  const children = [...block.children];\n  const downloadNewList = createElement('ul', { classes: 'download-new-list' });\n\n  children.forEach((e, idx) => {\n    const downloadItem = createElement('li', { classes: ['download-new-item', `download-new-item-${idx + 1}`] });\n    const allTexts = e.querySelectorAll('li');\n    const linkUrl = e.querySelector('a').getAttribute('href');\n\n    const fileExtension = linkUrl.split('.').pop();\n    const fileRoute = fileExtension === 'xlsm' ? `${window.hlx.codeBasePath}/files/${linkUrl.slice(7)}` : linkUrl;\n\n    const newCondition = e.children[1].innerText.toUpperCase();\n    const number = allTexts[1].innerText;\n    const title = allTexts[2].innerText;\n    const subTitle = allTexts[3].innerText;\n\n    downloadItem.innerHTML = `\n    <a href=\"${fileRoute}\" target=\"_blank\" class='download-new-link' title='${title}'>\n        <div class='download-new-texts'>\n          <p>\n            ${number}. ${title}\n          </p>\n          <small>\n            ${subTitle}\n          </small>\n        </div>\n    ${\n      newCondition.length === 0\n        ? ''\n        : `<div class='download-new-label'>\n      ${newCondition}\n    </div>`\n    }\n    </a>`;\n    downloadNewList.append(downloadItem);\n  });\n\n  block.textContent = '';\n  block.append(downloadNewList);\n};\n\nexport default function decorate(block) {\n  const typeDetector = [...block.classList];\n\n  // This detects what block needs to be render and calls the corresponding function.\n  if (!typeDetector.includes('new')) {\n    buildRegularDownloadBlock(block);\n  } else if (typeDetector.includes('new')) {\n    buildNewDownloadBlock(block);\n  }\n}\n","import {\n  selectVideoLink,\n  addPlayIcon,\n  showVideoModal,\n  isLowResolutionVideoUrl,\n  createIframe,\n  createLowResolutionBanner,\n  videoTypes,\n} from '../../scripts/video-helper.js';\n\nexport default function decorate(block) {\n  const { youtube, local, both } = videoTypes;\n  const isAutoplay = block.classList.contains('autoplay');\n  const isLoopedVideo = block.classList.contains('loop');\n  const isFullWidth = block.classList.contains('full-width');\n  const isYoutubeOnly = block.classList.contains('youtube-only');\n  const isLocalOnly = block.classList.contains('local-only');\n  const isBothOrDefault = block.classList.contains('both') || (!isYoutubeOnly && !isLocalOnly);\n  const videoWrapper = document.createElement('div');\n  // removing classes to avoid collision with other css\n  block.classList.remove('loop', 'autoplay', 'full-width');\n  videoWrapper.classList.add('embed-video');\n\n  let videoType;\n  if (isBothOrDefault) {\n    videoType = both;\n  } else if (isYoutubeOnly) {\n    videoType = youtube;\n  } else if (isLocalOnly) {\n    videoType = local;\n  }\n\n  const links = block.querySelectorAll('a');\n  const selectedLink = selectVideoLink(links, isFullWidth ? 'local' : 'auto', videoType);\n  const video = document.createElement('video');\n  const source = document.createElement('source');\n\n  if (!selectedLink) {\n    block.innerHTML = '';\n\n    console.warn('Embed block: There is no video link. Please check if the fallback video link is provided.');\n    return;\n  }\n\n  const isLowResolutionVideo = isLowResolutionVideoUrl(selectedLink.getAttribute('href'));\n  const showControls = isLowResolutionVideo && !isFullWidth;\n\n  video.appendChild(source);\n  block.innerHTML = '';\n  block.appendChild(videoWrapper);\n\n  const loadEmbed = () => {\n    if (video.classList.contains('embed-video-loaded') || !selectedLink) {\n      return;\n    }\n\n    if (isAutoplay) {\n      video.autoplay = true;\n      // autoplay requires the video to be muted otherwise the autoplay\n      // can be block by the browser\n      // https://developer.mozilla.org/en-US/docs/Web/Media/Autoplay_guide\n      video.muted = true;\n    }\n\n    if (isLoopedVideo) {\n      video.loop = true;\n    }\n\n    video.playsInline = true;\n    video.controls = showControls;\n    video.classList.add('embed-video-element', 'embed-video-loaded');\n    source.setAttribute('src', selectedLink.getAttribute('href'));\n    source.setAttribute('type', 'video/mp4');\n    videoWrapper.appendChild(video);\n\n    if (isFullWidth) {\n      const link = document.createElement('a');\n      link.setAttribute('href', selectVideoLink(links).getAttribute('href'));\n      block.classList.add('embed-full-width');\n      addPlayIcon(block);\n\n      video.addEventListener('click', () => {\n        showVideoModal(selectVideoLink(links).getAttribute('href'));\n      });\n    }\n\n    if (!isFullWidth && !isLocalOnly) {\n      const banner = createLowResolutionBanner();\n      videoWrapper.prepend(banner);\n    }\n  };\n\n  const observer = new IntersectionObserver((entries) => {\n    if (entries.some((e) => e.isIntersecting)) {\n      observer.disconnect();\n      if (isLowResolutionVideo) {\n        loadEmbed();\n      } else {\n        createIframe(selectedLink.getAttribute('href'), { parentEl: videoWrapper, classes: 'embed-video-element' });\n      }\n    }\n  });\n  observer.observe(block);\n}\n","import { createElement, getTextLabel, capitalizeWords } from '../../scripts/common.js';\nimport { fetchMagazineData, formatArticlesArray, formatFacetsArray } from '../../scripts/services/magazine.service.js';\n\nconst blockName = 'explore-articles';\n\nconst queryVariables = { limit: 100, facets: ['ARTICLE', 'TRUCK'], sort: 'PUBLISH_DATE_DESC' };\nconst allMagazineData = await fetchMagazineData(queryVariables);\nconst articleCount = allMagazineData?.count || 0;\nconst allArticles = formatArticlesArray(allMagazineData?.items);\nconst allFacets = formatFacetsArray(allMagazineData?.facets);\n\nconst { truck: allTrucks, category: allCategories } = allFacets;\nconst [categoryPlaceholder, truckPlaceholder] = getTextLabel('explore_articles:placeholders').split(',');\n\nlet counter = 1;\nconst artsPerChunk = 4;\n\nif (articleCount > allArticles.length) {\n  let offset = allArticles.length;\n  while (offset < articleCount) {\n    const newQueryVariables = { ...queryVariables, offset };\n    const newMagazineData = await fetchMagazineData(newQueryVariables);\n    const newItems = formatArticlesArray(newMagazineData?.items || []);\n    allArticles.push(...newItems);\n    offset += newItems.length;\n\n    // Exit loop if no more items are fetched or if the next offset exceeds the article count\n    if (newItems.length === 0 || offset >= articleCount) {\n      break;\n    }\n  }\n}\n\nconst divideArray = (mainArray, perChunk) => {\n  const dividedArrays = mainArray.reduce((resultArray, item, index) => {\n    const chunkIndex = Math.floor(index / perChunk);\n    if (!resultArray[chunkIndex]) {\n      resultArray[chunkIndex] = [];\n    }\n    resultArray[chunkIndex].push(item);\n    return resultArray;\n  }, []);\n  return dividedArrays;\n};\n\nconst getOptions = (list, placeholder) => {\n  const options = [];\n  list.unshift(placeholder);\n  list.forEach((el) => {\n    const option = createElement('option', { props: { value: el } });\n    option.innerText = capitalizeWords(el);\n    if (el.length !== 0) {\n      options.push(option);\n    }\n  });\n  return options;\n};\n\nconst buildSelect = (type, array, text) => {\n  const select = createElement('select', { classes: ['input-field', `${type}-input`], props: { id: type, name: type } });\n  const options = getOptions(array, text);\n  options.forEach((option) => {\n    select.append(option);\n  });\n  return select;\n};\n\nconst createTruckSection = (trucks) => {\n  const truckList = trucks?.map((item) => item.replace('Mack ', '')).join(', ');\n  return `\n    <div class=\"article-truck\">\n      <img\n        class=\"truck-icon\"\n        src=\"/icons/Truck_Key_icon.svg\"\n        alt=\"truck icon\"\n      />\n      <p class=\"article-truck-text\">${truckList}</p>\n    </div>`;\n};\n\nconst buildArticle = (article, idx) => {\n  const linkUrl = new URL(article.path, window.location.origin);\n  const categoriesWithDash = article.category.replaceAll(' ', '-').toLowerCase();\n  const categoryUrl = new URL(`magazine/categories/${categoriesWithDash}`, window.location.origin);\n  const articleDiv = createElement('div', { classes: 'article', props: { id: `group-${idx}` } });\n  const articleContent = document.createRange().createContextualFragment(`\n      <div class=\"article-image\">\n          <img src=\"${article.image}\" alt=\"article image\" class=\"image\">\n      </div>\n      <div class=\"article-content\">\n          ${article.category ? `<a href=\"${categoryUrl}\" class=\"article-category\">${article.category}</a>` : ''}\n          <a href=\"${linkUrl}\" class=\"article-link\">\n            <h3 class=\"article-title\">${article.title}</h3>\n            ${article.description ? `<p class=\"article-subtitle\">${article.description}</p>` : ''}\n          </a>\n          ${article.truck ? createTruckSection(article.truck) : ''}\n\n      </div>\n  `);\n  articleDiv.append(articleContent);\n  return articleDiv;\n};\n\nconst loadMoreArticles = (evt, articleGroups, amountOfGroups) => {\n  evt.preventDefault();\n  const activeButton = evt.srcElement;\n  const allShownArticles = document.querySelectorAll('.article');\n  const lastShownArticle = allShownArticles[allShownArticles.length - 1];\n  const lastShownId = +lastShownArticle.id.split('-').pop();\n  const nextArticleGroup = articleGroups[lastShownId + 1];\n\n  nextArticleGroup.forEach((e, idx) => {\n    if (idx !== 0) {\n      lastShownArticle.insertAdjacentElement('afterend', e);\n    }\n  });\n\n  if (amountOfGroups - 1 <= counter) {\n    activeButton.remove();\n  }\n\n  counter += 1;\n};\n\nconst getArticleGroups = (artGroup) => {\n  const groups = [];\n  artGroup.forEach((articleGroup, idx) => {\n    const group = [idx];\n    articleGroup.forEach((el) => {\n      const article = buildArticle(el, idx);\n      group.push(article);\n    });\n    groups.push(group);\n  });\n  return groups;\n};\n\nconst buildFirstArticles = (art, section) => {\n  const firstArticles = art[0];\n  firstArticles.forEach((e, idx) => {\n    if (idx !== 0) {\n      section.append(e);\n    }\n  });\n};\n\nconst getSelectedAmount = (array) => {\n  const initialValue = 0;\n  const total = array.reduce((acc, curr) => acc + curr.length, initialValue);\n  return total;\n};\n\nconst buildArticleList = (articles) => {\n  const groupedArticles = divideArray(articles, artsPerChunk);\n  const articleGroups = getArticleGroups(groupedArticles);\n  const selectedArticlesNumber = getSelectedAmount(groupedArticles);\n  const amountOfGroups = articleGroups.length;\n\n  const articlesSection = createElement('div', { classes: `${blockName}-articles` });\n  const articlesContent = document.createRange().createContextualFragment(`\n      <div class=\"pagination-section\">\n        <p class=\"article-amount\">\n          ${selectedArticlesNumber !== 0 ? `${selectedArticlesNumber} articles` : getTextLabel('explore_articles:no_article_message')}\n        </p>\n      </div>\n      <div class=\"article-list\"></div>\n      <div class=\"${blockName}-more\">\n        ${selectedArticlesNumber > artsPerChunk ? `<button class=\"more-btn\">${getTextLabel('explore_articles:load_more_button')}</button>` : ''}\n      </div>\n    `);\n\n  if (articleGroups.length !== 0) {\n    buildFirstArticles(articleGroups, articlesContent.querySelector('.article-list'));\n    articlesContent.querySelector('.more-btn')?.addEventListener('click', (evt) => loadMoreArticles(evt, articleGroups, amountOfGroups));\n  }\n  articlesSection.append(articlesContent);\n\n  return articlesSection;\n};\n\nconst handleForm = () => {\n  counter = 1;\n  const fieldset = document.querySelector('#explore-magazine-fieldset');\n  const selects = fieldset.querySelectorAll('select');\n  const [catSelect, truckSelect] = selects;\n\n  const filteredList = allArticles.filter((art) => {\n    const truckValue = truckSelect.value.toLowerCase();\n    const truckMatch = art.truck?.some((truck) => truck.toLowerCase() === truckValue);\n    const categoryMatch = art.category.toLowerCase() === catSelect.value.toLowerCase();\n\n    return (\n      (catSelect.value === categoryPlaceholder && truckSelect.value === truckPlaceholder) ||\n      (catSelect.value === categoryPlaceholder && truckMatch) ||\n      (categoryMatch && truckSelect.value === truckPlaceholder) ||\n      (categoryMatch && truckMatch)\n    );\n  });\n\n  const articleList = document.querySelector(`.${blockName}-articles`);\n  articleList.textContent = '';\n  const filteredArticles = buildArticleList(filteredList, 0);\n  articleList.append(filteredArticles);\n};\n\nconst buildFieldset = () => {\n  const formSection = createElement('div', { classes: `${blockName}-fieldset` });\n  const formFragment = document.createRange().createContextualFragment(`\n    <form>\n      <fieldset class=\"fieldset filter-list\" method=\"get\" name=\"article-fieldset\" id=\"explore-magazine-fieldset\">\n          <div class=\"category-field\"></div>\n          <div class=\"trucks-field\"></div>\n      </fieldset>\n    </form>\n  `);\n\n  formFragment.querySelector('form').addEventListener('change', handleForm);\n  formFragment.querySelector('.category-field').append(buildSelect('category', allCategories, categoryPlaceholder));\n  formFragment.querySelector('.trucks-field').append(buildSelect('truck', allTrucks, truckPlaceholder));\n\n  formSection.append(formFragment);\n\n  return formSection;\n};\n\nexport default async function decorate(block) {\n  const children = block.querySelectorAll('p');\n  const [title, text] = children;\n\n  const generalSection = createElement('div', { classes: `${blockName}-section` });\n  const contentWrapper = document.createRange().createContextualFragment(`\n    <div class=\"${blockName}-heading\">\n      <h4 class=\"${blockName}-title\" >${title.innerText}</h4>\n      <p class=\"${blockName}-text\" >${text.innerText}</p>\n    </div>\n    <div class=\"${blockName}-content\"></div>\n  `);\n\n  contentWrapper.querySelector(`.${blockName}-content`).append(buildFieldset(), buildArticleList(allArticles, 0));\n\n  generalSection.append(contentWrapper);\n\n  block.textContent = '';\n  block.append(generalSection);\n}\n","// media query match that indicates mobile/tablet width\nconst MQ = window.matchMedia('(min-width: 768px)');\nlet isInitialPainting = true;\n\nfunction addTitlesListener(container) {\n  const tabTitles = container.querySelectorAll('h4');\n  container.onclick = (e) => {\n    const { target } = e;\n    if (isInitialPainting) {\n      return;\n    }\n    if (target.localName !== 'h4') {\n      return;\n    }\n    const tabContent = target.nextElementSibling;\n    const contentWrapper = tabContent.querySelector('.content-wrapper');\n    const isActive = target.classList.contains('active');\n    [...tabTitles].forEach((tabTitle) => tabTitle.classList.remove('active'));\n    if (MQ.matches) {\n      target.classList.add('active');\n    } else {\n      target.classList.toggle('active', !isActive);\n    }\n    // tab fold/unfold animation\n    if (MQ.matches && isActive) {\n      return;\n    }\n    [...tabTitles].forEach((title) => {\n      title.nextElementSibling.style.height = 0;\n    });\n    tabContent.style.height = tabContent.clientHeight ? 0 : `${contentWrapper.clientHeight}px`;\n  };\n}\n\nfunction isOutOfRange(isNext, movement, lastSlide) {\n  const isFirstSlide = !isNext && movement > 0;\n  const isLastSlide = isNext && movement < lastSlide;\n  return isFirstSlide || isLastSlide;\n}\n\nfunction addClickListener(container) {\n  const slideControls = container.querySelector('.slide-controls');\n  const slidesContainer = container.querySelector('.slides-container');\n  const arrows = slideControls.querySelectorAll('.slide-control');\n  const previousBtn = slideControls.querySelector('.btn-previous');\n  const nextBtn = slideControls.querySelector('.btn-next');\n  const paginationBtns = slideControls.querySelectorAll('.pagination-link');\n  const { length } = slidesContainer.children;\n  slideControls.onclick = (e) => {\n    const { target } = e;\n    e.preventDefault();\n    if (target.localName !== 'a') {\n      return;\n    }\n    const activeSlide = slidesContainer.querySelector('.active');\n    const isArrow = target.classList.contains('slide-control');\n    let movement;\n    let targetSlide;\n    let targetArrow;\n    if (isArrow) {\n      const isNext = target.classList.contains('btn-next');\n      const lastSlide = (length - 1) * -100;\n      const sum = isNext ? -100 : 100;\n      const slideIndex = activeSlide.dataset.value;\n\n      targetArrow = target;\n      targetSlide = isNext ? +slideIndex + 1 : +slideIndex - 1;\n      movement = slideIndex * -100 + sum;\n      if (isOutOfRange(isNext, movement, lastSlide)) {\n        return;\n      }\n    } else {\n      targetSlide = +target.dataset.value;\n      movement = targetSlide * -100;\n      if (targetSlide === length - 1) {\n        targetArrow = nextBtn;\n      } else if (targetSlide === 0) {\n        targetArrow = previousBtn;\n      }\n    }\n    slidesContainer.style = `translate: ${movement}%`;\n    activeSlide.classList.remove('active');\n    slidesContainer.querySelector(`[data-value=\"${targetSlide}\"]`).classList.add('active');\n    [...arrows].forEach((arrow) => arrow.classList.remove('disabled'));\n    if (targetSlide === length - 1 || targetSlide === 0) {\n      targetArrow.classList.add('disabled');\n    }\n    [...paginationBtns].forEach((btn) => btn.classList.remove('active'));\n    slideControls.querySelector(`[data-value=\"${targetSlide}\"]`).classList.add('active');\n  };\n}\n\nfunction addSliderControls(contentWrapper, slidesLength) {\n  const tabBody = contentWrapper.querySelector('.description');\n  const slideControls = document.createElement('div');\n  const previousBtn = document.createElement('a');\n  const nextBtn = document.createElement('a');\n  const pagination = document.createElement('div');\n  const navList = document.createElement('ul');\n\n  for (let i = 0; i < slidesLength; i++) {\n    const li = document.createElement('li');\n    const a = document.createElement('a');\n    a.href = '#';\n    a.textContent = `${i}`;\n    a.dataset.value = `${i}`;\n    a.className = i !== 0 ? 'pagination-link' : 'pagination-link active';\n    li.appendChild(a);\n    navList.appendChild(li);\n  }\n  previousBtn.href = '#';\n  nextBtn.href = '#';\n  slideControls.className = 'slide-controls';\n  previousBtn.className = 'slide-control btn-previous disabled';\n  nextBtn.className = 'slide-control btn-next';\n  pagination.className = 'pagination';\n  previousBtn.textContent = 'PREVIOUS';\n  nextBtn.textContent = 'NEXT';\n  pagination.appendChild(navList);\n  slideControls.append(pagination, previousBtn, nextBtn);\n  contentWrapper.insertBefore(slideControls, tabBody);\n}\n\nfunction decorateSlider(container) {\n  // explore trucks' slider has to be the 1st h4 element\n  const tabContent = container.querySelector('h4:first-of-type + .tab-content');\n  const contentWrapper = tabContent.querySelector('.content-wrapper');\n  const sliderWrapper = contentWrapper.children[0]; // div with data-align center\n\n  const imageContainers = sliderWrapper.querySelectorAll('p');\n  const titles = sliderWrapper.querySelectorAll('h2');\n  const newSliderWrapper = document.createElement('div');\n  const slidesContainer = document.createElement('div');\n  newSliderWrapper.className = 'slider-wrapper';\n  slidesContainer.className = 'slides-container';\n\n  [...imageContainers].forEach((p, i) => {\n    const div = document.createElement('div');\n    const imgLink = document.createElement('a');\n    const picture = p.children[0];\n    imgLink.href = titles[i].querySelector('a').href;\n    div.className = i !== 0 ? 'slide' : 'slide active';\n    div.dataset.value = i;\n    imgLink.appendChild(picture);\n    p.prepend(imgLink);\n    div.append(p, titles[i]);\n    slidesContainer.appendChild(div);\n  });\n\n  newSliderWrapper.appendChild(slidesContainer);\n  contentWrapper.prepend(newSliderWrapper);\n  sliderWrapper.remove();\n\n  // add slider controls\n  addSliderControls(contentWrapper, titles.length);\n  addClickListener(container);\n}\n\nfunction onResizeCalculation(container) {\n  const tabContentList = container.querySelectorAll(':scope > .tab-content > .content-wrapper');\n\n  // resizing content of active tab\n  const resizeObserver = new ResizeObserver((entries) => {\n    const activeContent = container.querySelector(':scope > .tab-title.active + .tab-content > .content-wrapper');\n\n    entries.forEach((entry) => {\n      // resize the tab content element to fit the children node\n      if (activeContent === entry.target) {\n        activeContent.parentElement.style.height = `${entry.target.clientHeight}px`;\n      }\n    });\n  });\n\n  tabContentList.forEach((el) => {\n    resizeObserver.observe(el);\n  });\n\n  // handling the switch between row of elements (on desktop) and carousel (on tablet and mobile)\n  let translationsList = null;\n\n  MQ.addEventListener('change', (e) => {\n    const sliderContainersList = container.querySelectorAll('.slides-container');\n\n    if (!translationsList) {\n      translationsList = Array(sliderContainersList.length).fill(0);\n    }\n\n    sliderContainersList.forEach((el, index) => {\n      if (e.matches) {\n        // storing the mobile translation - the active slide in the carousel\n        translationsList[index] = el.style.translate;\n        el.style.translate = 0;\n      } else {\n        // reverting to the prev active slide on mobile\n        el.style.translate = translationsList[index];\n      }\n    });\n  });\n}\n\nfunction setupInitialStyles(container) {\n  const tabTitle = container.children[0];\n  const tabContent = container.children[1];\n  const contentWrapper = tabContent.children[0];\n  let resizeTimer = null;\n  tabContent.style.height = MQ.matches ? '578px' : 0;\n  const resizeObserver = new ResizeObserver((entries) => {\n    entries.forEach((entry) => {\n      if (entry.contentRect.height > 0 && MQ.matches) {\n        tabContent.style.height = `${entry.target.clientHeight}px`;\n      }\n    });\n    clearTimeout(resizeTimer);\n    resizeTimer = setTimeout(() => {\n      isInitialPainting = false;\n      resizeObserver.disconnect();\n    }, 3000);\n  });\n  resizeObserver.observe(contentWrapper);\n  if (MQ.matches) {\n    tabTitle.classList.add('active');\n  }\n}\n\nexport default function decorate(block) {\n  const tabContainers = block.children;\n  const exploreContainer = document.createElement('div');\n  [...tabContainers].forEach((tab) => {\n    const tabContent = document.createElement('div');\n    const contentWrapper = document.createElement('div');\n    const content = [...tab.children];\n    const tabTitle = tab.querySelector('h4');\n    const ctas = tab.querySelector('.button-container');\n    // relocate content to the new container\n    content.forEach((node) => {\n      contentWrapper.appendChild(node);\n    });\n    // add again the content and the title\n    tabContent.appendChild(contentWrapper);\n    exploreContainer.append(tabTitle, tabContent);\n    // add proper class names for styling\n    tabContent.style.height = 0;\n    ctas.classList.add('cta');\n    tabContent.className = 'tab-content';\n    contentWrapper.className = 'content-wrapper';\n    tab.className = 'tab-container';\n    tabTitle.className = 'tab-title';\n    tabTitle.setAttribute('tabindex', 0);\n    contentWrapper.children[0].className = 'tab-image';\n    contentWrapper.children[1].className = 'description';\n    tab.remove();\n  });\n\n  exploreContainer.className = 'tab-container';\n  block.appendChild(exploreContainer);\n  addTitlesListener(exploreContainer);\n  decorateSlider(exploreContainer);\n  setupInitialStyles(exploreContainer);\n  onResizeCalculation(exploreContainer);\n}\n","import { createElement } from '../../scripts/common.js';\n\nexport default function decorate(block) {\n  block.querySelectorAll('h1, h2, h3, h4, h5, h6').forEach((title) => {\n    // convert to h4 because it might be any header level\n    const h4 = createElement('h4', { classes: 'feature-title' });\n    h4.innerHTML = title.innerHTML;\n    title.replaceWith(h4);\n  });\n\n  block.querySelectorAll(':scope > div').forEach((row) => row.classList.add('row'));\n  block.querySelectorAll(':scope > div > div').forEach((cell) => cell.classList.add('feature'));\n\n  // unwrap picture so that text styles are not applied to this paragraph\n  block.querySelectorAll('picture').forEach((picture) => picture.closest('p').replaceWith(picture));\n}\n","import { createElement } from '../../scripts/common.js';\n\nexport default function decorate(block) {\n  const container = block.querySelector(':scope > div > div');\n  const inputContainer = createElement('div', { classes: 'find-dealer-input-wrapper' });\n  const input = createElement('input', {\n    classes: 'find-dealer-input',\n    props: {\n      title: 'code',\n      type: 'text',\n      placeholder: 'Enter Zip',\n    },\n  });\n  container.className = 'find-dealer-form-container';\n  input.onkeydown = (e) => {\n    if (e.key === 'Enter') {\n      const url = new URL('/buy-mack/find-a-dealer/', window.location.href);\n      url.searchParams.set('l', e.target.value);\n      window.location.href = url.toString();\n    }\n  };\n\n  inputContainer.appendChild(input);\n  container.appendChild(inputContainer);\n}\n","import { readBlockConfig, loadBlock, getMetadata } from '../../scripts/aem.js';\nimport { createElement, decorateIcons, getTextLabel } from '../../scripts/common.js';\n\nconst PLACEHOLDERS = {\n  subscribe: getTextLabel('footer:submit_button_aria_label'),\n  emailAddress: getTextLabel('footer:email_placeholder'),\n};\n\nconst addClassToTitle = (block, className) => {\n  const headings = block.querySelectorAll('h1, h2, h3, h4, h5, h6');\n  [...headings].forEach((h) => h.classList.add(className));\n};\n\nconst CLASSES = {\n  blockName: 'footer',\n  prefooter: 'prefooter',\n  truckList: 'footer-truck-list',\n  menu: 'footer-menu',\n  newsletter: 'footer-newsletter',\n  legal: 'footer-legal',\n};\n\nfunction findList(ele) {\n  if (ele.classList.contains(CLASSES.truckList)) {\n    return ele;\n  }\n  return findList(ele.parentElement);\n}\n\nfunction toggleExpand(targetH3) {\n  const clickedColumn = findList(targetH3);\n  const isExpanded = clickedColumn.classList.contains('expand');\n  const wrapper = targetH3.closest(`.${CLASSES.truckList}`);\n  const content = wrapper.querySelector(`.${CLASSES.truckList}__items`);\n  if (wrapper === clickedColumn && !isExpanded) {\n    wrapper.classList.add('expand');\n    content.style.maxHeight = `${content.scrollHeight}px`;\n  } else {\n    wrapper.classList.remove('expand');\n    content.style.maxHeight = null;\n  }\n}\n\nasync function setupNewsletterForm(footerBlock, footerMenuEl) {\n  const newsletterEl = createElement('div', { classes: CLASSES.newsletter });\n  const newsletterCol = footerMenuEl.querySelector(':scope > div:last-child');\n\n  let pardotForm = footerBlock.querySelector('.v2-newsletter');\n  if (pardotForm) {\n    pardotForm.setAttribute('data-block-name', 'v2-newsletter');\n    await loadBlock(pardotForm);\n    pardotForm = footerBlock.querySelector('.v2-newsletter');\n    newsletterEl.append(pardotForm);\n  }\n\n  const submitButton = newsletterEl.querySelector('button[type=\"submit\"]');\n  const emailInput = newsletterEl.querySelector('input[name=\"email\"]');\n  const pdtForm = newsletterEl.querySelector(':scope form');\n\n  if (pdtForm) {\n    pdtForm.className = 'pardot-form';\n  }\n\n  // change the submit button to arrow button\n  // and display it sticked to the right side of email input\n  if (submitButton && emailInput) {\n    emailInput.placeholder = PLACEHOLDERS.emailAddress;\n    submitButton.ariaLabel = `${PLACEHOLDERS.subscribe}`;\n  }\n\n  if (newsletterCol) {\n    newsletterEl.prepend(newsletterCol);\n  }\n\n  addClassToTitle(newsletterEl, `${CLASSES.newsletter}__title`);\n\n  return newsletterEl;\n}\n\nexport default async function decorate(block) {\n  const cfg = readBlockConfig(block);\n  block.textContent = '';\n\n  let footerPath = cfg.footer || '/footer';\n  const isCustomFooter = getMetadata('custom-footer');\n  const cfgMetadata = getMetadata('cfg-footer');\n\n  if (isCustomFooter) {\n    footerPath = isCustomFooter;\n    block.classList.add(`${CLASSES.blockName}__custom`);\n  }\n\n  if (cfgMetadata) {\n    footerPath = cfgMetadata;\n  }\n\n  const resp = await fetch(`${footerPath}.plain.html`);\n  const html = await resp.text();\n\n  block.innerHTML = html;\n\n  const footerItems = block.querySelectorAll(`:scope > div .${CLASSES.blockName} > div`);\n\n  // The footer is divided into 4 sections/rows in the block\n  let prefooterEl; // row 1\n  let truckListEl; // row 2\n  let footerMenuEl; // row 3\n  let footerLegalEl; // row 4\n\n  // Footer items\n  // 4 items: prefooter, truck list, menu, legal\n  if (footerItems.length === 4) {\n    const [row1, row2, row3, row4] = footerItems;\n    prefooterEl = row1.querySelector(':scope > div');\n    truckListEl = row2.querySelector(':scope > div');\n    footerMenuEl = row3;\n    footerLegalEl = row4.querySelector(':scope > div');\n  }\n\n  const newFooter = createElement('div');\n\n  // First row: Prefooter\n  if (prefooterEl) {\n    prefooterEl.classList.add(CLASSES.prefooter);\n    newFooter.append(prefooterEl);\n  }\n\n  // Second Row: Truck list\n  if (truckListEl) {\n    truckListEl.classList.add(`${CLASSES.truckList}__wrapper`);\n    truckListEl.querySelector('ul')?.classList.add(`${CLASSES.truckList}__items`);\n    addClassToTitle(truckListEl, `${CLASSES.truckList}__title`);\n    const truckListContent = createElement('div', { classes: CLASSES.truckList });\n    truckListContent.appendChild(truckListEl);\n\n    newFooter.append(truckListContent);\n  }\n\n  // Third row: Menu -> social media + logo + menu list + newsletter form\n  const newMenu = createElement('div', { classes: CLASSES.menu });\n  if (footerMenuEl) {\n    // First column, first row: Logo\n    const logo = document.createRange().createContextualFragment(`<div class=\"${CLASSES.menu}__logo\">\n      <a href=\"/\">\n        <span class=\"icon icon-logo\" />\n        <span class=\"screenreader\">${getTextLabel('footer:logo_link_text')}</span>\n      </a>\n    </div>`);\n    newMenu.appendChild(logo);\n\n    // First column, second row: Social media\n    const socialMedia = footerMenuEl.querySelector(':scope > div ul');\n    socialMedia.classList.add(`${CLASSES.menu}__socialmedia`);\n    const socialLinks = socialMedia.querySelectorAll('a');\n    [...socialLinks].forEach((a) => {\n      a.target = '_blank';\n    });\n    newMenu.appendChild(socialMedia);\n    // remove div which contained logo and social media\n    footerMenuEl.firstElementChild.remove();\n\n    // Second column: menu\n    const menuEl = createElement('div', { classes: `${CLASSES.menu}__columns` });\n    // Menu Columns: Newsletter form\n    const newsletterEl = await setupNewsletterForm(block, footerMenuEl);\n    newMenu.append(newsletterEl);\n\n    menuEl.append(footerMenuEl);\n    const menuList = menuEl.querySelectorAll(':scope > div');\n    menuList.forEach((item) => item.classList.add(`${CLASSES.menu}__column`));\n    if (menuEl.children.length) {\n      newMenu.appendChild(menuEl);\n    }\n\n    newFooter.append(newMenu);\n  }\n\n  if (footerLegalEl) {\n    footerLegalEl.classList.add(CLASSES.legal);\n\n    newFooter.append(footerLegalEl);\n  }\n\n  block.innerHTML = '';\n  block.append(newFooter);\n\n  await decorateIcons(block);\n  await loadBlock(block);\n\n  block.addEventListener('click', (e) => {\n    if (e.target.classList.contains(`${CLASSES.truckList}__title`)) {\n      toggleExpand(e.target);\n    }\n  });\n}\n","/*\n * Fragment Block\n * Include content on a page as a fragment.\n * https://www.aem.live/developer/block-collection/fragment\n */\n\nimport { decorateMain } from '../../scripts/scripts.js';\n\nimport { loadSections } from '../../scripts/aem.js';\n\n/**\n * Loads a fragment.\n * @param {string} path The path to the fragment\n * @returns {HTMLElement} The root element of the fragment\n */\nexport async function loadFragment(path) {\n  if (path && path.startsWith('/') && !path.startsWith('//')) {\n    const resp = await fetch(`${path}.plain.html`);\n    if (resp.ok) {\n      const main = document.createElement('main');\n      main.innerHTML = await resp.text();\n\n      // reset base path for media to fragment base\n      const resetAttributeBase = (tag, attr) => {\n        main.querySelectorAll(`${tag}[${attr}^=\"./media_\"]`).forEach((elem) => {\n          elem[attr] = new URL(elem.getAttribute(attr), new URL(path, window.location)).href;\n        });\n      };\n      resetAttributeBase('img', 'src');\n      resetAttributeBase('source', 'srcset');\n\n      decorateMain(main);\n      await loadSections(main);\n      return main;\n    }\n  }\n  return null;\n}\n\nexport default async function decorate(block) {\n  const link = block.querySelector('a');\n  const path = link ? link.getAttribute('href') : block.textContent.trim();\n  const fragment = await loadFragment(path);\n  if (fragment) {\n    block.replaceChildren(...fragment.childNodes);\n  }\n}\n","import { createElement, decorateIcons, decorateBlackLabel, generateId, getTextLabel, HEADER_CONFIGS, getLanguagePath } from '../../scripts/common.js';\nimport { createOptimizedPicture, getMetadata } from '../../scripts/aem.js';\nimport { getAllElWithChildren } from '../../scripts/scripts.js';\n\n// check if the header has to have a login and/or a search button\nconst { SEARCH_DISABLED = '', LOGIN_DISABLED = '' } = HEADER_CONFIGS;\n\nconst blockName = 'header';\n\nconst desktopMQ = window.matchMedia('(min-width: 1200px)');\nconst tabsVariants = {\n  TAB_WITH_CARDS: 'tabs-with-cards',\n  TAB: 'tabs',\n  FEATURED_CARD: 'featured-card',\n  FEATURED_CARD_DOUBLE: 'featured-card-double',\n};\nconst DESKTOP_MEDIA_QUERY = '(min-width: 1200px)';\nconst LARGE_IMAGE_WIDTHS = {\n  '2x': 1368,\n  '1x': 684,\n};\nconst STANDARD_IMAGE_WIDTHS = {\n  '2x': 580,\n  '1x': 290,\n};\n\nconst setTabIndexForLinks = (el, tabIndexValue) => {\n  try {\n    if (!el) {\n      throw new Error('No element provided to setTabIndexForLinks.');\n    }\n\n    const links = el.querySelectorAll('a, button');\n\n    if (!links.length) {\n      console.warn('No links or buttons found in the provided element:', el);\n      return;\n    }\n\n    links.forEach((link) => {\n      if (link && typeof link.setAttribute === 'function') {\n        link.setAttribute('tabindex', tabIndexValue);\n      } else {\n        console.warn('Skipped an invalid link element:', link);\n      }\n    });\n  } catch (error) {\n    console.error('setTabIndexForLinks encountered an error:', error, '\\nElement passed in:', el);\n  }\n};\n\nconst createLogo = (logoWrapper) => {\n  const logoImage = logoWrapper.querySelector('span.icon');\n\n  if (!logoImage) {\n    return createElement('div');\n  }\n\n  const logoLink = logoImage.parentElement.tagName === 'A' ? logoImage.parentElement : null;\n\n  logoImage.classList.add(`${blockName}__logo-image`);\n  logoImage.setAttribute('aria-hidden', 'true');\n  (logoLink || logoImage).classList.add(`${blockName}__logo-image-wrapper`);\n\n  if (logoLink) {\n    const logoLinkTextContainer = createElement('span', { classes: ['screenreader'] });\n    const logoLinkText = getTextLabel('header:logo_link_text');\n    logoLinkTextContainer.append(logoLinkText);\n\n    logoLink.append(logoLinkTextContainer);\n  }\n\n  return logoLink || logoImage;\n};\n\nconst createMainLinks = (mainLinksWrapper) => {\n  const list = mainLinksWrapper.querySelector('ul');\n  if (list) {\n    const listItems = list.querySelectorAll('li');\n    list.setAttribute('id', 'header-main-nav');\n    list.classList.add(`${blockName}__main-nav`);\n\n    if (listItems.length === 1) {\n      return list;\n    }\n\n    listItems.forEach((listItem) => {\n      const accordionContainer = document.createRange().createContextualFragment(`\n        <div class=\"${blockName}__accordion-container ${blockName}__main-link-wrapper\">\n          <div class=\"${blockName}__accordion-content-wrapper\">\n          </div>\n          <div class=\"desktop-wrapper\"></div>\n          <div class=\"desktop-wrapper-footer\"></div>\n        </div>\n      `);\n\n      listItem.classList.add(`${blockName}__main-nav-item`);\n      listItem.append(accordionContainer);\n\n      const mainNavLink = listItem.querySelector('a');\n      mainNavLink.setAttribute('id', generateId('main-nav'));\n    });\n\n    list.querySelectorAll('li > a').forEach((link) => {\n      link.classList.add(`${blockName}__main-nav-link`, `${blockName}__link`, `${blockName}__link-accordion`);\n    });\n\n    const closeMenuLabel = getTextLabel('header:close_menu_label');\n    const closeIcon = document.createRange().createContextualFragment(`\n      <li class=\"${blockName}__action-item ${blockName}__action-item--close-menu\">\n        <button\n          aria-label=\"${closeMenuLabel}\"\n          class=\"${blockName}__close-menu\"\n          aria-expanded=\"false\"\n          aria-controls=\"header-main-nav, header-actions-list\"\n        >\n          <span class=\"icon icon-close\" />\n        </button>\n      </li>\n    `);\n\n    list.prepend(closeIcon);\n\n    return list;\n  }\n  return null;\n};\n\nconst createActions = (actionsWrapper) => {\n  const list = actionsWrapper.querySelector('ul');\n\n  if (!list) {\n    return createElement('div');\n  }\n\n  list.setAttribute('id', 'header-actions-list');\n  list.classList.add(`${blockName}__actions-list`);\n  list.querySelectorAll('li').forEach((listItem) => {\n    listItem.classList.add(`${blockName}__action-item`);\n  });\n  list.querySelectorAll('li > a').forEach((link) => {\n    link.classList.add(`${blockName}__action-link`, `${blockName}__link`);\n\n    // wrapping text nodes into spans &\n    // adding aria labels (because text labels are hidden on mobile)\n    [...link.childNodes]\n      .filter((node) => node.nodeType === Node.TEXT_NODE)\n      .forEach((textNode) => {\n        const spanWrapper = createElement('span', { classes: [`${blockName}__action-link-text`] });\n\n        textNode.replaceWith(spanWrapper);\n        spanWrapper.append(textNode);\n        link.setAttribute('aria-label', textNode.textContent);\n      });\n  });\n\n  return list;\n};\n\nconst mobileActions = (shouldRenderMobileHeaderButton) => {\n  const mobileActionsEl = createElement('div', { classes: [`${blockName}__mobile-actions`] });\n  const searchLabel = getTextLabel('Search');\n  const openMenuLabel = getTextLabel('Open menu');\n  const searchResults = `${getLanguagePath()}search`;\n\n  const searchEl = `<a href=\"${searchResults}\" aria-label=\"${searchLabel}\" class=\"${blockName}__search-button ${blockName}__action-link ${blockName}__link\">\n    <span class=\"icon icon-search\" aria-hidden=\"true\"></span>\n  </a>`;\n\n  let actions = `\n    ${SEARCH_DISABLED?.toLowerCase() === 'true' ? '' : searchEl}\n  `;\n\n  if (shouldRenderMobileHeaderButton) {\n    actions += `\n      <button\n        aria-label=\"${openMenuLabel}\"\n        class=\"${blockName}__hamburger-menu ${blockName}__action-link ${blockName}__link\"\n        aria-expanded=\"false\"\n        aria-controls=\"header-main-nav, header-actions-list\"\n      >\n        <span class=\"icon icon-hamburger\" aria-hidden=\"true\"></span>\n      </button>\n    `;\n  }\n\n  const actionsFragment = document.createRange().createContextualFragment(actions);\n\n  mobileActionsEl.append(...actionsFragment.childNodes);\n\n  return mobileActionsEl;\n};\n\nconst rebuildCategoryItem = (item) => {\n  item.classList.add(`${blockName}__category-item`);\n\n  [...item.childNodes].forEach((el) => {\n    // unwrapping images & links inside EMPTY paragraphs\n    if (el.tagName === 'P') {\n      const links = el.querySelectorAll('a');\n      const linkTextLength = links[0]?.textContent.length;\n      const paragraphTextLength = el.textContent?.length;\n      const paragraphHasOwnText = linkTextLength && linkTextLength !== paragraphTextLength;\n      const paragraphContainsLinkOrImage = el.querySelectorAll(':scope > picture, :scope > a').length === 1;\n\n      if (paragraphHasOwnText) {\n        el.classList.add('with-inline-link');\n        links.forEach((link) => {\n          link.classList.add('inline-link');\n        });\n      } else if (paragraphContainsLinkOrImage) {\n        el.replaceWith(el.children[0]);\n      }\n    }\n\n    // second list of links should be rendered as buttons\n    if (item.querySelector(':scope > ul:nth-of-type(2)') === el) {\n      el.classList.add(`${blockName}__category-item-buttons`);\n\n      [...el.querySelectorAll('a')].forEach((button, index) => {\n        if (!index) {\n          button.classList.add('button', 'button--small', 'button--primary');\n        } else {\n          button.classList.add('button', 'button--small', 'button--secondary');\n        }\n      });\n    }\n  });\n\n  const firstLink = item.querySelector(':scope > a:first-of-type');\n\n  if (firstLink?.previousElementSibling?.tagName === 'PICTURE') {\n    firstLink.classList.add(`${blockName}__link--after-image`);\n  }\n};\n\n/**\n * Generates an array of responsive image source definitions for use in <picture> elements.\n *\n * @param {{ '2x': number, '1x': number }} widths - Object defining widths for 1x and 2x resolution.\n * @returns {Array<{ media: string, width: number }>} An array of responsive image source definitions.\n */\nconst getResponsiveSources = (widths) => [\n  { media: `${DESKTOP_MEDIA_QUERY} and (min-resolution: 2x)`, width: widths['2x'] },\n  { media: DESKTOP_MEDIA_QUERY, width: widths['1x'] },\n];\n\n/**\n * Replaces an existing <picture> element with an optimized version using responsive sources.\n *\n * @param {HTMLPictureElement} picture - The original picture element in the DOM.\n * @param {boolean} isInsideFeaturedCard - Whether the picture is part of a featured card (to use large sizes).\n * @returns {void}\n */\nconst optimiseImage = (picture, isInsideFeaturedCard) => {\n  const img = picture.querySelector('img');\n  if (!img?.src) {\n    return;\n  }\n\n  const widths = isInsideFeaturedCard ? LARGE_IMAGE_WIDTHS : STANDARD_IMAGE_WIDTHS;\n  const sources = getResponsiveSources(widths);\n  const newPicture = createOptimizedPicture(img.src, img.alt, false, sources);\n  picture.replaceWith(newPicture);\n};\n\n/**\n * Optimizes <picture> elements within the header menu.\n * Applies larger image widths for featured cards and smaller ones for standard menu items.\n *\n * @param {HTMLElement} menu - The menu element to process.\n */\nconst optimisePicturesInMenu = (menu) => {\n  [...menu.querySelectorAll('picture')].forEach((picture, i) => {\n    const isFeaturedCard = Boolean(picture.closest('.featured-card'));\n    const isDoubleFeaturedCard = Boolean(picture.closest('.featured-card-double'));\n\n    if (isFeaturedCard) {\n      // Optimise the first 2 pictures only (main + background) in a single featured card\n      optimiseImage(picture, i < 2);\n    } else if (isDoubleFeaturedCard) {\n      // Optimise the first 4 pictures only (2 cards × 2 images per card) in a double featured card\n      optimiseImage(picture, i < 4);\n    } else {\n      optimiseImage(picture);\n    }\n  });\n};\n\n/* transformMenuData unify HTML that comes from word doc */\nconst transformMenuData = (data) => {\n  // for each tab\n  data.forEach((menuData) => {\n    const titles = menuData.querySelectorAll('.menu > div > div:first-child > a');\n\n    // unwrapping the titles (.menu > div > div > a => .menu > a)\n    titles.forEach((title) => title.parentElement.parentElement.replaceWith(title));\n\n    // changing divs to lists\n    const menusContentList = [...menuData.querySelectorAll('.menu')];\n\n    // for each menu tab sub items\n    menusContentList.forEach((menuItem) => {\n      // for tracks menu only\n      if (menuItem.classList.contains(tabsVariants.TAB_WITH_CARDS)) {\n        // changing the structure to list\n        const item = menuItem.querySelectorAll(':scope > div > div');\n        const listEl = createElement('ul');\n\n        item.forEach((mItem) => {\n          const listItemEl = createElement('li');\n          mItem.parentElement.remove();\n          listItemEl.append(...mItem.children);\n          listEl.append(listItemEl);\n        });\n\n        menuItem.append(listEl);\n      } else {\n        // for other manu types,\n        // unwrap the list:\n        // .menu > div > div > ul => .menu > ul\n        const listEl = menuItem.querySelector('ul');\n        menuItem.children[1].replaceWith(listEl);\n      }\n    });\n  });\n\n  data.forEach(optimisePicturesInMenu);\n\n  const results = document.createRange().createContextualFragment(`\n    <div>\n      ${data.map((el) => el.outerHTML).join('')}\n    </div>\n  `);\n\n  return results.children[0];\n};\n\nconst setTabActive = (tab) => {\n  if (!tab) {\n    console.warn('No tab element provided to setTabActive.', { tab });\n    return;\n  }\n  const accordionIdElement = tab.closest('[menu-accordion-id]');\n  if (!accordionIdElement) {\n    console.warn('No accordion Id Element found for the provided tab.', { tab });\n    return;\n  }\n  const targetId = accordionIdElement.getAttribute('menu-accordion-id');\n  if (!targetId) {\n    console.warn('No targetId found for the provided tab.', { tab });\n    return;\n  }\n  const tabContent = document.querySelector(`#${targetId}`);\n\n  [...tabContent.parentElement.querySelectorAll(`.${blockName}__accordion-container`)].forEach((item) => {\n    if (item !== tabContent) {\n      item.setAttribute('data-active', 'false');\n    }\n  });\n\n  tabContent.setAttribute('data-active', 'true');\n\n  // scroll to proper tab content for tabs with cards\n  const tabsWithCards = tab.closest(`.${blockName}__main-link-wrapper--tabs-with-cards`);\n  if (tabsWithCards) {\n    const tabContentId = tab.getAttribute('aria-controls');\n    const target = document.querySelector(`#${tabContentId}`);\n    if (target) {\n      const container = target.parentElement;\n      const offsetLeft = target.offsetLeft;\n\n      // Scroll just the X axis\n      container.scrollTo({\n        left: offsetLeft,\n        behavior: 'smooth',\n      });\n    }\n  } else {\n    console.warn('No %ctabs with cards %cfound for the provided tab.', 'color:red', 'color:default', { tab });\n  }\n\n  // setting the aria-expanded for tabs and link's tab indexes\n  const accordionContentWrapper = tab.closest(`.${blockName}__accordion-content-wrapper`);\n  const tabLinks = accordionContentWrapper ? [...accordionContentWrapper.querySelectorAll(`.${blockName}__tab-link`)] : [];\n  tabLinks.forEach((tabLink) => {\n    const tId = tabLink.getAttribute('aria-controls');\n    const tContent = document.querySelector(`#${tId}`);\n\n    tabLink.setAttribute('aria-expanded', tabLink === tab ? 'true' : 'false');\n\n    setTabIndexForLinks(tContent, tabLink === tab ? '0' : '-1');\n  });\n};\n\nconst onNavExpandChange = (isExpanded) => {\n  document.querySelector(`.${blockName}.block`).classList.toggle(`${blockName}--expanded`, isExpanded);\n};\n\nconst onAccordionItemClick = (el) => {\n  const elClassList = el.currentTarget.classList;\n  const isMainLink = elClassList.contains(`${blockName}__main-nav-link`);\n  const isTabLink = elClassList.contains(`${blockName}__tab-link`);\n  const isDesktop = desktopMQ.matches;\n\n  if (isDesktop && !isMainLink && !isTabLink) {\n    return;\n  }\n\n  el.preventDefault();\n\n  const menuEl = el.currentTarget.parentElement;\n  menuEl.classList.toggle(`${blockName}__menu-open`);\n  const isExpanded = menuEl.classList.contains(`${blockName}__menu-open`);\n  el.currentTarget.setAttribute('aria-expanded', isExpanded);\n\n  if (!isDesktop) {\n    return;\n  }\n\n  if (isMainLink) {\n    // closing other open menus\n    if (menuEl.classList.contains(`${blockName}__main-nav-item`)) {\n      const openMenus = document.querySelectorAll(`.${blockName}__menu-open`);\n\n      [...openMenus]\n        .filter((menu) => menu !== menuEl)\n        .forEach((menu) => {\n          menu.classList.remove(`${blockName}__menu-open`);\n          menu.querySelector(':scope > a').setAttribute('aria-expanded', false);\n          setTabIndexForLinks(menu, '-1');\n        });\n\n      setTabIndexForLinks(menuEl, '0');\n    }\n\n    onNavExpandChange(isExpanded);\n\n    // set first tab active\n    const firstTabLink = el.target.parentElement.querySelector(`.${blockName}__main-link-wrapper a`);\n    setTabActive(firstTabLink);\n  }\n\n  if (isTabLink) {\n    setTabActive(el.currentTarget);\n  }\n};\n\nconst extractFeaturedCardData = (item) => {\n  const pictures = item.querySelectorAll('picture');\n  const paragraphs = [...item.querySelectorAll('p')];\n  return {\n    mainImage: pictures[0] || '',\n    backgroundImage: pictures[1] || '',\n    title: item.querySelector('h3 a') || '',\n    subtitle: paragraphs[2]?.textContent.trim() || '',\n    text: paragraphs[3]?.innerHTML || '',\n    primaryButton: paragraphs[4]?.querySelector('a') || '',\n    secondaryButton: paragraphs[5]?.querySelector('a') || '',\n    primaryLink: paragraphs[6]?.querySelector('a') || '',\n    secondaryLink: paragraphs[7]?.querySelector('a') || '',\n  };\n};\n\nconst generateFeaturedCardHtml = (data) => {\n  const { mainImage, backgroundImage, title, subtitle, text, primaryButton, secondaryButton, primaryLink, secondaryLink } = data;\n  const titleHref = title?.getAttribute('href')?.trim() || '';\n  const titleHtml = title?.outerHTML || '';\n  const mainImageHtml = mainImage?.outerHTML || '';\n  const backgroundImageHtml = backgroundImage?.outerHTML || '';\n\n  const buttonsHtml = [primaryButton, secondaryButton]\n    .filter(Boolean)\n    .map(\n      (btn, index) =>\n        `<a href=\"${btn.href?.trim()}\" class=\"${blockName}__featured-card-button button ${index === 0 ? 'button--primary' : 'button--secondary'}\">\n        ${btn.textContent}\n      </a>`,\n    )\n    .join('');\n\n  const linksHtml = [primaryLink, secondaryLink]\n    .filter(Boolean)\n    .map((link) => link.outerHTML)\n    .join('');\n\n  return `\n    <div class=\"${blockName}__featured-card\">\n      <div class=\"${blockName}__featured-card-image\">\n        <a class=\"${blockName}__featured-card-image-link\" href=\"${titleHref}\">\n          ${mainImageHtml}\n          ${backgroundImageHtml}\n        </a>\n      </div>\n      <div class=\"${blockName}__featured-card-content\">\n        ${titleHtml ? `<h3 class=\"${blockName}__featured-card-title\">${titleHtml}</h3>` : ''}\n        ${subtitle ? `<h5 class=\"${blockName}__featured-card-subtitle\">${subtitle}</h5>` : ''}\n        ${text ? `<p class=\"${blockName}__featured-card-text\">${text}</p>` : ''}\n        ${buttonsHtml ? `<div class=\"${blockName}__featured-card-buttons\">${buttonsHtml}</div>` : ''}\n        ${linksHtml ? `<div class=\"${blockName}__featured-card-links\">${linksHtml}</div>` : ''}\n      </div>\n    </div>\n  `;\n};\n\n/**\n * Injects the menu footer links into the menu that has the class 'inject-menu-footer'\n * @param {Element[]} categories\n * @param {Element} menuFooter\n * @returns {void}\n */\nconst injectMenuFooter = (categories, menuFooter) => {\n  const categoryItems = categories.filter((el) => el.classList.contains('inject-menu-footer'));\n  const menuFooterLinks = menuFooter.querySelectorAll('a');\n  if (menuFooterLinks.length > 0) {\n    categoryItems.forEach((categoryItem) => {\n      const list = categoryItem.querySelector(':scope > ul');\n      if (list) {\n        [...menuFooterLinks].forEach((link) => {\n          const li = createElement('li', { classes: [`${blockName}__category-item`, 'mobile-menu-footer'] });\n          const a = createElement('a', { classes: [`${blockName}__link`], props: { href: link.href } });\n          a.textContent = link.textContent;\n          li.append(a);\n          list.append(li);\n        });\n      }\n    });\n  }\n};\n\n/**\n * Builds and returns HTML for one or two featured cards,\n * and removes those cards from the given list to prevent duplication.\n *\n * @param {HTMLUListElement} list - The list containing card <li> elements.\n * @param {boolean} isDoubleFeaturedCard - Whether to extract two cards instead of one.\n * @returns {string} featuredCardsHtml - The resulting HTML markup for the featured cards.\n */\nconst buildFeaturedCardsHtml = (list, isDoubleFeaturedCard) => {\n  if (!list?.children?.length) {\n    return '';\n  }\n\n  let featuredCardsHtml = '';\n  const firstCardItem = list.children[0].cloneNode(true);\n  const firstCard = extractFeaturedCardData(firstCardItem);\n  featuredCardsHtml += generateFeaturedCardHtml(firstCard);\n\n  if (isDoubleFeaturedCard && list.children[1]) {\n    const secondCardItem = list.children[1].cloneNode(true);\n    const secondCard = extractFeaturedCardData(secondCardItem);\n    featuredCardsHtml += generateFeaturedCardHtml(secondCard);\n  }\n\n  if (isDoubleFeaturedCard) {\n    featuredCardsHtml = `<div class=\"${blockName}__featured-card-group\">${featuredCardsHtml}</div>`;\n  }\n\n  return featuredCardsHtml;\n};\n\n/**\n * Builds the menu content for the Mega-menu\n * @param {Element[]} menuData\n * @param {Element} navEl\n * @returns {void}\n */\nconst buildMenuContent = (menuData, navEl) => {\n  const menus = transformMenuData(menuData);\n  const navLinks = [...navEl.querySelectorAll(`.${blockName}__main-nav-link`)];\n\n  [...menus.children].forEach((menuItemData) => {\n    const tabName = menuItemData.querySelector(':scope > p > a');\n    if (!tabName) {\n      return;\n    }\n\n    const categories = [...menuItemData.querySelectorAll(':scope > div')];\n    const navLink = navLinks.find((el) => el.textContent.trim() === tabName.textContent.trim());\n    const accordionContentWrapper = navLink?.closest(`.${blockName}__main-nav-item`).querySelector(`.${blockName}__accordion-content-wrapper`);\n    // add the menu footer to the Mega-menu\n    const menuFooter = categories.find((el) => el.classList.contains('menu-footer'));\n\n    if (menuFooter) {\n      [...menuFooter.querySelectorAll('a')].forEach((link, index) => {\n        const classes = index ? ['standalone-link'] : ['button', 'button--primary', 'button--small'];\n        link.classList.add(...classes);\n      });\n\n      navLink.parentElement.querySelector('.desktop-wrapper-footer').append(menuFooter);\n\n      injectMenuFooter(categories, menuFooter);\n    }\n\n    categories\n      .filter((cat) => cat.classList.contains('menu'))\n      .forEach((cat) => {\n        const title = cat.querySelector(':scope > a');\n        const list = cat.querySelector(':scope > ul');\n        const accordionParentClassList = accordionContentWrapper.parentElement.classList;\n        let extraClass = '';\n        const isFeaturedCard = cat.classList.contains(tabsVariants.FEATURED_CARD) || cat.classList.contains(tabsVariants.FEATURED_CARD_DOUBLE);\n        const isDoubleFeaturedCard = cat.classList.contains(tabsVariants.FEATURED_CARD_DOUBLE);\n\n        title?.classList.add(`${blockName}__link`, `${blockName}__link-accordion`, `${blockName}__menu-heading`);\n        title?.removeAttribute('href');\n\n        if (isFeaturedCard) {\n          accordionParentClassList.add(tabsVariants.FEATURED_CARD);\n        }\n\n        if (isDoubleFeaturedCard) {\n          accordionParentClassList.add(tabsVariants.FEATURED_CARD_DOUBLE);\n        }\n\n        if (cat.classList.contains(tabsVariants.TAB_WITH_CARDS) || cat.classList.contains(tabsVariants.TAB)) {\n          title?.classList.add(`${blockName}__tab-link`);\n        }\n\n        if (cat.classList.contains(tabsVariants.TAB_WITH_CARDS)) {\n          extraClass = `${blockName}__main-link-wrapper--${tabsVariants.TAB_WITH_CARDS}`;\n        }\n\n        if (cat.classList.contains(tabsVariants.TAB)) {\n          extraClass = `${blockName}__main-link-wrapper--${tabsVariants.TAB}`;\n        }\n\n        const featuredCardsHtml = isFeaturedCard ? buildFeaturedCardsHtml(list, isDoubleFeaturedCard) : '';\n\n        list.classList.add(`${blockName}__category-items`);\n        [...list.querySelectorAll('li')].forEach(rebuildCategoryItem);\n        [...list.querySelectorAll('a')].forEach((el) => {\n          const isInlineLink = el.classList.contains('inline-link');\n          el.classList[isInlineLink ? 'remove' : 'add'](`${blockName}__link`);\n        });\n        [...list.querySelectorAll('li > a:not(.button):not(:only-child)')].forEach((el) => el.classList.add('standalone-link'));\n\n        let menuContent;\n\n        if (!title) {\n          menuContent = document.createRange().createContextualFragment(`\n            <div class=\"${blockName}__menu-content\">\n              ${list.outerHTML}\n            </div>\n          `);\n        } else {\n          menuContent = document.createRange().createContextualFragment(`\n            <div class=\"${blockName}__menu-content\">\n              ${title.outerHTML}\n              <div class=\"${blockName}__category-content ${blockName}__accordion-container\">\n                <div class=\"${blockName}__accordion-content-wrapper\">\n                  ${isFeaturedCard && featuredCardsHtml ? featuredCardsHtml : ''}\n                  ${list.outerHTML}\n                </div>\n              </div>\n            </div>\n          `);\n        }\n\n        menuContent.querySelector(`.${blockName}__link-accordion`)?.addEventListener('click', onAccordionItemClick);\n        accordionContentWrapper.append(menuContent);\n        if (extraClass) {\n          accordionParentClassList.add(extraClass);\n        }\n      });\n\n    navLink?.addEventListener('click', onAccordionItemClick);\n  });\n};\n\nconst decorateCTA = (wrapper) => {\n  const anchorTags = wrapper.querySelectorAll('a');\n  anchorTags.forEach((link) => {\n    link.classList.add(`${blockName}__custom-button`, 'button', 'button--primary');\n    wrapper.appendChild(link);\n  });\n\n  if (wrapper.firstElementChild) {\n    wrapper.firstElementChild.remove();\n  }\n\n  return wrapper;\n};\n\n/**\n * decorates the header, mainly the nav\n * @param {Element} block The header block element\n */\nexport default async function decorate(block) {\n  // clear the block\n  block.textContent = '';\n\n  // fetch nav content\n  const { pathname } = new URL(window.location.href);\n  const langCodeMatch = pathname.match('^(/[a-z]{2}(-[a-z]{2})?/).*');\n  let navPath = `${langCodeMatch ? langCodeMatch[1] : '/'}nav`;\n\n  const isCustomHeader = getMetadata('custom-header');\n  const isMobileMenuDisabled = getMetadata('custom-header-mobile-menu').toLowerCase() === 'false';\n  if (isCustomHeader) {\n    navPath = `${langCodeMatch ? langCodeMatch[1] : ''}${isCustomHeader}`;\n    block.classList.add(`${blockName}__custom`);\n\n    const customStyles = getMetadata('custom-header-style');\n    if (customStyles) {\n      block.classList.add(`${blockName}__custom--${customStyles}`);\n    }\n  }\n\n  const testHeader = getMetadata('test-header');\n  if (testHeader) {\n    navPath = testHeader;\n  }\n\n  const resp = await fetch(`${navPath}.plain.html`);\n\n  if (!resp.ok) {\n    console.error(`Header is not loaded: ${resp.status}`);\n  }\n\n  // get the navigation text, turn it into html elements\n  const content = document.createRange().createContextualFragment(await resp.text());\n\n  const [logoContainer, navigationContainer, actionsContainer, ...menuContent] = content.children;\n  const headerLogoAlignment = getMetadata('header-logo-alignment');\n  const nav = createElement('nav', { classes: [`${blockName}__nav`] });\n  if (headerLogoAlignment) {\n    nav.classList.add(`${blockName}__nav-logo--${headerLogoAlignment}`);\n  }\n\n  const headerMainLinks = createMainLinks(navigationContainer);\n  const headerMainLinksListItems = headerMainLinks.querySelectorAll('li');\n  const shouldRenderMobileHeaderButton = headerMainLinksListItems.length > 1;\n\n  const navContent = `\n    <div class=\"${blockName}__menu-overlay\"></div>\n    ${createLogo(logoContainer).outerHTML}\n    ${\n      navigationContainer.children.length\n        ? `<div class=\"${blockName}__main-links\">\n      ${headerMainLinks.outerHTML}\n    </div>`\n        : ''\n    }\n    <div class=\"${blockName}__actions\">\n      ${isMobileMenuDisabled ? '' : mobileActions(shouldRenderMobileHeaderButton).outerHTML}\n      ${isMobileMenuDisabled ? decorateCTA(actionsContainer).outerHTML : createActions(actionsContainer).outerHTML}\n    </div>\n  `;\n\n  const navContentFragment = document.createRange().createContextualFragment(navContent);\n\n  const setAriaForMenu = (isMenuVisible) => {\n    nav.querySelectorAll(`.${blockName}__close-menu, .${blockName}__hamburger-menu`).forEach((control) => {\n      control.setAttribute('aria-expanded', isMenuVisible);\n\n      document.querySelectorAll(`.${blockName}__main-nav-link`).forEach((el) => {\n        el.setAttribute('tabindex', isMenuVisible ? '0' : '-1');\n      });\n\n      document.querySelectorAll(`.${blockName}__action-item`).forEach((el) => {\n        setTabIndexForLinks(el, isMenuVisible ? '0' : '-1');\n      });\n\n      if (isMenuVisible) {\n        document.querySelector(`.${blockName}__close-menu`)?.focus();\n      }\n    });\n    nav.querySelectorAll('#header-main-nav, #header-actions-list').forEach((item) => {\n      item.setAttribute('aria-hidden', !isMenuVisible);\n    });\n  };\n\n  const initAriaForAccordions = () => {\n    const menuPrefix = 'menu-accordion';\n    const accordionContainers = block.querySelectorAll(`.${blockName}__link-accordion ~ .${blockName}__accordion-container`);\n\n    [...accordionContainers].forEach((container) => {\n      const id = generateId(menuPrefix);\n      const accordionLink = container.parentElement.querySelector(`.${blockName}__link-accordion`);\n\n      container.setAttribute('id', id);\n      accordionLink.setAttribute('aria-controls', id);\n      accordionLink.setAttribute('aria-expanded', false);\n      accordionLink.parentElement.setAttribute('menu-accordion-id', id);\n    });\n  };\n\n  const closeHamburgerMenu = () => {\n    block.classList.remove(`${blockName}--hamburger-open`);\n    onNavExpandChange(false);\n\n    block.querySelectorAll(`.${blockName}__menu-open`).forEach((el) => {\n      el.classList.remove(`${blockName}__menu-open`);\n      el.setAttribute('aria-expanded', 'false');\n    });\n\n    setAriaForMenu(false);\n  };\n\n  // add actions for search\n  if (SEARCH_DISABLED.toLowerCase() === 'false') {\n    navContentFragment.querySelector(`.${blockName}__search-button`)?.addEventListener('click', () => {\n      window.location.href = '/search';\n    });\n  }\n\n  // add action for hamburger\n  navContentFragment.querySelector(`.${blockName}__hamburger-menu`)?.addEventListener('click', () => {\n    block.classList.add(`${blockName}--hamburger-open`);\n    onNavExpandChange(true);\n    setAriaForMenu(true);\n  });\n\n  navContentFragment.querySelectorAll(`.${blockName}__menu-overlay, .${blockName}__close-menu`).forEach((el) => {\n    el.addEventListener('click', closeHamburgerMenu);\n  });\n\n  // hiding the hamburger menu when switch to desktop\n  desktopMQ.addEventListener('change', closeHamburgerMenu);\n\n  nav.append(navContentFragment);\n  block.append(nav);\n\n  setAriaForMenu(false);\n  if (menuContent) {\n    buildMenuContent(menuContent, nav);\n  }\n  initAriaForAccordions();\n\n  // hiding nav when clicking outside the menu\n  document.addEventListener('click', (event) => {\n    const isTargetOutsideMenu = !event.target.closest(`.${blockName}__main-nav`) && !event.target.closest(`.${blockName}__actions`);\n    const openMenu = block.querySelector(`.${blockName}__main-nav-item.${blockName}__menu-open`);\n\n    if (isTargetOutsideMenu && openMenu) {\n      openMenu.classList.remove(`${blockName}__menu-open`);\n      openMenu.setAttribute('aria-expanded', false);\n      onNavExpandChange(false);\n    }\n  });\n\n  const swapMenuMountPoint = (isDesktop) => {\n    const selector = `\n      .${blockName}__main-link-wrapper--tabs-with-cards .${blockName}__category-content.${blockName}__accordion-container,\n      .${blockName}__main-link-wrapper--tabs .${blockName}__category-content.${blockName}__accordion-container\n    `;\n    const menus = [...document.querySelectorAll(selector)];\n\n    if (isDesktop) {\n      menus.forEach((item) => {\n        const desktopMountPoint = item.closest(`.${blockName}__main-link-wrapper`).querySelector('.desktop-wrapper');\n\n        desktopMountPoint.append(item);\n      });\n    } else {\n      menus.forEach((item) => {\n        const mobileMountPoints = [...item.closest(`.${blockName}__main-link-wrapper`).querySelectorAll(`.${blockName}__menu-content`)];\n        const mountPoint = mobileMountPoints.find((el) => el.getAttribute('menu-accordion-id') === item.getAttribute('id'));\n\n        mountPoint.append(item);\n      });\n    }\n  };\n\n  const swapActionsLinks = (isDesktop) => {\n    const actionsLinksList = document.querySelector(`#${blockName}-actions-list`) || createElement('div');\n    const actionsLinksDesktopMountPoint = document.querySelector(`.${blockName}__actions`);\n    const headerMainNav = document.querySelector(`.${blockName}__main-links`); // mobile actions links mount point\n    const buttonsWithoutIcons = getAllElWithChildren([...actionsLinksList.querySelectorAll('a')], '.icon', true);\n    const loginLink = actionsLinksList.querySelector(`.${blockName}__action-item a[href*=\"login\"]`);\n\n    if (loginLink && LOGIN_DISABLED.toLowerCase() === 'true') {\n      loginLink.remove();\n    }\n\n    if (isDesktop) {\n      actionsLinksDesktopMountPoint.append(actionsLinksList);\n      buttonsWithoutIcons.forEach((el) => el.classList.add('button', 'button--primary'));\n    } else {\n      headerMainNav.append(actionsLinksList);\n      buttonsWithoutIcons.forEach((el) => el.classList.remove('button', 'button--primary'));\n    }\n  };\n\n  const setupAriaAndTabIndexes = (isDesktop) => {\n    if (!isDesktop) {\n      const mainLinksEl = block.querySelector(`.${blockName}__main-links`);\n      const actionsEl = block.querySelector(`.${blockName}__actions-list`);\n\n      if (mainLinksEl) {\n        setTabIndexForLinks(mainLinksEl, '-1');\n      }\n\n      if (actionsEl) {\n        setTabIndexForLinks(actionsEl, '-1');\n      }\n\n      [...mainLinksEl.querySelectorAll('[aria-expanded=\"true\"]')].forEach((el) => {\n        el.setAttribute('aria-expanded', 'false');\n      });\n    } else {\n      const mainNav = block.querySelector(`.${blockName}__main-nav`);\n\n      if (mainNav) {\n        setTabIndexForLinks(mainNav);\n      }\n    }\n  };\n\n  if (!isMobileMenuDisabled) {\n    desktopMQ.addEventListener('change', (e) => {\n      const isDesktop = e.matches;\n\n      setupAriaAndTabIndexes(isDesktop);\n      swapMenuMountPoint(isDesktop);\n      swapActionsLinks(isDesktop);\n    });\n\n    setupAriaAndTabIndexes(desktopMQ.matches);\n    swapMenuMountPoint(desktopMQ.matches);\n    swapActionsLinks(desktopMQ.matches);\n  }\n  decorateIcons(block);\n  decorateBlackLabel(block);\n}\n","import { getImageURLs, createResponsivePicture, createElement } from '../../scripts/common.js';\n\nconst decorateVideo = (link) => {\n  const { parentElement } = link;\n  const video = createElement('video', {\n    classes: ['hero-video', 'hide'],\n    props: {\n      loop: 'loop',\n    },\n  });\n  const source = createElement('source', { props: { src: link.href, type: 'video/mp4' } });\n  video.appendChild(source);\n  parentElement.appendChild(video);\n  link.remove();\n  setTimeout(() => {\n    video.classList.remove('hide');\n    video.muted = true;\n    video.play();\n  }, 3000);\n};\n\nconst createHeroResponsiveImage = (block) => {\n  const pictures = [...block.querySelectorAll('p > picture')];\n  if (pictures.length !== 1) {\n    return null;\n  }\n\n  const imageURLs = getImageURLs(pictures);\n  const imageData = [\n    {\n      src: imageURLs[0],\n      breakpoints: [\n        { media: '(min-width: 600px)', width: 600 },\n        { media: '(min-width: 1200px)', width: 1200 },\n        { media: '(min-width: 1440px)', width: 1440 },\n        { media: '(min-width: 1920px)', width: 1920 },\n        { width: 1600 },\n      ],\n    },\n  ];\n\n  const altText = [pictures[0].querySelector('img.alt')].filter(Boolean);\n  const responsivePicture = createResponsivePicture(imageData, true, altText, 'hero__image');\n  pictures[0].parentNode.remove();\n  const wrapper = createElement('div', { classes: 'hero__image-wrapper' });\n  wrapper.appendChild(responsivePicture);\n  return wrapper;\n};\n\nexport default function decorate(block) {\n  const isAutoBlock = block.classList.contains('auto-block');\n  if (isAutoBlock) {\n    return;\n  }\n\n  const contentWrapper = block.querySelector(':scope > div > div');\n  const parentContainer = contentWrapper.parentElement;\n\n  const video = block.querySelector('a[href*=\".mp4\"]');\n  const videoWrapper = video && video.closest('p');\n  const videoLink = videoWrapper?.firstElementChild;\n  const contentContainer = createElement('div', { classes: 'hero-content-container' });\n  const mediaWrapper = createElement('div', { classes: 'hero-content-media' });\n\n  const responsiveImage = createHeroResponsiveImage(block);\n  if (responsiveImage) {\n    mediaWrapper.appendChild(responsiveImage);\n  }\n\n  if (videoLink) {\n    decorateVideo(videoLink);\n    mediaWrapper.appendChild(videoWrapper);\n  }\n\n  parentContainer.prepend(mediaWrapper);\n  contentContainer.appendChild(contentWrapper);\n  parentContainer.appendChild(contentContainer);\n  contentContainer.prepend(mediaWrapper);\n  contentWrapper.className = 'hero-content-wrapper';\n}\n","import { addSpot } from '../hotspots/hotspots.js';\n\n/**\n * This is a synthetic block that is only used to structure the content.\n * All content is then added to the closest 'hotspots' block.\n */\nexport default function decorate(block) {\n  const hotspotsBlock = block.closest('.hotspots-container').querySelector('.hotspots.block');\n\n  const hotspot = parseHotspotContent(block);\n  addSpot(hotspotsBlock, hotspot);\n\n  // Content was added to other block, therefore we can remove it\n  block.remove();\n}\n\n/**\n *\n * @param block {HTMLDivElement} raw block with content\n * @return {HotspotContent}\n */\nfunction parseHotspotContent(block) {\n  const picture = block.querySelector('picture');\n  // remove the paragraph that contains the picture to avoid finding it when looking for text\n  block.querySelector('picture').closest('p').remove();\n\n  // this is based on order, not header level\n  const category = block.querySelector('p, h1, h2, h3, h4, h5, h6');\n  category?.remove();\n\n  const title = block.querySelector('p, h1, h2, h3, h4, h5, h6');\n  title?.remove();\n\n  const text = block.querySelector('p');\n\n  const positionRegExp = /position-([0-9]+)-([0-9]+)/;\n  const positionClass = [...block.classList].find((el) => positionRegExp.test(el));\n  const positionMatch = positionClass.match(positionRegExp);\n\n  const positionLeft = `${positionMatch[1].trim()}%`;\n  const positionTop = `${positionMatch[2].trim()}%`;\n\n  return {\n    picture,\n    category,\n    title,\n    text,\n    positionLeft,\n    positionTop,\n  };\n}\n","import { createElement, decorateIcons } from '../../scripts/common.js';\n\n/**\n * @typedef {Object} HotspotContent\n *\n * @property {number} id\n * @property {HTMLPictureElement} picture\n * @property {HTMLElement} category\n * @property {HTMLElement} title\n * @property {HTMLElement} text\n * @property {string} positionLeft\n * @property {string} positionTop\n */\n\nlet hotspotBlockCounter = 0;\n\nexport default function decorate(block) {\n  const firstBlockRow = block.querySelector(':scope > div');\n  const firstPicture = firstBlockRow.querySelector('picture');\n  const title = firstBlockRow.querySelector('h1, h2');\n  const description = firstBlockRow.querySelector('p');\n\n  // every instance of this block needs a unique id.\n  hotspotBlockCounter += 1;\n  block.closest('.section.hotspots-container').dataset.hotspotAreaId = hotspotBlockCounter;\n  // first hotspots group is active by default (used for mobile view)\n  if (hotspotBlockCounter === 1) {\n    block.closest('.section.hotspots-container').classList.add('active');\n  }\n\n  block.innerHTML = `\n    <div class=\"main\">\n        <div class=\"hotspot-mobile\"></div>\n    </div>\n    <div class=\"hotspot-layover\" style=\"display: none;\"></div>\n  `;\n\n  decorateImageAndTitle(block.querySelector('.main'), firstPicture, title, description);\n\n  addMobileTabNavigation(block, title, hotspotBlockCounter);\n\n  block.querySelector('.hotspot-layover').addEventListener('click', (event) => {\n    const layoverDialog = block.querySelector('.hotspot-layover-box.is-active');\n    handleCloseLayover(event, layoverDialog, block);\n  });\n\n  decorateIcons(block);\n}\n\nfunction handleClickHotspot(event, iconLink, hotspotId, block) {\n  event.preventDefault();\n\n  iconLink.classList.add('active-spot');\n\n  const allLayovers = block.querySelector('.hotspot-layover');\n  allLayovers.style.display = 'block';\n  allLayovers.classList.add('is-active');\n\n  // Workaround: Delay adding the class, otherwise slide-in animation is not played.\n  setTimeout(() => {\n    const layoverDialog = allLayovers.querySelector(`.hotspot-layover-box[data-hotspot-content=\"${hotspotId}\"]`);\n    layoverDialog.classList.add('is-active');\n  }, 0);\n}\n\n/**\n *\n * @param event\n * @param layoverDialog {HTMLDialogElement}\n * @param block {HTMLDivElement}\n */\nfunction handleCloseLayover(event, layoverDialog, block) {\n  block.querySelectorAll('.hotspot-icon-set .active-spot').forEach((spot) => spot.classList.remove('active-spot'));\n\n  layoverDialog.parentElement.classList.remove('is-active');\n  layoverDialog.classList.remove('is-active');\n\n  setTimeout(() => {\n    layoverDialog.parentElement.style.display = 'none';\n  }, 300);\n}\n\n/**\n *\n * @param block\n * @param index {number} 0-based index of the linked dialog\n */\nfunction switchToOtherHotspot(block, index) {\n  const dialogs = block.querySelectorAll('.hotspot-layover-box');\n  dialogs.forEach((box) => box.classList.add('no-animation'));\n  dialogs.forEach((box) => box.classList.remove('is-active'));\n\n  block.querySelectorAll('.hotspot-icon-set .active-spot').forEach((spot) => spot.classList.remove('active-spot'));\n\n  const switchTo = dialogs[index];\n  switchTo.classList.add('is-active');\n\n  // activate the hotspot icon that links to the dialog\n  block.querySelector(`[data-spot=\"${switchTo.dataset.hotspotContent}\"]`).classList.add('active-spot');\n\n  // open the new dialog\n  setTimeout(() => {\n    // workaround: for some reason the animation is still played when the class is added immediately\n    block.querySelectorAll('.hotspot-layover-box').forEach((box) => box.classList.remove('no-animation'));\n  }, 0);\n}\n\nfunction addDesktopHotspotIcon(hotspot, block, main) {\n  const iconLink = createElement('a', {\n    classes: 'hotspot-icon',\n    props: { href: '#' },\n  });\n  iconLink.dataset.spot = hotspot.id;\n  iconLink.style.left = hotspot.positionLeft;\n  iconLink.style.top = hotspot.positionTop;\n\n  const image = createElement('img', {\n    props: {\n      src: '/icons/hotspot.png',\n      alt: hotspot.title.textContent,\n    },\n  });\n  iconLink.appendChild(image);\n  iconLink.onclick = (event) => handleClickHotspot(event, iconLink, hotspot.id, block);\n\n  main.querySelector('.hotspot-icon-set').append(iconLink);\n}\n\nfunction addDesktopLayover(hotspot, block) {\n  const container = document.createElement('div');\n  container.innerHTML = `\n<div class=\"hotspot-layover-box\" data-hotspot-content=\"1\">\n    <div class=\"hotspot-layover-thumb\" style=\"background-image: url();\"></div>\n    <div class=\"hotspot-layover-close\">\n        <img src=\"/icons/x.png\" alt=\"close\">\n    </div>\n    <div class=\"hotspot-layover-text\">\n        <h5></h5>\n        <h3></h3>\n        <p class=\"large\"></p>\n    </div>\n    <div class=\"hotspot-layover-controls\">\n        <a class=\"hotspot-layover-button prev\">\n            <img src=\"/icons/left-arrow-small.png\" alt=\"Left arrow\">\n            <span></span>\n        </a>\n        <a class=\"hotspot-layover-button next\">\n            <img src=\"/icons/right-arrow-small.png\" alt=\"Right arrow\">\n            <span></span>\n        </a>\n    </div>\n</div>`;\n\n  const dialog = container.querySelector('.hotspot-layover-box');\n  dialog.dataset.hotspotContent = hotspot.id.toString();\n  dialog.querySelector('.hotspot-layover-thumb').style.backgroundImage = `url(${hotspot.picture.querySelector('img').src})`;\n  dialog.querySelector('.hotspot-layover-text h5').innerHTML = hotspot.category.innerHTML;\n  dialog.querySelector('.hotspot-layover-text h3').innerHTML = hotspot.title.innerHTML;\n  dialog.querySelector('.hotspot-layover-text p').innerHTML = hotspot.text.innerHTML;\n\n  // don't close if clicked on sidebar\n  dialog.addEventListener('click', (event) => event.stopPropagation());\n\n  dialog.querySelector('.hotspot-layover-close').addEventListener('click', (event) => handleCloseLayover(event, dialog, block));\n\n  block.querySelector('.hotspot-layover').append(...container.childNodes);\n}\n\nfunction addMobileAlternativeCards(hotspot, main) {\n  // using styles from \"hotspots-features.css\"\n  const featureBlock = document.createElement('div');\n  featureBlock.innerHTML = `\n    <div class=\"features animated\" data-fade-object=\"true\">\n        <div class=\"row\">\n            <div class=\"feature\">\n                <picture></picture>\n                <h4 class=\"feature-title\"></h4>\n                <p></p></div>\n        </div>\n    </div>`;\n\n  featureBlock.querySelector('picture').innerHTML = hotspot.picture.innerHTML;\n  featureBlock.querySelector('.feature-title').innerHTML = hotspot.title.innerHTML;\n  featureBlock.querySelector('.feature p').innerHTML = hotspot.text.innerHTML;\n\n  const mobileDiv = main.querySelector('.hotspot-mobile');\n  mobileDiv.append(...featureBlock.childNodes);\n}\n\nfunction updateDesktopLayoverBeforeAndNextButtons(block) {\n  const dialogs = block.querySelectorAll('.hotspot-layover-box');\n  dialogs.forEach((dialog, index) => {\n    const prevIndex = index === 0 ? dialogs.length - 1 : index - 1;\n    const prevTextHtml = dialogs[prevIndex].querySelector('h3').innerHTML;\n    dialog.querySelector('.hotspot-layover-button.prev span').innerHTML = prevTextHtml;\n    dialog.querySelector('.hotspot-layover-button.prev').addEventListener('click', () => switchToOtherHotspot(block, prevIndex));\n\n    const nextIndex = index === dialogs.length - 1 ? 0 : index + 1;\n    const nextTextHtml = dialogs[nextIndex].querySelector('h3').innerHTML;\n    dialog.querySelector('.hotspot-layover-button.next span').innerHTML = nextTextHtml;\n    dialog.querySelector('.hotspot-layover-button.next').addEventListener('click', () => switchToOtherHotspot(block, nextIndex));\n  });\n}\n\n/**\n *\n * @param block\n * @param hotspot {HotspotContent}\n */\nexport function addSpot(block, hotspot) {\n  // desktop hotspot icon\n  const main = block.querySelector('.main');\n\n  // keep track of the number of hotspots in the DOM\n  main.dataset.hotspotCounter = (+main.dataset.hotspotCounter || 0) + 1;\n  hotspot.id = main.dataset.hotspotCounter;\n\n  addDesktopHotspotIcon(hotspot, block, main);\n  addDesktopLayover(hotspot, block);\n  updateDesktopLayoverBeforeAndNextButtons(block);\n\n  addMobileAlternativeCards(hotspot, main);\n}\n\n/**\n *\n * @param mainDiv {HTMLDivElement}\n * @param firstPicture {HTMLPictureElement}\n * @param title {HTMLElement}\n * @param description {HTMLElement}\n */\nfunction decorateImageAndTitle(mainDiv, firstPicture, title, description) {\n  const hotspot = createElement('div', { classes: ['hotspot', 'animated'] });\n  hotspot.innerHTML = `\n      <picture class=\"hotspot-bg-img desktop\"></picture>\n      <picture class=\"hotspot-bg-img mobile\"></picture>\n\n      <div class=\"hotspot-content content-wrapper \">\n          <h1 class=\"hotspot-header\"></h1>\n          <p class=\"hotspot-text reduced-width\"></p>\n      </div>\n\n      <div class=\"hotspot-icon-set\"></div>`;\n\n  hotspot.querySelector('.hotspot-bg-img.desktop').innerHTML = firstPicture.innerHTML;\n  hotspot.querySelector('.hotspot-bg-img.mobile').innerHTML = firstPicture.innerHTML;\n  hotspot.querySelector('.hotspot-header').innerHTML = title.innerHTML;\n  hotspot.querySelector('.hotspot-text').innerHTML = description.innerHTML;\n\n  mainDiv.prepend(hotspot);\n}\n\nfunction addMobileTabNavigation(block, title, hotspotAreaId) {\n  // only one tab navigation is needed for the entire page\n  let mobileNav = document.querySelector('main > div#hotspots-mobile-nav');\n  if (!mobileNav) {\n    mobileNav = createElement('div', {\n      props: { id: 'hotspots-mobile-nav' },\n    });\n\n    const ul = createElement('ul', { classes: 'featurenav-list' });\n    mobileNav.append(ul);\n\n    document.querySelector('main').append(mobileNav);\n  }\n\n  const li = createElement('li', { classes: 'featurenav-list-item' });\n  li.dataset.hotspotTargetId = hotspotAreaId;\n  if (mobileNav.firstElementChild.childElementCount === 0) {\n    li.classList.add('active');\n  }\n\n  const link = createElement('a', { props: { href: `#${title.textContent}` } });\n  link.innerHTML = title.innerHTML;\n  li.append(link);\n  mobileNav.firstElementChild.append(li);\n\n  li.addEventListener('click', (event) => {\n    event.preventDefault();\n\n    const clickedButton = event.target.closest('li');\n    if (clickedButton.classList.contains('active')) {\n      return;\n    }\n\n    const id = clickedButton.dataset.hotspotTargetId;\n    // Remove the active class from other active elements and add to current\n    const activeElements = mobileNav.querySelectorAll('li.active');\n    activeElements.forEach((el) => el.classList.remove('active'));\n    clickedButton.classList.add('active');\n\n    // Scroll to the top of the page\n    window.scrollTo(0, 0);\n\n    // Remove the active class from other active hotspot areas\n    document.querySelectorAll('.section.hotspots-container.active').forEach((activeHotspotArea) => activeHotspotArea.classList.remove('active'));\n\n    // activate the new hotspot area\n    const targetHotspotArea = document.querySelector(`.section.hotspots-container[data-hotspot-area-id=\"${id}\"]`);\n    targetHotspotArea.classList.add('active');\n  });\n}\n","import { createElement } from '../../scripts/common.js';\n\nexport default async function decorate(block) {\n  const link = block.querySelector('a')?.getAttribute('href');\n  const iframe = createElement('iframe', {\n    props: { frameborder: 0, src: link },\n  });\n  const fixedHeightClass = [...block.classList].find((el) => /[0-9]+px/.test(el));\n  const maxWidthClass = [...block.classList].find((el) => /width-[0-9]+px/.test(el));\n\n  if (fixedHeightClass) {\n    iframe.height = fixedHeightClass;\n  }\n  if (maxWidthClass) {\n    const maxWidth = maxWidthClass.split('width-')[1];\n    iframe.style.maxWidth = maxWidth;\n  }\n  block.replaceChildren(iframe);\n}\n","import { buildBlock, decorateBlock, loadBlock } from '../../scripts/aem.js';\nimport { createElement, getTextLabel, MAGAZINE_CONFIGS } from '../../scripts/common.js';\n\nexport default async function decorate(block) {\n  const { HREF: href, IFRAME_SIZE } = MAGAZINE_CONFIGS;\n  const content = document.createRange().createContextualFragment(`\n    <div class=\"default-content-wrapper\">\n      <h2 id=\"subscribe-to-bulldog-magazine\">${getTextLabel('magazine_subscribe:heading')}</h2>\n      <p>${getTextLabel('magazine_subscribe:text')}</p>\n    </div>\n  `);\n\n  const iframeLink = createElement('a', {\n    classes: 'iframe-link',\n    props: { href: href || '' },\n  });\n  const iframeForm = buildBlock('iframe', { elems: [iframeLink] });\n\n  block.textContent = '';\n  block.append(content);\n  block.parentElement.classList.add('section', 'center', 'padding-0');\n  block.parentElement.setAttribute('data-form-type', 'Subscribe-magazine');\n  block.insertAdjacentElement('afterend', iframeForm);\n  if (IFRAME_SIZE) {\n    iframeForm.classList.add(IFRAME_SIZE);\n  }\n  decorateBlock(iframeForm);\n  loadBlock(iframeForm);\n}\n","import { showModal } from '../../common/modal/modal-component.js';\nimport fragmentBlock from '../fragment/fragment.js';\n\nconst cacheList = [];\n\ndocument.addEventListener('open-modal', (event) => {\n  const { modalId } = event.detail;\n\n  if (modalId) {\n    const modalData = cacheList.find((el) => el.modalId === modalId);\n    const { content, classes } = modalData;\n\n    if (modalData) {\n      showModal(content, { classes: ['modal-form', ...classes] });\n    }\n  }\n});\n\nexport default async function decorate(block) {\n  const content = block.querySelector(':scope > div');\n  const fragmentLink = content.innerText.trim();\n  const modalId = [...block.classList].find((el) => el.startsWith('id-modal'));\n  const classes = [...block.classList].filter((el) => el !== modalId && el !== 'block');\n  const itemFromCache = cacheList.find((el) => el.modalId === modalId);\n\n  // load fragment only if it wasn't loaded yet\n  if (!itemFromCache) {\n    await fragmentBlock(content);\n\n    const newContent = block.querySelector(':scope > .fragment');\n\n    cacheList.push({\n      modalId,\n      fragmentLink,\n      classes,\n      content: newContent,\n    });\n  } else {\n    itemFromCache.modalId = modalId;\n    itemFromCache.fragmentLink = fragmentLink;\n    itemFromCache.classes = classes;\n  }\n\n  // modal block do not render anything by itself\n  // it just add event that shows up the modal with proper content\n  block.remove();\n}\n","import { createElement, FEEDS } from '../../scripts/common.js';\nimport { getBodyBuilderNews, getMackNews, PagingInfo } from '../../scripts/services/news.service.js';\nimport { readBlockConfig } from '../../scripts/aem.js';\n\nexport default async function decorate(block) {\n  const config = readBlockConfig(block);\n\n  // TODO: This is a duplicate of the logic in news-sidebar.js\n  // Review this hard coded logic attached to the url\n  const type = window.location.pathname.startsWith('/parts-and-services/support/body-builders') ? 'body-builder-news' : 'mack-news';\n\n  const filter = config.filter || '';\n  block.textContent = '';\n\n  if (FEEDS[type]) {\n    const rssLink = createElement('a', {\n      classes: ['title-with-icon'],\n      props: { href: FEEDS[type]?.path, target: '_blank' },\n    });\n    rssLink.textContent = 'News RSS';\n    block.append(rssLink);\n  }\n\n  const pagingInfo = new PagingInfo();\n  const posts = type === 'body-builder-news' ? await getBodyBuilderNews(pagingInfo) : await getMackNews(window.location.pathname, pagingInfo, filter);\n\n  const list = createElement('ul', { classes: ['news-sidebar-list'] });\n  list.append(\n    ...posts.map((post) => {\n      const articleLink = createElement('a', { props: { href: post.path } });\n\n      const heading = createElement('h3');\n      heading.textContent = post.title && post.title !== '0' ? post.title : '';\n      articleLink.append(heading);\n\n      const summary = createElement('p');\n      summary.textContent = post.summary;\n      articleLink.append(summary);\n\n      const li = createElement('li');\n      li.append(articleLink);\n      return li;\n    }),\n  );\n  block.append(list);\n}\n","import { createElement, FEEDS } from '../../scripts/common.js';\nimport { getBodyBuilderNews, getMackNews, PagingInfo } from '../../scripts/services/news.service.js';\n\nexport default async function decorate(block) {\n  // TODO: This is a duplicate of the logic in news-list.js\n  // Review this hard coded logic attached to the url\n  const type = window.location.pathname.startsWith('/parts-and-services/support/body-builders') ? 'body-builder-news' : 'mack-news';\n\n  const pagingInfo = new PagingInfo();\n  const newsPage = type === 'body-builder-news' ? await getBodyBuilderNews(pagingInfo) : await getMackNews(window.location.pathname, pagingInfo, '');\n\n  block.textContent = '';\n  const list = createElement('ul', { classes: ['news-sidebar-list'] });\n  block.append(list);\n\n  const rssLink = createElement('a', {\n    classes: ['news-sidebar-rss-icon'],\n    props: { href: FEEDS[type]?.path },\n  });\n\n  if (FEEDS[type]) {\n    rssLink.textContent = 'News RSS';\n    list.appendChild(rssLink);\n  }\n\n  list.appendChild(getParentCategoryLink(window.location.pathname));\n\n  newsPage.forEach((newsData) => {\n    const li = createElement('li');\n\n    const newsItem = createElement('a', { props: { href: newsData.path } });\n    if (window.location.pathname === newsData.path) {\n      newsItem.classList.add('new-sidebar-active-link');\n    }\n    newsItem.textContent = newsData.title && newsData.title !== '0' ? newsData.title.split('|')[0] : '';\n\n    li.append(newsItem);\n    list.append(li);\n  });\n\n  // creating select - for mobile only\n  const div = document.createElement('div');\n  div.innerHTML = `\n    <div class=\"news-sidebar-select\">\n      <div class=\"news-sidebar-select-label\">\n        <div class=\"news-sidebar-select-text\">Choose...</div>\n        <div class=\"news-sidebar-select-icon\">\n          <span>▲</span>\n        </div>\n      </div>\n      <select>\n        <option>Choose...</option>\n      </select>\n    </div>\n  `;\n\n  const selectContainer = createElement('div', { classes: 'news-sidebar-select-container' });\n\n  const select = div.querySelector('select');\n  newsPage.forEach((item) => {\n    const option = createElement('option', { props: { value: item.path } });\n\n    option.textContent = item.title.split('|')[0];\n    select.append(option);\n  });\n  const selectEl = div.firstElementChild;\n\n  if (FEEDS[type]) {\n    const clonedRssLink = rssLink.cloneNode(true);\n    selectContainer.appendChild(clonedRssLink);\n    selectContainer.appendChild(selectEl);\n    block.append(selectContainer);\n  }\n\n  select.addEventListener('change', (event) => {\n    const selectedNews = newsPage.find((item) => item.path === event.target.value);\n    block.querySelector('.news-sidebar-select-text').textContent = selectedNews?.title.split('|')[0];\n    window.location = event.target.value;\n  });\n}\n\nfunction getParentCategoryLink(pagePath) {\n  const parentFolders = pagePath.split('/').filter((item) => item !== '');\n  parentFolders.pop();\n  // either a category like 'news-and-events' or a year like '2023'\n  let parentFolderName = parentFolders.at(-1);\n\n  // format the parent folder name to be more readable\n  parentFolderName = parentFolderName?.replaceAll('-', ' ');\n\n  const category = createElement('a', {\n    props: {\n      href: `/${parentFolders.join('/')}/`,\n    },\n  });\n  category.textContent = parentFolderName;\n  return category;\n}\n","import { a, button, div, domEl, p, ul, li } from '../../scripts/scripts.js';\nimport { loadScript } from '../../scripts/aem.js';\nimport { getTextLabel } from '../../scripts/common.js';\n\nconst MQ = window.matchMedia('(min-width: 744px)');\nconst blockName = 'performance-specifications';\n\nconst TEXTS = {\n  btnText: getTextLabel('performance_specifications:download_button_text'),\n  engineRatings: getTextLabel('performance_specifications:engine_ratings_labels'),\n  bottomChartLabel: getTextLabel('performance_specifications:bottom_chart_label'),\n};\n\nconst COLORS = {\n  white: '#ffffff',\n  chartLines: ['#b3976b', '#ffffff', '#87754E', '#A7ABAF'],\n  bgColor: '#1D1D1D',\n  verticalLines: '#8e8e8e',\n};\n\nconst rpmValues = [600, 700, 800, 900, 1000, 1100, 1200, 1300, 1400, 1500, 1600, 1700, 1800, 1900, 2000, 2100, 2200];\n\n/**\n * as multiple blocks might be on the same page, the data is accessed using they block node as the\n * key.\n *\n * @type {Map<HTMLElement, Record<string, CategoryData>>}>}\n */\nconst engineData = new Map();\n\nconst moveNavigationLine = (navigationLine, activeTab, tabNavigation) => {\n  const { x: navigationX } = tabNavigation.getBoundingClientRect();\n  const { x, width } = activeTab.getBoundingClientRect();\n  Object.assign(navigationLine.style, {\n    left: `${x + tabNavigation.scrollLeft - navigationX}px`,\n    width: `${width}px`,\n  });\n};\n\nconst centerTab = (tabList, itemTab) => {\n  const { clientWidth: itemWidth, offsetLeft } = itemTab;\n  const scrollPosition = offsetLeft - (tabList.clientWidth - itemWidth) / 2;\n  tabList.scrollTo({\n    left: scrollPosition,\n    behavior: 'smooth',\n  });\n};\n\n/**\n * @param chartContainer {HTMLElement}\n * @param performanceData {Array<Array<string>>}\n */\nconst updateChart = async (chartContainer, engineDetails) => {\n  const performanceData = engineDetails.performanceData;\n\n  if (!window.echarts) {\n    // delay by 3 seconds to ensure a good lighthouse score\n\n    await new Promise((resolve) => setTimeout(resolve, 3000));\n\n    // custom small bundle created on https://echarts.apache.org/en/builder.html\n    await loadScript('/common/echarts-5.4.2/echarts.custom.only-linecharts.min.js');\n  }\n\n  const chartHeight = () => ({\n    height: MQ.matches ? 510 : 480,\n  });\n\n  let myChart = window.echarts.getInstanceByDom(chartContainer);\n  if (!myChart) {\n    myChart = window.echarts.init(chartContainer, 'dark', chartHeight());\n    window.addEventListener('resize', () => {\n      myChart.resize(chartHeight());\n      if (!myChart.isDisposed()) {\n        myChart.resize();\n      }\n    });\n  }\n\n  const getEchartsSeries = () => {\n    const metrics = Object.keys(performanceData);\n    const series = metrics.map((title, idx) => {\n      const metricValues = Object.entries(performanceData[title]).map(([rpm, value]) => [Number(rpm), Number(value)]);\n\n      return {\n        type: 'line',\n        name: title.toUpperCase(),\n        yAxisIndex: idx,\n        symbolSize: 12,\n        itemStyle: {\n          borderWidth: 1,\n          borderType: 'solid',\n          borderColor: COLORS.bgColor,\n        },\n        smooth: false,\n        data: metricValues,\n        z: metrics.length - (idx + 1),\n      };\n    });\n\n    return series;\n  };\n\n  const getLineValues = () => {\n    const lines = [];\n    Object.keys(performanceData).forEach((key) => {\n      const isTorqueRating = key.toLowerCase().includes('torque');\n      const lineObj = {\n        type: 'value',\n        position: isTorqueRating ? 'left' : 'right',\n        axisTick: {\n          show: false,\n        },\n        axisLine: {\n          show: false,\n        },\n        axisLabel: {\n          formatter(value) {\n            // remove thousands separator\n            return value;\n          },\n          margin: 20,\n        },\n        splitLine: {\n          show: false,\n        },\n        min: 0,\n        max: isTorqueRating ? 2000 : 600,\n        interval: isTorqueRating ? 200 : 50,\n      };\n      lines.push(lineObj);\n    });\n    return lines;\n  };\n\n  const option = {\n    legend: {\n      icon: 'circle',\n      fontFamily: 'Inter',\n      top: 'top',\n      left: MQ.matches ? 'auto' : '0',\n      right: MQ.matches ? '0' : 'auto',\n      itemHeight: 25,\n      itemGap: MQ.matches ? 50 : 10,\n      selectedMode: false,\n      textStyle: {\n        fontSize: 12,\n        lineHeight: 15,\n        fontWeight: 700,\n        color: COLORS.white,\n      },\n    },\n\n    series: getEchartsSeries(),\n    // Global palette:\n    color: COLORS.chartLines,\n    backgroundColor: COLORS.bgColor,\n    //  reduce space around the chart\n    grid: {\n      left: 50,\n      right: 40,\n      top: 80,\n      containLabel: false,\n    },\n    textStyle: {\n      color: COLORS.white,\n    },\n    xAxis: {\n      min: rpmValues.at(0),\n      max: rpmValues.at(-1),\n      interval: 200,\n      type: 'value',\n\n      // label center bellow chart\n      name: TEXTS.bottomChartLabel,\n      nameGap: 40,\n      nameLocation: 'center',\n      nameTextStyle: {\n        fontSize: 15,\n        fontWeight: 'bold',\n      },\n\n      // use lines at each 100 RPM\n      splitLine: {\n        show: true,\n        lineStyle: {\n          color: COLORS.verticalLines,\n          width: 1,\n        },\n      },\n      minorSplitLine: {\n        show: true,\n        lineStyle: {\n          color: COLORS.verticalLines,\n          width: 1,\n        },\n      },\n      axisTick: {\n        show: false,\n      },\n      minorTick: {\n        show: false,\n        splitNumber: 2,\n      },\n      axisLabel: {\n        show: true,\n        interval: 0,\n        showMinLabel: true,\n        showMaxLabel: true,\n        formatter(value) {\n          // remove thousands separator\n          return value;\n        },\n        margin: 15,\n      },\n      axisLine: {\n        show: false,\n      },\n    },\n    yAxis: getLineValues(),\n    animation: true,\n    animationDuration: 400,\n  };\n\n  myChart.setOption(option, {\n    // https://github.com/apache/echarts/issues/6202\n    notMerge: true,\n  });\n};\n\n/**\n * @typedef {Object} EngineDetail\n * @property {Array<Array<string>>} facts\n * @property {Object<string, Object<number, number>>} performanceData\n */\nconst renderEngineSpecs = (engineDetails) => {\n  const factsDownloadSpecs = engineDetails.facts.filter((fact) => fact[0] === 'download specs')[0]?.[1] || null;\n  // remove download specs from facts\n  if (factsDownloadSpecs) {\n    engineDetails.facts = engineDetails.facts.filter((fact) => fact[0] !== 'download specs');\n  }\n  const downloadSpecs = factsDownloadSpecs || engineDetails['download specs'] || null;\n  // check if the download specs share the same domain as the current page\n  const isSameDomain = downloadSpecs && downloadSpecs.includes(window.location.origin);\n  const specsLink = downloadSpecs && new URL(downloadSpecs);\n  if (downloadSpecs && !isSameDomain) {\n    specsLink.hostname = window.location.hostname;\n    specsLink.protocol = window.location.protocol;\n    if (window.location.port) {\n      specsLink.port = window.location.port;\n    }\n  }\n\n  // noinspection JSCheckFunctionSignatures\n  return div(\n    { class: 'key-specs' },\n    domEl('dl', {}, ...engineDetails.facts.map((cells) => [domEl('dt', cells[0]), domEl('dd', cells[1])]).flat()),\n    p(\n      { class: 'button-container' },\n      a(\n        {\n          class: 'button button--primary download-specs',\n          href: downloadSpecs ? specsLink.toString() : '#',\n          target: '_blank',\n          style: `display: ${downloadSpecs ? 'block' : 'none'};`,\n        },\n        TEXTS.btnText,\n      ),\n    ),\n  );\n};\n\nconst refreshDetailView = (block) => {\n  const { categoryId } = block.querySelector('.category-tablist button[aria-selected=\"true\"]')?.dataset || null;\n  const engineId = block.querySelector('.engine-tablist button[aria-selected=\"true\"]')?.textContent || null;\n  const engineDetail = engineData.get(block)[categoryId]?.engines[engineId];\n  const engineDetails = engineDetail || {};\n\n  // replace key specs\n  block.querySelector('.key-specs').replaceWith(renderEngineSpecs(engineDetails));\n\n  // update chart\n  const chartContainer = block.querySelector('.performance-chart');\n  // noinspection JSIgnoredPromiseFromCall\n  updateChart(chartContainer, engineDetails);\n};\n\nconst renderCategoryDetail = (block, categoryData, selectEngineId = null) => {\n  const categoryDetails = div({ class: 'category-detail' });\n  categoryDetails.innerHTML = `\n    <h3>${categoryData.nameHTML}</h3>\n    ${categoryData.descriptionHTML ? `<p class=\"category-description\">${categoryData.descriptionHTML}</p>` : ''}\n    <div class=\"engine-navigation\">\n      <p class=\"engine-ratings\">${TEXTS.engineRatings}</p>\n      <div class=\"engine-tablist\" role=\"tablist\" aria-label=\"${TEXTS.engineRatings}\"> </div>\n    </div>`;\n\n  const tabList = categoryDetails.querySelector('.engine-tablist');\n\n  Object.keys(categoryData.engines).forEach((engineId, index) => {\n    const isSelected = selectEngineId ? engineId === selectEngineId : index === 0;\n    const engineButton = button({ role: 'tab', 'aria-selected': isSelected }, engineId);\n\n    engineButton.addEventListener('click', () => {\n      // ignore click if already selected\n      if (engineButton.getAttribute('aria-selected') === 'true') {\n        return;\n      }\n\n      // Remove selection from currently selected tabs and set this tab as selected\n      tabList.querySelectorAll('[aria-selected=\"true\"]').forEach((tab) => tab.setAttribute('aria-selected', false));\n      engineButton.setAttribute('aria-selected', true);\n\n      centerTab(tabList, engineButton);\n\n      refreshDetailView(block);\n    });\n    tabList.append(engineButton);\n  });\n\n  return categoryDetails;\n};\n\nconst tabListClickHandler = ({ ...params }) => {\n  const { tabList, activeLine, block } = params;\n  tabList.addEventListener('click', (e) => {\n    const isIcon = e.target.parentElement.tagName === 'BUTTON';\n    const isButton = e.target.tagName === 'BUTTON' || isIcon;\n    const isActiveBtn = e.target.getAttribute('aria-selected') === 'true';\n    if (!isButton || isActiveBtn) {\n      return;\n    }\n\n    const buttonTab = isIcon ? e.target.parentElement : e.target;\n    const activeTab = tabList.querySelectorAll('.active');\n    [...activeTab].forEach((tab) => {\n      tab.classList.remove('active');\n      tab.firstElementChild.setAttribute('aria-selected', false);\n    });\n    buttonTab.setAttribute('aria-selected', true);\n    buttonTab.parentElement.classList.add('active');\n\n    moveNavigationLine(activeLine, buttonTab, tabList);\n    if (!MQ.matches) {\n      centerTab(tabList, buttonTab.parentElement);\n    }\n\n    block.querySelector('.category-detail').replaceWith(renderCategoryDetail(block, engineData.get(block)[buttonTab.dataset.categoryId]));\n\n    refreshDetailView(block);\n  });\n};\n\nconst tabListHoverHandler = ({ ...params }) => {\n  const { tabList, activeLine } = params;\n  tabList.addEventListener('mouseover', (e) => {\n    const isButton = e.target.tagName === 'BUTTON';\n    if (!isButton) {\n      return;\n    }\n    moveNavigationLine(activeLine, e.target, tabList);\n  });\n};\n\nconst renderCategoryTabList = ({ block, categoryData, activeCategory }) => {\n  const tabListWrapper = div({ class: 'category-tablist-wrapper' });\n  const tabList = ul({ role: 'tablist', class: 'category-tablist' });\n  const activeLine = li({ class: 'active-line' });\n\n  Object.keys(categoryData).forEach((categoryId) => {\n    const isActive = categoryId === activeCategory;\n    const { nameHTML } = categoryData[categoryId];\n    const tabItem = li({ class: `category-tab${isActive ? ' active' : ''}` });\n    const tabButton = button({\n      class: 'tab',\n      role: 'tab',\n      'aria-selected': isActive,\n      'data-category-id': categoryId,\n    });\n    tabButton.innerHTML = nameHTML;\n    tabItem.append(tabButton);\n    tabList.append(tabItem);\n  });\n  tabList.append(activeLine);\n  tabListWrapper.append(tabList);\n\n  tabListClickHandler({ tabList, activeLine, block });\n  tabListHoverHandler({ tabList, activeLine });\n\n  return tabListWrapper;\n};\n\n/**\n * converts the rows into columns, and vice versa.\n * @return {Object<string, string[]>}\n */\nconst transposeTable = (data) => {\n  const newData = {};\n  data.forEach((row) => {\n    const label = row.ID.toLowerCase().trim();\n    for (const modelId in row) {\n      if (modelId !== 'ID') {\n        if (!newData[modelId]) {\n          newData[modelId] = [];\n        }\n        newData[modelId].push([label, row[modelId]]);\n      }\n    }\n  });\n  return newData;\n};\n\nconst parseEngineJsonData = (data, block) => {\n  // need to convert because the Excel sheet is column based and the JSON API returns rows.\n  const rows = transposeTable(data);\n  Object.values(rows).forEach((modelArray) => {\n    const engine = { facts: [], performanceData: {} };\n    let metricName = null;\n    // extract RPM data into engine.performanceData. The rows after the key `rpm`\n    // are the performance data. They value of the RPM row contains the metric name.\n    for (const [key, value] of modelArray) {\n      if (key === 'rpm') {\n        metricName = value;\n      } else if (key === 'model' || key === 'series' || key === 'download specs') {\n        engine[key] = value;\n      } else if (metricName !== null) {\n        // handle performance data\n        if (!engine.performanceData[metricName]) {\n          engine.performanceData[metricName] = {};\n        }\n        const rpmValue = Number(key);\n        engine.performanceData[metricName][rpmValue] = Number(value);\n      } else {\n        engine.facts.push([key, value]);\n      }\n    }\n\n    // remove empty performance data\n    Object.keys(engine.performanceData).forEach((key) => {\n      if (Object.values(engine.performanceData[key])[0] === 0 && Object.values(engine.performanceData[key])[1] === 0) {\n        delete engine.performanceData[key];\n      }\n    });\n\n    const categoryId = engine.series.replaceAll('®', '').toLowerCase().trim();\n    if (!engineData.get(block)[categoryId]) {\n      console.error(\n        `The engine type ${categoryId} was used in Excel, but the not defined in the Engine-Specifications block. Please update the block used on this page.`,\n      );\n      // create empty object to prevent errors\n      engineData.get(block)[categoryId] = { engines: {}, nameHTML: engine.series, descriptionHTML: '' };\n    }\n    engineData.get(block)[categoryId].engines[engine.model] = engine;\n  });\n};\n\nexport default async function decorate(block) {\n  const blockSection = block.closest('.section');\n  const sectionTitle = blockSection.querySelector('h2');\n  if (sectionTitle) {\n    sectionTitle.classList.add(`${blockName}__section-title`);\n  }\n  engineData.set(block, {});\n\n  let jsonUrl;\n  // load categories  data\n  [...block.children].forEach((rawTabHeader) => {\n    // any first cell that contains a link is the json url\n    if (rawTabHeader.children[0].querySelector('a')) {\n      jsonUrl = rawTabHeader.children[0].querySelector('a').getAttribute('href');\n      return;\n    }\n    const categoryId = rawTabHeader.children[0].textContent.replaceAll('®', '').toLowerCase().trim();\n    engineData.get(block)[categoryId] = {\n      nameHTML: rawTabHeader.children[0].innerHTML,\n      descriptionHTML: rawTabHeader.children[1].innerHTML,\n      engines: {},\n    };\n  });\n  [...block.children].forEach((node) => node.remove());\n\n  // load data\n  const response = await fetch(jsonUrl);\n  const result = await response.json();\n  parseEngineJsonData(result.data, block);\n\n  const initialCategoryId = Object.keys(engineData.get(block))[0];\n  const initialEngineId = Object.keys(engineData.get(block)[initialCategoryId].engines)[0];\n\n  // add tabs\n  block.append(\n    renderCategoryTabList({\n      block,\n      categoryData: engineData.get(block),\n      activeCategory: initialCategoryId,\n    }),\n  );\n\n  // Render the navigation line below the active tab when the section is loaded\n  const observer = new MutationObserver((mutations) => {\n    mutations.forEach((mutation) => {\n      if (mutation.type !== 'attributes') {\n        return;\n      }\n      const { sectionStatus } = mutation.target.dataset;\n      if (sectionStatus !== 'loaded') {\n        return;\n      }\n      const tabList = block.querySelector('.category-tablist');\n      const tabLine = block.querySelector('.active-line');\n      moveNavigationLine(tabLine, tabList.querySelector('.active'), tabList);\n      observer.disconnect();\n    });\n  });\n\n  observer.observe(blockSection, { attributes: true, attributeFilter: ['data-section-status'] });\n\n  // add category details and engine selection (\"XY HP\")\n  block.append(renderCategoryDetail(block, engineData.get(block)[initialCategoryId], initialEngineId));\n\n  // Add detail panel with facts and chart\n  const engineDetails = engineData.get(block)[initialCategoryId].engines[initialEngineId];\n  const detailPanel = div(\n    { class: 'details-panel' },\n    renderEngineSpecs(engineDetails),\n    div({ class: 'performance-chart' }, div({ class: 'loading-spinner' })),\n  );\n  block.append(detailPanel);\n\n  const chartContainer = block.querySelector('.performance-chart');\n  // noinspection JSIgnoredPromiseFromCall,ES6MissingAwait\n  updateChart(chartContainer, engineDetails);\n}\n","import { createElement, getOrigin, getTextLabel } from '../../scripts/common.js';\nimport { extractLimitFromBlock, clearRepeatedArticles, fetchMagazineData, formatArticlesArray } from '../../scripts/services/magazine.service.js';\nimport { createOptimizedPicture } from '../../scripts/aem.js';\n\nconst sectionTitle = getTextLabel('recent_articles:title');\nconst readNowText = getTextLabel('recent_articles:read_now_text');\nconst defaultLimit = 5;\nconst blockName = 'recent-articles';\n\nconst createList = (articles) => `\n  <ul class=\"${blockName}-list\">\n  ${articles\n    .map((article, idx) => {\n      const firstOrRestClass = idx === 0 ? 'first' : 'rest';\n      const picture = createOptimizedPicture(article.image, article.title);\n      const pictureTag = picture.outerHTML;\n      const linkUrl = new URL(article.path, getOrigin());\n\n      const articleCategory = article.category;\n      const categoryWithDash = articleCategory.replaceAll(' ', '-').toLowerCase();\n      const categoryUrl = new URL(`magazine/categories/${categoryWithDash}`, getOrigin());\n\n      return `\n      <li class=\"${blockName}-${firstOrRestClass}-item\">\n        <div class=\"${blockName}-${firstOrRestClass}-image\">\n          <a href=\"${linkUrl}\">${pictureTag}</a>\n        </div>\n        ${idx === 0 && article.category ? `<a class=\"${blockName}-${firstOrRestClass}-category\" href=\"${categoryUrl}\">${article.category}</a>` : ''}\n        <a class=\"${blockName}-${firstOrRestClass}-title\" href=\"${linkUrl}\">${article.title}</a>\n        ${idx === 0 && article.subtitle ? `<p class=\"${blockName}-${firstOrRestClass}-subtitle\">${article.subtitle}</p>` : ''}\n        ${idx === 0 ? `<a class=\"${blockName}-${firstOrRestClass}-link\" href=\"${linkUrl}\">${readNowText}</a>` : ''}\n      </li>`;\n    })\n    .join('')}\n  </ul>`;\n\nexport default async function decorate(block) {\n  const limit = extractLimitFromBlock(block) || defaultLimit;\n\n  const queryVariables = { limit: limit + 1, sort: 'PUBLISH_DATE_DESC' };\n  const allMagazineData = await fetchMagazineData(queryVariables);\n  const allArticles = formatArticlesArray(allMagazineData?.items);\n\n  const filteredArticles = clearRepeatedArticles(allArticles);\n  const selectedArticles = filteredArticles.slice(0, limit);\n\n  const recentArticlesSection = createElement('div', { classes: `${blockName}-section` });\n  const recentArticleContent = document.createRange().createContextualFragment(`\n      <h3 class=\"${blockName}-section-title\">${sectionTitle}</h3>\n      ${createList(selectedArticles)}\n    `);\n  recentArticlesSection.append(recentArticleContent);\n\n  block.textContent = '';\n  block.append(recentArticlesSection);\n}\n","import { createElement, getOrigin, getTextLabel } from '../../scripts/common.js';\nimport {\n  extractLimitFromBlock,\n  clearRepeatedArticles,\n  fetchMagazineData,\n  formatArticlesArray,\n  isMagazineTemplate,\n} from '../../scripts/services/magazine.service.js';\nimport { getMetadata, createOptimizedPicture } from '../../scripts/aem.js';\n\nconst recommendationsText = getTextLabel('recommendations:title');\nconst readNowText = getTextLabel('recommendations:read_now_text');\nconst defaultLimit = 2;\nconst blockName = 'recommendations';\n\nconst createTruckSection = (trucks) => {\n  const truckList = trucks?.map((item) => item.replace('Mack ', '')).join(', ');\n  return `\n    <div class=\"${blockName}-truck\">\n      <img\n        class=\"truck-icon\"\n        src=\"/icons/Truck_Key_icon.svg\"\n        alt=\"truck icon\"\n      />\n      <p class=\"${blockName}-truck-text\">${truckList}</p>\n    </div>`;\n};\n\nconst createList = (articles) => `\n  <ul class=\"${blockName}-list\">\n    ${articles\n      .map((article, idx) => {\n        const picture = createOptimizedPicture(article.image, article.title);\n        const pictureTag = picture.outerHTML;\n        const linkUrl = new URL(article.path, getOrigin());\n\n        const articleCategory = article.category;\n        const categoryWithDash = articleCategory.replaceAll(' ', '-').toLowerCase();\n        const categoryUrl = new URL(`magazine/categories/${categoryWithDash}`, getOrigin());\n\n        return `\n        <li class=\"${blockName}-item ${blockName}-item-${idx}\">\n          <div class=\"${blockName}-image\">\n            <a href=\"\" class=\"image-link\">\n              ${pictureTag}\n            </a>\n          </div>\n          <div class=\"${blockName}-text-content\">\n            ${article.category && isMagazineTemplate ? `<a class=\"${blockName}-category\" href=\"${categoryUrl}\">${article.category}</a>` : ''}\n            <a class=\"${blockName}-title\" href=\"${linkUrl}\">${article.title}</a>\n            ${article.truck && !isMagazineTemplate ? createTruckSection(article.truck) : ''}\n            <a class=\"${blockName}-link\" href=\"${linkUrl}\">${readNowText}</a>\n          </div>\n        </li>`;\n      })\n      .join('')}\n    </ul>`;\n\nexport default async function decorate(block) {\n  const limit = extractLimitFromBlock(block) || defaultLimit;\n  const category = getMetadata('article-category');\n\n  const queryVariables = {\n    limit: limit + 1,\n    facets: ['ARTICLE'],\n    sort: 'PUBLISH_DATE_DESC',\n    article: { category },\n  };\n  const allMagazineData = await fetchMagazineData(queryVariables);\n  const allArticles = formatArticlesArray(allMagazineData?.items);\n\n  const filteredArticles = clearRepeatedArticles(allArticles);\n  const selectedArticles = filteredArticles.slice(0, limit);\n\n  const recommendationsSection = createElement('div', { classes: `${blockName}-section` });\n  const recommendationsContent = document.createRange().createContextualFragment(`\n        <h3 class=\"${blockName}-section-title\">${recommendationsText}</h3>\n        ${createList(selectedArticles)}\n      `);\n\n  recommendationsSection.append(recommendationsContent);\n  block.textContent = '';\n  block.append(recommendationsSection);\n}\n","import { createElement } from '../../scripts/common.js';\n\nfunction newId() {\n  return (Math.random() + 1).toString(36).substring(7);\n}\n\nfunction calcScrollHeight(rowgroup) {\n  return [...rowgroup.children].map((child) => child.clientHeight).reduce((l, r) => l + r, 0);\n}\n\nfunction expand(event) {\n  const button = event.target.closest('button');\n  const rowgroup = button.nextElementSibling;\n  const isExpanded = button.ariaExpanded === 'true';\n  rowgroup.style.height = isExpanded ? 0 : `${rowgroup.scrollHeight}px`;\n  rowgroup.ariaHidden = isExpanded;\n  button.ariaExpanded = !isExpanded;\n}\n\nfunction normalizeCells(cells, rowheaderRole = 'rowheader', cellRole = 'cell') {\n  [...cells].forEach((cell, j) => {\n    cell.normalize();\n    // remove any blank text nodes\n    if (cell.firstChild && cell.firstChild.nodeType === 3 && cell.firstChild.nodeValue.trim() === '') {\n      cell.firstChild.remove();\n    }\n    if (cell.lastChild && cell.lastChild.nodeType === 3 && cell.lastChild.nodeValue.trim() === '') {\n      cell.lastChild.remove();\n    }\n    // remove leading or trailing breaks\n    if (cell.firstChild && cell.firstChild.tagName === 'BR') {\n      cell.firstChild.remove();\n    }\n    if (cell.lastChild && cell.lastChild.tagName === 'BR') {\n      cell.lastChild.remove();\n    }\n    // wrap text-only cells with a <p>\n    if (cell.children.length === 0 && !cell.querySelector('p') && cell.textContent !== '') {\n      const text = cell.innerHTML;\n      const fragment = document.createRange().createContextualFragment(text);\n      const pWrapper = createElement('p');\n      cell.textContent = '';\n      pWrapper.appendChild(fragment);\n      cell.appendChild(pWrapper);\n    }\n    cell.role = j === 0 && cells.length > 1 ? rowheaderRole : cellRole;\n    cell.className = 'cell';\n  });\n}\n\nfunction activateMobileColumn(block, index) {\n  block.querySelectorAll('.cell.expand').forEach((cell) => cell.classList.remove('expand'));\n  block\n    .querySelectorAll(`.image-header .cell:nth-child(${index}),.row .cell:nth-child(${index + 1})`)\n    .forEach((cell) => cell.classList.add('expand'));\n  // adjust the height of all expanded rowgroups\n  block.querySelectorAll('[role=\"rowgroup\"][aria-hidden=\"false\"]').forEach((rowgroup) => {\n    rowgroup.style.height = `${calcScrollHeight(rowgroup)}px`;\n  });\n}\n\nfunction changeMobileColumn(event) {\n  activateMobileColumn(event.target.closest('.block'), parseInt(event.target.value, 10));\n}\n\nexport default function decorate(block) {\n  const colCount = block.firstElementChild.children.length;\n  const header = block.firstElementChild;\n  let firstRowIndex = 0;\n\n  block.role = 'table';\n  block.style.setProperty('--grid-col-count', colCount);\n\n  if (header.children.length > 1) {\n    header.className = 'column-header';\n    normalizeCells(header.children, 'rowheader', 'columnheader');\n    const mobileColumnHeader = createElement('div', { classes: 'column-header-mobile' });\n    const select = `<select>\n      ${[...header.querySelectorAll('[role=\"columnheader\"]')]\n        .map((columnHeader, i) => `<option value=\"${i + 1}\">${columnHeader.textContent}</option>`)\n        .join('')}\n      </select>`;\n    const fragment = document.createRange().createContextualFragment(select);\n    mobileColumnHeader.appendChild(fragment);\n    mobileColumnHeader.firstElementChild.addEventListener('change', changeMobileColumn);\n    header.insertAdjacentElement('afterend', mobileColumnHeader);\n    firstRowIndex += 2;\n  }\n\n  const rows = [...block.children];\n  let rowCount = 0;\n\n  let singleColumn = true;\n  for (let i = firstRowIndex; i < rows.length && singleColumn; i += 1) {\n    singleColumn = rows[i].children.length === 1;\n  }\n  for (let i = firstRowIndex, rowgroup = null; i < rows.length; i += 1) {\n    const row = rows[i];\n    const cells = row.children;\n    const firstChild = cells[0].firstElementChild;\n\n    if (cells.length === 1 && (!singleColumn || (cells[0].children.length === 1 && firstChild && firstChild.tagName === 'STRONG'))) {\n      const button = createElement('button', {\n        classes: 'rowgroup-header',\n        props: { type: 'button' },\n      });\n      button.appendChild(cells[0]);\n      button.addEventListener('click', expand);\n      button.ariaExpanded = false;\n      row.insertAdjacentElement('beforebegin', button);\n\n      rowgroup = row;\n      rowgroup.role = 'rowgroup';\n      rowgroup.id = newId();\n      rowgroup.ariaHidden = true;\n      button.setAttribute('aria-controls', rowgroup.id);\n    } else {\n      row.className = 'row';\n      row.role = 'row';\n      rowCount += 1;\n      if (rowgroup) {\n        rowgroup.appendChild(row);\n      }\n      normalizeCells(cells);\n    }\n  }\n\n  block.ariaRowCount = rowCount;\n  block.ariaColCount = colCount;\n\n  activateMobileColumn(block, 1);\n}\n","import { createElement, getLocale } from '../../scripts/common.js';\nimport { autosuggestQuery, fetchData, TENANT } from '../../scripts/search-api.js';\n\nconst autoSuggestClass = 'autosuggest-results-item-highlighted';\n\nexport function fetchAutosuggest(term, autosuggestEle, rowEle, func) {\n  const fragmentRange = document.createRange();\n  const locale = getLocale();\n  const language = locale.split('-')[0].toUpperCase();\n\n  fetchData({\n    query: autosuggestQuery(),\n    variables: {\n      tenant: TENANT,\n      term,\n      language,\n      sizeSuggestions: 5,\n    },\n  }).then(({ errors, data }) => {\n    if (errors) {\n      console.log('%cSomething went wrong', { errors });\n    } else {\n      const { edsWordPhraseSuggest: { terms } = {} } = data;\n      autosuggestEle.textContent = '';\n      autosuggestEle.classList.remove('show');\n\n      if (terms.length) {\n        terms.forEach((val) => {\n          const row = createElement(rowEle.tag, { classes: rowEle.class, props: rowEle.props });\n          const suggestFragment = fragmentRange.createContextualFragment(`<b>\n            ${val}\n          </b>`);\n          row.appendChild(suggestFragment);\n\n          row.onclick = () => func(val);\n\n          autosuggestEle.appendChild(row);\n          autosuggestEle.classList.add('show');\n        });\n      }\n    }\n  });\n}\n\nexport function handleArrowUp(props) {\n  let { liSelected, next, index } = props;\n  const { list } = props;\n  const listLen = list.length - 1;\n\n  if (liSelected) {\n    liSelected.classList.remove(autoSuggestClass);\n    index -= 1;\n\n    next = list[index];\n    if (next && index >= 0) {\n      liSelected = next;\n    } else {\n      index = list.length - 1;\n      liSelected = list[index];\n    }\n  } else {\n    index = 0;\n    liSelected = list[listLen];\n  }\n\n  liSelected.classList.add(autoSuggestClass);\n  return { liSelected, index, next };\n}\n\nexport function handleArrowDown(props) {\n  let { index, liSelected, next } = props;\n  const { list } = props;\n\n  index += 1;\n\n  if (liSelected) {\n    liSelected.classList.remove(autoSuggestClass);\n\n    next = list[index];\n    if (next && index < list.length) {\n      liSelected = next;\n    } else {\n      index = 0;\n      [liSelected] = list;\n    }\n  } else {\n    index = 0;\n    [liSelected] = list;\n  }\n\n  liSelected.classList.add(autoSuggestClass);\n  return { index, liSelected, next };\n}\n","import { debounce } from '../../scripts/scripts.js';\nimport { getTextLabel, getLocale } from '../../scripts/common.js';\nimport { getFacetsTemplate, getNoResultsTemplate, getMainTemplate, getResultsItemsTemplate, getShowingResultsTemplate } from './templates.js';\n\nimport { searchQuery, fetchData, sanitizeQueryTerm, TENANT } from '../../scripts/search-api.js';\n\nimport { fetchAutosuggest, handleArrowDown, handleArrowUp } from './autosuggest.js';\n\nconst PLACEHOLDERS = {\n  searchFor: getTextLabel('search:search_for'),\n  noResults: getTextLabel('search:no_results'),\n  refine: getTextLabel('search:refine'),\n  showingResults: getTextLabel('search:showing_results_for'), // searchResultSummarySection\n  sortBy: getTextLabel('search:sort_by'), // searchOptionsSection\n  sortFilter: getTextLabel('search:sort_filter'),\n  previous: getTextLabel('search:previous'),\n  next: getTextLabel('search:next'),\n};\n\nconst SEARCH_PARAMS = {\n  _q: 'q',\n  _start: 'start',\n  _sort: 'sort',\n  _article: 'article',\n  _topic: 'topic',\n  _truck: 'truck',\n  _category: 'category',\n};\n\nexport default function decorate(block) {\n  const fragmentRange = document.createRange();\n  const locale = getLocale();\n  const language = locale.split('-')[0].toUpperCase();\n\n  // check if url has query params\n  const { _q, _start, _sort, _article, _topic, _truck, _category } = SEARCH_PARAMS;\n\n  const urlParams = new URLSearchParams(window.location.search);\n  const searchTerm = urlParams.get(_q);\n  const tenant = TENANT;\n\n  let offset = urlParams.get(_start);\n  offset = offset ? Number(offset) : 0;\n  let resultCount = 0;\n  const limit = 25;\n  let nextOffset = offset + limit;\n  let hasResults = true;\n  let facetsFilters = [];\n\n  const mainTemplate = getMainTemplate(PLACEHOLDERS);\n  const mainFragment = fragmentRange.createContextualFragment(mainTemplate);\n  block.textContent = '';\n  block.appendChild(mainFragment);\n\n  // after insert the main template, these elements are present then\n  const searchBtn = block.querySelector('.sf-form > span');\n  const input = document.getElementById('searchTerm');\n  input.value = searchTerm;\n  const facetsWrapper = document.getElementById('searchFacetSection');\n  const resultsWrapper = document.getElementById('searchResultsSection');\n  const summary = document.getElementById('searchResultSummarySection');\n  const sortBy = document.getElementById('searchOptionsSection');\n  const listEl = block.querySelector('.autosuggest__results-container ul');\n\n  function searchResults(hideAutoSuggest = true) {\n    if (hideAutoSuggest) {\n      listEl.textContent = '';\n    }\n    offset = 0;\n\n    deleteUrlParam(_category);\n    insertUrlParam(_q, input.value);\n    insertUrlParam(_start, offset);\n\n    fetchResults();\n  }\n\n  searchBtn.onclick = () => searchResults();\n\n  const onClickHandler = (val) => {\n    input.value = val;\n    searchResults();\n  };\n\n  const delayFetchData = debounce((term) =>\n    fetchAutosuggest(\n      term,\n      listEl,\n      {\n        tag: 'li',\n        class: 'autosuggest__results-item',\n        props: {\n          role: 'option',\n          'data-section-name': 'default',\n        },\n      },\n      onClickHandler,\n    ),\n  );\n\n  let liSelected;\n  let next;\n  let index = -1;\n\n  input.onkeyup = (e) => {\n    const term = e.target.value;\n    const list = listEl.getElementsByTagName('li');\n\n    if (e.key === 'Enter') {\n      searchResults();\n    } else if (e.key === 'Escape') {\n      listEl.textContent = '';\n    } else if (['ArrowUp', 'ArrowDown'].includes(e.key)) {\n      let returnObj;\n\n      if (e.key === 'ArrowUp') {\n        returnObj = handleArrowUp({\n          list,\n          liSelected,\n          index,\n          next,\n        });\n      } else {\n        returnObj = handleArrowDown({\n          list,\n          liSelected,\n          index,\n          next,\n        });\n      }\n\n      liSelected = returnObj.liSelected;\n      index = returnObj.index;\n      next = returnObj.next;\n      input.value = liSelected.firstElementChild.textContent.replace(/[ ]{2,}/g, '');\n      searchResults(false);\n    } else {\n      delayFetchData(term);\n    }\n  };\n\n  // pagination events\n  const paginationContainer = block.querySelector('.search-pagination-container');\n  const countSpan = paginationContainer.querySelector('.count');\n  const resRange = paginationContainer.querySelector('.page-range');\n\n  const nextBtn = paginationContainer.querySelector('.next');\n  nextBtn.onclick = () => pagination('next');\n\n  const prevBtn = paginationContainer.querySelector('.prev');\n  prevBtn.onclick = () => pagination('prev');\n\n  const addMoreBtnToggleEvent = (e) => {\n    const facetList = e.target.parentElement.previousElementSibling;\n    const isMore = e.target.textContent.toLowerCase() === 'more';\n    e.target.textContent = isMore ? 'Less' : 'More';\n    [...facetList.children].forEach((li, i) => {\n      if (i <= 2) {\n        return;\n      }\n      li.classList.toggle('d-none', !isMore);\n    });\n  };\n\n  const addFacetTitlesToggleEvent = (e) => {\n    const titleList = e.target.closest('.sidebar-heading').nextElementSibling;\n    const isShown = titleList.classList.contains('show');\n    e.target.classList.toggle('active', !isShown);\n    titleList.classList.toggle('show', !isShown);\n  };\n\n  const addToggleOverlayEvent = (sidebar, overlay, isOpen = false) => {\n    const showClass = 'show-facet-overlay';\n    sidebar.classList.toggle(showClass, isOpen);\n    overlay.classList.toggle(showClass, isOpen);\n  };\n\n  // handle filters\n  const addFilterEvent = (e, form) => {\n    form.requestSubmit();\n  };\n\n  const updateFilterCheckbox = () => {\n    const form = block.querySelector('form');\n    [...form].forEach((field) => {\n      const isChecked = facetsFilters.find(({ value }) => value.includes(field.value));\n      if (isChecked) {\n        field.checked = true;\n      }\n    });\n  };\n\n  const addFilterSubmitEvent = (e) => {\n    e.preventDefault();\n    const form = e.target;\n    const inputsChecked = [];\n    [...form].forEach((field) => {\n      inputsChecked.push(field.id);\n\n      const facetIndex = facetsFilters.findIndex((item) => item.field === field.dataset.filter);\n\n      if (facetIndex > -1) {\n        facetsFilters[facetIndex].value = facetsFilters[facetIndex].value.filter((val) => val !== field.value);\n\n        if (field.checked) {\n          facetsFilters[facetIndex].value.push(field.value);\n        }\n        if (!facetsFilters[facetIndex].value.length) {\n          facetsFilters = facetsFilters.filter((item) => item.field !== field.dataset.filter);\n        }\n      } else if (field.checked) {\n        facetsFilters.push({\n          field: field.dataset.filter,\n          value: [field.value],\n        });\n      }\n    });\n    const filterParams = [_article, _topic, _truck, _category];\n\n    filterParams.forEach((item) => {\n      const filter = facetsFilters.find(({ field }) => field.toLowerCase() === item);\n\n      if (filter) {\n        insertUrlParam(item, filter.value);\n        return;\n      }\n      deleteUrlParam(item);\n    });\n    facetsFilters = [];\n    offset = 0;\n    insertUrlParam(_start, offset);\n    fetchResults();\n  };\n\n  const addFacetsEvents = (facets) => {\n    if (!facets) {\n      return;\n    }\n    const facetSidebar = facets.querySelector('.sf-sidebar-container');\n    const facetOverlay = facets.querySelector('.sidebar-background');\n    const closeBtns = facets.querySelectorAll('.search-close-button, .close-button');\n    const titles = facets.querySelectorAll('.sidebar-heading a');\n    const filtersForm = facets.querySelector('#facetsFilters');\n    if (titles.length > 0) {\n      [...titles].forEach((title) => {\n        title.onclick = addFacetTitlesToggleEvent;\n      });\n    }\n    const moreBtns = facets.querySelectorAll('.more-less a');\n    if (moreBtns.length > 0) {\n      [...moreBtns].forEach((btn) => {\n        btn.onclick = addMoreBtnToggleEvent;\n      });\n    }\n    const filterByBtn = facets.querySelector('.pill');\n    filterByBtn.onclick = () => {\n      addToggleOverlayEvent(facetSidebar, facetOverlay, true);\n    };\n\n    [...closeBtns].forEach((btn) => {\n      btn.onclick = () => addToggleOverlayEvent(facetSidebar, facetOverlay);\n    });\n\n    filtersForm.addEventListener('submit', addFilterSubmitEvent);\n    filtersForm.onchange = (e) => addFilterEvent(e, filtersForm);\n\n    if (facetsFilters.length) {\n      updateFilterCheckbox();\n    }\n  };\n\n  // handle sort\n  const sortResults = block.querySelector('.custom-select-searchstudio-js');\n  const sort = urlParams.get(_sort);\n  if (sort) {\n    sortResults.value = sort;\n  }\n  sortResults.onchange = (e) => {\n    insertUrlParam(_sort, e.target.value);\n    fetchResults();\n  };\n\n  function showResults(data) {\n    const { items, count, facets } = data;\n    const queryTerm = sanitizeQueryTerm(input.value);\n    let resultsText = '';\n    let facetsText = null;\n    if (items.length > 0) {\n      // items by query: 25, count has the total\n      paginationContainer.classList.add('show');\n      summary.parentElement.classList.remove('no-results');\n      resultsText = getResultsItemsTemplate({ items, queryTerm });\n      facetsText = getFacetsTemplate(facets);\n      resultCount = count;\n      hasResults = true;\n    } else {\n      const noResults = PLACEHOLDERS.noResults.replace('$0', `\"<span>${queryTerm.trim() === '' ? ' ' : queryTerm}</span>\"`);\n      summary.parentElement.classList.add('no-results');\n      resultsText = getNoResultsTemplate({ noResults, refine: PLACEHOLDERS.refine });\n      hasResults = false;\n    }\n    const fragment = fragmentRange.createContextualFragment(resultsText);\n    summary.textContent = '';\n    resultsWrapper.textContent = '';\n    facetsWrapper.textContent = '';\n    if (hasResults) {\n      const newOffset = nextOffset > count ? count : nextOffset;\n      const showingResults = PLACEHOLDERS.showingResults\n        .replace('$0', `${count > 0 ? offset + 1 : 0}`)\n        .replace('$1', newOffset)\n        .replace('$2', count)\n        .replace('$3', queryTerm);\n      const showingResultsText = getShowingResultsTemplate(showingResults);\n      const summaryFragment = fragmentRange.createContextualFragment(showingResultsText);\n      const facetsFragment = fragmentRange.createContextualFragment(facetsText);\n      resultsWrapper.appendChild(fragment);\n      summary.appendChild(summaryFragment);\n      facetsWrapper.appendChild(facetsFragment);\n      addFacetsEvents(facetsWrapper);\n    } else {\n      summary.appendChild(fragment);\n      paginationContainer.classList.remove('show');\n    }\n    sortBy.classList.toggle('hide', !hasResults);\n  }\n\n  function deleteUrlParam(key) {\n    if (window.history.pushState) {\n      const searchUrl = new URL(window.location.href);\n      searchUrl.searchParams.delete(key);\n      window.history.pushState({}, '', searchUrl.toString());\n    }\n  }\n\n  function insertUrlParam(key, value) {\n    if (window.history.pushState) {\n      const searchUrl = new URL(window.location.href);\n      searchUrl.searchParams.set(key, value);\n      window.history.pushState({}, '', searchUrl.toString());\n    }\n  }\n\n  function updatePaginationDOM(data) {\n    let isPrevDisabled = false;\n    let isNextDisabled = false;\n    const rangeText = `${offset + 1}-${nextOffset >= resultCount ? resultCount : nextOffset}`;\n\n    // disable the prev , next buttons\n    if (offset === 0) {\n      isPrevDisabled = 'disabled';\n    }\n    if (nextOffset >= data.count) {\n      isNextDisabled = 'disabled';\n    }\n    prevBtn.setAttribute('disabled', isPrevDisabled);\n    nextBtn.setAttribute('disabled', isNextDisabled);\n    resRange.innerText = rangeText;\n  }\n\n  async function fetchResults() {\n    const searchParams = new URLSearchParams(window.location.search);\n    const queryTerm = sanitizeQueryTerm(searchParams.get(_q));\n    const offsetVal = Number(searchParams.get(_start));\n    const sortVal = searchParams.get(_sort) || 'BEST_MATCH';\n\n    const filters = {\n      category: { field: 'CATEGORY', value: _category },\n      article: { field: 'ARTICLE', value: _article },\n      topic: { field: 'TOPIC', value: _topic },\n      truck: { field: 'TRUCK', value: _truck },\n    };\n    const objectFilters = Object.keys(filters);\n\n    const variables = {\n      q: queryTerm,\n      language,\n      limit,\n      offset: offsetVal,\n      sort: sortVal,\n      tenant,\n      facets: [...objectFilters.map((key) => filters[key].field)],\n      article: {},\n    };\n\n    objectFilters.forEach((key) => {\n      // check for filters in the url ...\n      const value = searchParams.get(filters[key].value);\n      // updates the variables object ...\n      if (value) {\n        const splittedValue = value.split(',');\n        if (key === 'category') {\n          variables[key] = splittedValue;\n        } else {\n          const articleKey = key === 'article' ? 'category' : key;\n          variables.article[articleKey] = splittedValue;\n        }\n        // and updates the facetsFilters to be used to update the checkboxes\n        facetsFilters.push({\n          field: filters[key].field,\n          value: splittedValue,\n        });\n      }\n    });\n\n    fetchData({\n      query: searchQuery(),\n      variables,\n    }).then(({ errors, data }) => {\n      if (errors) {\n        console.log('%cSomething went wrong', errors);\n      } else {\n        const { edssearch } = data;\n        nextOffset = offset + limit;\n        countSpan.innerText = edssearch.count;\n        showResults(edssearch);\n        updatePaginationDOM(edssearch);\n      }\n    });\n  }\n\n  function getNextOffset(isNext = false) {\n    if (isNext) {\n      return nextOffset <= resultCount ? nextOffset : offset;\n    }\n    const temp = offset - limit;\n    return temp > 0 ? temp : 0;\n  }\n\n  function pagination(type) {\n    offset = getNextOffset(type === 'next');\n    insertUrlParam(_start, offset);\n    fetchResults();\n  }\n\n  // hide autocomplete, click was outside container.\n  const containingElement = document.querySelector('#searchInput');\n\n  document.body.addEventListener('click', (event) => {\n    if (!containingElement.contains(event.target)) {\n      listEl.textContent = '';\n    }\n  });\n\n  if (searchTerm) {\n    fetchResults();\n  }\n}\n","export const getMainTemplate = (PLACEHOLDERS) => {\n  const [relevance, newest, oldest] = PLACEHOLDERS.sortFilter.split(',');\n  return `\n  <div class=\"search-input-wrapper\">\n    <div id=\"searchInput\" class=\"input-container-custom\">\n      <div class=\"sf-header-searchstudio-js mb-5\">\n        <div class=\"sf-form\">\n          <div id=\"autosuggest\" class=\"form-control-suggest\">\n            <div role=\"combobox\" aria-expanded=\"false\" aria-haspopup=\"listbox\"\n              aria-owns=\"autosuggest-autosuggest__results\">\n              <input type=\"text\" autocomplete=\"off\" aria-autocomplete=\"list\" id=\"searchTerm\"\n                aria-controls=\"autosuggest-autosuggest__results\"\n                placeholder=\"${PLACEHOLDERS.searchFor}...\" autofocus=\"autofocus\">\n            </div>\n            <div id=\"autosuggest-autosuggest__results\" class=\"autosuggest__results-container\">\n              <div aria-labelledby=\"autosuggest\" class=\"autosuggest__results\"> \n                <ul role=\"listbox\"></ul>\n              </div>\n            </div>\n          </div>\n          <span>\n            <button type=\"submit\" class=\"btn text-primary search-close-button\">\n              <span class=\"fa fa-search search-icon\"></span>\n            </button>\n          </span>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <div class=\"search-results-summary-options-wrapper\">\n    <div id=\"searchResultSummarySection\"></div>\n    <div id=\"searchOptionsSection\" class=\"hide\">\n      <div class=\"sf-filter-actions-wrapper\">\n        <div class=\"ml-auto sf-filter-actions-custom\">\n          <div class=\"form-inline justify-content-end\">\n            <label for=\"sort-by\" class=\"ml-4 mr-2\">${PLACEHOLDERS.sortBy}</label>\n            <select id=\"order-by\" class=\"custom-select-searchstudio-js\">\n              <option value=\"BEST_MATCH\">${relevance}</option>\n              <option value=\"PUBLISH_DATE_DESC\">${newest}</option>\n              <option value=\"PUBLISH_DATE_ASC\">${oldest}</option>\n            </select>\n          </div>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <div class=\"search-results-wrapper\">\n    <div class=\"facet-container-wrapper\">\n      <div id=\"searchFacetSection\" class=\"facet-wrapper facet-container-holder\"></div>\n    </div>\n    <div class=\"result-container-wrapper\">\n      <div id=\"searchResultsSection\"></div>\n      <div id=\"paginationSection\">\n        <div class=\"search-pagination-container\">\n          <ul class=\"pagination\">\n            <li class=\"page-item\">\n              <a variant=\"outline-primary\" class=\"page-link-searchstudio-js prev\"> &lt; ${PLACEHOLDERS.previous} </a>\n            </li>\n            <li class=\"page-item\">\n              <span class=\"page-link-searchstudio-js page-number\"><strong class=\"page-range\">1 — 25 </strong> of <strong class=\"count\">113</strong></span>\n            </li>\n            <li class=\"page-item\">\n              <a variant=\"outline-primary\" class=\"page-link-searchstudio-js next\">  ${PLACEHOLDERS.next}  &gt; </a>\n            </li>\n          </ul>\n        </div>\n      </div>\n    </div>\n  </div>\n`;\n};\n\nexport const getNoResultsTemplate = ({ noResults, refine }) => `\n  <div class=\"search-feedback-filters-wrapper\">\n    <div class=\"search-feedback-filters-custom\">\n      <div class=\"sf-filter-info-custom\">\n        <span class=\"no-result-msg\">${noResults}</span>\n        <br />\n        <span class=\"no-result-msg2\">${refine}</span>\n      </div>\n    </div>\n  </div>\n`;\n\nconst addEmTag = (text, value) => {\n  const words = text.split(' ');\n  const result = words.map((word) => (word.toLowerCase() === value.toLowerCase() ? `<em>${word}</em>` : word));\n  return result.join(' ');\n};\n\nexport const getResultsItemsTemplate = ({ items, queryTerm }) => {\n  let result = '';\n  items.forEach((item) => {\n    const { description, title, url } = item.metadata;\n    const emDescription = description ? addEmTag(description, queryTerm) : '';\n    const emTitle = title ? addEmTag(title, queryTerm) : '';\n    result += `\n      <div class=\"list-wrapper\">\n        <div class=\"card-searchstudio-js-custom\">\n          <div class=\"card-searchstudio-jsClass\">\n            <div class=\"card-searchstudio-js-body p-0\">\n              <div class=\"card-searchstudio-js-title\">\n                <a href=\"${url}\" target=\"_blank\" class=\"stretched-link\">\n                  <h4>${emTitle}</h4>\n                </a>\n              </div>\n              <div class=\"card-searchstudio-js-body p-0\">\n                <div class=\"card-searchstudio-js-text article_promo_short_overview_t\">\n                  <p class=\"Find\">${emDescription}</p>\n                </div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </div>\n    `;\n  });\n  return `\n    <div id=\"searchContainer\">\n      <div class=\"container\">\n        <div class=\"result-edit\">\n          <div class=\"sf-lists active layout-list\">\n            <div class=\"row reset-row\">\n              <div class=\"sf-list w-100 p-0 d-flex flex-wrap position-relative\">\n                ${result}\n              </div>\n            </div>\n          </div>\n        </div>\n      </div>\n    </div>\n  `;\n};\n\nexport const getShowingResultsTemplate = (text) => `\n  <div class=\"search-feedback-filters-wrapper-container\">\n    <div class=\"search-feedback-filters-wrapper\">\n      <div class=\"search-feedback-filters-custom align-items-center333\">\n        <div class=\"sf-filter-info\">\n          <span>${text}</span>\n        </div>\n      </div>\n    </div>\n  </div>\n`;\n\nconst sanitizeString = (string) => string.replaceAll(' ', '-');\n\nconst getItemsList = (items, filter) =>\n  items\n    .map((item, i) => {\n      const sanitizedValue = sanitizeString(item.value);\n      return `\n    <li ${i > 2 ? 'class=\"d-none\"' : ''}>\n      <input type=\"checkbox\" id=\"${sanitizedValue}\" data-filter=\"${filter}\" value=\"${item.value}\" />\n      <label for=\"${sanitizedValue}\" class=\"ml-1\">\n      <span class=\"facet-name\" title=\"${sanitizedValue}\"> ${item.value} </span> (${item.count}) </label>\n    </li>\n  `;\n    })\n    .join('');\n\nexport const getFacetsTemplate = (facets) => {\n  const [truck, topic, article, category] = facets;\n  const categoryItemsText = getItemsList(category.items, 'CATEGORY');\n  const articleItemsText = getItemsList(article.items, 'ARTICLE');\n  const topicItemsText = getItemsList(topic.items, 'TOPIC');\n  const truckItemsText = getItemsList(truck.items, 'TRUCK');\n\n  return `\n    <div class=\"facet-template-container-custom\">\n      <div class=\"pill-container\">\n        <div class=\"pill\">Filter By <span class=\"pill-close filter-by\"></span></div>\n      </div>\n      <div class=\"sidebar-background\"></div>\n      <div class=\"sf-sidebar-container\">\n        <div class=\"sf-mobile-header\">\n          <div class=\"sf-mobile-header-text\">Filter By</div>\n          <button type=\"button\" class=\"btn btn-custom text-primary search-close-button fa fa-close\">\n          </button>\n        </div>\n        <div class=\"sf-sidebar\">\n          <ul id=\"search-facets\" class=\"list-group accordion\">\n            <li class=\"list-group-item-searchstudio-js\">\n              <div id=\"collapse-topics\" data-parent=\"#search-facets\" class=\"collapse show\">\n                <ul class=\"list-unstyled\">\n                  <div id=\"ss-search-results\">\n                    <div class=\"filters\">\n                      <form id=\"facetsFilters\">\n                        ${\n                          category.items.length > 0\n                            ? `\n                        <div class=\"facet-list mb-4\">\n                          <h4 class=\"sidebar-heading\">\n                            <a href=\"#\" class=\"text-uppercase active\">Page Categories </a>\n                          </h4>\n                          <div class=\"collapse show\">\n                            <ul class=\"list-unstyled pl-3\">\n                              ${categoryItemsText}\n                            </ul>\n                            ${\n                              category.items.length > 3\n                                ? `\n                            <div class=\"more-less\">\n                              <a href=\"#\">More</a>\n                            </div>`\n                                : ''\n                            }\n                          </div>\n                        </div>`\n                            : ''\n                        }\n                        ${\n                          article.items.length > 0\n                            ? `\n                        <div class=\"facet-list mb-4\">\n                          <h4 class=\"sidebar-heading\">\n                            <a href=\"#\" class=\"text-uppercase active\">Article Categories </a>\n                          </h4>\n                          <div class=\"collapse show\">\n                            <ul class=\"list-unstyled pl-3\">\n                              ${articleItemsText}\n                            </ul>\n                            ${\n                              article.items.length > 3\n                                ? `\n                            <div class=\"more-less\">\n                              <a href=\"#\">More</a>\n                            </div>`\n                                : ''\n                            }\n                          </div>\n                        </div>`\n                            : ''\n                        }\n                        ${\n                          topic.items.length > 0\n                            ? `\n                        <div class=\"facet-list mb-4\">\n                          <h4 class=\"sidebar-heading\">\n                            <a href=\"#\" class=\"text-uppercase active\">Topics </a>\n                          </h4>\n                          <div class=\"collapse show\">\n                            <ul class=\"list-unstyled pl-3\">\n                              ${topicItemsText}\n                            </ul>\n                            ${\n                              topic.items.length > 3\n                                ? `\n                            <div class=\"more-less\">\n                              <a href=\"#\">More</a>\n                            </div>`\n                                : ''\n                            }\n                          </div>\n                        </div>`\n                            : ''\n                        }\n                        ${\n                          truck.items.length > 0\n                            ? `\n                        <div class=\"facet-list mb-4\">\n                          <h4 class=\"sidebar-heading\">\n                            <a href=\"#\" class=\"text-uppercase active\">Trucks </a>\n                          </h4>\n                          <div class=\"collapse show\">\n                            <ul class=\"list-unstyled pl-3\">\n                              ${truckItemsText}\n                            </ul>\n                            ${\n                              truck.items.length > 3\n                                ? `\n                            <div class=\"more-less\">\n                              <a href=\"#\">More</a>\n                            </div>`\n                                : ''\n                            }\n                          </div>\n                        </div>`\n                            : ''\n                        }\n                      </form>\n                    </div>\n                  </div>\n                </ul>\n              </div>\n            </li>\n          </ul>\n          <button type=\"button\" class=\"btn btn-custom close-button\">Done</button>\n        </div>\n      </div>\n    </div>\n  `;\n};\n","import { createElement } from '../../scripts/common.js';\n\nconst buildLinkAndList = (block) => {\n  const specsTitle = block.querySelector('h3');\n  const subtitles = block.querySelectorAll('p');\n  const uls = block.querySelectorAll('ul');\n  const lis = block.querySelectorAll('li');\n\n  lis.forEach((li) => {\n    if (li.textContent.length === 0) {\n      li.remove();\n    }\n  });\n  uls.forEach((ul) => {\n    ul.classList.add('link-and-list');\n  });\n\n  const specsSection = createElement('div', { classes: 'specs-section' });\n  const specsHeading = createElement('div', { classes: 'specs-heading' });\n  const specsList = createElement('ul', { classes: 'specs-list' });\n\n  for (let idx = 0; idx < subtitles.length; idx += 1) {\n    const item = createElement('li', { classes: ['specs-item', `specs-item-${idx + 1}`] });\n    const link = subtitles[idx].querySelector('a');\n\n    if (link) {\n      link.classList.remove('button', 'primary');\n      link.classList.add('specs-link');\n      item.append(link);\n    } else {\n      item.append(subtitles[idx]);\n    }\n    item.append(uls[idx]);\n    specsList.append(item);\n  }\n  specsHeading.append(specsTitle);\n  specsSection.append(specsHeading, specsList);\n\n  block.textContent = '';\n  block.append(specsSection);\n};\n\nconst buildDefaultSpecs = (block) => {\n  const children = [...block.children];\n  const ulElements = [...block.querySelectorAll('ul')];\n\n  const specsTitle = children.shift().querySelector('h3');\n\n  const specsSection = createElement('div', { classes: 'specs-section' });\n  const specsHeading = createElement('div', { classes: 'specs-heading' });\n  const specsList = createElement('ul', { classes: 'specs-list' });\n\n  if (ulElements.length === 1) {\n    const liElements = [...ulElements[0].querySelectorAll('li')];\n\n    liElements.forEach((e, idx) => {\n      const item = createElement('li', { classes: ['specs-item', `specs-item-${idx + 1}`] });\n      const text = createElement('p', { classes: 'p-element' });\n      const isStrong = e.querySelector('strong');\n      const link = e.querySelector('a');\n\n      if (link) {\n        link.classList.remove('button', 'primary');\n        link.classList.add('specs-link');\n        item.append(link);\n      } else {\n        text.append(isStrong ?? e.innerText);\n        item.append(text);\n      }\n      const extraArrowSpan = item.querySelector('span');\n      if (extraArrowSpan) {\n        extraArrowSpan.remove();\n      }\n      specsList.append(item);\n    });\n  } else if (ulElements.length > 1) {\n    specsList.classList.add('specs-list-multiple');\n\n    ulElements.forEach((e, idx) => {\n      const item = createElement('li', { classes: ['specs-item', `specs-item-${idx + 1}`] });\n\n      const subtitle = e.parentNode.querySelector('p');\n      subtitle.classList.add('specs-item-subtitle');\n      if (idx <= 2) {\n        item.append(subtitle);\n      }\n\n      const liElements = [...e.querySelectorAll('li')];\n      const features = createElement('div', { classes: 'feature-list' });\n\n      liElements.forEach((feature) => {\n        const text = createElement('p', { classes: 'p-element' });\n        const isStrong = feature.querySelector('strong');\n\n        text.append(isStrong ?? feature.innerText);\n        features.append(text);\n      });\n      item.append(features);\n      specsList.append(item);\n    });\n  } else {\n    children.forEach((e, idx) => {\n      const item = createElement('li', { classes: ['specs-item', `specs-item-${idx + 1}`, 'specs-item-with-image'] });\n\n      const pElements = [...e.querySelectorAll('p')];\n      const picture = e.querySelector('picture');\n      const [subtitle, content] = pElements;\n\n      if (!subtitle || !content) {\n        const singleText = e.innerText;\n        const text = createElement('p', { classes: 'single-text' });\n        const strongTag = createElement('strong', { classes: 'single-text' });\n        strongTag.innerText = singleText;\n        text.append(strongTag);\n        item.append(text);\n      } else {\n        if (picture) {\n          item.append(picture);\n        }\n        const link = e.querySelector('a');\n        if (link) {\n          link.classList.remove('button', 'primary');\n          link.classList.add('specs-link');\n          item.append(subtitle, link);\n        } else {\n          item.append(subtitle, content);\n        }\n      }\n      specsList.append(item);\n    });\n  }\n  specsHeading.append(specsTitle);\n  specsSection.append(specsHeading, specsList);\n\n  block.textContent = '';\n  block.append(specsSection);\n};\n\nexport default function decorate(block) {\n  const typeDetector = [...block.classList];\n  if (typeDetector.includes('link-and-list')) {\n    buildLinkAndList(block);\n  } else {\n    buildDefaultSpecs(block);\n  }\n}\n","import { decorateButtons, getAllElWithChildren } from '../../scripts/scripts.js';\nimport { createElement, getTextLabel, MAGAZINE_CONFIGS } from '../../scripts/common.js';\n\nconst MQ = window.matchMedia('(min-width: 1140px)');\nconst subscribeText = getTextLabel('sub_nav:subscribe_button_text');\nconst overviewText = getTextLabel('sub_nav:overview_text');\nlet fullHeight = 0;\n\nfunction toggleHeightList(ul) {\n  const isOpen = ul.classList.contains('open');\n  if (ul.offsetHeight >= fullHeight) {\n    fullHeight = ul.offsetHeight;\n  }\n  ul.style.maxHeight = `${isOpen ? fullHeight : 0}px`;\n}\n\nfunction setDefaultHeight(ul) {\n  fullHeight = ul.offsetHeight;\n  ul.style.maxHeight = 0;\n}\n\nfunction setOverviewUrl(ref, currentUrl) {\n  const subNavPath = ref.replace('sub-nav', '');\n  const subNavUrl = new URL(currentUrl);\n  subNavUrl.pathname = subNavPath;\n  return subNavPath.pathname === currentUrl.pathname ? currentUrl.href : subNavUrl.href;\n}\n\nasync function createSubNav(block, ref) {\n  const resp = await fetch(`${ref}.plain.html`);\n  if (!resp.ok) {\n    return;\n  }\n  const currentUrl = new URL(window.location);\n  const { pathname } = currentUrl;\n  const overviewUrl = setOverviewUrl(ref, currentUrl);\n  const text = await resp.text();\n  const fragment = document.createRange().createContextualFragment(text);\n  const title = fragment.querySelector('p');\n  const textUl = fragment.querySelector('ul');\n  const subNavWrapper = createElement('div', { classes: 'sub-nav-container' });\n  const ul = textUl || createElement('ul');\n  const buttons = getAllElWithChildren(fragment.querySelectorAll('p'), 'em, strong');\n  const ctasWrapper = buttons.length > 0 && createElement('li', { classes: 'sub-nav-cta-wrapper' });\n  // add a caret arrow for mobile version\n  const caretIcon = createElement('div', { classes: ['fa', 'fa-caret-down', 'icon'] });\n\n  if (textUl) {\n    const overview = createElement('li');\n    const overviewLink = createElement('a', { props: { href: overviewUrl } });\n    // set the active link, if is not found then use overview as default\n    const activeLink = [...ul.querySelectorAll('li a')].find((a) => new URL(a.href).pathname === pathname);\n    const activeLi = activeLink ? activeLink.closest('li') : overview;\n    activeLi.className = 'active';\n    overviewLink.textContent = overviewText;\n    overview.appendChild(overviewLink);\n    ul.prepend(overview);\n  }\n  title.className = 'sub-nav-title';\n  if (ctasWrapper) {\n    buttons.forEach((btn) => {\n      ctasWrapper.appendChild(btn);\n    });\n    ul.appendChild(ctasWrapper);\n    decorateButtons(ctasWrapper);\n  }\n  subNavWrapper.append(caretIcon, title, ul);\n  block.appendChild(subNavWrapper);\n  if (!MQ.matches) {\n    setDefaultHeight(ul);\n  }\n\n  window.onresize = () => {\n    const isDesktop = MQ.matches;\n    if (isDesktop) {\n      caretIcon.classList.remove('fa-caret-up');\n      ul.classList.remove('open');\n      ul.style.maxHeight = null;\n    } else if (ul.style.maxHeight === '') {\n      setDefaultHeight(ul);\n    }\n  };\n\n  caretIcon.onclick = () => {\n    caretIcon.classList.toggle('fa-caret-up');\n    ul.classList.toggle('open');\n    toggleHeightList(ul);\n  };\n}\n\nfunction toggleListMagazine(el) {\n  el.classList.toggle('open');\n}\n\nasync function buildMagazineSubNav(block, ref) {\n  const resp = await fetch(`${ref}.plain.html`);\n  if (!resp.ok) {\n    return;\n  }\n  const subscribeSection = document.querySelector('[data-form-type=\"Subscribe-magazine\"]');\n  const isSubscribeEnabled = !!MAGAZINE_CONFIGS.HREF && !!subscribeSection;\n  const text = await resp.text();\n  const fragment = document.createRange().createContextualFragment(text);\n  const mainTitleImgWrapper = fragment.querySelector('div');\n  // bar main section\n  const mainTitleImg = mainTitleImgWrapper.querySelector('picture');\n  const mainTitleLink = mainTitleImgWrapper.querySelector('a');\n  const subNavContainer = createElement('div', { classes: 'sub-nav-container' });\n  const subNavTitle = createElement('p', { classes: 'sub-nav-title' });\n  const mainSubNav = createElement('div', { classes: 'sub-nav-content' });\n  // add (hamburger menu)/(down arrow) to open close the sub-nav-list\n  const iconClass = MQ.matches ? 'fa-bars' : 'fa-caret-down';\n  const listIcon = createElement('div', { classes: ['fa', iconClass, 'icon'] });\n  // hamburger dropdown: list section overlay\n  const closeBtn = createElement('div', { classes: ['fa', 'fa-close', 'icon'] });\n  const listContainer = createElement('div', { classes: 'sub-nav-list-container' });\n  const listWrapper = getAllElWithChildren(fragment.querySelectorAll('div'), 'ul')[0];\n  const dogIconWrapper = getAllElWithChildren(listWrapper.querySelectorAll('p'), 'picture')[0];\n  const mainList = listWrapper.querySelector('ul');\n  const innerList = mainList.querySelector('ul');\n  const elementsToAppend = [listIcon, mainSubNav, listContainer];\n  listWrapper.className = 'sub-nav-list-wrapper';\n  dogIconWrapper.className = 'sub-nav-list-icon';\n  mainList.className = 'sub-nav-list main';\n  innerList.className = 'sub-nav-list inner';\n  listWrapper.appendChild(closeBtn);\n\n  if (isSubscribeEnabled) {\n    // add a cta button to open a form (subscribe to bulldog) in the dropdown list\n    const listSubscribeBtnContainer = createElement('div', { classes: 'list-button-container' });\n    const listSubscribeBtn = createElement('button', {\n      classes: ['magazine-subscribe-button', 'list-subscribe-button'],\n      props: { type: 'button' },\n    });\n    const supR = createElement('sup');\n    listSubscribeBtn.textContent = subscribeText;\n    supR.textContent = '®';\n    listSubscribeBtn.appendChild(supR);\n    listSubscribeBtnContainer.appendChild(listSubscribeBtn);\n    listContainer.append(listWrapper, listSubscribeBtnContainer);\n  } else {\n    listContainer.appendChild(listWrapper);\n  }\n\n  mainList.nextElementSibling.remove();\n\n  // adding it to the block\n  mainTitleLink.textContent = '';\n  mainTitleLink.title = mainTitleImg.lastElementChild.alt;\n  mainTitleLink.appendChild(mainTitleImg);\n  subNavTitle.appendChild(mainTitleLink);\n  mainSubNav.appendChild(subNavTitle);\n\n  if (isSubscribeEnabled) {\n    // add a cta button to open a form (subscribe to bulldog)\n    const subscribeBtnContainer = createElement('div', { classes: 'button-container' });\n    const subscribeBtn = createElement('button', {\n      classes: ['magazine-subscribe-button', 'button-container'],\n      props: { type: 'button' },\n    });\n    subscribeBtn.textContent = subscribeText;\n    subscribeBtnContainer.appendChild(subscribeBtn);\n    elementsToAppend.push(subscribeBtnContainer);\n  }\n\n  subNavContainer.append(...elementsToAppend);\n  block.appendChild(subNavContainer);\n\n  const allSubscribeButtons = document.querySelectorAll('.magazine-subscribe-button');\n  allSubscribeButtons.forEach((btn) => {\n    btn.addEventListener('click', () => {\n      if (subscribeSection) {\n        subscribeSection.scrollIntoView({ block: 'start', behavior: 'smooth' });\n      } else if (MAGAZINE_CONFIGS.HREF) {\n        window.location.href = MAGAZINE_CONFIGS.HREF;\n      }\n    });\n  });\n\n  window.onresize = () => {\n    const isDesktop = MQ.matches;\n    listIcon.classList.toggle('fa-bars', isDesktop);\n    listIcon.classList.toggle('fa-caret-down', !isDesktop);\n  };\n\n  listIcon.onclick = () => {\n    toggleListMagazine(listContainer);\n  };\n\n  closeBtn.onclick = () => {\n    toggleListMagazine(listContainer);\n  };\n}\n\nexport default async function decorate(block) {\n  const { content } = document.head.querySelector('meta[name=\"sub-navigation\"]');\n  if (content.includes('magazine')) {\n    block.classList.add('magazine');\n    buildMagazineSubNav(block, content);\n    return;\n  }\n  createSubNav(block, content);\n}\n","import { createElement } from '../../scripts/common.js';\n\nexport default async function decorate(block) {\n  const headings = block.querySelectorAll('table h1, table h2, table h3, table h4, table h5, table h6');\n\n  headings.forEach((heading) => {\n    // unifing headings\n    const newHeading = createElement('h5', { classes: 'table-cell-heading' });\n    newHeading.innerHTML = heading.innerHTML;\n    heading.replaceWith(newHeading);\n    newHeading.closest('tr')?.classList.add('table-heading');\n  });\n\n  const isRowHeader = block.classList.contains('row-header');\n  if (isRowHeader) {\n    const firstColumn = block.querySelectorAll('table td:first-child');\n    firstColumn.forEach((cell) => {\n      const newP = createElement('p');\n      newP.textContent = cell.querySelector('strong').textContent;\n      cell.replaceChild(newP, cell.querySelector('strong'));\n      cell.addEventListener('click', () => {\n        cell.classList.toggle('open');\n        cell.nextElementSibling.classList.toggle('open');\n      });\n    });\n  }\n\n  return block;\n}\n","export default function decorate(block) {\n  const tabsItems = block.querySelectorAll(':scope > div');\n  // makes the 1st tab by default as the active one...\n  tabsItems.forEach((el, i) => {\n    el.className = i > 0 ? `tabs-tab-item${i === 1 ? ' active' : ''}` : 'tabs-tab-titles';\n  });\n  const tabTitles = block.querySelector('.tabs-tab-titles ul');\n  const items = block.querySelectorAll('.tabs-tab-item');\n  // ... also for the 1st tab-title\n  const defaultActive = tabTitles.firstElementChild;\n  defaultActive.className = 'active';\n  // make tab-titles focusable\n  [...tabTitles.children].forEach((li) => {\n    li.tabIndex = 0;\n  });\n  // add picture & text wrappers a css class\n  [...items].forEach((item) => {\n    const picture = item.querySelector('picture');\n    const p = item.querySelector('p');\n    picture.parentElement.className = 'tab-picture-wrapper';\n    p.parentElement.className = 'tab-text-wrapper';\n  });\n\n  const setActiveTab = (e) => {\n    if (e.target.localName !== 'li') {\n      return;\n    }\n    const { parentElement } = e.target;\n    const idx = [...parentElement.children].indexOf(e.target);\n    [...parentElement.children].forEach((li, i) => {\n      li.className = '';\n      items[i].classList.remove('active');\n    });\n    e.target.className = 'active';\n    items[idx].classList.add('active');\n  };\n\n  tabTitles.onclick = (e) => setActiveTab(e);\n  tabTitles.onkeydown = (e) => {\n    if (e.key === 'Enter') {\n      setActiveTab(e);\n    }\n  };\n}\n","import { createElement } from '../../scripts/common.js';\n\nexport default function decorate(block) {\n  block.querySelectorAll(':scope > div').forEach((row) => row.classList.add('row'));\n  block.querySelectorAll(':scope > div > div').forEach((cell) => {\n    cell.classList.add('teaser-column');\n\n    if (cell.querySelector('picture')) {\n      cell.classList.add('text-on-image-column');\n    } else {\n      const textCol = createElement('div', { classes: ['text-wrapper'] });\n      textCol.innerHTML = cell.innerHTML;\n      cell.innerHTML = '';\n      cell.appendChild(textCol);\n    }\n  });\n\n  // unwrap picture so that text styles are not applied to this paragraphs\n  block.querySelectorAll('picture').forEach((picture) => picture.closest('p').replaceWith(picture));\n}\n","import { createElement } from '../../scripts/common.js';\n\nexport default function decorate(block) {\n  const children = [...block.children];\n\n  const teaserGridList = createElement('ul', { classes: 'teaser-grid-list' });\n\n  children.forEach((e, idx) => {\n    const teaserGridItem = createElement('li', { classes: ['teaser-grid-item', `teaser-grid-item-${idx + 1}`] });\n\n    const image = e.querySelector('picture').innerHTML;\n    const linkUrl = e.querySelector('a').getAttribute('href');\n    const texts = e.querySelectorAll('li');\n\n    const buttonText = texts[0].innerText;\n    const title = texts[1].innerText;\n    const subtitle = `${texts[2].innerText} >`;\n\n    let categoriesUrl = buttonText.replaceAll(' ', '-').toLowerCase();\n    categoriesUrl = `${window.location.href}categories/${categoriesUrl}`;\n\n    teaserGridItem.innerHTML = `\n        <div class='teaser-card'>\n          <picture class='teaser-image'>\n            ${image}\n          </picture>\n          <div class='teaser-card-content'>\n            <a class='teaser-button teaser-button-${idx + 1}' href=${categoriesUrl}>\n              ${buttonText}\n            </a>\n            <a class='teaser-link' href=${linkUrl}>\n              <h3 class='teaser-title'>\n                ${title}\n              </h3>\n              <h4 class='teaser-subtitle'>\n                ${subtitle}\n              </h4>\n            </a>\n          </div>\n        </div>\n        `;\n    teaserGridList.append(teaserGridItem);\n  });\n\n  block.textContent = '';\n  block.append(teaserGridList);\n}\n","import { createElement, decorateIcons, variantsClassesToBEM } from '../../scripts/common.js';\n\nconst CLASSES = {\n  blockName: 'v2-accordion-column',\n  left: 'left',\n};\n\nconst { blockName, left } = CLASSES;\nconst variants = Object.values(CLASSES).splice(1);\n\nconst addAccordionClass = (item) => {\n  const hasPicture = item.querySelector('picture');\n  if (hasPicture) {\n    item.classList.add(`${blockName}__item-image`);\n  } else {\n    const header = item.querySelector(':is(h1, h2, h3, h4, h5, h6)');\n    if (header) {\n      header.classList.add(`${blockName}__item-title`);\n    }\n    item.classList.add(`${blockName}__item-description`);\n  }\n};\n\nexport default function decorate(block) {\n  const accordionItems = [...block.querySelectorAll(':scope > div')];\n  const accordionContainer = createElement('div', { classes: `${blockName}__accordion-container` });\n  const itemsContainer = createElement('div', { classes: `${blockName}__items-container` });\n  const hasLeftClass = block.classList.contains(left); // accordion at left side\n  /** @type {boolean} */\n  const isLeftVariant = hasLeftClass || (!hasLeftClass && !!accordionItems[0].lastElementChild.querySelector('picture'));\n  if (!hasLeftClass && isLeftVariant) {\n    block.classList.add(left);\n  }\n  variantsClassesToBEM(block.classList, variants, blockName);\n  block.parentElement.classList.add('full-width');\n\n  // is responsibility of the author to add the proper amount of images and text\n  accordionItems.forEach((item, i) => {\n    const buttons = [...block.querySelectorAll('.button-container')];\n    buttons.forEach((el) => {\n      el.classList.add(`${blockName}__button-container`);\n      [...el.querySelectorAll('a')].forEach((link) => {\n        if (link.classList.contains('button--primary') || link.classList.contains('button--secondary') || link.classList.contains('button--red')) {\n          link.classList.add('button--small');\n        } else {\n          link.classList.add('standalone-link', `${blockName}__button`);\n        }\n      });\n    });\n\n    const colBtnTitle = createElement('button', {\n      classes: `${blockName}__item-header-button`,\n      props: { type: 'button' },\n    });\n    const dropdownArrowIcon = createElement('span', { classes: [`${blockName}__icon`, 'icon', 'icon-dropdown-caret'] });\n    const colItems = [...item.querySelectorAll(':scope > div')];\n\n    // add the proper classes to each accordion item\n    item.classList.add(`${blockName}__item`);\n    if (i === 0) {\n      item.classList.add('active');\n    }\n    colItems.forEach((col) => addAccordionClass(col));\n    colBtnTitle.prepend(item.querySelector(`.${blockName}__item-title`), dropdownArrowIcon);\n    colBtnTitle.onclick = () => {\n      const active = accordionContainer.querySelector('.active');\n      if (active && active !== item) {\n        active.classList.remove('active');\n      }\n      item.classList.add('active');\n    };\n    item.prepend(colBtnTitle);\n    itemsContainer.appendChild(item);\n  });\n\n  accordionContainer.append(itemsContainer);\n\n  block.appendChild(accordionContainer);\n  decorateIcons(block);\n}\n","import { createElement, decorateIcons } from '../../scripts/common.js';\nimport fragmentBlock from '../fragment/fragment.js';\n\nconst blockName = 'v2-accordion';\n\nfunction isContentLinkedCheck(el, startsWithString) {\n  if ((el.children.length === 1 && el.children[0].tagName.toLowerCase() === 'p') || (el.children.length === 0 && el.textContent === el.innerHTML)) {\n    return el.textContent.startsWith(startsWithString);\n  }\n  return false;\n}\n\n/* Function checks if the content of the provided element is just a link to other doc */\nfunction isContentLink(el) {\n  return isContentLinkedCheck(el, '/');\n}\n\nfunction isContentInsideAnotherElement(el) {\n  return isContentLinkedCheck(el, '#id-');\n}\n\nfunction loaded(element, pointedContent, display) {\n  element.innerHTML = '';\n  element.append(pointedContent.parentElement);\n  pointedContent.parentElement.style.display = display;\n}\n\nexport default async function decorate(block) {\n  const section = block.closest('.section');\n  const hasAccordion = section?.classList.contains(`${blockName}-container`);\n  const rows = [...block.querySelectorAll(':scope > div')];\n  const accordionsPromises = rows.map(async (row) => {\n    const accordionHeader = row.querySelector(\n      ':scope > div > h1, :scope > div > h2, :scope > div > h3, :scope > div > h4, :scope > div > h5, :scope > div > h6',\n    );\n    accordionHeader?.classList.add(`${blockName}__title`);\n    const accordionContent = row.querySelector(':scope > div:nth-child(2)');\n\n    const headerButton = createElement('button', { classes: `${blockName}__button` });\n    const dropdownArrowIcon = hasAccordion ? createElement('span', { classes: [`${blockName}__icon`, 'icon', 'icon-dropdown-caret'] }) : null;\n\n    headerButton.append(accordionHeader);\n    if (dropdownArrowIcon) {\n      headerButton.append(dropdownArrowIcon);\n    }\n\n    const contentEl = createElement('div', { classes: [`${blockName}__content`, `${blockName}__content-close`] });\n\n    if (isContentLink(accordionContent)) {\n      await fragmentBlock(accordionContent);\n    }\n\n    contentEl.innerHTML = accordionContent.innerHTML;\n\n    if (isContentInsideAnotherElement(accordionContent)) {\n      const pointedContent = [...document.querySelectorAll(`.${accordionContent.textContent.substring(1)}`)].at(-1);\n      if (pointedContent) {\n        const prevDisplay = pointedContent.parentElement.style.display;\n        pointedContent.parentElement.style.display = 'none';\n\n        if (pointedContent.dataset.blockStatus === 'loaded') {\n          loaded(contentEl, pointedContent, prevDisplay);\n        } else {\n          // lets wait for loading of the content that we want to put inside the accordion\n          new MutationObserver((_, observer) => {\n            if (pointedContent.dataset.blockStatus === 'loaded') {\n              observer.disconnect();\n              loaded(contentEl, pointedContent, prevDisplay);\n            }\n          }).observe(pointedContent, { attributes: true });\n        }\n      }\n    }\n\n    const accordionEl = createElement('div', { classes: [`${blockName}__item`, ...(hasAccordion ? [`${blockName}__item-close`] : [])] });\n    accordionEl.append(headerButton);\n    accordionEl.append(contentEl);\n\n    if (hasAccordion) {\n      headerButton.addEventListener('click', () => {\n        accordionEl.classList.toggle(`${blockName}__item-close`);\n      });\n    }\n\n    decorateIcons(accordionEl);\n    return accordionEl;\n  });\n\n  block.innerHTML = '';\n  await Promise.allSettled(accordionsPromises);\n  accordionsPromises.forEach(async (acc) => {\n    const result = await acc;\n    block.append(result);\n  });\n  decorateIcons(block);\n}\n","import { createElement, getTextLabel } from '../../scripts/common.js';\n\n// Define break point/s\nconst blockName = 'v2-all-trucks';\n\nexport default function decorate(block) {\n  const truckElement = block.querySelectorAll(`.${blockName} > div`);\n  truckElement.forEach((div) => {\n    div.classList.add(`${blockName}__truck`);\n\n    const truckImageWrapper = block.querySelectorAll(`.${blockName}__truck > div:first-child`);\n    truckImageWrapper.forEach((imageWrapper) => {\n      imageWrapper.classList.add(`${blockName}__truck-image`);\n      const pictures = imageWrapper.querySelectorAll('picture');\n      const link = imageWrapper.querySelector('a');\n      link.text = '';\n      link.classList.remove('button', 'button--primary');\n      link.append(...pictures);\n      imageWrapper.innerHTML = '';\n      imageWrapper.append(link);\n    });\n\n    const truckInfoWrapper = block.querySelectorAll(`.${blockName}__truck> div:last-child`);\n    truckInfoWrapper.forEach((info) => {\n      info.classList.add(`${blockName}__truck-info`);\n    });\n  });\n\n  const trucksWrapper = document.querySelector(`.${blockName}-wrapper`);\n  trucksWrapper.classList.add('full-width');\n\n  const trucks = document.querySelectorAll(`.${blockName}__truck`);\n  const segmentList = document.querySelectorAll(`.${blockName}__truck > div > ul`);\n\n  // Add truck name to truck element class list\n  getTruckName();\n\n  // Create menu buttons from truck segments\n  const allSegmentNames = [getTextLabel('All Trucks')];\n  segmentList.forEach((ul) => {\n    ul.classList.add(`${blockName}__segment-list`);\n    const segmentListItems = ul.querySelectorAll('li');\n    const segmentNames = Array.from(segmentListItems).map((item) => {\n      const segmentName = item.textContent.trim().toLowerCase().replaceAll(' ', '-');\n      if (!allSegmentNames.includes(segmentName)) {\n        allSegmentNames.push(segmentName);\n      }\n      return segmentName;\n    });\n    const truck = ul.closest(`.${blockName}__truck`);\n    segmentNames.forEach((segment) => {\n      truck.classList.add(segment);\n    });\n  });\n\n  const dropdownWrapper = createElement('div', { classes: `${blockName}__dropdown` });\n  const selectedItemWrapper = createElement('div', { classes: `${blockName}__selected-item-wrapper` });\n  const selectedItem = createElement('div', { classes: `${blockName}__selected-item` });\n  const segmentNamesList = createElement('ul', { classes: `${blockName}__button-list` });\n\n  // Create a dropdown icon fragment\n  const dropdownArrowIcon = document.createRange().createContextualFragment(`<span class=\"${blockName}__svg-wrapper\">\n    <svg xmlns=\"http://www.w3.org/2000/svg\"><use href=\"#icons-sprite-dropdown-caret\"></use></svg>\n  </span>`);\n  selectedItemWrapper.append(selectedItem);\n  selectedItemWrapper.appendChild(...dropdownArrowIcon.children);\n\n  dropdownWrapper.append(selectedItemWrapper);\n  dropdownWrapper.append(segmentNamesList);\n  block.prepend(dropdownWrapper);\n  allSegmentNames.forEach((segment, index) => {\n    const li = createElement('li');\n    const filterButton = createElement('button', { classes: `${blockName}__segment-button` });\n    filterButton.textContent = segment;\n\n    if (index === 0) {\n      // Default selected item\n      filterButton.classList.add('active');\n      selectedItem.textContent = segment;\n    }\n\n    segmentNamesList.appendChild(li);\n    li.append(filterButton);\n\n    filterButton.addEventListener('click', () => {\n      const clickedSegment = filterButton.textContent.trim().toLowerCase();\n      selectedItem.textContent = clickedSegment;\n\n      trucks.forEach((truck) => {\n        const isAllTrucks = clickedSegment === getTextLabel('v2_all_trucks:all_trucks').trim().toLowerCase();\n        truck.style.display = truck.classList.contains(clickedSegment) || isAllTrucks ? 'flex' : 'none';\n        const isSelected = truck.style.display === 'flex';\n        truck.style.display = isSelected ? 'flex' : 'none';\n        truck.classList.toggle('selected-truck', isSelected);\n      });\n\n      const allTrucksRows = document.querySelectorAll(`.${blockName}__truck`);\n\n      allTrucksRows.forEach((truck) => {\n        if (truck.classList.contains('selected-truck')) {\n          truck.classList.remove('odd', 'even');\n\n          const selectedTrucks = document.querySelectorAll('.selected-truck');\n\n          selectedTrucks.forEach((selectedTruck, i) => {\n            if (i % 2 === 0) {\n              selectedTruck.classList.remove('even-row');\n              selectedTruck.classList.add('odd-row');\n            } else {\n              selectedTruck.classList.remove('odd-row');\n              selectedTruck.classList.add('even-row');\n            }\n          });\n        } else if (!truck.classList.contains('selected-truck')) {\n          truck.classList.remove('odd', 'even');\n        }\n      });\n    });\n  });\n\n  // Listener to toggle the dropdown (open / close)\n  document.addEventListener('click', (e) => {\n    if (e.target.closest(`.${blockName}__selected-item-wrapper`)) {\n      dropdownWrapper.classList.toggle(`${blockName}__dropdown--open`);\n    } else {\n      dropdownWrapper.classList.remove(`${blockName}__dropdown--open`);\n    }\n  });\n\n  function getActiveFilterButton() {\n    const AllFilterButtons = document.querySelectorAll(`.${blockName}__button-list .${blockName}__segment-button`);\n\n    AllFilterButtons.forEach((filterButton) => {\n      filterButton.addEventListener('click', (e) => {\n        AllFilterButtons.forEach((button) => {\n          if (button !== e.target) {\n            button.classList.remove('active');\n          } else if (button === e.target && !button.classList.contains('active')) {\n            e.target.classList.toggle('active');\n          }\n        });\n      });\n    });\n  }\n\n  getActiveFilterButton();\n}\n\nfunction getTruckName() {\n  const modelName = document.querySelectorAll(`.${blockName}__truck > div + div > h3`);\n  modelName.forEach((model) => {\n    const parentNodeElement = model.parentNode.parentNode;\n    parentNodeElement.classList.add(model.id);\n  });\n}\n","import { readBlockConfig } from '../../scripts/aem.js';\nimport { createElement, getTextLabel, variantsClassesToBEM, addTargetBlankToExternalLink } from '../../scripts/common.js';\n\nconst blockName = 'v2-breadcrumb';\nconst sectionStatus = 'data-section-status';\nconst breadcrumb = getTextLabel('v2_breadcrumbs:aria_label');\nconst homeText = {\n  home: getTextLabel('v2_breadcrumbs:home_text'),\n  ellipsis: '…', // unicode ellipsis\n};\nconst variantClasses = ['custom'];\n\nconst formatText = (str) => str.replace(/-/g, ' ').toLowerCase();\n\nconst getPadding = (elCompCSS) =>\n  parseInt(elCompCSS.getPropertyValue('padding-left'), 10) + parseInt(elCompCSS.getPropertyValue('padding-right'), 10);\n\nconst getCrumbsWidth = (block) => {\n  const crumbs = block.querySelectorAll(`.${blockName}__crumb-item`);\n  return [...crumbs].reduce((acc, item) => {\n    const itemCompCSS = window.getComputedStyle(item);\n    return acc + parseInt(itemCompCSS.getPropertyValue('width'), 10);\n  }, 0);\n};\n\nconst getBlockWidth = (block) => {\n  const computedCSS = window.getComputedStyle(block);\n  const blockWidth = parseInt(computedCSS.getPropertyValue('width'), 10);\n  const boxSizing = computedCSS.getPropertyValue('box-sizing');\n  const padding = boxSizing === 'border-box' ? getPadding(computedCSS) : 0;\n  return blockWidth - padding;\n};\n\nconst fitting = (block) => getCrumbsWidth(block) < getBlockWidth(block);\n\nconst hasFormattingTags = (element) => {\n  return element.querySelectorAll('em, strong, sup').length > 0;\n};\n\nconst generateCustomUrl = (block) => {\n  const allCrumbs = [];\n  block.querySelectorAll(':scope > div').forEach((row) => {\n    if (row.children) {\n      const cols = [...row.children];\n      if (cols[1]) {\n        const crumbEl = cols[0].children[0] || null;\n        const obj = {\n          element: crumbEl,\n          hasFormattingTags: crumbEl ? hasFormattingTags(crumbEl) : false,\n          key: cols[0].textContent,\n          value: row.children[1].textContent,\n        };\n\n        allCrumbs.push(obj);\n      }\n    }\n  });\n  const keyString = allCrumbs.map((obj) => obj.key).join('/');\n\n  return [keyString, allCrumbs];\n};\n\nexport default function decorate(block) {\n  variantsClassesToBEM(block.classList, variantClasses, blockName);\n  let url;\n  let customLinks;\n  const hasCustomClass = block.classList.contains(`${blockName}--custom`);\n\n  const cfg = readBlockConfig(block);\n  const hasPath = cfg && Object.hasOwn(cfg, 'path');\n\n  if (hasPath) {\n    url = cfg.path;\n  } else if (hasCustomClass) {\n    const [customPath, allCrumbs] = generateCustomUrl(block);\n    customLinks = allCrumbs;\n    url = customPath;\n  } else {\n    url = window.location.pathname;\n  }\n\n  const path = url.split('/').filter(Boolean);\n  const nav = createElement('nav', { classes: [`${blockName}__crumb-nav`] });\n  const ul = createElement('ul', { classes: [`${blockName}__crumb-list`] });\n\n  const crumbs = path\n    .map((_, i) => {\n      const liEl = createElement('li', { classes: [`${blockName}__crumb-item`] });\n      const crumbClasses = [`${blockName}__crumb`];\n      let content;\n      let crumbProps = {};\n\n      if (hasCustomClass) {\n        const linkData = customLinks[i];\n        if (!linkData) {\n          return null;\n        }\n        content = path[i];\n        crumbProps = { 'data-content': content };\n        if (i !== path.length - 1) {\n          crumbProps.href = linkData.value;\n        } else {\n          crumbClasses.push(`${blockName}__crumb--active`);\n          crumbProps['aria-current'] = 'page';\n        }\n        const crumb = createElement('a', { classes: crumbClasses, props: crumbProps });\n        addTargetBlankToExternalLink(crumb);\n        if (linkData.hasFormattingTags) {\n          crumb.append(...linkData.element.childNodes);\n        } else {\n          crumb.textContent = content;\n        }\n        liEl.append(crumb);\n      } else {\n        content = formatText(path[i]);\n        crumbProps = { 'data-content': content };\n        if (i !== path.length - 1) {\n          crumbProps.href = `/${path.slice(0, i + 1).join('/')}/`;\n        } else {\n          crumbClasses.push(`${blockName}__crumb--active`);\n          crumbProps['aria-current'] = 'page';\n        }\n        const crumb = createElement('a', { classes: crumbClasses, props: crumbProps });\n        crumb.textContent = content;\n        liEl.append(crumb);\n      }\n\n      return liEl;\n    })\n    .filter(Boolean);\n\n  const homeItem = createElement('li', { classes: [`${blockName}__crumb-item`] });\n  const homeEl = createElement('a', {\n    classes: [`${blockName}__crumb`, `${blockName}__crumb--home`],\n    props: { href: hasCustomClass ? `${customLinks[0].value}` : '/' },\n  });\n  addTargetBlankToExternalLink(homeEl);\n\n  homeEl.textContent = hasCustomClass ? `${customLinks[0].key}` : homeText.home;\n  homeItem.append(homeEl);\n  crumbs.unshift(homeItem);\n  if (hasCustomClass) {\n    crumbs.splice(1, 1);\n  }\n  ul.append(...crumbs);\n  nav.append(ul);\n  block.textContent = '';\n  block.append(nav);\n  block.parentElement.classList.add('full-width');\n  block.setAttribute('aria-label', breadcrumb);\n\n  const checkCrumbsFits = () => {\n    // 1st check if home fits, if not it become an ellipsis\n    if (!fitting(block) && crumbs.length > 2) {\n      homeEl.textContent = homeText.ellipsis;\n    }\n    // if still doesn't fit, remove active crumb\n    if (!fitting(block)) {\n      crumbs.at(-1).firstElementChild.textContent = '';\n      crumbs.at(-1).classList.add(`${blockName}__crumb-item--hidden`);\n    }\n    // if it still doesn't fit again, remove the crumbs from the middle\n    if (!fitting(block)) {\n      let i = 1;\n      while (i < crumbs.length - 2 && !fitting(block)) {\n        crumbs[i].firstElementChild.textContent = '';\n        crumbs[i].classList.add(`${blockName}__crumb-item--hidden`);\n        i += 1;\n      }\n    }\n  };\n\n  const rObserver = new ResizeObserver((entries) => {\n    entries.forEach((entry) => {\n      if (!entry.contentBoxSize) {\n        return;\n      }\n      // add again the content from each item and check if it fits again or not\n      homeEl.textContent = hasCustomClass ? `${customLinks[0].key}` : homeText.home;\n      crumbs.forEach((crumb, i) => {\n        const link = crumb.firstElementChild;\n        if (i > 0) {\n          crumb.classList.remove(`${blockName}__crumb-item--hidden`);\n\n          if (!hasFormattingTags(link)) {\n            link.textContent = link.dataset.content;\n          }\n        }\n      });\n      checkCrumbsFits();\n    });\n  });\n\n  const mObserver = new MutationObserver((mutations) => {\n    mutations.forEach((mutation) => {\n      // check if the attribute data-section-status has the value 'loaded'\n      if (mutation.attributeName !== sectionStatus) {\n        return;\n      }\n      const section = mutation.target;\n      const status = section.getAttribute(sectionStatus);\n      if (status !== 'loaded') {\n        return;\n      }\n      rObserver.observe(block);\n      mObserver.disconnect();\n    });\n  });\n  mObserver.observe(block.closest('.section'), {\n    childList: true,\n    attributeFilter: [sectionStatus],\n  });\n}\n","import { variantsClassesToBEM } from '../../scripts/common.js';\nimport { createVideo, isVideoLink } from '../../scripts/video-helper.js';\n\nconst blockName = 'v2-cards';\nconst variantClasses = [\n  'no-background',\n  'horizontal',\n  'image-aspect-ratio-7-5',\n  'large-heading',\n  '4-cards-row',\n  '2-cards-row',\n  'spaced',\n  'with-border',\n  'with-uncropped-image',\n];\n\nconst decoratePicture = (picture) => {\n  const imageEl = picture.querySelector('img');\n  picture.classList.add(`${blockName}__picture`);\n  picture.parentElement.classList.add(`${blockName}__media-wrapper`);\n  picture.parentElement.classList.remove(`${blockName}__text-wrapper`);\n  imageEl.classList.add(`${blockName}__image`);\n};\n\nconst processVideoLink = (card, link) => {\n  const videoWrapper = createVideo(link.href, `${blockName}__video-wrapper`, {\n    autoplay: true,\n    muted: true,\n    playsinline: true,\n    controls: false,\n    loop: true,\n  });\n  const videoEl = videoWrapper.querySelector('video');\n  card.classList.add(`${blockName}__media-wrapper`);\n  card.classList.remove(`${blockName}__text-wrapper`);\n  videoEl.classList.add(`${blockName}__video`);\n  videoEl.classList.remove(`${blockName}__video-wrapper`);\n  link.parentElement.replaceWith(videoWrapper);\n};\n\nconst decorateMedia = (block) => {\n  const cards = [...block.querySelectorAll(':scope > div > div:first-of-type')];\n  cards.forEach((card) => {\n    const pictureEl = card.querySelector(':scope > picture');\n    const links = [...card.querySelectorAll(':scope a')];\n    if (pictureEl) {\n      decoratePicture(pictureEl);\n    }\n    if (links.length) {\n      links.forEach((link) => {\n        if (isVideoLink(link)) {\n          processVideoLink(card, link);\n        }\n      });\n    }\n  });\n};\n\nexport default async function decorate(block) {\n  variantsClassesToBEM(block.classList, variantClasses, blockName);\n\n  const cardsItems = [...block.querySelectorAll(':scope > div')];\n  cardsItems.forEach((el) => el.classList.add(`${blockName}__card-item`));\n\n  const cardsSections = [...block.querySelectorAll(':scope > div > div')];\n  cardsSections.forEach((el) => {\n    el.classList.add(`${blockName}__text-wrapper`);\n  });\n\n  decorateMedia(block);\n\n  const cardsHeadings = [...block.querySelectorAll('h1, h2, h3, h4, h5, h6')];\n  cardsHeadings.forEach((el) => {\n    el.classList.add(`${blockName}__heading`);\n    if (el.querySelector('a')) {\n      block.classList.add(`${blockName}--heading-with-arrow`);\n    }\n  });\n\n  const buttons = [...block.querySelectorAll('.button-container')];\n  buttons.forEach((el) => {\n    el.classList.add(`${blockName}__button-container`);\n    [...el.querySelectorAll('a')].forEach((link) => {\n      if (link.classList.contains('button--primary') || link.classList.contains('button--secondary') || link.classList.contains('button--red')) {\n        link.classList.add('button--small');\n      } else {\n        link.classList.add('standalone-link', `${blockName}__button`);\n      }\n      if (block.classList.contains(`${blockName}--spaced`)) {\n        link.classList.replace('button--small', 'button--large');\n      }\n    });\n  });\n}\n","import { createElement, clearElementAttributes, decorateIcons, removeEmptyTags } from '../../scripts/common.js';\nimport { isVideoLink, createVideo } from '../../scripts/video-helper.js';\n\nconst blockName = 'v2-category-collage';\n\nconst CLASSES = {\n  itemContainer: `${blockName}__item-container`,\n  itemContent: `${blockName}__item-content`,\n  itemTitle: `${blockName}__item-title`,\n  itemCategoryTitle: `${blockName}__item-category-title`,\n  itemMedia: `${blockName}__item-media`,\n  itemLinkClass: `${blockName}__item-link`,\n};\n\nconst getItemTitleContainer = (item) => item.querySelector('div:nth-child(3)');\nconst getItemCategoryTitleContainer = (item) => item.querySelector('div:nth-child(2)');\nconst getItemLink = (item) => item.querySelector('div:nth-child(3) > a, div:nth-child(3) > p > a');\n\nconst arrowButtonElement = () => createElement('span', { classes: ['icon', 'icon-arrow-right'] });\n\nconst decorateImage = (itemLink, itemImage) => {\n  const hasImageContainer = itemImage.parentElement === itemLink;\n\n  if (!hasImageContainer) {\n    const imageContainer = itemImage.parentElement;\n    itemImage.classList.add(CLASSES.itemMedia);\n    itemLink.prepend(itemImage);\n    imageContainer.remove();\n  }\n\n  itemImage.setAttribute('tabindex', 0);\n};\n\nconst decorateVideo = async (itemLink) => {\n  const videoLink = itemLink.querySelector('a.text-link-with-video');\n\n  if (!videoLink || !isVideoLink(videoLink)) {\n    return;\n  }\n\n  const video = await createVideo(videoLink.getAttribute('href'), CLASSES.itemMedia, {\n    muted: true,\n    autoplay: true,\n    loop: true,\n    playsinline: true,\n    tabindex: 0,\n  });\n\n  itemLink.prepend(video);\n  videoLink.remove();\n};\n\nconst decorateMedia = (item, itemImage) => {\n  const itemLink = item.querySelector(`.${CLASSES.itemLinkClass}`);\n\n  if (itemImage) {\n    decorateImage(itemLink, itemImage);\n  } else {\n    decorateVideo(itemLink);\n  }\n};\n\nconst removeInnerLink = (link) => {\n  const text = link.parentElement;\n  const linkText = link.innerHTML;\n\n  text.innerHTML = linkText;\n};\n\nconst decorateNewItemContainer = (item, itemContainer, innerLink) => {\n  const { href = '', title = '' } = innerLink || {};\n  const newItemContainer = createElement('a', {\n    classes: CLASSES.itemLinkClass,\n    props: { href, title, tabindex: -1 },\n  });\n  const itemContent = createElement('div', {\n    classes: CLASSES.itemContent,\n  });\n  const itemCategoryTitleContainer = getItemCategoryTitleContainer(item);\n  const itemTitleContainer = getItemTitleContainer(item);\n\n  if (innerLink) {\n    removeInnerLink(innerLink);\n  }\n\n  item.classList.add(CLASSES.itemContainer);\n  clearElementAttributes(itemTitleContainer).classList.add(CLASSES.itemTitle);\n  clearElementAttributes(itemCategoryTitleContainer).classList.add(CLASSES.itemCategoryTitle);\n\n  itemTitleContainer.append(arrowButtonElement());\n\n  itemContent.append(itemCategoryTitleContainer);\n  itemContent.append(itemTitleContainer);\n\n  newItemContainer.innerHTML = itemContainer.innerHTML;\n  newItemContainer.prepend(itemContent);\n  itemContainer.remove();\n  item.append(newItemContainer);\n};\n\nconst decorateCollageItems = (items) => {\n  items.forEach((item) => {\n    const itemContainer = item.firstElementChild;\n    const itemLink = getItemLink(item);\n\n    decorateNewItemContainer(item, itemContainer, itemLink);\n    decorateMedia(item, item.querySelector('picture'));\n  });\n};\n\nexport default function decorate(block) {\n  const blockWrapper = block.parentElement;\n  const collageItemContainers = block.querySelectorAll(':scope > div');\n\n  blockWrapper.classList.add('full-width');\n\n  decorateCollageItems([...collageItemContainers]);\n  decorateIcons(block);\n  removeEmptyTags(block, true);\n}\n","import { createElement, variantsClassesToBEM, decorateBlackLabel } from '../../scripts/common.js';\nimport { createVideo, isVideoLink } from '../../scripts/video-helper.js';\n\nconst blockName = 'v2-columns';\n\nconst getLastTextElmts = (block) => {\n  const allTexts = block.querySelectorAll('p');\n  const linksTitle = allTexts[allTexts.length - 1];\n  linksTitle.classList.add('list-title');\n  return linksTitle;\n};\n\nconst retrieveVideoConfig = (block) => {\n  return {\n    autoplay: block.classList.contains('autoplay'),\n    muted: block.classList.contains('autoplay') || block.classList.contains('muted'),\n    loop: block.classList.contains('loop'),\n    controls: block.classList.contains('controls'),\n    disablePictureInPicture: block.classList.contains('disable-picture-in-picture'),\n  };\n};\n\nconst insertVideo = (block, videoAnchor, picture) => {\n  const img = picture?.querySelector('img');\n  const posterUrl = img ? new URL(img.getAttribute('src'), window.location.href).href : undefined;\n  const videoConfig = retrieveVideoConfig(block);\n  const videoElement = createVideo(\n    videoAnchor.getAttribute('href'),\n    `${blockName}__video`,\n    {\n      ...videoConfig,\n      fill: true,\n      language: document.documentElement.lang,\n      poster: posterUrl,\n    },\n    {\n      addMuteToggle: true,\n    },\n  );\n  const videoColumn = block.querySelector(`.${blockName}__column:last-of-type`);\n  videoColumn.className = `${blockName}__video-column`;\n  videoColumn.innerHTML = '';\n  videoColumn.append(videoElement);\n};\n\nexport default async function decorate(block) {\n  const blockParent = block.parentElement.parentElement;\n\n  const variantClasses = [\n    'with-background-image',\n    'background-plane',\n    'icon-list',\n    'navigation-links',\n    'inset',\n    'headline',\n    'video-launcher',\n    'with-dots',\n  ];\n  variantsClassesToBEM(block.classList, variantClasses, blockName);\n\n  const isBackgroundImageVariant = block.classList.contains(`${blockName}--with-background-image`);\n  const isIconListVariant = block.classList.contains(`${blockName}--icon-list`);\n  const is3LinksVariant = block.classList.contains(`${blockName}--navigation-links`);\n  const isListVariant = isIconListVariant || is3LinksVariant;\n  const hasHeader = blockParent.classList.contains('header-with-mark') || blockParent.classList.contains('header-no-mark');\n  const isHeadlineVariant = block.classList.contains(`${blockName}--headline`);\n  const isVideoLauncherVariant = block.classList.contains(`${blockName}--video-launcher`);\n\n  const rows = [...block.querySelectorAll(':scope > div')];\n  const columns = [...block.querySelectorAll(':scope > div > div')];\n\n  rows.forEach((row) => {\n    row.classList.add(`${blockName}__row`);\n  });\n\n  columns.forEach((col) => {\n    col.classList.add(`${blockName}__column`);\n\n    const picture = col.querySelector('picture');\n    const allTextElmts = col.querySelectorAll('p, ul, ol');\n    const bodyElmts = [];\n    const linkList = createElement('div', { classes: `${blockName}--links` });\n    const link = col.querySelector('a');\n    const videoAnchor = link && isVideoLink(link) ? link : null;\n\n    if (picture && !isVideoLauncherVariant) {\n      col.classList.add(`${blockName}__column--with-image`);\n    } else {\n      col.classList.add(`${blockName}__column--with-text`);\n    }\n\n    allTextElmts.forEach((e) => {\n      const nextElmt = e.nextElementSibling;\n\n      const isButton = [...e.classList].includes('button-container');\n      const isPretitle = nextElmt?.tagName.toLowerCase()[0] === 'h';\n      const hasLinkList = isListVariant && (e.tagName.toLowerCase() === 'ul' || e.tagName.toLowerCase() === 'ol');\n\n      if (hasLinkList) {\n        if (is3LinksVariant) {\n          linkList.append(getLastTextElmts(col));\n        }\n        linkList.append(e);\n      } else if (!isPretitle && !isButton) {\n        bodyElmts.push(e);\n      }\n    });\n    bodyElmts.forEach((e) => {\n      if (!e.classList.contains('list-title')) {\n        e.classList.add(`${blockName}__body`);\n      }\n    });\n\n    const buttons = [...col.querySelectorAll('.button-container a')];\n\n    if (isBackgroundImageVariant) {\n      blockParent.classList.add(`${blockName}-container--with-background-image`);\n      const btnSection = createElement('div', { classes: 'button-container' });\n\n      buttons.forEach((btn) => {\n        btn.classList.add('button--large');\n        const btnContainer = btn.closest('.button-container');\n        btnContainer.replaceWith(btn);\n        btnSection.append(btn);\n      });\n      if (!picture) {\n        col.append(btnSection);\n      }\n      if (isListVariant) {\n        linkList.querySelectorAll('a').forEach((e) => e.classList.add('standalone-link'));\n        col.append(linkList);\n      }\n\n      if (hasHeader) {\n        const defaultContent = blockParent.querySelector('.default-content-wrapper');\n\n        if (defaultContent) {\n          const header = [...defaultContent.querySelectorAll('h1, h2, h3, h4, h5, h6')];\n          header[0].classList.add(`${blockName}__body-header`, !blockParent.classList.contains('header-no-mark') && 'with-marker');\n          bodyElmts[0].insertAdjacentElement('beforebegin', header[0]);\n          defaultContent.remove();\n        }\n      }\n    } else {\n      buttons.forEach((btn) => {\n        btn.classList.add('button--large');\n      });\n    }\n\n    const headings = [...col.querySelectorAll('h1, h2, h3, h4, h5, h6')];\n\n    if (isHeadlineVariant) {\n      headings.forEach((heading) => heading.classList.add(`${blockName}__heading`, 'with-marker'));\n    } else {\n      headings.forEach((heading) => heading.classList.add(`${blockName}__heading`, 'h2'));\n    }\n\n    const prevEl = headings[0]?.previousElementSibling;\n    const pretitleText = prevEl && !prevEl.classList.contains('icon') && prevEl.textContent;\n\n    if (pretitleText) {\n      const pretitle = createElement('span', { classes: 'pretitle' });\n      pretitle.textContent = pretitleText;\n      prevEl.replaceWith(pretitle);\n    }\n\n    if (isVideoLauncherVariant && videoAnchor) {\n      insertVideo(block, videoAnchor, picture);\n    }\n  });\n\n  decorateBlackLabel(block);\n}\n","import { loadScript, sampleRUM } from '../../scripts/aem.js';\nimport { getTextLabel, createElement, variantsClassesToBEM, normalizeUrlText, isHttp, HOLIDAYS } from '../../scripts/common.js';\nimport { getCustomDropdown } from '../../common/custom-dropdown/custom-dropdown.js';\n\nconst blockName = 'v2-custom-form';\nconst variantClasses = ['double-column', 'redirect-new-tab'];\n\nconst CLASSES = {\n  IGNORE_ON_FORM_SUBMIT: 'ignore-on-form-submit',\n};\n\nconst successMessage = (successTitle, successText) => `<h3 class='${blockName}__title ${blockName}__title--success'>${successTitle}</h3>\n<p class='${blockName}__text ${blockName}__text--success'>${successText}</p>\n`;\n\nconst errorMessage = (errorTitle, errorText) => `<h3 class='${blockName}__title ${blockName}__title--error'>${errorTitle}</h3>\n<p class='${blockName}__text ${blockName}__text--error'>${errorText}</p>\n`;\n\nwindow.__activeForms = window.__activeForms || new Set();\n\n// BRAND SPECIFIC\nconst buttonClasses = ['button', 'button--primary'];\n\n/**\n * Get the message text from placeholder.json based on the success and title\n * @param {Boolean} isSuccess get the success message if true, otherwise the error message\n * @param {Boolean} isTitle get the title message if true, otherwise the text message\n * @returns {String} use the fn getTextLabel to get the message from placeholder.json\n */\nconst getMessageText = (isSuccess, isTitle) => {\n  const key = isSuccess ? 'successful' : 'error';\n  const type = isTitle ? 'title' : 'text';\n  return getTextLabel(`v2_custom_form:${key}_submission_${type}`);\n};\n\n// Form Block identifies the submit endpoint via these rules and in order\n// 1. action property on the submit button\n// 2. SUBMIT_ACTION constant\n// 3. the path of the spreadsheet\nconst SUBMIT_ACTION = '';\n\n/**\n * Fetch the custom message from the thank you page fragment\n * @param {String} url the url of the thank you page fragment\n * @returns {String} the custom message from the thank you page fragment\n */\nasync function getCustomMessage(url) {\n  try {\n    const resp = await fetch(url);\n    if (resp.ok) {\n      return resp.text();\n    }\n  } catch (error) {\n    console.error('Error fetching custom message:', error);\n    return errorMessage(getMessageText(false, true), getMessageText(false, false));\n  }\n  return '';\n}\n\nfunction throwFormNotFound(form) {\n  console.error('Form with data-submitting=true not found', { form });\n}\n\nfunction tryRedirect(form, redirectKey, { warnLabel = redirectKey, redirectNewTab = false } = {}) {\n  if (!form) {\n    return false;\n  }\n\n  const redirectValue = normalizeUrlText(form.dataset?.[redirectKey]);\n  if (!redirectValue || form.dataset.redirecting === 'true') {\n    return false;\n  }\n\n  try {\n    const resolvedUrl = new URL(redirectValue, window.location.href);\n    if (isHttp(resolvedUrl.protocol)) {\n      form.dataset.redirecting = 'true';\n\n      if (redirectNewTab) {\n        window.open(resolvedUrl.href, '_blank', 'noopener,noreferrer');\n      } else {\n        window.location.assign(resolvedUrl.href);\n      }\n      return true;\n    }\n  } catch {\n    console.warn(`Invalid ${warnLabel} URL`);\n  }\n  return false;\n}\n\nasync function submissionSuccess(form, redirectNewTab = false) {\n  sampleRUM('form:submit');\n\n  if (!form) {\n    throwFormNotFound(form);\n    return;\n  }\n\n  if (tryRedirect(form, 'successRedirect', { redirectNewTab })) {\n    window.__activeForms.delete(form);\n    return;\n  }\n\n  const successDiv = createElement('div', {\n    classes: [`${blockName}--message`, `${blockName}__message--success`],\n  });\n  successDiv.innerHTML = successMessage(getMessageText(true, true), getMessageText(true, false));\n\n  const customMessageUrl = form.dataset.customMessage;\n\n  if (customMessageUrl) {\n    successDiv.innerHTML = await getCustomMessage(customMessageUrl);\n  }\n  form.setAttribute('data-submitting', 'false');\n  form.replaceWith(successDiv);\n  window.__activeForms.delete(form);\n}\n\nasync function submissionFailure(form, redirectNewTab = false) {\n  if (!form) {\n    throwFormNotFound(form);\n    return;\n  }\n\n  if (tryRedirect(form, 'errorRedirect', { warnLabel: 'errorRedirect', redirectNewTab })) {\n    console.log('redirecting to errorRedirect');\n    window.__activeForms.delete(form);\n    return;\n  } else {\n    console.log('no errorRedirect found, showing error message');\n  }\n\n  const errorDiv = createElement('div', {\n    classes: [`${blockName}--message`, `${blockName}__message--error`],\n  });\n  errorDiv.innerHTML = errorMessage(getMessageText(false, true), getMessageText(false, false));\n\n  form.setAttribute('data-submitting', 'false');\n  form.querySelector('button[type=\"submit\"]').disabled = false;\n  form.replaceWith(errorDiv);\n  window.__activeForms.delete(form);\n}\n\nwindow.showResult = function showResult(json) {\n  const activeForms = Array.from(window.__activeForms);\n  const form = activeForms.reverse().find((f) => f.dataset.submitting === 'true');\n\n  if (!form) {\n    console.warn('showResult: no active submitting form found');\n    return;\n  }\n\n  const block = form.closest(`.${blockName}`);\n  const redirectNewTab = block?.classList.contains(`${blockName}--redirect-new-tab`) || false;\n\n  if (json.result === 'success') {\n    submissionSuccess(form, redirectNewTab);\n  } else if (json.result === 'error') {\n    submissionFailure(form, redirectNewTab);\n  }\n\n  window.__activeForms.delete(form);\n  form.dataset.submitting = 'false';\n};\n\nfunction serialize(obj) {\n  const str = Object.keys(obj).map((key) => `${encodeURIComponent(key)}=${encodeURIComponent(obj[key])}`);\n  return str.join('&');\n}\n\nfunction generateUnique() {\n  return new Date().valueOf() + Math.random();\n}\n\nfunction constructPayload(form) {\n  const payload = { __id__: generateUnique() };\n  [...form.elements].forEach((fe) => {\n    if (fe.name && !fe.classList.contains(CLASSES.IGNORE_ON_FORM_SUBMIT)) {\n      if (fe.type === 'radio' && fe.checked) {\n        payload[fe.name] = fe.value;\n      } else if (fe.type === 'checkbox' && fe.checked) {\n        payload[fe.name] = payload[fe.name] ? `${payload[fe.name]},${fe.value}` : fe.value;\n      } else if (fe.type === 'select-one' && fe.value.includes(':')) {\n        // Read only the value to be sent to the server\n        payload[fe.name] = fe.value.split(':')[0];\n      } else if (fe.type !== 'file' && fe.type !== 'checkbox' && fe.type !== 'radio') {\n        payload[fe.name] = fe.value;\n      }\n    }\n  });\n  payload.callback = 'showResult';\n  return { payload };\n}\n\nasync function prepareRequest(form) {\n  const { payload } = constructPayload(form);\n  const url = form.dataset.action;\n\n  const serializedData = serialize(payload);\n  loadScript(`${url}?${serializedData}`, { type: 'text/javascript', charset: 'UTF-8' });\n}\n\nasync function handleSubmit(form) {\n  if (form.getAttribute('data-submitting') !== 'true') {\n    form.setAttribute('data-submitting', 'true');\n    window.__activeForms.add(form);\n    await prepareRequest(form);\n  }\n}\n\nfunction setPlaceholder(element, fd) {\n  if (fd.Placeholder) {\n    element.setAttribute('placeholder', fd.Placeholder);\n  }\n}\n\nconst constraintsDef = Object.entries({\n  'email|text|textarea': [\n    ['Max', 'maxlength'],\n    ['Min', 'minlength'],\n    ['Pattern', 'pattern'],\n  ],\n  'number|range|date': ['Max', 'Min', 'Step'],\n  file: ['Accept', 'Multiple'],\n  fieldset: ['Max', 'Min'],\n}).flatMap(([types, constraintDef]) => types.split('|').map((type) => [type, constraintDef.map((cd) => (Array.isArray(cd) ? cd : [cd, cd]))]));\n\nconst constraintsObject = Object.fromEntries(constraintsDef);\n\nfunction setConstraints(element, fd) {\n  const constraints = constraintsObject[fd.Type];\n  if (constraints) {\n    constraints\n      .filter(([nm]) => fd[nm])\n      .forEach(([nm, htmlNm]) => {\n        element.setAttribute(htmlNm, htmlNm === 'pattern' ? fd[nm].replace(/^\\/|\\/$/g, '') : fd[nm]);\n      });\n  }\n}\n\nfunction createLabel(fd, tagName = 'label') {\n  const label = createElement(tagName, {\n    classes: 'field-label',\n    props: {\n      for: fd.Id,\n    },\n  });\n  if (fd.tooltip) {\n    label.title = fd.tooltip;\n  }\n  if (fd.Label) {\n    label.textContent = fd.Label;\n  }\n  return label;\n}\n\nfunction createHelpText(fd) {\n  const div = createElement('div', {\n    classes: 'field-description',\n    props: {\n      'aria-live': 'polite',\n      id: `${fd.Id}-description`,\n    },\n  });\n  div.textContent = fd.Description;\n  return div;\n}\n\nfunction kebabName(name) {\n  return name\n    .replace(/\\s+/g, '-')\n    .replace(/([a-z0-9])([A-Z])/g, '$1-$2')\n    .toLowerCase();\n}\n\nfunction createFieldWrapper(fd, tagName = 'div') {\n  const nameStyle = fd.Name ? `form-${kebabName(fd.Name)}` : '';\n  let props = {};\n\n  if (tagName !== 'div') {\n    props = {\n      id: fd.Id,\n      name: fd.Name,\n    };\n  }\n\n  const fieldWrapper = createElement(tagName, {\n    classes: [`form-${fd.Type}-wrapper`, 'field-wrapper'],\n    props,\n  });\n  if (fd.Mandatory && fd.Mandatory.toLowerCase() === 'true') {\n    fieldWrapper.setAttribute('required', 'required');\n  }\n  if (fd.Fieldset) {\n    fieldWrapper.dataset.fieldset = fd.Fieldset;\n  }\n  if (nameStyle) {\n    fieldWrapper.classList.add(nameStyle);\n  }\n  fieldWrapper.append(createLabel(fd));\n  return fieldWrapper;\n}\n\nfunction createButton(fd) {\n  const wrapper = createFieldWrapper(fd);\n  const button = createElement('button', {\n    classes: buttonClasses,\n    props: {\n      type: fd.Type,\n      id: fd.Id,\n      name: fd.Name,\n    },\n  });\n  if (fd.Type === 'submit' && fd.Action) {\n    button.formAction = fd.Action;\n  }\n  if (fd.Extra) {\n    button.dataset.redirect = fd.Extra;\n  }\n  button.textContent = fd.Label;\n  wrapper.replaceChildren(button);\n  return wrapper;\n}\n\nfunction createSubmit(fd) {\n  const wrapper = createButton(fd);\n  return wrapper;\n}\n\nfunction createInput(fd) {\n  const input = createElement('input', {\n    props: {\n      type: fd.Type,\n    },\n  });\n  setPlaceholder(input, fd);\n  setConstraints(input, fd);\n  return input;\n}\n\nfunction formatDate(date) {\n  return date.toISOString().split('T')[0];\n}\n\nfunction excelDateToISO(serial) {\n  // Excel's day 1 = 1900-01-01, but it wrongly counts 1900 as a leap year\n  const excelEpoch = new Date(Date.UTC(1899, 11, 30));\n  const jsDate = new Date(excelEpoch.getTime() + serial * 86400000);\n\n  return jsDate.toISOString().split('T')[0]; // returns YYYY-MM-DD\n}\n\nfunction createDateInput(fd) {\n  const input = createElement('input', {\n    props: {\n      type: fd.Type,\n    },\n  });\n  setPlaceholder(input, fd);\n  setConstraints(input, fd);\n\n  if (fd['Custom Options'] && fd['Custom Options'] !== '') {\n    try {\n      const customOptions = fd['Custom Options'];\n      const customOptionsObj = JSON.parse(customOptions.replace(/(\\w+):/g, '\"$1\":'));\n\n      if (customOptionsObj.ignoreNonWorkingDays && customOptionsObj.ignoreNonWorkingDays === true) {\n        // Implement logic to restrict date picker to working days only\n        input.addEventListener('input', (e) => {\n          const selectedDate = new Date(e.target.value);\n          const day = selectedDate.getUTCDay();\n\n          const holidayDates = Object.values(HOLIDAYS).map((date) => excelDateToISO(date));\n          const selectedDateISO = selectedDate.toISOString().split('T')[0];\n\n          // 0 = Sunday, 6 = Saturday\n          if (day === 0 || day === 6) {\n            const invalidFormWeekendDayLabel = getTextLabel('v2_custom_form:invalid_form_weekend_day_label');\n\n            e.target.setCustomValidity(invalidFormWeekendDayLabel);\n          } else if (holidayDates.includes(selectedDateISO)) {\n            const invalidFormHolidayLabel = getTextLabel('v2_custom_form:invalid_form_holiday_label');\n            e.target.setCustomValidity(invalidFormHolidayLabel);\n          } else {\n            e.target.setCustomValidity('');\n          }\n        });\n      }\n\n      if (customOptionsObj.minDay) {\n        const today = new Date();\n        const minDate = new Date();\n\n        minDate.setDate(today.getDate() + customOptionsObj.minDay);\n\n        input.min = formatDate(minDate);\n      }\n\n      if (customOptionsObj.maxDay) {\n        let maxDay = customOptionsObj.maxDay;\n\n        if (customOptionsObj.ignoreNonWorkingDays) {\n          // If ignoreNonWorkingDays is true, we need to know how many weekend days there are between today and maxDay\n          // or if customOptionsObj.minDay is set, between minDay and maxDay\n          // if that is the case we need to add those invalid days to the maxDay\n          const today = new Date();\n          const startDate = customOptionsObj.minDay ? new Date(today.setDate(today.getDate() + customOptionsObj.minDay)) : today;\n          let nonWorkingDays = 0;\n\n          for (let i = 0; i <= maxDay + nonWorkingDays; i++) {\n            const checkDate = new Date(startDate);\n            checkDate.setDate(startDate.getDate() + i);\n            const day = checkDate.getUTCDay();\n            const checkDateISO = checkDate.toISOString().split('T')[0];\n            const isHoliday = Object.values(HOLIDAYS)\n              .map((date) => excelDateToISO(date))\n              .includes(checkDateISO);\n\n            if (day === 0 || day === 6 || isHoliday) {\n              nonWorkingDays += 1;\n            }\n          }\n\n          maxDay += nonWorkingDays;\n        }\n        const today = new Date();\n        const maxDate = new Date();\n\n        maxDate.setDate(today.getDate() + maxDay);\n\n        input.max = formatDate(maxDate);\n      }\n    } catch (error) {\n      console.error('Error parsing Custom Options JSON:', error);\n    }\n  }\n\n  return input;\n}\n\nconst withFieldWrapper = (element) => (fd) => {\n  const wrapper = createFieldWrapper(fd);\n  wrapper.append(element(fd));\n  return wrapper;\n};\n\nconst createTextArea = withFieldWrapper((fd) => {\n  const textArea = createElement('textarea');\n  setConstraints(textArea, fd);\n  setPlaceholder(textArea, fd);\n  return textArea;\n});\n\nconst createSelect = withFieldWrapper((fd) => {\n  const select = createElement('select');\n  if (fd.Placeholder) {\n    const ph = createElement('option', {\n      props: {\n        selected: '',\n        disabled: '',\n      },\n    });\n    ph.textContent = fd.Placeholder;\n    select.append(ph);\n  }\n  fd.Options.split(',').forEach((o) => {\n    const oTrimed = o.trim();\n    const option = createElement('option', {\n      props: {\n        value: oTrimed,\n      },\n    });\n    option.textContent = oTrimed;\n    select.append(option);\n  });\n  return select;\n});\n\nfunction checkboxHandler(e) {\n  if (e.type === 'keydown' && e.key !== 'Enter' && e.key !== ' ') {\n    return;\n  }\n  e.preventDefault();\n  const wrapper = e.currentTarget.closest('.field-wrapper');\n  const checkbox = wrapper.querySelector('input[type=\"checkbox\"]');\n  checkbox.checked = !checkbox.checked;\n  checkbox.dispatchEvent(new Event('change'));\n}\n\nfunction createCheckbox(fd) {\n  const wrapper = createElement('div', {\n    classes: [`form-${fd.Type}-wrapper`, 'field-wrapper', `form-${kebabName(fd.Name)}`],\n    props: {\n      id: fd.Id,\n      name: fd.Name,\n    },\n  });\n\n  if (fd.Mandatory?.toLowerCase() === 'true') {\n    wrapper.setAttribute('required', 'required');\n  }\n\n  const input = createElement('input', {\n    props: {\n      type: 'checkbox',\n      id: fd.Id,\n      name: fd.Name,\n      value: fd.Value || 'on',\n      tabindex: '-1',\n      ...(fd.Mandatory?.toLowerCase() === 'true' ? { required: true } : {}),\n    },\n  });\n\n  const label = createElement('label', {\n    props: {\n      for: fd.Id,\n      tabindex: '0',\n    },\n  });\n\n  const circle = createElement('span', {\n    classes: ['form-checkbox-circle'],\n  });\n\n  label.append(circle, document.createTextNode(fd.Label || fd.Name));\n  label.addEventListener('click', checkboxHandler);\n  label.addEventListener('keydown', checkboxHandler);\n  wrapper.append(input, label);\n  return wrapper;\n}\n\nfunction createRadio(fd) {\n  const wrapper = createRadioWrapper(fd);\n\n  const options = getRadioOptions(fd);\n  if (!options || options.length === 0) {\n    return wrapper;\n  }\n\n  options.forEach((option, index) => {\n    const radioOption = createRadioOption(option, index, fd);\n    wrapper.append(radioOption);\n  });\n\n  appendHelpText(wrapper, fd);\n\n  return wrapper;\n}\n\nfunction createRadioWrapper(fd) {\n  const isButtonVariant = fd.Type === 'buttons';\n  const classes = ['form-radio-wrapper', 'field-wrapper'];\n  if (isButtonVariant) {\n    classes.push('form-radio-wrapper--buttons');\n  }\n\n  const wrapper = createElement('fieldset', {\n    classes,\n    props: { name: fd.Name },\n  });\n\n  if (fd.Mandatory?.toLowerCase() === 'true') {\n    wrapper.setAttribute('required', 'required');\n  }\n\n  if (fd.Name) {\n    wrapper.classList.add(`form-${kebabName(fd.Name)}`);\n  }\n\n  const legend = createElement('legend', {\n    classes: ['form-radio-legend'],\n  });\n  legend.textContent = fd.Label || fd.Name;\n  wrapper.append(legend);\n\n  return wrapper;\n}\n\nfunction getRadioOptions(fd) {\n  if (!fd.Options) {\n    console.warn(`Missing \"Options\" for radio field: ${fd.Name}`);\n    return null;\n  }\n\n  const options = fd.Options.split(',')\n    .map((o) => o.trim())\n    .filter(Boolean);\n\n  if (options.length === 0) {\n    console.warn(`No valid options parsed for radio field: ${fd.Name}`);\n  }\n\n  return options;\n}\n\nfunction createRadioOption(option, index, fd) {\n  const radioId = `${fd.Id}-${index}`;\n  const radioWrapper = createElement('div', {\n    classes: ['form-radio-option'],\n  });\n\n  const input = createElement('input', {\n    classes: ['form-radio-input'],\n    props: {\n      type: 'radio',\n      id: radioId,\n      name: fd.Name,\n      value: option,\n      required: fd.Mandatory?.toLowerCase() === 'true',\n    },\n  });\n\n  const label = createElement('label', {\n    classes: ['form-radio-label'],\n    props: { for: radioId },\n  });\n\n  const visualCircle = createElement('span', {\n    classes: ['form-radio-circle'],\n  });\n\n  label.append(visualCircle, document.createTextNode(option));\n  radioWrapper.append(input, label);\n  return radioWrapper;\n}\n\nfunction appendHelpText(wrapper, fd) {\n  if (fd.Description) {\n    wrapper.append(createHelpText(fd));\n  }\n}\n\nconst createOutput = withFieldWrapper((fd) => {\n  const output = createElement('output', {\n    props: {\n      name: fd.Name,\n    },\n  });\n  if (fd.Fieldset) {\n    output.dataset.fieldset = fd.Fieldset;\n  }\n  output.textContent = fd.Value;\n  return output;\n});\n\nfunction createHidden(fd) {\n  const input = createElement('input', {\n    props: {\n      type: 'hidden',\n      id: fd.Id,\n      name: fd.Name,\n      value: fd.Value,\n    },\n  });\n  return input;\n}\n\nfunction createHiddenMeta(fd) {\n  let value = '';\n\n  // get the value from the head meta tag with the name === fd.Name\n  const meta = document.querySelector(`head meta[name=\"${fd.Name}\"]`);\n\n  if (meta) {\n    value = meta.content;\n  } else {\n    // if the meta tag doens't exist, create it and append it to the head\n    const newMeta = createElement('meta', {\n      props: {\n        name: fd.Name,\n        content: fd.Value || '',\n      },\n    });\n\n    document.head.append(newMeta);\n    value = fd.Value || '';\n  }\n\n  const inputField = createElement('input', {\n    props: {\n      type: 'hidden',\n      id: fd.Id,\n      name: fd.Name,\n      value,\n    },\n  });\n\n  // observe the head meta tag with the name === fd.Name and everytime the value changes, update the hidden input value\n  const observer = new MutationObserver((mutationsList) => {\n    for (const mutation of mutationsList) {\n      if (mutation.type === 'attributes' && mutation.attributeName === 'content') {\n        const newValue = mutation.target.content;\n        if (inputField) {\n          inputField.value = newValue;\n        }\n      }\n    }\n  });\n\n  if (meta) {\n    observer.observe(meta, { attributes: true });\n  }\n\n  return inputField;\n}\n\nfunction createLegend(fd) {\n  return createLabel(fd, 'legend');\n}\n\nfunction createFieldSet(fd) {\n  const wrapper = createFieldWrapper(fd, 'fieldset');\n  wrapper.name = fd.Name;\n  wrapper.replaceChildren(createLegend(fd));\n  if (fd.Repeatable && fd.Repeatable.toLowerCase() === 'true') {\n    setConstraints(wrapper, fd);\n    wrapper.dataset.repeatable = 'true';\n  }\n  return wrapper;\n}\n\nfunction groupFieldsByFieldSet(form) {\n  const fieldsets = form.querySelectorAll('fieldset');\n  fieldsets?.forEach((fieldset) => {\n    const fields = form.querySelectorAll(`[data-fieldset=\"${fieldset.name}\"`);\n    fields?.forEach((field) => {\n      fieldset.append(field);\n    });\n  });\n}\n\nfunction createPlainText(fd) {\n  const nameStyle = fd.Name ? `form-${kebabName(fd.Name)}` : '';\n  const paragraph = createElement('p', {\n    classes: nameStyle,\n  });\n  if (fd.Fieldset) {\n    paragraph.dataset.fieldset = fd.Fieldset;\n  }\n  paragraph.textContent = fd.Label;\n  return paragraph;\n}\n\nasync function createCustomDropdown(fd) {\n  const configFd = {\n    optionList: fd.Options.split(',').map((o) => o.trim()),\n    placeholder: fd.Placeholder,\n    id: fd.Id,\n    name: fd.Name,\n    mandatory: fd.Mandatory,\n  };\n\n  if (fd.onChangeCallback) {\n    configFd.onChangeCallback = ({ label, value }) => fd.onChangeCallback({ label, value, name: fd.Name });\n  }\n\n  const customDropdown = await getCustomDropdown(configFd);\n  const select = customDropdown.querySelector('select');\n  // since dropdown is async, it replaces a temporary select\n  // we need to set again the invalid listener\n  select.addEventListener('invalid', showError);\n  return customDropdown;\n}\n\nconst getId = (function getId() {\n  const ids = {};\n  return (name) => {\n    ids[name] = ids[name] || 0;\n    const idSuffix = ids[name] ? `-${ids[name]}` : '';\n    ids[name] += 1;\n    return `${name}${idSuffix}`;\n  };\n})();\n\nconst fieldRenderers = {\n  radio: createRadio,\n  buttons: createRadio,\n  checkbox: createCheckbox,\n  textarea: createTextArea,\n  select: createSelect,\n  button: createButton,\n  submit: createSubmit,\n  output: createOutput,\n  hidden: createHidden,\n  fieldset: createFieldSet,\n  plaintext: createPlainText,\n  date: createDateInput,\n  'custom-dropdown': createSelect, // create a select as a placeholder for the custom dropdown\n};\n\nfunction renderField(fd) {\n  const renderer = fieldRenderers[fd.Type];\n  let field;\n  if (fd.Type === 'date' && typeof renderer === 'function') {\n    field = createFieldWrapper(fd);\n    field.append(renderer(fd));\n  } else if (typeof renderer === 'function') {\n    field = renderer(fd);\n  } else {\n    field = createFieldWrapper(fd);\n    field.append(createInput(fd));\n  }\n  if (fd.Description) {\n    field.append(createHelpText(fd));\n  }\n  return field;\n}\n\nfunction renderTitle(config) {\n  const text = config.Label || '';\n  const tag = config.Name && ['h1', 'h2', 'h3', 'h4', 'h5', 'h6'].includes(config.Name.toLowerCase()) ? config.Name.toLowerCase() : 'h2';\n  const title = createElement(tag, {\n    classes: [`${blockName}__subtitle`],\n  });\n  title.textContent = text;\n\n  return title;\n}\n\nasync function fetchData(url) {\n  try {\n    const resp = await fetch(url);\n    const json = await resp.json();\n    return json.data.map((fd) => ({\n      ...fd,\n      Id: fd.Id || getId(fd.Name),\n      Value: fd.Value || '',\n    }));\n  } catch (error) {\n    console.error('Error fetching data:', error);\n    return [];\n  }\n}\n\nasync function fetchForm(pathname) {\n  // get the main form\n  try {\n    const jsonData = await fetchData(pathname);\n    return jsonData;\n  } catch (error) {\n    console.error('Error fetching form data:', error);\n    return [];\n  }\n}\n\nfunction showError(evnt) {\n  const isHidden = !!evnt.currentTarget.closest('.hidden');\n  if (isHidden) {\n    return;\n  }\n\n  let field = evnt.target;\n  const fieldWrapper = field.closest('.field-wrapper');\n  fieldWrapper.classList.add('invalid');\n  let errorSpan = fieldWrapper.querySelector('span.error');\n  if (!errorSpan) {\n    errorSpan = createElement('span', { classes: 'error' });\n    fieldWrapper.append(errorSpan);\n  }\n  errorSpan.innerText = field.validationMessage;\n  if (fieldWrapper.classList.contains('form-custom-dropdown-wrapper')) {\n    field = fieldWrapper.querySelector('.custom-dropdown__button');\n  }\n  field.addEventListener('blur', hideError);\n}\n\nfunction hideError(evnt) {\n  const isCustomDropdown = evnt.target.classList.contains('custom-dropdown__button');\n  const field = isCustomDropdown ? evnt.target.parentNode.querySelector('select') : evnt.target;\n  const fieldWrapper = field.closest('.field-wrapper');\n  const isValid = field.checkValidity();\n  // to avoid showing error messages on blur\n  fieldWrapper.classList.toggle('invalid', !isValid);\n  const errorSpan = fieldWrapper.querySelector('span.error');\n  if (errorSpan && isValid) {\n    errorSpan.remove();\n  }\n}\n\nfunction decorateValidation(form) {\n  form.setAttribute('novalidate', '');\n  form.querySelectorAll('input,textarea,select').forEach((el) => {\n    el.addEventListener('invalid', showError);\n  });\n}\n\nfunction cleanErrorMessages(form) {\n  const spanErrors = form.querySelectorAll('span.error');\n  spanErrors.forEach((span) => {\n    const parentEl = span.closest('.field-wrapper.invalid');\n    if (!parentEl) {\n      span.remove();\n    }\n  });\n}\n\nfunction toggleNovalidateOnInput(element, novalidate = true) {\n  const inputField = element.querySelector('input,select,textarea');\n  if (inputField) {\n    if (novalidate) {\n      element.classList.add('hidden');\n      inputField.setAttribute('novalidate', '');\n      inputField.classList.add(CLASSES.IGNORE_ON_FORM_SUBMIT);\n      inputField.setAttribute('aria-invalid', 'false');\n      inputField.classList.remove('invalid');\n      inputField.disabled = true;\n    } else {\n      element.classList.remove('hidden');\n      inputField.classList.remove(CLASSES.IGNORE_ON_FORM_SUBMIT);\n      inputField.removeAttribute('novalidate');\n      inputField.setAttribute('aria-invalid', 'true');\n      inputField.classList.add('invalid');\n      inputField.disabled = false;\n    }\n  }\n}\n\nfunction validateSubmitButton(data) {\n  let hasAction = true;\n  let hasSubmit = false;\n  data.forEach((fd) => {\n    if (fd.Type === 'submit') {\n      hasSubmit = true;\n      if (!fd.Action || fd.Action.trim() === '') {\n        console.warn('%cSubmit button%c is missing an action attribute.', 'color: red;', 'color: inherit;');\n        hasAction = false;\n      }\n    }\n  });\n  if (!hasSubmit) {\n    console.warn('Form is missing a %csubmit button.%c No submit Type has been found', 'color: red;', 'color: inherit;');\n  }\n  return hasSubmit && hasAction;\n}\n\nasync function createForm(formURL, time) {\n  const { pathname } = new URL(formURL);\n  const data = await fetchForm(pathname);\n\n  if (data.length === 0) {\n    return createElement('div', {\n      classes: 'custom-form__error',\n      content: 'Error fetching form data',\n    });\n  } else if (!validateSubmitButton(data)) {\n    return;\n  }\n\n  const form = createElement('form');\n  form.dataset.secRef = time;\n  const customDropdowns = [];\n  const dependencies = []; // these will be used to show/hide the fields based on the dependencies\n  data.forEach(async (fd) => {\n    let el;\n\n    if (fd.Type === 'title') {\n      el = renderTitle(fd);\n    } else if (fd.Type === 'paragraph') {\n      el = createPlainText(fd);\n    } else if (fd.Type === 'meta') {\n      el = createHiddenMeta(fd);\n    } else {\n      el = renderField(fd);\n\n      if (fd.Type === 'custom-dropdown') {\n        customDropdowns.push(fd);\n      }\n\n      const formField = el.querySelector('input,textarea,select');\n      if (formField) {\n        if (fd.Mandatory && fd.Mandatory.toLowerCase() === 'true') {\n          formField.setAttribute('required', 'required');\n        }\n        if (!formField.id) {\n          formField.id = fd.Id;\n        }\n        formField.name = fd.Name;\n\n        if (fd.Type !== 'radio') {\n          formField.value = fd.Value;\n        }\n\n        if (fd.Description) {\n          formField.setAttribute('aria-describedby', `${fd.Id}-description`);\n        }\n      }\n      if (fd.Dependency) {\n        // If it has a dependency, we need to hide it by default\n        dependencies.push({\n          element: el,\n          dependency: fd.Dependency,\n\n          name: (fd.Dependency && fd.Dependency.split(':')[0]) || '',\n          value: (fd.Dependency && fd.Dependency.split(':')[1]) || '',\n        });\n      }\n    }\n    form.append(el);\n  });\n\n  if (customDropdowns.length > 0) {\n    customDropdowns.forEach(async (fd, index) => {\n      const hasDependency = dependencies.find((d) => d.name === fd.Name);\n\n      if (hasDependency) {\n        fd.onChangeCallback = (selected) => {\n          const { name, value } = selected;\n          dependencies.forEach((d) => {\n            if (d.name === name) {\n              toggleNovalidateOnInput(d.element, d.value !== value);\n            }\n          });\n        };\n      }\n\n      const customDropdownPlaceholder = form.querySelectorAll('.form-custom-dropdown-wrapper')[index];\n      const placeholderSelect = customDropdownPlaceholder.querySelector('select');\n      const customDropdown = await createCustomDropdown(fd);\n      placeholderSelect.replaceWith(customDropdown);\n\n      if (hasDependency) {\n        const { value } = hasDependency;\n\n        setTimeout(() => {\n          dependencies.forEach((d) => {\n            if (d.name === hasDependency.name) {\n              toggleNovalidateOnInput(d.element, d.value !== value);\n            }\n          });\n        }, 0);\n      }\n    });\n  }\n\n  groupFieldsByFieldSet(form);\n  form.addEventListener('submit', (e) => {\n    let isValid = true;\n    if (form.hasAttribute('novalidate')) {\n      isValid = form.checkValidity();\n    }\n    // after been submitted, the form needs to clean the error messages if the fields are valid\n    cleanErrorMessages(form);\n    e.preventDefault();\n\n    const activeForm = e.currentTarget;\n    const minMs = (parseInt(activeForm.dataset.secRef, 10) || 3) * 1000;\n    const fullyLoadedTime = parseFloat(activeForm.dataset.loaded || 0);\n    const msElapsed = performance.now() - fullyLoadedTime;\n    const isSecure = msElapsed >= minMs;\n\n    // Track usage of form in Google Analytics\n    window.dataLayer = window.dataLayer || [];\n    window.dataLayer.push({\n      event: 'contact_form_submitted',\n      status: isSecure ? 'accepted' : 'rejected',\n      time_to_fill_ms: Math.ceil(msElapsed),\n    });\n\n    if (!isSecure) {\n      console.warn(`Form submission blocked: Fields were filled in less than: ${Math.floor(msElapsed / 1000)} seconds (possible bot).`);\n      return;\n    }\n\n    const honeypot = form.querySelector('input[name=\"form_extra_field\"]');\n    if (honeypot && honeypot.value) {\n      console.warn('Form submission blocked: honeypot field was filled (possible bot).');\n      return;\n    }\n\n    if (isValid) {\n      const block = form.closest(`.${blockName}`);\n      const formTitle = block.querySelector(`.${blockName}__title`);\n      if (formTitle) {\n        formTitle.remove();\n      }\n      e.submitter.setAttribute('disabled', '');\n      form.dataset.action = e.submitter.formAction || SUBMIT_ACTION || pathname.split('.json')[0];\n      handleSubmit(form);\n    }\n  });\n  decorateValidation(form);\n  return form;\n}\n\nfunction decorateTitles(block) {\n  const previousSibling = block.parentElement.previousElementSibling;\n  if (!previousSibling) {\n    return;\n  }\n  const title = previousSibling.querySelector('h3');\n  const subtitle = previousSibling.querySelector('h5');\n  if (title) {\n    title.classList.add('h3');\n  }\n  if (subtitle) {\n    subtitle.classList.add('h5');\n  }\n}\n\nfunction addTitleText(titleText, block) {\n  const titleTextContent = createElement('div', {\n    classes: [`${blockName}__title`],\n  });\n  titleTextContent.innerHTML = titleText.innerHTML;\n  block.append(titleTextContent);\n}\n\nfunction createHoneypotField() {\n  const fragment = document.createRange().createContextualFragment(`\n    <div class=\"field-wrapper visually-hidden\" aria-hidden=\"true\">\n      <label for=\"form_extra_field\">Comments</label>\n      <input\n        type=\"text\"\n        id=\"form_extra_field\"\n        name=\"form_extra_field\"\n        tabindex=\"-1\"\n        autocomplete=\"off\"\n      >\n    </div>\n  `);\n  return fragment.firstElementChild;\n}\n\nfunction getConfigValueCell(block, propName) {\n  for (const row of block.querySelectorAll(':scope > div')) {\n    const [propCell, valueCell] = row.children || [];\n    if (propCell && propCell.textContent.trim() === propName) {\n      return valueCell || null;\n    }\n  }\n  return null;\n}\n\nexport default async function decorate(block) {\n  variantsClassesToBEM(block.classList, variantClasses, blockName);\n\n  const titleCell = getConfigValueCell(block, 'title');\n  const linkCell = getConfigValueCell(block, 'link');\n  const successFragmentCell = getConfigValueCell(block, 'successFragmentUrl');\n  const successRedirectCell = getConfigValueCell(block, 'successRedirectUrl');\n  const errorRedirectCell = getConfigValueCell(block, 'errorRedirectUrl');\n  const timeValue = getConfigValueCell(block, 'time');\n\n  const formUrl = linkCell ? (linkCell.querySelector('a')?.href || linkCell.textContent).trim() : '';\n  const isJsonUrl = formUrl.toLowerCase().trim().endsWith('.json');\n  const thankYouPageUrl = successFragmentCell ? (successFragmentCell.querySelector('a')?.href || successFragmentCell.textContent).trim() : '';\n  const successRedirectUrl = successRedirectCell ? (successRedirectCell.querySelector('a')?.href || successRedirectCell.textContent).trim() : '';\n  const errorRedirectUrl = errorRedirectCell ? (errorRedirectCell.querySelector('a')?.href || errorRedirectCell.textContent).trim() : '';\n  const parsedValue = timeValue ? parseInt(timeValue.textContent, 10) : 3;\n  const minRequiredSeconds = Math.max(isNaN(parsedValue) ? 3 : parsedValue, 1);\n\n  if (!formUrl || !isJsonUrl) {\n    console.error('%cForm link%c is missing or not a .json', 'color:red', 'color:inherit', { formUrl });\n    block.textContent = '';\n    return;\n  }\n\n  decorateTitles(block);\n\n  const form = await createForm(formUrl, minRequiredSeconds);\n  if (!form) {\n    console.error('%cForm%c could not be created. No form data found.', 'color:red', 'color:inherit', { formUrl, form });\n    block.textContent = '';\n    return;\n  }\n\n  if (successRedirectUrl) {\n    form.dataset.successRedirect = successRedirectUrl;\n  }\n  if (errorRedirectUrl) {\n    form.dataset.errorRedirect = errorRedirectUrl;\n  }\n  if (!successRedirectUrl && thankYouPageUrl) {\n    form.dataset.customMessage = `${thankYouPageUrl}.plain.html`;\n  }\n\n  block.textContent = '';\n  if (titleCell) {\n    addTitleText(titleCell, block);\n  }\n\n  form.append(createHoneypotField());\n  block.append(form);\n\n  // Register time the moment after the form is appended and add the miliseconds value to the form\n  form.dataset.loaded = Math.ceil(performance.now());\n\n  window.addEventListener('unhandledrejection', ({ reason, error }) => {\n    console.error('Unhandled rejection. Error submitting form:', { reason, error });\n\n    const activeForms = Array.from(window.__activeForms || []);\n    const form = activeForms.reverse().find((f) => f.dataset.submitting === 'true');\n\n    if (!form) {\n      throwFormNotFound(form);\n      return;\n    }\n\n    const block = form.closest(`.${blockName}`);\n    const redirectNewTab = block?.classList.contains(`${blockName}--redirect-new-tab`) || false;\n    submissionFailure(form, redirectNewTab);\n  });\n}\n","const defaultFilterOptionTemplate = `\n  <ul id=\"filter-options\">\n      <li>\n          <label for=all>All Dealers\n              <input name=type-filter type=checkbox id=all value=\"All Dealers\" checked=checked/>\n              <span class=\"checkmark\"></span>\n          </label>\n      </li>\n      <li>\n          <label for=rental-leasing>Rental &amp; Leasing\n              <input name=type-filter type=checkbox id=rental-leasing value=Leasing/>\n              <span class=\"checkmark\"></span>\n          </label>\n      </li>\n  </ul>`;\nconst laFilterOptionTemplate = `\n  <ul id=\"filter-options\">\n      <li>\n          <label for=all>All Dealers\n              <input name=type-filter type=checkbox id=all value=\"All Dealers\" checked=checked/>\n              <span class=\"checkmark\"></span>\n          </label>\n      </li>\n      <li>\n          <label for=sales-service>Sales, service &amp; Parts\n              <input name=type-filter type=checkbox id=sales-service value=Sales, Service & Parts />\n              <span class=\"checkmark\"></span>\n          </label>\n      </li>\n      <li>\n          <label for=services-parts>Service &amp; Parts\n              <input name=type-filter type=checkbox id=services-parts value=Service and Parts />\n              <span class=\"checkmark\"></span>\n          </label>\n      </li>\n      <li>\n          <label for=customer-service>Customer Service Center\n              <input name=type-filter type=checkbox id=customer-service value=Customer Service Centre />\n              <span class=\"checkmark\"></span>\n          </label>\n      </li>\n      <li>\n          <label for=head-office>Head office\n              <input name=type-filter type=checkbox id=head-office value=/>\n              <span class=\"checkmark\"></span>\n          </label>\n      </li>\n  </ul>`;\n\nconst template = ({ zipCode, isMobile, isExportMarket }) => {\n  const rangeFilterValue = isExportMarket ? 75 : 100;\n\n  return `<input id=\"hoverText\" value=\"Please unselect the selected option to click this option\" hidden/>\n  <div class=\"wrapper\">\n      <div class=\"mobile-main-header\">\n          <div class=\"panel-header\">\n              <input type=\"text\" id=\"location2\"\n                ${zipCode && isMobile ? `value=\"${zipCode}\"` : ''}\n                placeholder=\"Enter City, State, or Zip Code\"/>\n              <div class=\"search-container\">\n                  <button type=\"button\" id=\"search\" onclick=\"$.fn.setAddress2();\">\n                      <img src=\"/blocks/v2-dealer-locator/images/search.svg\"/>\n                  </button>\n              </div>\n              <div class=\"filter-container\">\n                  <button type=\"button\" onclick=\"$.fn.switchSidebarPane('sidebar-filter');\">\n                      <div style=\"width:44px;\">\n                          <div class=\"icon\"><img src=\"/blocks/v2-dealer-locator/images/filter.svg\"/></div>\n                      </div>\n                  </button>\n             