(e) => {\n    if (formContent.onSubmit) {\n      e.preventDefault();\n      formObj.dataset.action = e.currentTarget.action;\n      formContent.onSubmit(formObj, handleSubmit);\n    }\n\n    e.preventDefault();\n    let isValid = true;\n    if (formObj.hasAttribute('novalidate')) {\n      isValid = formObj.checkValidity();\n    }\n    if (isValid) {\n      e.submitter.setAttribute('disabled', '');\n      formObj.dataset.action = e.currentTarget.action;\n\n      handleSubmit(formObj);\n    }\n  });\n\n  formContent.postLoad?.(formObj);\n};\n\nexport default async function decorate(block) {\n  const forceLoad = block?.getAttribute('data-force-load');\n\n  if (forceLoad === 'true') {\n    await addForm(block);\n    return;\n  }\n\n  const observer = new IntersectionObserver(\n    (entries) => {\n      if (entries.some((e) => e.isIntersecting)) {\n        observer.disconnect();\n        addForm(block);\n      }\n    },\n    {\n      rootMargin: '300px',\n    },\n  );\n  observer.observe(block);\n}\n","import { loadBlock } from '../../scripts/aem.js';\nimport { createElement } from '../../scripts/common.js';\nimport { decorateLinks } from '../../scripts/scripts.js';\nimport { variantClasses as heroVariantClasses } from '../v2-hero/v2-hero.js';\n\nfunction buildRevealHero(innerBlockCode, v2HeroRevealBlockClassList) {\n  return getV2HeroBlockCode(innerBlockCode, v2HeroRevealBlockClassList);\n}\n\nfunction isCountDownFinished(eventTime) {\n  const now = new Date();\n  const diff = eventTime - now;\n\n  return diff <= 0;\n}\n\nfunction getV2HeroBlockCode(innerBlockCode, v2HeroRevealBlockClassList) {\n  const block = createElement('div', { classes: ['v2-hero', 'block'], props: { 'data-block-name': 'v2-hero', 'data-block-status': 'initialized' } });\n  const providedVariantClasses = Array.from(v2HeroRevealBlockClassList).filter((className) => heroVariantClasses.includes(className));\n\n  block.append(innerBlockCode);\n\n  block.classList.add(...providedVariantClasses);\n\n  return block;\n}\n\nfunction validateBlockConfiguration(blockRows) {\n  if (blockRows.length !== 2) {\n    console.warn('V2 Hero Reveal block: Block misconfigured, please provide Countdown and Reveal Hero blocks.');\n    return false;\n  }\n  return true;\n}\n\nfunction validateHeroBlocks(preRevealCountdownHeroBlock, revealHeroBlock) {\n  if (!preRevealCountdownHeroBlock || !revealHeroBlock) {\n    console.warn('V2 Hero Reveal block: Countdown and Reveal Hero blocks not provided.');\n    return false;\n  }\n  return true;\n}\n\nfunction validateRevealDate(revealEventTimeIso) {\n  if (!revealEventTimeIso) {\n    console.warn('V2 Hero Reveal block: Reveal date not provided in the Section Metadata.');\n    return false;\n  }\n\n  if (isNaN(new Date(revealEventTimeIso))) {\n    console.warn('V2 Hero Reveal block: Reveal date invalid.');\n    return false;\n  }\n  return true;\n}\n\nfunction initializeHeroBlock(preRevealCountdownHeroBlock, revealHeroBlock, eventTime, blockClassList) {\n  let v2HeroBlock;\n\n  if (isCountDownFinished(eventTime)) {\n    v2HeroBlock = buildRevealHero(revealHeroBlock, blockClassList);\n  } else {\n    v2HeroBlock = buildRevealHero(preRevealCountdownHeroBlock, blockClassList);\n\n    const intervalId = setInterval(() => {\n      if (isCountDownFinished(eventTime)) {\n        const newV2HeroBlock = buildRevealHero(revealHeroBlock, blockClassList);\n\n        v2HeroBlock.replaceWith(newV2HeroBlock);\n        loadBlock(newV2HeroBlock);\n        decorateLinks(newV2HeroBlock);\n        clearInterval(intervalId);\n      }\n    }, 500);\n  }\n\n  return v2HeroBlock;\n}\n\nfunction decorate(block) {\n  const blockRows = block.querySelectorAll(':scope > div');\n\n  if (!validateBlockConfiguration(blockRows)) {\n    return;\n  }\n\n  const preRevealCountdownHeroBlock = blockRows[0]?.cloneNode(true);\n  const revealHeroBlock = blockRows[1]?.cloneNode(true);\n\n  if (!validateHeroBlocks(preRevealCountdownHeroBlock, revealHeroBlock)) {\n    return;\n  }\n\n  const blockSection = block.parentElement?.parentElement;\n  const revealEventTimeIso = blockSection?.dataset?.revealDate;\n\n  if (!validateRevealDate(revealEventTimeIso)) {\n    return;\n  }\n\n  const eventTime = new Date(revealEventTimeIso);\n  const blockClassList = block.classList;\n\n  const v2HeroBlock = initializeHeroBlock(preRevealCountdownHeroBlock, revealHeroBlock, eventTime, blockClassList);\n\n  decorateLinks(v2HeroBlock);\n  block.replaceWith(v2HeroBlock);\n  loadBlock(v2HeroBlock);\n}\n\nexport default decorate;\n","import { getImageURLs, createResponsivePicture, variantsClassesToBEM, decorateIcons, createElement } from '../../scripts/common.js';\nimport { isVideoLink, createVideo } from '../../scripts/video-helper.js';\nimport { initializeCountdown } from '../../common/countdown/countdown.js';\n\nexport const variantClasses = ['dark', 'light', 'half-height', 'magazine', 'countdown', 'with-engine-stats'];\nconst blockName = 'v2-hero';\nlet hasVideo;\n\nconst addLineBreaksToWords = (element) => {\n  element.innerHTML = element.textContent\n    .split(' ')\n    .map((word) => `<span>${word}</span>`)\n    .join(' ');\n};\n\nconst getCountdownDate = (block) => {\n  const section = block.closest('.section');\n  const countdownDate = section.dataset.countdownDate;\n  if (!countdownDate) {\n    console.error('Countdown date is not defined in the section dataset.');\n  }\n  return countdownDate;\n};\n\nconst getFirstBlockHeader = (block) => {\n  const firstBlockHeader = block.querySelector(':scope h1, :scope h2, :scope h3');\n  if (!firstBlockHeader) {\n    console.warn('First block header is missing.');\n  }\n  return firstBlockHeader;\n};\n\nconst setupCountdownSection = async (block, wrapper) => {\n  try {\n    const targetDate = getCountdownDate(block);\n    const firstBlockHeader = getFirstBlockHeader(block);\n\n    if (targetDate) {\n      const countdown = await initializeCountdown(targetDate);\n      const section = block.closest('.section');\n      const iframe = section.querySelector('.iframe');\n\n      if (countdown) {\n        if (firstBlockHeader) {\n          // append the countdown after the first block header\n          firstBlockHeader.insertAdjacentElement('afterend', countdown);\n        } else {\n          wrapper.prepend(countdown);\n        }\n      }\n\n      if (iframe) {\n        const iframeContainer = createElement('div', { classes: `${blockName}__iframe-container` });\n        iframeContainer.appendChild(iframe);\n        wrapper.appendChild(iframeContainer);\n      }\n    }\n  } catch (error) {\n    console.error('Error initializing countdown feature:', error);\n  }\n};\n\nconst processVideoLink = (block, link) => {\n  const linkText = link.innerText.trim().toLowerCase();\n\n  if (linkText === 'background') {\n    const video = createVideo(link.getAttribute('href'), `${blockName}__video`, {\n      muted: true,\n      autoplay: true,\n      loop: true,\n      playsinline: true,\n    });\n\n    block.prepend(video);\n    link.parentElement.remove();\n  }\n};\n\nconst handleMultipleButtons = (content, buttons = []) => {\n  const heading = content.querySelector(`.${blockName}__heading`);\n  content.classList.add(`${blockName}__content--2-buttons`);\n  const buttonsWrapper = createElement('div');\n  heading.after(buttonsWrapper, buttons[0]);\n  buttonsWrapper.append(...buttons);\n};\n\nexport default function decorate(block) {\n  variantsClassesToBEM(block.classList, variantClasses, blockName);\n  const blockContainer = block.parentElement.parentElement;\n  const isPdp = blockContainer.dataset.page === 'pdp';\n  const isHalfHeight = block.classList.contains(`${blockName}--half-height`);\n  const isMagazine = block.classList.contains(`${blockName}--magazine`);\n  const isCountdown = block.classList.contains(`${blockName}--countdown`);\n  const hasEngineStats = block.classList.contains(`${blockName}--with-engine-stats`);\n  const hasBackgroundImage = block.closest('.section--with-background');\n\n  if (hasEngineStats && hasBackgroundImage) {\n    hasBackgroundImage.classList.add('reduced-height');\n  }\n\n  const images = [...block.querySelectorAll('p > picture')];\n  const imageURLs = getImageURLs(images);\n  const imageData = imageURLs.map((src) => ({ src, breakpoints: [] }));\n\n  const links = block.querySelectorAll('a');\n\n  if (links) {\n    links.forEach((link) => {\n      const isVideo = isVideoLink(link);\n      if (isVideo) {\n        hasVideo = true;\n      }\n      processVideoLink(block, link);\n    });\n  }\n\n  if (imageData.length === 1) {\n    imageData[0].breakpoints = [\n      { media: '(min-width: 600px)', width: 600 },\n      { media: '(min-width: 1200px)', width: 1200 },\n      { media: '(min-width: 1440px)', width: 1440 },\n      { media: '(min-width: 1920px)', width: 1920 },\n      { width: 1600 },\n    ];\n  }\n\n  if (imageData.length > 1) {\n    imageData[0].breakpoints = [{ media: '(min-width: 600px)', width: 600 }, { width: 1600 }];\n\n    imageData[1].breakpoints = [\n      { media: '(min-width: 1200px)', width: 1200 },\n      { media: '(min-width: 1440px)', width: 1440 },\n      { media: '(min-width: 1920px)', width: 1920 },\n    ];\n  }\n\n  const altText = [...block.querySelectorAll('p > picture img.alt')];\n  const newPicture = createResponsivePicture(imageData, true, altText, `${blockName}__image`);\n  images.forEach((image) => image.parentNode.remove());\n\n  if (images.length !== 0) {\n    block.prepend(newPicture);\n  } else if (!hasVideo) {\n    block.classList.add(`${blockName}--no-image`);\n  }\n\n  const contentWrapper = block.querySelector(':scope > div:last-of-type');\n  contentWrapper.classList.add(`${blockName}__content-wrapper`);\n\n  const content = block.querySelector(':scope > div > div');\n  content.classList.add(`${blockName}__content`);\n\n  const headings = [...content.querySelectorAll('h1, h2, h3, h4, h5, h6')];\n  headings.forEach((h) => h.classList.add(`${blockName}__heading`));\n\n  if (!isPdp && !isMagazine && !isCountdown) {\n    const firstHeading = headings[0];\n    firstHeading?.classList.add('with-marker');\n  }\n\n  if (isMagazine) {\n    const heading = content.querySelector(`.${blockName}__heading`);\n    if (heading) {\n      addLineBreaksToWords(heading);\n    }\n  }\n\n  const button = content.querySelector('a');\n  const allTexts = content.querySelectorAll('p');\n\n  const buttons = content.querySelectorAll('p.button-container');\n  if (buttons.length > 1) {\n    handleMultipleButtons(content, buttons);\n  }\n\n  if (!button && allTexts.length > 0) {\n    content.classList.add('with-text');\n    allTexts.forEach((p) => p.classList.add(`${blockName}__text`));\n  }\n\n  const ctaButtons = content.querySelectorAll('.button-container > a');\n  [...ctaButtons].forEach((b) => {\n    b.classList.add(isPdp ? `${blockName}__cta` : 'button--large', 'button--red', 'button');\n    if (!isHalfHeight) {\n      b.classList.remove('button--primary');\n    }\n    b.parentElement.classList.add(`${blockName}__cta-wrapper`);\n  });\n\n  if (isCountdown) {\n    setupCountdownSection(block, content);\n  }\n\n  block.parentElement.classList.add('full-width');\n  decorateIcons(block);\n}\n","import { addSpot } from '../v2-hotspots/v2-hotspots.js';\n\n/**\n * This is a synthetic block that is only used to structure the content.\n * All content is then added to the closest 'hotspots' block.\n */\nexport default function decorate(block) {\n  const hotspotsBlock = block.closest('.v2-hotspots-container').querySelector('.v2-hotspots.block');\n\n  const hotspot = parseHotspotContent(block);\n  addSpot(hotspotsBlock, hotspot);\n\n  // Content was added to other block, therefore we can remove it\n  block.remove();\n}\n\n/**\n *\n * @param block {HTMLDivElement} raw block with content\n * @return {HotspotContent}\n */\nfunction parseHotspotContent(block) {\n  const picture = block.querySelector('picture');\n  // remove the paragraph that contains the picture to avoid finding it when looking for text\n  block.querySelector('picture').closest('p').remove();\n\n  // this is based on order, not header level\n  const title = block.querySelector('p, h1, h2, h3, h4, h5, h6');\n  title?.remove();\n\n  const text = block.querySelectorAll('p');\n\n  const positionRegExp = /position-([0-9]+)-([0-9]+)/;\n  const positionClass = [...block.classList].find((el) => positionRegExp.test(el));\n  const positionMatch = positionClass.match(positionRegExp);\n\n  const positionLeft = `${positionMatch[1].trim()}%`;\n  const positionTop = `${positionMatch[2].trim()}%`;\n\n  return {\n    picture,\n    title,\n    text,\n    positionLeft,\n    positionTop,\n  };\n}\n","import { createElement, decorateIcons } from '../../scripts/common.js';\n\n/**\n * @typedef {Object} HotspotContent\n *\n * @property {number} id\n * @property {HTMLPictureElement} picture\n * @property {HTMLElement} title\n * @property {HTMLElement} text\n * @property {string} positionLeft\n * @property {string} positionTop\n */\n\nlet hotspotBlockCounter = 0;\nlet previousSpot = 0;\nconst blockName = 'v2-hotspots';\n\nexport default function decorate(block) {\n  const firstBlockRow = block.querySelector(':scope > div');\n  const firstPicture = firstBlockRow.querySelector('picture');\n  const title = firstBlockRow.querySelector('h1, h2');\n\n  // every instance of this block needs a unique id.\n  hotspotBlockCounter += 1;\n  block.closest(`.section.${blockName}-container`).dataset.hotspotAreaId = hotspotBlockCounter;\n\n  block.innerHTML = `\n    <div class=\"main\">\n      <div class=\"hotspot-features\"></div>\n    </div>\n    <div class=\"hotspot-layover\" style=\"display: none;\"></div>\n  `;\n\n  decorateImageAndTitle(block.querySelector('.main'), firstPicture, title);\n\n  decorateIcons(block);\n}\n\n/**\n *\n * @param block {HTMLDivElement}\n */\nfunction handleClose(block) {\n  previousSpot = 0;\n  block.querySelector('.hotspot-features').style = 'transform: translateX(200%)';\n  block.querySelectorAll('.hotspot-icon').forEach((icon) => icon.classList.remove('active-spot'));\n}\n\n/**\n *\n * @param event {click event}\n * @param iconLink {clicked anchor element}\n * @param hotspotId {anchor element's id}\n * @param block {HTMLDivElement}\n */\nfunction handleClickHotspot(event, iconLink, hotspotId, block) {\n  event.preventDefault();\n\n  if (previousSpot > 0 && Number(hotspotId) === previousSpot) {\n    handleClose(block);\n    return;\n  }\n\n  previousSpot = Number(hotspotId);\n\n  block.querySelectorAll('.hotspot-icon').forEach((icon) => icon.classList.remove('active-spot'));\n  block.querySelector('.hotspot-features').style = 'transform: translateX(0)';\n\n  iconLink.classList.add('active-spot');\n\n  block.querySelector('.features.is-active').classList.remove('is-active');\n  block.querySelector(`.features.number-${hotspotId}`).classList.add('is-active');\n}\n\nfunction addDesktopHotspotIcon(hotspot, block, main) {\n  const iconLink = createElement('a', {\n    classes: 'hotspot-icon',\n    props: {\n      href: '#',\n      'data-spot': hotspot.id,\n      style: `left: ${hotspot.positionLeft}; top: ${hotspot.positionTop};`,\n    },\n  });\n\n  const plusIcon = createElement('img', { props: { src: '/icons/plus.svg' } });\n  iconLink.appendChild(plusIcon);\n\n  iconLink.onclick = (event) => handleClickHotspot(event, iconLink, hotspot.id, block);\n\n  main.querySelector('.hotspot-icon-set').append(iconLink);\n}\n\nfunction addCards(hotspot, main) {\n  const featureBlock = document.createElement('div');\n  featureBlock.innerHTML = `\n    <div class=\"features number-${hotspot.id}\" data-fade-object=\"true\">\n      <button class=\"feature-close\"></button>\n      <div class=\"row\">\n        <div class=\"feature\">\n          <h3 class=\"feature-title\"></h3>\n          <picture></picture>\n          <div class=\"feature-text\"></div>\n        </div>\n        <div class='feature-pagination'></div>\n      </div>\n    </div>\n  `;\n\n  featureBlock.querySelector('picture').innerHTML = hotspot.picture.innerHTML;\n  featureBlock.querySelector('.feature-title').innerHTML = hotspot.title.innerHTML;\n  if (Number(hotspot.id) === 1) {\n    featureBlock.querySelector('.features').classList.add('is-active');\n  }\n\n  hotspot.text.forEach((p) => {\n    const pEl = createElement('p');\n    pEl.innerHTML = p.innerHTML;\n    featureBlock.querySelector('.feature-text').append(pEl);\n  });\n\n  const closeBtn = featureBlock.querySelector('.feature-close');\n  closeBtn.addEventListener('click', () => handleClose(main));\n\n  const closeIcon = createElement('img', { props: { src: '/icons/close.svg' } });\n  closeBtn.appendChild(closeIcon);\n\n  const featuresDiv = main.querySelector('.hotspot-features');\n  featuresDiv.append(...featureBlock.childNodes);\n}\n\nfunction addPaginationButtons(block) {\n  const allFeatures = block.querySelectorAll('.features');\n  allFeatures.forEach((feature, idx) => {\n    const paginationStructure = `\n      <a class=\"hotspot-feature-button prev\"></a>\n      <span class=\"hotspot-feature-pagination\">${idx + 1}/${allFeatures.length}</span>\n      <a class=\"hotspot-feature-button next\"></a>\n    `;\n    feature.querySelector('.feature-pagination').innerHTML = paginationStructure;\n\n    feature.querySelectorAll('.hotspot-feature-button').forEach((arrow) => {\n      const image = createElement('img', { props: { src: '/icons/arrow-right.svg' } });\n      arrow.appendChild(image);\n    });\n  });\n}\n\nfunction updateActiveHotspot(event, clickedNum, block) {\n  const totalSlides = block.querySelectorAll('.features').length;\n  let slideNumber;\n  if (clickedNum > totalSlides) {\n    slideNumber = 1;\n  } else if (clickedNum < 1) {\n    slideNumber = totalSlides;\n  } else {\n    slideNumber = clickedNum;\n  }\n\n  previousSpot = clickedNum;\n\n  const clickedElmt = event.target.closest('.features');\n  clickedElmt.classList.remove('is-active');\n\n  clickedElmt.parentElement.querySelector(`.features.number-${slideNumber}`).classList.add('is-active');\n\n  block.querySelectorAll('.hotspot-icon').forEach((icon) => icon.classList.remove('active-spot'));\n  block.querySelector(`.hotspot-icon[data-spot=\"${slideNumber}\"]`).classList.add('active-spot');\n}\n\nfunction updateFeature(block) {\n  const features = block.querySelectorAll('.features');\n\n  features.forEach((feat, idx) => {\n    feat.querySelector(`.features.number-${idx + 1} .hotspot-feature-button.prev`).onclick = (e) => updateActiveHotspot(e, idx, block);\n    feat.querySelector(`.features.number-${idx + 1} .hotspot-feature-button.next`).onclick = (e) => updateActiveHotspot(e, idx + 2, block);\n  });\n}\n\n/**\n *\n * @param block\n * @param hotspot {HotspotContent}\n */\nexport function addSpot(block, hotspot) {\n  // desktop hotspot icon\n  const main = block.querySelector('.main');\n\n  // keep track of the number of hotspots in the DOM\n  main.dataset.hotspotCounter = (+main.dataset.hotspotCounter || 0) + 1;\n  hotspot.id = main.dataset.hotspotCounter;\n  addDesktopHotspotIcon(hotspot, block, main);\n\n  addCards(hotspot, main);\n\n  addPaginationButtons(block);\n\n  updateFeature(block);\n}\n\n/**\n *\n * @param mainDiv {HTMLDivElement}\n * @param firstPicture {HTMLPictureElement}\n * @param title {HTMLElement}\n//  * @param description {HTMLElement}\n */\nfunction decorateImageAndTitle(mainDiv, firstPicture, title) {\n  const hotspot = createElement('div', { classes: 'hotspot' });\n  hotspot.innerHTML = `\n      <picture class=\"hotspot-bg-img\"></picture>\n      <div class=\"hotspot-content content-wrapper \">\n        <h1 class=\"hotspot-header with-marker\"></h1>\n      </div>\n\n      <div class=\"hotspot-icon-set\"></div>`;\n\n  hotspot.querySelector('.hotspot-bg-img').innerHTML = firstPicture.innerHTML;\n  hotspot.querySelector('.hotspot-header').innerHTML = title.innerHTML;\n\n  mainDiv.prepend(hotspot);\n}\n","import { createElement, decorateIcons, getTextLabel, variantsClassesToBEM, isMobileViewport } from '../../scripts/common.js';\n\nconst blockName = 'v2-icon-cards';\nconst variantClasses = ['no-background', 'alt-font-size', 'slider'];\n\nfunction numberCardsToNavigate(block) {\n  const isMobile = isMobileViewport();\n  if (isMobile) {\n    return 1;\n  }\n\n  if (block.classList.contains('slider-slide-2')) {\n    return 2;\n  }\n  if (block.classList.contains('slider-slide-3')) {\n    return 3;\n  }\n  if (block.classList.contains('slider-slide-4')) {\n    return 4;\n  }\n\n  return 1;\n}\n\nfunction mergeColumnsInOneRow(block) {\n  const columns = [...block.querySelectorAll(':scope > div > div')];\n\n  if (columns.length > 5) {\n    const row = document.createElement('div');\n\n    row.append(...columns);\n    block.innerHTML = '';\n    block.append(row);\n  }\n}\n\nfunction setSliderNavButtonEvents(block) {\n  const numberCardsToNavigatePerClick = numberCardsToNavigate(block);\n  const sliderNav = block.querySelector('.v2-icon-cards__slider-nav');\n  const sliderNavPrev = sliderNav.querySelector('.v2-icon-cards__slider-nav-button--prev');\n  const sliderNavNext = sliderNav.querySelector('.v2-icon-cards__slider-nav-button--next');\n  const scrollContainer = block.querySelector('.v2-icon-cards__row');\n  const numberItems = block.querySelectorAll('.v2-icon-cards__column')?.length;\n  const scrollContainerScrollWidth = scrollContainer.scrollWidth;\n  const itemWidth = scrollContainerScrollWidth / numberItems;\n\n  sliderNavPrev.addEventListener('click', () => {\n    scrollContainer.scrollLeft -= itemWidth * numberCardsToNavigatePerClick;\n  });\n\n  sliderNavNext.addEventListener('click', () => {\n    scrollContainer.scrollLeft += itemWidth * numberCardsToNavigatePerClick;\n  });\n}\n\nfunction initialiseSliderNav(block) {\n  let intervalId = null;\n  let progressBarInitialised = false;\n  const progressBar = block.querySelector('.v2-icon-cards__slider-progress');\n  const scrollContainer = block.querySelector('.v2-icon-cards__row');\n\n  const setupNavAndProgressBar = () => {\n    const blockClientWidth = block.clientWidth;\n    const scrollContainerScrollWidth = scrollContainer.scrollWidth;\n\n    if (!blockClientWidth || !scrollContainerScrollWidth) {\n      return;\n    }\n    const visibleScrollPercentage = (blockClientWidth * 100) / scrollContainerScrollWidth;\n    const remainingScrollWidth = scrollContainerScrollWidth - blockClientWidth;\n    const scrollLeftPosition = scrollContainer.scrollLeft;\n    const remainingScrollPercentage = (scrollLeftPosition / remainingScrollWidth) * (100 - visibleScrollPercentage) || 0;\n\n    progressBar.style.width = `${remainingScrollPercentage + visibleScrollPercentage}%`;\n\n    progressBarInitialised = true;\n  };\n\n  // Set initial width\n  const initialiseProgressBar = () => {\n    setupNavAndProgressBar();\n\n    if (progressBarInitialised) {\n      setSliderNavButtonEvents(block);\n      clearInterval(intervalId);\n    }\n  };\n\n  intervalId = setInterval(initialiseProgressBar, 100);\n\n  // Update width on scroll\n  scrollContainer.addEventListener('scroll', setupNavAndProgressBar);\n}\n\nfunction setupSlider(block) {\n  mergeColumnsInOneRow(block);\n  const rows = [...block.querySelectorAll(':scope > div')];\n\n  rows.forEach((row) => {\n    row.classList.add(`${blockName}__row`);\n  });\n\n  const sliderNav = document.createRange().createContextualFragment(`\n      <div class=\"${blockName}__slider-nav\">\n        <div class=\"${blockName}__slider-nav-arrows\">\n          <button class=\"${blockName}__slider-nav-button ${blockName}__slider-nav-button--prev\" aria-label=\"${getTextLabel('v2_icon_cards:previous')}\"><span class=\"icon icon-chevron-right\"></span></button>\n          <button class=\"${blockName}__slider-nav-button ${blockName}__slider-nav-button--next\" aria-label=\"${getTextLabel('v2_icon_cards:next')}\"><span class=\"icon icon-chevron-right\"></span></button>\n        </div>\n        <div class=\"${blockName}__slider-progress-wrapper\"> <div class=\"${blockName}__slider-progress\"></div></div>\n      </div>\n    `);\n\n  block.append(sliderNav);\n  decorateIcons(block);\n\n  initialiseSliderNav(block);\n}\n\nexport default async function decorate(block) {\n  variantsClassesToBEM(block.classList, variantClasses, blockName);\n\n  const columns = [...block.querySelectorAll(':scope > div > div')];\n  const isSliderEnabled = block.classList.contains(`${blockName}--slider`);\n\n  if (isSliderEnabled) {\n    setupSlider(block);\n  } else {\n    const rows = [...block.querySelectorAll(':scope > div')];\n    rows.forEach((row) => {\n      row.classList.add(`${blockName}__row`);\n    });\n  }\n\n  const parentSection = block.parentElement.parentElement;\n  const hasHeader = parentSection.classList.contains('header-with-mark');\n  const hasExtraColumn = columns.length === 4;\n\n  if (hasExtraColumn) {\n    block.classList.add(`${blockName}--4-cols`);\n  }\n  if ((hasExtraColumn && hasHeader) || (isSliderEnabled && hasHeader)) {\n    parentSection.querySelector('.default-content-wrapper').classList.add(`${blockName}--short-header`);\n  }\n\n  columns.forEach((col, idx) => {\n    const isExtraColumn = idx === 3;\n    col.classList.add(`${blockName}__column`);\n\n    const allTextElmts = col.querySelectorAll('p');\n    const allLiElements = col.querySelectorAll('li');\n    const bodyElmts = [];\n\n    allTextElmts.forEach((e) => {\n      const nextElmt = e.nextElementSibling;\n\n      const isButton = [...e.classList].includes('button-container');\n      const isPretitle = nextElmt?.tagName.toLowerCase()[0] === 'h';\n\n      if (!isPretitle && !isButton) {\n        bodyElmts.push(e);\n      }\n    });\n\n    [...bodyElmts, ...allLiElements].forEach((e) => e.classList.add(`${blockName}__body`));\n\n    const buttons = [...block.querySelectorAll('.button-container a')];\n    buttons.forEach((btn) => {\n      const buttonContainer = btn.closest('.button-container');\n      if (buttonContainer) {\n        buttonContainer.replaceWith(btn);\n      }\n\n      if (btn.classList.contains('button--primary') || btn.classList.contains('button--secondary') || btn.classList.contains('button--red')) {\n        btn.classList.add('button--small');\n      } else {\n        btn.classList.add('standalone-link', `${blockName}__button`);\n      }\n    });\n\n    if (isExtraColumn) {\n      col.classList.add(`${blockName}__column--extra-col`);\n      col.dataset.theme = 'gold';\n    }\n\n    const headings = [...col.querySelectorAll('h1, h2, h3, h4, h5, h6')];\n    headings.forEach((heading) => heading.classList.add(`${blockName}__heading`, 'h2'));\n\n    // icons\n    [...col.querySelectorAll('.icon')].forEach((icon, index) => {\n      const iconParentEl = icon.parentElement;\n      if (iconParentEl.children.length === 1 && index === 0) {\n        icon.classList.add('top-icon');\n        iconParentEl.replaceWith(icon);\n      }\n    });\n\n    const prevEl = headings[0]?.previousElementSibling;\n    const pretitleText = prevEl && !prevEl.classList.contains('icon') && prevEl.textContent;\n\n    if (pretitleText) {\n      const pretitle = createElement('span', { classes: 'pretitle' });\n      pretitle.textContent = pretitleText;\n      prevEl.replaceWith(pretitle);\n    }\n  });\n\n  const headings = [...block.querySelectorAll('h3, h4, h5, h6')];\n  const h2List = [...block.querySelectorAll('h2')];\n\n  headings.forEach((h) => {\n    h.classList.add('h5');\n    h.classList.remove('h2');\n  });\n\n  h2List.forEach((h) => {\n    h.classList.add('with-marker', 'h2');\n    h.classList.remove('h1');\n    h.closest(`.${blockName}__column`)?.classList.add(`${blockName}__column--main`);\n  });\n\n  // replacing headings (h3, h4, h5, h6) with strong so the block will not break semantic\n  // (example breaking semantic: col 1 -> h5, col 2 -> h2)\n  headings.forEach((heading) => {\n    const newHeadingEl = createElement('strong', { classes: [...heading.classList] });\n    newHeadingEl.innerHTML = heading.innerHTML;\n    heading.replaceWith(newHeadingEl);\n  });\n}\n","import { createElement, variantsClassesToBEM } from '../../scripts/common.js';\n\nconst blockName = 'v2-iframe';\nconst variantClasses = ['fullscreen'];\n\n/**\n * Returns the first class name matching the provided RegExp.\n *\n * @param {DOMTokenList} classList\n * @param {RegExp} pattern\n * @returns {string|null}\n */\nconst findClass = (classList, pattern) => [...classList].find((cls) => pattern.test(cls)) || null;\n\n/**\n * Extracts a fixed height value from block classes (e.g. \"600px\").\n *\n * @param {HTMLElement} block\n * @returns {string|null}\n */\nconst getFixedHeight = (block) => findClass(block.classList, /^[0-9]+px$/);\n\n/**\n * Extracts a max-width value from block classes (e.g. \"width-800px\").\n *\n * @param {HTMLElement} block\n * @returns {string|null}\n */\nconst getMaxWidth = (block) => findClass(block.classList, /^width-[0-9]+px$/)?.replace('width-', '') || null;\n\n/**\n * Enables fullscreen mode for the iframe block.\n *\n * Adds:\n *  - `${blockName}-container--fullscreen` to the block container\n *  - `${blockName}-fullscreen` to the document body\n *\n * @param {HTMLElement} block\n */\nconst enableFullscreenMode = (block) => {\n  const container = block.closest(`.${blockName}-container`);\n  if (container) {\n    container.classList.add(`${blockName}-container--fullscreen`);\n  }\n  document.body.classList.add(`${blockName}-fullscreen`);\n};\n\n/**\n * Creates an iframe element with default configuration.\n *\n * @param {string} src\n * @returns {HTMLIFrameElement}\n */\nconst createIframe = (src) =>\n  createElement('iframe', {\n    props: {\n      src,\n      frameborder: 0,\n      loading: 'lazy',\n    },\n  });\n\nexport default async function decorate(block) {\n  variantsClassesToBEM(block.classList, variantClasses, blockName);\n\n  const isFullscreen = block.classList.contains(`${blockName}--fullscreen`);\n  const src = block.querySelector('a')?.getAttribute('href') || '';\n\n  const iframe = createIframe(src);\n\n  if (!isFullscreen) {\n    const fixedHeight = getFixedHeight(block);\n    const maxWidth = getMaxWidth(block);\n\n    if (fixedHeight) {\n      iframe.height = fixedHeight;\n    }\n\n    if (maxWidth) {\n      iframe.style.maxWidth = maxWidth;\n    }\n  } else {\n    enableFullscreenMode(block);\n  }\n\n  block.replaceChildren(iframe);\n}\n","import { unwrapDivs, variantsClassesToBEM, debounce } from '../../scripts/common.js';\n\nconst variantClasses = ['16-9', '4-3'];\nconst blockName = 'v2-image-banner';\n\n/**\n * Finds the matching source element based on the media query.\n * @param {HTMLElement} picture - The picture element containing the sources.\n * @returns {HTMLElement|null} The matching source element or null if none found.\n */\nconst findMatchingSource = (picture) => {\n  const sources = Array.from(picture.querySelectorAll('source'));\n  return sources.find((source) => {\n    const media = source.getAttribute('media');\n    return !media || window.matchMedia(media).matches;\n  });\n};\n\n/**\n * Retrieves the image source URL from a block element.\n * @param {HTMLElement} block - The block element containing the picture.\n * @returns {string} The image source URL.\n */\nconst getImgSrc = (block) => {\n  const picture = block.querySelector('picture');\n  if (!picture) {\n    return '';\n  }\n\n  const matchingSource = findMatchingSource(picture);\n  if (matchingSource) {\n    return matchingSource.getAttribute('srcset');\n  }\n\n  const img = picture.querySelector('img');\n  return img ? img.getAttribute('src') : '';\n};\n\n/**\n * Sets the background image of a block element.\n * @param {HTMLElement} block - The block element to set the background image for.\n * @param {string} imgSrc - The image source URL.\n */\nconst setImgSrc = (block, imgSrc) => {\n  block.style.backgroundImage = `url(${imgSrc})`;\n};\n\n/**\n * Updates the image source if the media query has changed.\n * @param {HTMLElement} block - The block element to update.\n * @param {string} currentMediaQuery - The current media query.\n * @returns {string} The new media query.\n */\nconst updateImageSrc = (block, currentMediaQuery) => {\n  const picture = block.querySelector('picture');\n  if (!picture) {\n    return currentMediaQuery;\n  }\n\n  const matchingSource = findMatchingSource(picture);\n  const newMediaQuery = matchingSource ? matchingSource.getAttribute('media') : '';\n  if (newMediaQuery !== currentMediaQuery) {\n    const newImgSrc = matchingSource ? matchingSource.getAttribute('srcset') : picture.querySelector('img').getAttribute('src');\n    setImgSrc(block, newImgSrc);\n    return newMediaQuery;\n  }\n\n  return currentMediaQuery;\n};\n\n/**\n * Initializes a ResizeObserver to update the background image URL based on the block's size.\n * @param {HTMLElement} block - The block element to observe.\n */\nconst initResizeObserver = (block) => {\n  let currentMediaQuery = '';\n\n  const debouncedUpdateImageSrc = debounce(() => {\n    currentMediaQuery = updateImageSrc(block, currentMediaQuery);\n  }, 100);\n\n  const resizeObserver = new ResizeObserver(debouncedUpdateImageSrc);\n  resizeObserver.observe(block);\n};\n\n/**\n * Decorates the block element with the appropriate classes and background image.\n * @param {HTMLElement} block - The block element to decorate.\n */\nexport default async function decorate(block) {\n  variantsClassesToBEM(block.classList, variantClasses, blockName);\n  block.parentElement.classList.add('full-width');\n\n  const imgSrc = getImgSrc(block);\n  if (imgSrc) {\n    setImgSrc(block, imgSrc);\n  }\n\n  initResizeObserver(block);\n  unwrapDivs(block);\n}\n","import { createOptimizedPicture } from '../../scripts/aem.js';\nimport { createElement, removeEmptyTags, getTextLabel, debounce, decorateIcons, variantsClassesToBEM } from '../../scripts/common.js';\nimport { getAllElWithChildren } from '../../scripts/scripts.js';\nimport { showModal } from '../../common/modal/modal-component.js';\n\nconst blockName = 'v2-images-grid';\nconst variantClasses = ['with-captions'];\n\nconst scrollLeft = (el, leftPadding, behavior = 'smooth') => {\n  el.scrollTo({\n    left: leftPadding,\n    behavior,\n  });\n};\n\nconst udpateArrowsState = (activeSlideIndex, itemsCount) => {\n  const arrowButtons = [...document.querySelectorAll(`.${blockName}__modal-arrows-wrapper button`)];\n\n  if (!arrowButtons.length) {\n    return;\n  }\n\n  if (activeSlideIndex === 0) {\n    arrowButtons[0].setAttribute('disabled', 'disabled');\n  } else {\n    arrowButtons[0].removeAttribute('disabled');\n  }\n\n  if (activeSlideIndex === itemsCount - 1) {\n    arrowButtons[1].setAttribute('disabled', 'disabled');\n  } else {\n    arrowButtons[1].removeAttribute('disabled');\n  }\n};\n\nconst setActiveSlide = (activeSlideIndex, carouselItemsList, carouselImagesList, modalContent, behavior) => {\n  const itemWidth = carouselItemsList.getBoundingClientRect().width;\n\n  udpateArrowsState(activeSlideIndex, carouselItemsList.children.length, modalContent);\n\n  scrollLeft(carouselImagesList, activeSlideIndex * 90, behavior);\n  scrollLeft(carouselItemsList, activeSlideIndex * itemWidth, behavior);\n};\n\nconst createModalContent = (content) => {\n  const carouselItemsList = createElement('ul', { classes: `${blockName}__carousel-items-list` });\n  const carouselImagesList = createElement('ul', { classes: `${blockName}__carousel-preview-list` });\n\n  let isScrolling = false;\n  let stopScrolling;\n\n  carouselItemsList.addEventListener('scroll', () => {\n    isScrolling = true;\n\n    clearTimeout(stopScrolling);\n    stopScrolling = setTimeout(() => {\n      isScrolling = false;\n    }, 50);\n  });\n\n  const debouncedOnItemChange = debounce((index) => {\n    if (isScrolling) {\n      return;\n    }\n\n    scrollLeft(carouselImagesList, index * 90);\n  }, 100);\n\n  [...content.querySelectorAll('.v2-images-grid__item')].forEach((el, index) => {\n    const image = el.querySelector('img');\n\n    // adding image to carousel preview\n    const carouselImage = createOptimizedPicture(image.src, image.alt, false, [{ width: '80' }]);\n    const carousePreviewlItem = createElement('li', { classes: `${blockName}__carousel-preview-item` });\n    const buttonWithImage = createElement('button');\n\n    buttonWithImage.addEventListener('click', () => {\n      const itemWidth = carouselItemsList.getBoundingClientRect().width;\n\n      scrollLeft(carouselItemsList, index * itemWidth);\n    });\n\n    buttonWithImage.append(carouselImage);\n    carousePreviewlItem.append(buttonWithImage);\n    carouselImagesList.append(carousePreviewlItem);\n\n    // creating item content\n    const itemImage = createOptimizedPicture(image.src, image.alt, false);\n    const [, caption, description] = el.querySelectorAll('p');\n    const carouselItem = createElement('li', { classes: `${blockName}__carousel-item` });\n\n    carouselItem.append(itemImage, description || caption);\n    carouselItemsList.append(carouselItem);\n\n    const options = {\n      root: carouselItemsList,\n      rootMargin: '0px',\n      threshold: 1.0,\n    };\n\n    const observer = new IntersectionObserver((entries) => {\n      if (!entries[0].isIntersecting) {\n        return;\n      }\n\n      debouncedOnItemChange(index);\n\n      udpateArrowsState(index, carouselItemsList.children.length, el.closest(`${blockName}__carousel-items-wrapper`));\n    }, options);\n\n    observer.observe(carouselItem);\n  });\n\n  const itemsWrapper = createElement('div', { classes: `${blockName}__carousel-items-wrapper` });\n  const wrapper = createElement('div', { classes: `${blockName}__modal-content` });\n\n  itemsWrapper.innerHTML = `<div class=\"${blockName}__modal-arrows-wrapper\">\n    <button class=\"${blockName}__modal-arrow\" aria-label=\"${getTextLabel('v2_images_grid:previous')}\">\n      <span class=\"icon icon-arrow-left\" />\n    </button>\n    <button class=\"${blockName}__modal-arrow\" aria-label=\"${getTextLabel('v2_images_grid:next')}\">\n      <span class=\"icon icon-arrow-right\" />\n    </button>\n  </div>`;\n  itemsWrapper.append(carouselItemsList);\n\n  [...itemsWrapper.querySelectorAll('button')].forEach((el, elIndex) => {\n    const modifiers = [-1, 1];\n\n    el.addEventListener('click', () => {\n      const itemWidth = carouselItemsList.getBoundingClientRect().width;\n      const index = Math.round(carouselItemsList.scrollLeft / itemWidth) + modifiers[elIndex];\n\n      setActiveSlide(index, carouselItemsList, carouselImagesList, content);\n    });\n  });\n\n  decorateIcons(itemsWrapper);\n\n  wrapper.append(itemsWrapper, carouselImagesList);\n\n  return wrapper;\n};\n\nconst showImagesGridModal = async (modalContent) => {\n  await showModal(modalContent, { classes: ['modal-content--bottom'] });\n};\n\nconst buildOverlayFragment = (captionText) => {\n  return document.createRange().createContextualFragment(`\n    <button class=\"${blockName}__btn ${blockName}__info-btn\" aria-label=\"${getTextLabel('v2_images_grid:image_info_open_aria_label')}\" aria-haspopup=\"dialog\" aria-expanded=\"false\">\n      <span class=\"icon icon-info\" aria-hidden=\"true\">Info</span>\n    </button>\n    <div class=\"${blockName}__caption-panel\" hidden role=\"dialog\" aria-label=\"${getTextLabel('v2_images_grid:image_info_dialog_aria_label')}\">\n      <p class=\"${blockName}__caption-text\">${captionText}</p>\n    </div>\n    <button class=\"${blockName}__btn ${blockName}__close-btn\" hidden aria-label=\"${getTextLabel('v2_images_grid:image_info_close_aria_label')}\">\n      <span class=\"icon icon-close\" aria-hidden=\"true\">Close</span>\n    </button>\n  `);\n};\n\nconst attachOverlayEvents = (container) => {\n  const infoBtn = container.querySelector(`.${blockName}__info-btn`);\n  const captionPanel = container.querySelector(`.${blockName}__caption-panel`);\n  const closeBtn = container.querySelector(`.${blockName}__close-btn`);\n\n  infoBtn?.addEventListener('click', (e) => {\n    e.stopPropagation();\n    captionPanel.removeAttribute('hidden');\n    closeBtn.removeAttribute('hidden');\n    infoBtn.setAttribute('aria-expanded', 'true');\n    infoBtn.style.display = 'none';\n  });\n\n  closeBtn?.addEventListener('click', (e) => {\n    e.stopPropagation();\n    captionPanel.setAttribute('hidden', 'true');\n    closeBtn.setAttribute('hidden', 'true');\n    infoBtn.setAttribute('aria-expanded', 'false');\n    infoBtn.style.display = 'block';\n  });\n};\n\nconst createCaptionOverlay = (captionText) => {\n  const overlay = createElement('div', { classes: `${blockName}__overlay` });\n  overlay.append(buildOverlayFragment(captionText));\n  attachOverlayEvents(overlay);\n  return overlay;\n};\n\nexport default function decorate(block) {\n  variantsClassesToBEM(block.classList, variantClasses, blockName);\n  const isCaptionsVariant = block.classList.contains(`${blockName}--with-captions`);\n\n  // all items are inside a ul list with classname called 'v2-images-grid__items'\n  const ul = createElement('ul', { classes: `${blockName}__items` });\n  [...block.querySelectorAll(':scope > div > div')].forEach((cell) => {\n    // If cell contain any element, we add them in the ul\n    if (cell.childElementCount) {\n      const li = createElement('li', { classes: `${blockName}__item` });\n      li.append(...cell.childNodes);\n      ul.append(li);\n    }\n    cell.remove();\n  });\n  if (isCaptionsVariant) {\n    const amountOfItems = ul.querySelectorAll('li').length;\n    ul.classList.add(`${blockName}__${amountOfItems}-items`);\n  }\n  block.append(ul);\n\n  const modalContent = !isCaptionsVariant && createModalContent(ul);\n\n  // give format to the first 4 list items\n  [...ul.children].forEach((li, idx) => {\n    if (idx < 4) {\n      const captionEle = getAllElWithChildren(li.querySelectorAll('p'), 'picture', true)[0];\n      let picture = li.querySelector('picture');\n      let overlay;\n\n      if (picture) {\n        const img = picture.lastElementChild;\n        // no width provided because we are using object-fit, we need the biggest option\n        const newPicture = createOptimizedPicture(img.src, captionEle?.textContent, false);\n        picture.replaceWith(newPicture);\n        picture = newPicture;\n        picture.classList.add(`${blockName}__picture`);\n        // use figcaption for text\n        const figCaption = createElement('figcaption', { classes: `${blockName}__figcaption` });\n        figCaption.textContent = captionEle?.textContent;\n        picture.append(figCaption);\n        overlay = createCaptionOverlay(captionEle?.textContent);\n      }\n\n      li.innerHTML = '';\n      li.append(picture, overlay);\n\n      if (!isCaptionsVariant) {\n        li.addEventListener('click', async () => {\n          const carouselItemsList = modalContent.querySelector(`.${blockName}__carousel-items-list`);\n          const carouselImagesList = modalContent.querySelector(`.${blockName}__carousel-preview-list`);\n\n          await showImagesGridModal(modalContent);\n          setActiveSlide(idx, carouselItemsList, carouselImagesList, modalContent, 'instant');\n        });\n      }\n      return;\n    }\n    li.remove();\n  });\n\n  if (!isCaptionsVariant) {\n    const button = createElement('a', {\n      classes: ['button', 'button--large', 'button--primary'],\n    });\n    button.textContent = getTextLabel('v2_images_grid:button_text');\n    button.addEventListener('click', async () => {\n      const carouselItemsList = modalContent.querySelector(`.${blockName}__carousel-items-list`);\n      const carouselImagesList = modalContent.querySelector(`.${blockName}__carousel-preview-list`);\n\n      await showImagesGridModal(modalContent);\n      setActiveSlide(0, carouselItemsList, carouselImagesList, modalContent);\n    });\n\n    block.append(button);\n  }\n\n  decorateIcons(block);\n  removeEmptyTags(block);\n}\n","import { getMetadata } from '../../scripts/aem.js';\nimport { createElement, debounce, decorateIcons } from '../../scripts/common.js';\n\nconst blockName = 'v2-inpage-navigation';\n\nconst scrollToSection = (id) => {\n  let timeout;\n\n  const container = document.querySelector(`main .section[data-inpageid='${id}']`);\n  container?.scrollIntoView({ behavior: 'smooth' });\n\n  // Checking if the height of the main element changes while scrolling (caused by layout shift)\n  const main = document.querySelector('main');\n  const resizeObserver = new ResizeObserver(() => {\n    clearTimeout(timeout);\n    container?.scrollIntoView({ behavior: 'smooth' });\n\n    timeout = setTimeout(() => {\n      resizeObserver.disconnect();\n    }, 500);\n  });\n  resizeObserver.observe(main);\n};\n\nconst inpageNavigationButton = () => {\n  // if we have a button title & button link\n  if (getMetadata('inpage-button') && getMetadata('inpage-link')) {\n    const titleMobile = getMetadata('inpage-button');\n    const url = getMetadata('inpage-link');\n    const link = createElement('a', {\n      classes: ['button', 'button--large', 'button--red', `${blockName}__cta`],\n      props: {\n        href: url,\n        title: titleMobile,\n      },\n    });\n    const mobileText = createElement('span', { classes: `${blockName}__cta--mobile` });\n    mobileText.textContent = titleMobile;\n    link.appendChild(mobileText);\n\n    const titleDesktop = getMetadata('inpage-button-large');\n    if (titleDesktop) {\n      const desktopText = createElement('span', { classes: `${blockName}__cta--desktop` });\n      desktopText.textContent = titleDesktop;\n      link.setAttribute('title', titleDesktop);\n      link.appendChild(desktopText);\n    }\n\n    return link;\n  }\n\n  return null;\n};\n\n// Retrieve an array of sections with its corresponding intersectionRatio\nconst wrapSectionItems = (elements) => {\n  const elementsData = [];\n  const viewportHeight = window.innerHeight;\n  elements.forEach((item) => {\n    const elementRect = item.getBoundingClientRect();\n\n    // Calculate the vertical space occupied by the element within the viewport\n    const verticalSpace = Math.min(elementRect.bottom, viewportHeight) - Math.max(elementRect.top, 0);\n\n    // Calculate the ratio of vertical space to the viewport height\n    const spaceRatio = verticalSpace / viewportHeight;\n\n    elementsData.push({\n      element: item,\n      intersectionRatio: Math.max(0, Math.min(1, spaceRatio)),\n    });\n  });\n\n  return elementsData;\n};\n\nconst gotoSection = (event) => {\n  const { target } = event;\n  const button = target.closest('button');\n\n  if (button) {\n    const { id } = button.dataset;\n\n    scrollToSection(id);\n  }\n};\n\nconst updateActive = (id) => {\n  const activeItemInList = document.querySelector(`.${blockName}__item--active`);\n\n  // Prevent reassign active value\n  if (activeItemInList?.firstElementChild?.dataset.id === id) {\n    return;\n  }\n\n  // Remove focus position\n  document.activeElement.blur();\n\n  // check active id is equal to id don't do anything\n  const selectedItem = document.querySelector(`.${blockName}__selected-item`);\n  activeItemInList?.classList.remove(`${blockName}__item--active`);\n  const itemsButton = document.querySelectorAll(`.${blockName}__items button`);\n  const { pathname } = window.location;\n\n  if (id) {\n    const selectedButton = [...itemsButton].find((button) => button.dataset.id === id);\n    if (!selectedButton) {\n      return;\n    }\n    selectedItem.textContent = selectedButton.textContent;\n    selectedButton.parentNode.classList.add(`${blockName}__item--active`);\n\n    window.history.replaceState({}, '', `${pathname}#${id}`);\n  } else {\n    window.history.replaceState({}, '', `${pathname}`);\n  }\n};\n\nexport default async function decorate(block) {\n  const ctaButton = inpageNavigationButton();\n\n  const wrapper = block.querySelector(':scope > div');\n  wrapper.classList.add(`${blockName}__wrapper`);\n  const itemsWrapper = block.querySelector(':scope > div > div > p');\n\n  const dropdownWrapper = createElement('div', { classes: `${blockName}__dropdown` });\n  const selectedItemWrapper = createElement('div', { classes: `${blockName}__selected-item-wrapper` });\n  const selectedItem = createElement('div', { classes: `${blockName}__selected-item` });\n\n  const list = createElement('ul', { classes: `${blockName}__items` });\n\n  [...itemsWrapper.children].forEach((item, index) => {\n    const classes = [`${blockName}__item`];\n    if (index === 0) {\n      // Default selected item\n      classes.push(`${blockName}__item--active`);\n      selectedItem.textContent = item.textContent;\n    }\n    const listItem = createElement('li', { classes });\n\n    listItem.innerHTML = item.outerHTML;\n    list.appendChild(listItem);\n  });\n\n  const dropdownArrowIcon = createElement('span', { classes: [`${blockName}__icon`, 'icon', 'icon-dropdown-caret'] });\n  selectedItemWrapper.append(selectedItem);\n  selectedItemWrapper.appendChild(dropdownArrowIcon);\n\n  dropdownWrapper.append(selectedItemWrapper);\n  dropdownWrapper.append(list);\n  wrapper.append(dropdownWrapper);\n\n  itemsWrapper.remove();\n\n  if (ctaButton) {\n    wrapper.appendChild(ctaButton);\n  }\n\n  list.addEventListener('click', gotoSection);\n\n  // on load Go to section if defined\n  const hash = window.location.hash.substring(1);\n  if (hash) {\n    updateActive(hash);\n\n    setTimeout(() => {\n      scrollToSection(hash);\n    }, 1000);\n  }\n\n  // Listener to toggle the dropdown (open / close)\n  document.addEventListener('click', (e) => {\n    if (e.target.closest(`.${blockName}__selected-item-wrapper`)) {\n      dropdownWrapper.classList.toggle(`${blockName}__dropdown--open`);\n    } else {\n      dropdownWrapper.classList.remove(`${blockName}__dropdown--open`);\n    }\n  });\n\n  const sectionsList = document.querySelectorAll('main .section');\n  // listen scroll to change the url + navigation item\n  window.addEventListener(\n    'scroll',\n    debounce(() => {\n      // Calculate intersectionRatio from all section items\n      const elementsData = wrapSectionItems(sectionsList);\n\n      // Get intersected item that occupies most of the space in the viewport\n      const intersectedItem = elementsData.reduce((prev, current) => (prev.intersectionRatio > current.intersectionRatio ? prev : current));\n\n      if (intersectedItem.element.dataset?.inpageid) {\n        updateActive(intersectedItem.element.dataset.inpageid);\n      } else {\n        updateActive();\n      }\n\n      // detecting if the element inpage nav sticks to navigation\n      const navHeight = Number.parseInt(getComputedStyle(block).getPropertyValue('--nav-height'), 10);\n      const isStuck = block.getBoundingClientRect().top <= navHeight;\n      block.classList[isStuck ? 'add' : 'remove']('v2-inpage-navigation--stuck');\n    }),\n  );\n\n  decorateIcons(block);\n}\n","import { createElement, unwrapDivs } from '../../scripts/common.js';\n\nconst blockName = 'v2-intro-section';\n\nexport default function decorate(block) {\n  const content = block.querySelector(':scope > div > div:first-child');\n  const image = block.querySelector(':scope > div > div:nth-child(2) > picture');\n  const button = content.querySelector('.button-container');\n\n  const parent = block.parentElement;\n  parent.classList.add(button ? `${blockName}__with-button` : 'full-width');\n\n  content.classList.add(`${blockName}__text-content`);\n\n  const heading = content.querySelectorAll('h1, h2, h3, h4, h5, h6');\n  heading[0].classList.add(`${blockName}__heading`, button && 'with-marker');\n\n  if (button) {\n    const texts = createElement('div', { classes: `${blockName}__content` });\n    texts.append(content, button);\n    block.append(texts);\n  }\n\n  parent.prepend(image);\n  unwrapDivs(block);\n}\n","import { createElement, unwrapDivs, getTextLabel, decorateIcons } from '../../scripts/common.js';\nimport { fetchMagazineData, formatArticlesArray } from '../../scripts/services/magazine.service.js';\nimport { setCarouselPosition, listenScroll } from '../../scripts/carousel-helper.js';\nimport { isVideoLink, createVideo } from '../../scripts/video-helper.js';\n\nconst blockName = 'v2-magazine-tabbed-carousel';\nconst activeTabClass = `${blockName}__navigation-item--active`;\nconst activeCarouselClass = `${blockName}__carousel-item--active`;\n\nlet autoScrollEnabled = true;\nconst maxAmountOfTabs = 4;\n\nconst queryVariables = { facets: [] };\nconst allMagazineData = await fetchMagazineData(queryVariables);\nconst allArticles = formatArticlesArray(allMagazineData?.items);\n\nlet activeVideo = null;\n\nconst handleVideoAutoplay = (carouselItem, index) => {\n  if (!carouselItem || !carouselItem.children[index]) {\n    return;\n  }\n\n  const currentVideo = carouselItem.children[index].querySelector('video');\n\n  if (currentVideo) {\n    if (activeVideo && activeVideo !== currentVideo) {\n      activeVideo.pause();\n    }\n    currentVideo.play();\n    activeVideo = currentVideo;\n  } else if (activeVideo) {\n    activeVideo.pause();\n    activeVideo = null;\n  }\n};\n\nconst updateActiveItem = (elements, entry) => {\n  elements.forEach((el, index) => {\n    if (el === entry.target && entry.intersectionRatio >= 0.75) {\n      const carouselItems = el.parentElement;\n      const navigation = el.parentElement.nextElementSibling;\n\n      [carouselItems, navigation].forEach((c) => {\n        c.querySelectorAll(`.${activeTabClass}, .${activeCarouselClass}`).forEach((i) => {\n          i.classList.remove(`${activeTabClass}`, `${activeCarouselClass}`);\n        });\n      });\n      carouselItems.children[index].classList.add(activeCarouselClass);\n      navigation.children[index].classList.add(activeTabClass);\n\n      // Center navigation item\n      const navigationActiveItem = navigation.querySelector(`.${activeTabClass}`);\n\n      if (navigation && navigationActiveItem) {\n        const { clientWidth: itemWidth, offsetLeft } = navigationActiveItem;\n        // Calculate the scroll position to center the active item\n        const scrollPosition = offsetLeft - (navigation.clientWidth - itemWidth) / 2;\n        navigation.scrollTo({\n          left: scrollPosition,\n          behavior: 'smooth',\n        });\n      }\n\n      handleVideoAutoplay(carouselItems, index);\n    }\n  });\n};\n\nconst buildTabNavigation = (carousel, title, category, index) => {\n  const item = document.createRange().createContextualFragment(`\n    <button tabindex=\"0\" class=\"${blockName}__navigation-item item-${index + 1}\">\n      <p class=\"pretitle\">${category}</p>\n      <p class=\"title\">${title}</p>\n    </button>\n  `);\n  item.querySelector('button').addEventListener('click', () => setCarouselPosition(carousel, index));\n\n  return item;\n};\n\nconst appendMediaToFigure = (figure, picture, links) => {\n  if (picture) {\n    figure.append(picture);\n  } else {\n    const videoLink = Array.from(links).find((link) => link.classList.contains('text-link-with-video'));\n    const isVideo = videoLink ? isVideoLink(videoLink) : false;\n    if (isVideo) {\n      createVideo(figure, videoLink.getAttribute('href'), `${blockName}__video`, {\n        muted: true,\n        autoplay: false,\n        loop: true,\n        playsinline: true,\n      });\n      videoLink.remove();\n    }\n  }\n};\n\nconst buildTabItems = (carousel, navigation, items, articles) => {\n  items.forEach((item, index) => {\n    if (index <= maxAmountOfTabs - 1) {\n      const picture = item.querySelector('picture');\n      const links = item.querySelectorAll('a');\n      const tabContent = Array.from(links).find((link) => !link.classList.contains('text-link-with-video'));\n      const articlePath = tabContent.href;\n\n      const liItem = createElement('li', { classes: [`${blockName}__item`, `item-${index + 1}`] });\n      const figure = createElement('figure', { classes: `${blockName}__figure` });\n\n      appendMediaToFigure(figure, picture, links);\n\n      const figureCaption = createElement('figcaption');\n      figureCaption.append(tabContent);\n      figure.append(figureCaption);\n\n      liItem.append(figure);\n      carousel.appendChild(liItem);\n\n      const fullArticleObj = articles.find((path) => {\n        const shortUrl = articlePath.split('/magazine/')[1];\n        const shortPath = path.path.split('/magazine/')[1];\n        return shortPath === shortUrl;\n      });\n\n      // Gracefully handle missing article data\n      if (!fullArticleObj) {\n        console.warn(`Article data not found for path: ${articlePath}`);\n        return;\n      }\n\n      const { title, category } = fullArticleObj;\n\n      const navItem = buildTabNavigation(carousel, title, category, index);\n      navigation.append(navItem);\n    }\n    item.innerHTML = '';\n  });\n};\n\nconst autoScrollFunction = (container) => {\n  const amountOfSlides = container.querySelectorAll(`.${blockName}__item`).length;\n  const activeSlide = container.querySelector(`.${activeCarouselClass}`);\n  const classlistArray = [...activeSlide.classList];\n  const item = classlistArray.find((el) => el.slice(0, 5) === 'item-');\n  const itemNum = Number(item.split('-')[1]);\n\n  activeSlide.classList.remove(`${activeCarouselClass}`);\n\n  const nextNum = itemNum === amountOfSlides ? 1 : itemNum + 1;\n  const nextSlide = container.querySelector(`.item-${nextNum}`);\n\n  nextSlide.classList.add(`${activeCarouselClass}`);\n  if (nextSlide.classList.contains(`${blockName}__item`)) {\n    const itemsContainer = nextSlide.parentElement;\n    const { x: itemWidth } = nextSlide.getBoundingClientRect();\n    itemsContainer.scrollLeft += itemWidth;\n  }\n};\n\nconst handleSwitch = (e, setAutoScroll) => {\n  const slider = e.target.parentElement.querySelector('.switch-slider');\n  const isOff = e.target.matches('[data-autoscroll=\"off\"]');\n  if (autoScrollEnabled === isOff) {\n    autoScrollEnabled = !isOff;\n  }\n  slider.style.left = isOff ? '53px' : '0';\n  setAutoScroll(autoScrollEnabled);\n};\n\nexport default async function decorate(block) {\n  let isFirstLoad = true;\n  let scrollIntervalID;\n  const carouselContainerSection = block.closest('.section.v2-magazine-tabbed-carousel-container');\n  const intervalTime = parseInt(carouselContainerSection?.dataset.magazineTabbedCarouselIntervalTime || '6000', 10);\n\n  const switchFullTexts = getTextLabel('v2_magazine_tabbed_carousel:switch_text');\n\n  const carouselContainer = createElement('div', { classes: `${blockName}__container` });\n  const carouselItems = createElement('ul', { classes: `${blockName}__items` });\n  carouselContainer.append(carouselItems);\n\n  const tabNavigation = createElement('nav', { classes: `${blockName}__navigation` });\n\n  const tabItems = block.querySelectorAll(':scope > div');\n\n  buildTabItems(carouselItems, tabNavigation, tabItems, allArticles);\n\n  const handleAutoScroll = (isEnabled) => {\n    if (isEnabled) {\n      scrollIntervalID = setInterval(() => {\n        autoScrollFunction(carouselContainer);\n      }, intervalTime);\n    } else {\n      clearInterval(scrollIntervalID);\n      scrollIntervalID = null;\n    }\n  };\n\n  const switchSplittedTexts = switchFullTexts.split(',');\n  const autoScrollSwitch = document.createRange().createContextualFragment(`\n    <div class=\"switch\">\n      <p class=\"switch-label\">${switchSplittedTexts[0]}</p>\n      <div class=\"switch-buttons\">\n        <button>${switchSplittedTexts[1]}</button>\n        <button data-autoscroll=\"off\">${switchSplittedTexts[2]}</button>\n        <div class=\"switch-slider\"></div>\n      </div>\n    </div>\n  `);\n\n  autoScrollSwitch.querySelectorAll('button').forEach((btn) => btn.addEventListener('click', (e) => handleSwitch(e, handleAutoScroll)));\n\n  carouselContainer.append(tabNavigation);\n\n  block.parentElement.classList.add('full-width');\n  block.append(carouselContainer);\n\n  if (isFirstLoad && !window.matchMedia('(prefers-reduced-motion: reduce)').matches) {\n    carouselContainer.append(autoScrollSwitch);\n    handleAutoScroll(autoScrollEnabled);\n    isFirstLoad = false;\n  }\n\n  // update the button indicator on scroll\n  const elements = carouselItems.querySelectorAll(':scope > *');\n  listenScroll(carouselItems, elements, updateActiveItem, 0.75);\n  unwrapDivs(block);\n  decorateIcons(block);\n}\n","import { variantsClassesToBEM, createElement, unwrapDivs } from '../../scripts/common.js';\n\nexport default async function decorate(block) {\n  const blockName = 'v2-media-with-content';\n  const variantClasses = ['with-icons'];\n  variantsClassesToBEM(block.classList, variantClasses, blockName);\n\n  const contentWrapper = block.querySelector(':scope > div');\n  contentWrapper.classList.add(`${blockName}__content-wrapper`);\n\n  const content = [...block.querySelectorAll(':scope > div > div')];\n  content.forEach((col) => {\n    col.classList.add(`${blockName}__column`);\n    if (col.firstElementChild.tagName === 'PICTURE') {\n      col.classList.add('column-with-image');\n    } else {\n      col.classList.add('column-with-text');\n    }\n  });\n\n  if (content[1].firstElementChild.tagName === 'PICTURE') {\n    contentWrapper.classList.add(`${blockName}__content-wrapper--image-right`);\n  }\n\n  const header = [...block.querySelectorAll('h1, h2, h3, h4, h5, h6')];\n  header.forEach((h) => {\n    h.classList.add(`${blockName}__title`);\n  });\n\n  const text = [...block.querySelectorAll('p')];\n  text.forEach((t) => {\n    t.classList.add(`${blockName}__text`);\n  });\n\n  if (block.classList.contains(`${blockName}--with-icons`)) {\n    const iconList = block.querySelector('ul');\n    iconList.classList.add(`${blockName}__icon-list`);\n\n    const items = iconList.querySelectorAll('li');\n    items.forEach((item) => {\n      item.classList.add(`${blockName}__list-item`);\n      const image = item.querySelector('picture');\n      const figure = createElement('figure');\n      const pElmt = createElement('figcaption');\n      const liText = item.innerText.trim();\n      pElmt.textContent = liText;\n\n      if (image) {\n        figure.append(image);\n      }\n\n      figure.append(pElmt);\n      item.textContent = '';\n      item.append(figure);\n    });\n  }\n\n  unwrapDivs(block);\n}\n","import { unwrapDivs, variantsClassesToBEM } from '../../scripts/common.js';\n\nconst blockName = 'v2-navigation-hub';\nconst variantClasses = ['media-left', 'media-right', 'overlap'];\nconst blockNames = {\n  column: `${blockName}__column`,\n  card: `${blockName}__card-container`,\n  cardContent: `${blockName}__card-content`,\n  cardNavigation: `${blockName}__card-navigation`,\n  cardNavTitle: `${blockName}__card-nav-title`,\n  cardNavList: `${blockName}__card-nav-list`,\n  media: `${blockName}__media-container`,\n  mediaRight: `${blockName}__media-right`,\n  mediaLeft: `${blockName}__media-left`,\n  mediaImage: `${blockName}__image`,\n};\n\nexport default function decorate(block) {\n  variantsClassesToBEM(block.classList, variantClasses, blockName);\n  const blockWrapper = block.closest(`.${blockName}-wrapper`);\n  // Card elements\n  const cardContainer = block.querySelector(':scope > div:first-child');\n  const cardContent = cardContainer.querySelector(':scope > div:first-child');\n  const cardButton = cardContent.querySelector(':scope .button-container a');\n  const cardNavigation = cardContainer.querySelector(':scope > div:last-child');\n  const cardNavTitle = cardNavigation.querySelector(':scope > :first-child');\n  const cardNavList = cardNavigation.querySelector(':scope > ul');\n  const cardNavLinks = [...cardNavList.querySelectorAll('a')];\n  // Media element\n  const mediaContainer = block.querySelector(':scope > div:last-child');\n  const mediaImage = mediaContainer.querySelector('img');\n  const isMediaLeft = mediaContainer.firstElementChild.children.length > 0;\n  // By default, media is on the left side\n  const mediaPosition = isMediaLeft ? blockNames.mediaLeft : blockNames.mediaRight;\n\n  blockWrapper.classList.add('full-width');\n  cardContainer.className = `${blockNames.card} ${blockNames.column}`;\n  cardContent.className = blockNames.cardContent;\n  cardButton.classList.add('button--large');\n  cardNavigation.className = blockNames.cardNavigation;\n  cardNavTitle.className = blockNames.cardNavTitle;\n  cardNavList.className = blockNames.cardNavList;\n  cardNavLinks.forEach((link) => {\n    link.className = 'standalone-link';\n  });\n  mediaContainer.className = `${blockNames.media} ${blockNames.column}`;\n  mediaImage.className = blockNames.mediaImage;\n\n  block.classList.add(mediaPosition);\n\n  unwrapDivs(mediaContainer);\n}\n","import { loadBlock, sampleRUM } from '../../scripts/aem.js';\nimport { createElement } from '../../scripts/common.js';\n\nconst blockName = 'v2-newsletter';\nexport const logResults = {\n  success: 'success',\n  error: 'error',\n};\nlet thanksMessageEl;\nlet errorMessageEl;\n\n//* init response handling *\nasync function handleSubmissionResult(isSuccess) {\n  const form = document.querySelector('form[data-submitting=true]');\n  const message = isSuccess ? thanksMessageEl : errorMessageEl;\n  message.className = `${blockName}__message`;\n\n  if (isSuccess) {\n    sampleRUM('form:submit');\n  }\n\n  form.setAttribute('data-submitting', 'false');\n  form.replaceWith(message);\n}\n//* end response handling *\n\nwindow.logResult = function logResult(json) {\n  handleSubmissionResult(json.result === logResults.success);\n};\n\nexport default async function decorate(block) {\n  const formLink = block.firstElementChild.innerText.trim();\n  const thanksEl = block.firstElementChild.nextElementSibling.firstElementChild;\n  const errorEl = block.lastElementChild.firstElementChild;\n\n  const container = createElement('div', { classes: `${blockName}__container` });\n\n  thanksMessageEl = thanksEl.cloneNode(true);\n  errorMessageEl = errorEl.cloneNode(true);\n  thanksEl.remove();\n  errorEl.remove();\n\n  const form = document.createRange().createContextualFragment(`\n    <div class=\"v2-forms block\" data-block-name=\"v2-forms\" data-block-status=\"\" data-force-load=\"true\">\n      <div>\n        <div>subscribe</div>\n      </div>\n      <div>\n        <div>${formLink}</div>\n      </div>\n    </div>`);\n\n  container.append(...form.children);\n\n  await loadBlock(container.querySelector('.v2-forms'));\n\n  const newBlock = createElement('div', { classes: `${blockName}` });\n  newBlock.append(container);\n\n  block.replaceWith(newBlock);\n}\n","import { getImageURLs, createResponsivePicture, variantsClassesToBEM, createElement } from '../../scripts/common.js';\n\nfunction addDataAttributes(element, block) {\n  const dataName = element.querySelector('div:first-child > p');\n  const dataValue = element.querySelector('div:last-child > p');\n  const segment = dataName ? dataName.innerText.trim().toLowerCase() : '';\n  const segmentValue = dataValue ? dataValue.innerText.trim().toLowerCase() : '';\n  if (segment && segmentValue) {\n    block.dataset[segment] = segmentValue;\n  }\n  element.remove();\n}\n\nexport default async function decorate(block) {\n  const blockName = 'v2-pencil-promo';\n  // variant pencil banner black is default\n  const variantClasses = ['pencil-banner-black', 'pencil-banner-copper', 'promo-banner-gold', 'promo-banner-copper', 'narrow-text'];\n  const indexVariant = variantClasses.findIndex((variant) => block.classList.contains(variant));\n  const currentVariant = (indexVariant >= 0 && variantClasses[indexVariant]) || variantClasses[0];\n  const isPencil = currentVariant.includes('pencil');\n  const dataSegment = block.querySelector(':scope > div:nth-child(2)');\n  const isFirstTab = block.querySelector(':scope > div:nth-child(3)');\n  variantsClassesToBEM(block.classList, variantClasses, blockName);\n\n  if (dataSegment) {\n    addDataAttributes(dataSegment, block);\n  }\n\n  if (isFirstTab) {\n    addDataAttributes(isFirstTab, block);\n  }\n\n  block.classList.add(`${blockName}__${isPencil ? 'pencil' : 'promo'}-banner`);\n  if (isPencil) {\n    const parent = block.parentElement;\n    parent.classList.add('full-width');\n    parent.classList.toggle(`${blockName}--hidden`, dataSegment && !isFirstTab);\n  } else {\n    block.classList.add(`${blockName}__promo-banner--with-image`);\n  }\n\n  const bannerImage = block.querySelector('picture');\n  if (isPencil && bannerImage !== null) {\n    bannerImage.remove();\n  } else if (!isPencil) {\n    const images = [...block.querySelectorAll('p > picture')];\n    const imageURLs = getImageURLs(images);\n    const imageData = imageURLs.map((src) => ({ src, breakpoints: [] }));\n\n    const breakpoints0 = [{ media: '(min-width: 600px)', width: 800 }, { width: 600 }];\n\n    const breakpoints1 = [\n      { media: '(min-width: 744px)', width: 800 },\n      { media: '(min-width: 1200px)', width: 1200 },\n      { media: '(min-width: 1440px)', width: 1440 },\n      { media: '(min-width: 1920px)', width: 1920 },\n    ];\n\n    if (images.length === 1) {\n      imageData[0].breakpoints = [...breakpoints0, ...breakpoints1];\n    } else if (images.length > 1) {\n      imageData[0].breakpoints = [...breakpoints0];\n      imageData[1].breakpoints = [...breakpoints1];\n    }\n\n    const altText = [...block.querySelectorAll('p > picture img.alt')];\n    const newPicture = createResponsivePicture(imageData, true, altText, `${blockName}__image`);\n    images.forEach((image) => image.parentNode.remove());\n\n    block.prepend(newPicture);\n  }\n\n  const contentWrapper = block.querySelector(':scope > div');\n  contentWrapper.classList.add(`${blockName}__content-wrapper`);\n\n  const content = block.querySelector(':scope > div > div');\n  content.classList.add(`${blockName}__content`);\n  if (content.querySelectorAll('p').length === 0) {\n    const p = createElement('p');\n    while (content.firstChild) {\n      p.appendChild(content.firstChild);\n    }\n    content.appendChild(p);\n  }\n\n  const ctaButtons = content.querySelectorAll('.button-container > a');\n  [...ctaButtons].forEach((b) => {\n    b.classList.remove('button', 'button--primary');\n    b.parentElement.classList.remove('button-container');\n    b.parentElement.removeAttribute('class');\n  });\n\n  const bannerLinks = block.querySelectorAll('a');\n\n  bannerLinks.forEach((link) => {\n    const closestParent = link.closest(`.${blockName}`);\n    closestParent.addEventListener('click', () => {\n      const linkHref = link.getAttribute('href');\n      if (linkHref) {\n        window.location.href = linkHref;\n      }\n    });\n  });\n}\n","import { createElement, getTextLabel, isMobileViewport } from '../../scripts/common.js';\n\nconst BLOCK_NAME = 'v2-picture-tooltips';\n\n/**\n * Extracts hotspot data from a given block element.\n *\n * This function processes a block element to extract information about hotspots.\n * Each hotspot is represented as an object containing its index, coordinates,ß\n * and text content. After extracting the hotspots, the function removes all\n * non-first child elements from the block.\n *\n * @param {HTMLElement} block - The block element containing hotspot data.\n * @returns {Array<Object>} An array of hotspot objects, where each object contains:\n *   - `index` {number}: The index of the hotspot.\n *   - `coords` {string}: The coordinates of the hotspot, extracted from the first child paragraph.\n *   - `textContent` {Array<HTMLElement>}: An array of child elements from the last child of the hotspot.\n */\nfunction extractHotSpotsFrom(block) {\n  const hotSpotsElements = Array.from(block.querySelectorAll(':scope > div')).slice(1);\n  const hotSpots = hotSpotsElements.map((hotSpot, index) => ({\n    index,\n    coords: hotSpot.querySelector(':scope > div:first-child p').textContent,\n    textContent: Array.from(hotSpot.querySelector(':scope > div:last-child').children),\n  }));\n\n  block.querySelectorAll(':scope > div:not(:first-child)').forEach((element) => {\n    element.remove();\n  });\n\n  return hotSpots;\n}\n\n/**\n * Generates a CSS style string for positioning based on given coordinates.\n *\n * @param {string} coords - A string representing coordinates in the format \"x:y\",\n *                          where `x` and `y` are percentages.\n * @returns {string} A CSS style string in the format \"left: x%; top: y%;\".\n */\nfunction getCoordsStyle(coords) {\n  const [x, y] = coords.split(':');\n\n  return `left: ${x}%; top: ${y}%`;\n}\n\nfunction getBottomStyleClass(coords) {\n  const [, y] = coords.split(':');\n\n  return y > 50 ? `${BLOCK_NAME}__tooltip--bottom` : '';\n}\n\n/**\n * Decorates a block element with hotspots and tooltips.\n *\n * @param {HTMLElement} block - The block element to decorate.\n * @param {Array<Object>} hotSpots - An array of hotspot objects to add to the block.\n * @param {string} hotSpots[].coords - The coordinates for the hotspot, used for positioning.\n * @param {Array<HTMLElement>} hotSpots[].textContent - An array of HTML elements representing the content of the tooltip.\n * @param {number} hotSpots[].index - The index of the hotspot, used for labeling.\n */\nfunction decorateBlockWithHotSpots(block, hotSpots) {\n  // Cell with the image:\n  const firstBlockCol = block.querySelector(':scope > div > div');\n  // Cell with the html text content:\n  const secondBlockCol = block.querySelector(':scope > div > div:nth-child(2)');\n  const firstBlockRow = block.querySelector(':scope > div');\n  const pictureWrapper = createElement('div', { classes: `${BLOCK_NAME}__picture-wrapper` });\n\n  if (!firstBlockCol) {\n    return;\n  }\n\n  firstBlockCol.classList.add(`${BLOCK_NAME}__picture-container`);\n  firstBlockCol.appendChild(pictureWrapper);\n\n  // Move all elements from the first block column to the picture wrapper\n  while (firstBlockCol.firstChild !== pictureWrapper) {\n    pictureWrapper.appendChild(firstBlockCol.firstChild);\n  }\n\n  const hotspotsTooltip = document.createElement('ol');\n  hotspotsTooltip.classList.add(`${BLOCK_NAME}__tooltips-wrapper`);\n  firstBlockRow.insertAdjacentElement('afterend', hotspotsTooltip);\n  firstBlockRow.classList.add(`${BLOCK_NAME}__main-wrapper`);\n\n  if (secondBlockCol) {\n    secondBlockCol.classList.add(`${BLOCK_NAME}__text-container`);\n    firstBlockRow.classList.add(`${BLOCK_NAME}__main-wrapper--two-columns`);\n  }\n\n  hotSpots.forEach((hotSpot, index) => {\n    pictureWrapper.insertAdjacentHTML(\n      'beforeend',\n      `\n        <div class=\"${BLOCK_NAME}__hotspot-wrapper ${index === 0 ? 'active' : ''}\" data-coords=\"${hotSpot.coords}\" style=\"${getCoordsStyle(hotSpot.coords)}\">\n          <button class=\"${BLOCK_NAME}__hotspot\" aria-label=\"${getTextLabel('v2_picture_tooltips:hotspot_aria_label')}\">${hotSpot.index + 1}<span class=\"icon\"></span></button>\n          <div class=\"${BLOCK_NAME}__tooltip ${getBottomStyleClass(hotSpot.coords)}\">\n            <div class=\"${BLOCK_NAME}__tooltip-content\">\n              ${hotSpot.textContent.map((el) => el.outerHTML).join('')}\n            </div>\n          </div>\n        </div>\n      `,\n    );\n\n    hotspotsTooltip.insertAdjacentHTML(\n      'beforeend',\n      `\n      <li class=\"${BLOCK_NAME}__tooltip ${index === 0 ? 'active' : ''}\" data-coords=\"${hotSpot.coords}\">\n        <div class=\"${BLOCK_NAME}__tooltip-content\">\n          ${hotSpot.textContent.map((el) => el.outerHTML).join('')}\n        </div>\n      </li>\n    `,\n    );\n  });\n}\n\n/**\n * Handles the click event on a hotspot element within a block.\n * This function manages the activation of the clicked hotspot and its corresponding tooltip,\n * ensures smooth scrolling to the block if necessary, and sets focus to the tooltip.\n *\n * @param {Event} event - The click event triggered by the user.\n * @param {HTMLElement} block - The parent block element containing hotspots and tooltips.\n */\nfunction handleClickHotspot(event, block) {\n  // remove all active classes and assign the correct ones to the clicked element and to the tooltip with the same data-coords\n  const hotspot = event.target;\n  const hotspotWrapper = hotspot.closest(`.${BLOCK_NAME}__hotspot-wrapper`);\n  const hotspotCoords = hotspotWrapper.getAttribute('data-coords');\n  const tooltip = block.querySelector(`.${BLOCK_NAME}__tooltip[data-coords=\"${hotspotCoords}\"]`);\n\n  block.querySelectorAll(`.${BLOCK_NAME}__hotspot-wrapper`).forEach((el) => el.classList.remove('active'));\n  block.querySelectorAll(`.${BLOCK_NAME}__tooltip`).forEach((el) => el.classList.remove('active'));\n\n  hotspotWrapper.classList.add('active');\n  tooltip.classList.add('active');\n\n  if (isMobileViewport() && block.getBoundingClientRect().top > 0) {\n    tooltip.scrollIntoView({ behavior: 'smooth', block: 'center' });\n  }\n\n  // set focus to the tooltip\n  tooltip.focus();\n}\n\n/**\n * Assigns a click event listener to all hotspot elements within the specified block.\n * When a hotspot is clicked, it triggers the `handleClickHotspot` function.\n *\n * @param {HTMLElement} block - The parent block element containing hotspot elements.\n */\nfunction assignHotspotClickEvent(block) {\n  block.querySelectorAll(`.${BLOCK_NAME}__hotspot`).forEach((hotspot) => {\n    hotspot.addEventListener('click', (event) => handleClickHotspot(event, block));\n  });\n}\n\n/**\n * Adds specific CSS classes to all heading elements (h1, h2, h3, h4, h5, h6) within a given block.\n *\n * @param {HTMLElement} block - The container element within which to find and decorate heading elements.\n * @returns {void}\n */\nfunction decorateHeadings(block) {\n  // TODO: Move this to common.js and find other usages of this 'with-marker' class\n  const headings = [...block.querySelectorAll('h1, h2, h3, h4, h5, h6')];\n\n  headings.forEach((heading) => heading.classList.add(`${BLOCK_NAME}__heading`, 'with-marker'));\n}\n\n/**\n * Decorates a given block element by extracting hotspots, decorating the block with them,\n * and assigning click events to the hotspots.\n *\n * @param {HTMLElement} block - The block element to decorate.\n */\nfunction decorate(block) {\n  const hotSpots = extractHotSpotsFrom(block);\n\n  decorateHeadings(block);\n  decorateBlockWithHotSpots(block, hotSpots);\n\n  assignHotspotClickEvent(block);\n}\n\nexport default decorate;\n","import {\n  createElement,\n  createResponsivePicture,\n  decorateBlackLabel,\n  getImageURLs,\n  getTextLabel,\n  variantsClassesToBEM,\n} from '../../scripts/common.js';\n\nconst blockName = 'v2-product-listing';\nconst variantClasses = ['with-filter', 'with-dots', '2-columns', 'pencil-promo'];\n\nfunction getActiveFilterButton(block) {\n  const AllFilterButtons = block.querySelectorAll(`.${blockName}__button-list .${blockName}__segment-button`);\n  AllFilterButtons.forEach((filterButton) => {\n    filterButton.addEventListener('click', (e) => {\n      AllFilterButtons.forEach((button) => {\n        if (button !== e.target) {\n          button.classList.remove('active');\n        } else if (button === e.target && !button.classList.contains('active')) {\n          e.target.classList.toggle('active');\n        }\n      });\n    });\n  });\n}\n\nfunction getPictures(imageWrapper) {\n  const pictures = [...imageWrapper.querySelectorAll('picture')];\n  const imageURLs = getImageURLs(pictures);\n  const imageData = imageURLs.map((src) => ({ src, breakpoints: [] }));\n\n  if (imageData.length === 2) {\n    imageData[0].breakpoints = [\n      { media: '(min-width: 600px)', width: 600 },\n      { media: '(min-width: 1200px)', width: 1200 },\n      { media: '(min-width: 1440px)', width: 1440 },\n      { width: 750 },\n    ];\n  }\n\n  if (imageData.length > 2) {\n    imageData[0].breakpoints = [{ media: '(min-width: 600px)', width: 600 }, { width: 750 }];\n\n    imageData[1].breakpoints = [\n      { media: '(min-width: 1200px)', width: 1200 },\n      { media: '(min-width: 1440px)', width: 1440 },\n    ];\n  }\n  const newPicture = createResponsivePicture(imageData, true, 'small image', `${blockName}__image`);\n\n  return [newPicture, pictures[pictures.length - 1]];\n}\n\nfunction buildProductImageDom(prodEle) {\n  const productImageWrapper = prodEle.querySelectorAll(`.${blockName}__product > div:first-child`);\n\n  productImageWrapper.forEach((imageWrapper) => {\n    imageWrapper.classList.add(`${blockName}__product-image`);\n    const pictures = getPictures(imageWrapper);\n    const link = imageWrapper.querySelector('a');\n    link.text = '';\n    link.classList.add(`${blockName}__product-image-link`);\n    link.append(...pictures);\n    imageWrapper.innerHTML = '';\n    imageWrapper.append(link);\n  });\n}\n\nfunction buildProductInfoDom(prodEle) {\n  const productInfoWrapper = prodEle.querySelectorAll(`.${blockName}__product> div:last-child`);\n  productInfoWrapper.forEach((info) => {\n    const buttonContainer = createElement('div', { classes: `${blockName}__button-container` });\n    const buttons = info.querySelectorAll('.button-container a');\n    const primaryButton = info.querySelector('.button--primary');\n\n    info.classList.add(`${blockName}__product-info`);\n\n    [...buttons].forEach((b) => {\n      const parent = b.parentElement;\n      b.classList.add('button--large');\n      buttonContainer.appendChild(b);\n      parent.remove(); // Remove the previous empty button container\n    });\n    info.appendChild(buttonContainer);\n\n    primaryButton?.addEventListener('mouseover', () => {\n      info.previousElementSibling.classList.add(`${blockName}__product-image--show-background`);\n    });\n\n    primaryButton?.addEventListener('mouseout', () => {\n      info.previousElementSibling.classList.remove(`${blockName}__product-image--show-background`);\n    });\n  });\n}\n\nfunction buildSegments(segmentList, allSegmentNames) {\n  segmentList.forEach((ul) => {\n    ul.classList.add(`${blockName}__segment-list`);\n    const segmentListItems = ul.querySelectorAll('li');\n    const segmentNames = Array.from(segmentListItems).map((item) => {\n      const segmentName = item.textContent.trim().toLowerCase().replaceAll(' ', '-');\n      if (!allSegmentNames.includes(segmentName)) {\n        allSegmentNames.push(segmentName);\n      }\n      return segmentName;\n    });\n    const product = ul.closest(`.${blockName}__product`);\n    segmentNames.forEach((segment) => {\n      product.classList.add(segment);\n    });\n  });\n}\n\nfunction handFilterClick(e, firstSegment, featuredAmount) {\n  const { target } = e;\n  const activeBlock = target.closest(`.${blockName}`);\n  const products = activeBlock.querySelectorAll(`.${blockName}__product`);\n  const clickedSegment = target.textContent.trim().toLowerCase();\n  const selectedItem = activeBlock.querySelector(`.${blockName}__selected-item`);\n  selectedItem.textContent = clickedSegment;\n\n  const dropdown = activeBlock.querySelector(`.${blockName}__dropdown`);\n  dropdown.dataset.selected = clickedSegment;\n\n  const isFirstSegmentActive = firstSegment === clickedSegment;\n  activeBlock.dataset.selected = clickedSegment;\n\n  dropdown.classList.toggle('initial-state', isFirstSegmentActive);\n\n  products.forEach((product, idx) => {\n    product.style.display = product.classList.contains(clickedSegment) || isFirstSegmentActive ? 'flex' : 'none';\n    const isSelected = product.style.display === 'flex';\n    product.style.display = isSelected ? 'flex' : 'none';\n    product.classList.toggle('selected-product', isSelected);\n\n    if (idx < featuredAmount) {\n      product.classList.toggle('featured', isFirstSegmentActive);\n    }\n  });\n\n  const allProductsRows = activeBlock.querySelectorAll(`.${blockName}__product`);\n\n  allProductsRows.forEach((product) => {\n    if (product.classList.contains('selected-product')) {\n      product.classList.remove('odd', 'even');\n\n      const selectedProducts = activeBlock.querySelectorAll('.selected-product');\n      selectedProducts.forEach((selectedProduct, i) => {\n        const newIdx = isFirstSegmentActive ? i + featuredAmount : i;\n        console.log(newIdx);\n        if (newIdx % 2 === 0) {\n          selectedProduct.classList.remove('even');\n          selectedProduct.classList.add('odd');\n        } else {\n          selectedProduct.classList.remove('odd');\n          selectedProduct.classList.add('even');\n        }\n      });\n    } else if (!product.classList.contains('selected-product')) {\n      product.classList.remove('odd', 'even');\n    }\n  });\n\n  // show/hide pencil promo text blocks depending on the clicked segment if pencil promo variant is present\n  if (!activeBlock.classList.contains(`${blockName}--pencil-promo`)) {\n    return;\n  }\n  const allPencilPromo = activeBlock.closest('.section').querySelectorAll('[data-segment]');\n  allPencilPromo.forEach((promo) => {\n    const promoSegment = promo.dataset.segment.trim().toLowerCase();\n    const isClickedSegment = promoSegment === clickedSegment;\n    promo.parentElement.classList.toggle('v2-pencil-promo--hidden', !isClickedSegment);\n  });\n}\n\nfunction buildFilter(allSegmentNames, firstSegment, featuredAmount) {\n  const dropdownWrapper = createElement('div', { classes: `${blockName}__dropdown` });\n  const selectedItemWrapper = createElement('div', { classes: `${blockName}__selected-item-wrapper` });\n  const selectedItem = createElement('div', { classes: `${blockName}__selected-item` });\n  const segmentNamesList = createElement('ul', { classes: `${blockName}__button-list` });\n\n  const dropdownArrowIcon = createElement('span', { classes: [`${blockName}__icon`, 'icon', 'icon-dropdown-caret'] });\n  selectedItemWrapper.append(selectedItem);\n  selectedItemWrapper.appendChild(dropdownArrowIcon);\n\n  dropdownWrapper.append(selectedItemWrapper);\n  dropdownWrapper.append(segmentNamesList);\n\n  allSegmentNames.forEach((segment, index) => {\n    const li = createElement('li');\n    const filterButton = createElement('button', { classes: `${blockName}__segment-button` });\n    filterButton.textContent = segment;\n\n    if (index === 0) {\n      // Default selected item\n      filterButton.classList.add('active');\n      selectedItem.textContent = segment;\n    }\n\n    segmentNamesList.appendChild(li);\n    li.append(filterButton);\n\n    filterButton.addEventListener('click', (e) => handFilterClick(e, firstSegment, featuredAmount));\n  });\n\n  return dropdownWrapper;\n}\n\nfunction handleListeners(dropdownWrapper, block) {\n  // Listener to toggle the dropdown (open / close)\n  block.addEventListener('click', (e) => {\n    if (e.target.closest(`.${blockName}__selected-item-wrapper`)) {\n      dropdownWrapper.classList.toggle(`${blockName}__dropdown--open`);\n    } else {\n      dropdownWrapper.classList.remove(`${blockName}__dropdown--open`);\n    }\n  });\n}\n\nconst getRowClass = (idx, amount) => {\n  const newId = amount + idx;\n  return newId % 2 ? 'even' : 'odd';\n};\n\nexport default function decorate(block) {\n  let featuredAmount = 0;\n\n  variantsClassesToBEM(block.classList, variantClasses, blockName);\n  const allSegmentNames = [getTextLabel('v2_product_listing:all_segment_text')];\n  const firstSegment = allSegmentNames[0].trim().toLowerCase();\n  const hasFilters = block.classList.contains(`${blockName}--with-filter`);\n\n  const classes = block.classList;\n  classes.forEach((cl) => {\n    if (cl.endsWith('-featured')) {\n      featuredAmount = Number(cl.split('-')[1]);\n    }\n  });\n\n  if (featuredAmount !== 0) {\n    block.classList.add('with-featured');\n  }\n\n  const productElement = block.querySelectorAll(`.${blockName} > div`);\n  productElement.forEach((prodEle, idx) => {\n    prodEle.classList.add(`${blockName}__product`);\n\n    if (idx < featuredAmount) {\n      prodEle.classList.add('featured');\n    }\n\n    const rowClass = getRowClass(idx, featuredAmount);\n    prodEle.classList.add(rowClass);\n\n    buildProductImageDom(prodEle);\n    buildProductInfoDom(prodEle);\n  });\n\n  block.parentElement.classList.add('full-width');\n  // Add product name to product element class list\n  getProductName(block);\n\n  if (hasFilters) {\n    // Create menu buttons from product segments\n    const segmentList = block.querySelectorAll(`.${blockName}__product > div > ul`);\n    block.dataset.selected = firstSegment;\n    buildSegments(segmentList, allSegmentNames);\n    const dropdownWrapper = buildFilter(allSegmentNames, firstSegment, featuredAmount);\n    block.prepend(dropdownWrapper);\n    dropdownWrapper.dataset.selected = firstSegment;\n    dropdownWrapper.classList.add('initial-state');\n\n    handleListeners(dropdownWrapper, block);\n    getActiveFilterButton(block);\n  } else {\n    const detailList = block.querySelectorAll(`.${blockName}__product > div > ul`);\n    detailList.forEach((ul) => {\n      ul.classList.add(`${blockName}__detail-list`);\n    });\n  }\n\n  decorateBlackLabel(block);\n}\n\nfunction getProductName(block) {\n  const modelName = block.querySelectorAll(`.${blockName}__product > div + div > h3`);\n  modelName.forEach((model) => {\n    const parentNodeElement = model.parentNode.parentNode;\n    parentNodeElement.classList.add(model.id);\n  });\n}\n","import { unwrapDivs, variantsClassesToBEM } from '../../scripts/common.js';\n\nconst blockName = 'v2-pull-quote';\nconst variantClasses = ['half-width'];\nlet quoteIsRight = true;\n\nexport default function decorate(block) {\n  variantsClassesToBEM(block.classList, variantClasses, blockName);\n  const parentWrapper = block.parentElement;\n\n  const isHalfWidth = block.classList.contains(`${blockName}--half-width`);\n  const previousTextEl = parentWrapper.previousElementSibling.lastChild;\n\n  if (isHalfWidth && previousTextEl) {\n    parentWrapper.classList.add(`${blockName}-wrapper--half-width`, quoteIsRight ? 'quote-right' : 'quote-left');\n    quoteIsRight = !quoteIsRight;\n    previousTextEl.classList.add('half-width-text');\n    parentWrapper.prepend(previousTextEl);\n  }\n  unwrapDivs(block);\n}\n","import { unwrapDivs, createElement } from '../../scripts/common.js';\nimport { getMetadata } from '../../scripts/aem.js';\nimport { fetchRecommendedArticles, sortArticlesByDateField, formatRecommendedArticlesArray } from '../../scripts/services/magazine.service.js';\nimport { createVideo, isValidVideoUrl } from '../../scripts/video-helper.js';\n\nconst blockName = 'v2-recommendations';\n\n/**\n * Returns up to `limit` articles, prioritizing those matching the target category.\n * Maintains the order from the original (already sorted) input list.\n *\n * @param {Array<Object>} articles - Pre-sorted list of articles.\n * @param {string} targetCategory - Lowercased category to prioritize.\n * @param {number} limit - Maximum number of articles to return.\n * @returns {Array<Object>} - Ordered list of articles, with priority given to matching category.\n */\nconst filterArticlesByCategoryWithFallback = (articles, targetCategory = '', limit = 3) => {\n  const primary = [];\n  const fallback = [];\n\n  const normalize = (val) => (typeof val === 'string' ? val.toLowerCase() : '');\n  const matchesCategory = (cat) => normalize(cat) === targetCategory;\n\n  for (const article of articles) {\n    const categories = Array.isArray(article.category) ? article.category : [article.category];\n    if (categories.some(matchesCategory)) {\n      primary.push(article);\n    } else {\n      fallback.push(article);\n    }\n\n    if (primary.length + fallback.length >= limit * 2) {\n      break;\n    }\n  }\n\n  return [...primary, ...fallback].slice(0, limit);\n};\n\n/**\n * Creates an article element containing a video player outside the anchor.\n *\n * @param {Object} article - The article data object.\n * @param {string} article.path - The URL to the article page.\n * @param {string} article.videoUrl - The video URL.\n * @param {string} article.category - The article category label.\n * @param {string} article.title - The article title.\n * @param {string} blockName - The base CSS class name for styling.\n * @returns {HTMLElement} The article element containing the video and metadata.\n */\nconst createVideoArticle = (article, blockName) => {\n  const articleEl = createElement('article', { classes: `${blockName}__article` });\n\n  articleEl.innerHTML = `\n    <div class=\"${blockName}__article-media\">\n      <div class=\"${blockName}__video-placeholder\"></div>\n    </div>\n    <a href=\"${article.path}\" class=\"${blockName}__article-link\">\n      <div class=\"${blockName}__article-content\">\n        <p class=\"${blockName}__article-content-category\">${article.category}</p>\n        <h4 class=\"${blockName}__article-content-title\">${article.title}</h4>\n      </div>\n    </a>\n  `;\n\n  const placeholder = articleEl.querySelector(`.${blockName}__video-placeholder`);\n  const videoEl = createVideo(article.videoUrl, `${blockName}__article-video`, {\n    autoplay: true,\n    muted: true,\n    playsinline: true,\n    controls: false,\n    loop: true,\n  });\n\n  videoEl.setAttribute('aria-label', article.title);\n  placeholder.replaceWith(videoEl);\n  return articleEl;\n};\n\n/**\n * Creates an article element with an image wrapped inside the anchor.\n *\n * @param {Object} article - The article data object.\n * @param {string} article.path - The URL to the article page.\n * @param {string} article.image - The image URL.\n * @param {string} article.category - The article category label.\n * @param {string} article.title - The article title.\n * @param {string} blockName - The base CSS class name for styling.\n * @returns {HTMLElement} The article element containing the image and metadata.\n */\nconst createImageArticle = (article, blockName) => {\n  const articleEl = createElement('article', { classes: `${blockName}__article` });\n\n  articleEl.innerHTML = `\n    <a href=\"${article.path}\" class=\"${blockName}__article-link\">\n      <img src=\"${article.image}\" alt=\"${article.title}\" class=\"${blockName}__article-image\">\n      <div class=\"${blockName}__article-content\">\n        <p class=\"${blockName}__article-content-category\">${article.category}</p>\n        <h4 class=\"${blockName}__article-content-title\">${article.title}</h4>\n      </div>\n    </a>\n  `;\n\n  return articleEl;\n};\n\n/**\n * Builds and appends a block of related articles to a given block element.\n *\n * Each article is rendered inside a container with either:\n * - a video displayed outside the anchor (if `videoUrl` is defined)\n * - or an image inside the anchor (default)\n *\n * @param {Array<Object>} articles - An array of article objects to render.\n *   Each object should have:\n *     - path {string}: URL of the article\n *     - image {string}: Image URL (for non-video articles)\n *     - videoUrl {string} [optional]: Video URL\n *     - category {string}: Article category\n *     - title {string}: Article title\n * @param {HTMLElement} block - The DOM element to append the rendered block to.\n */\nconst buildBlock = (articles, block) => {\n  const fragment = document.createDocumentFragment();\n\n  articles.forEach((article) => {\n    const articleEl = isValidVideoUrl(article.videoUrl) ? createVideoArticle(article, blockName) : createImageArticle(article, blockName);\n    fragment.appendChild(articleEl);\n  });\n\n  const articlesContainer = createElement('div', { classes: `${blockName}__articles` });\n  articlesContainer.appendChild(fragment);\n  block.appendChild(articlesContainer);\n};\n\n/**\n * Main function to decorate the block element with the top articles.\n * Fetches the articles, sorts them by date, filters them by category, and displays up to\n * three articles.\n * @param {HTMLElement} block - The block element to decorate.\n * @returns {void}\n */\nexport default async function decorate(block) {\n  let recommendedData;\n  try {\n    recommendedData = await fetchRecommendedArticles();\n  } catch (e) {\n    console.error('Failed to fetch recommended articles:', e);\n    return;\n  }\n\n  const items = recommendedData?.items || [];\n  const formattedArticles = formatRecommendedArticlesArray(items);\n  if (!formattedArticles.length) {\n    return;\n  }\n\n  const sortedArticles = sortArticlesByDateField(formattedArticles, 'date');\n  const articleCategory = getMetadata('article-category')?.toLowerCase?.() || '';\n  const filteredArticles = filterArticlesByCategoryWithFallback(sortedArticles, articleCategory);\n\n  if (filteredArticles.length) {\n    buildBlock(filteredArticles, block);\n    block.parentElement.classList.add('full-width');\n    unwrapDivs(block);\n  }\n}\n","import { variantsClassesToBEM } from '../../scripts/common.js';\n\nconst blockName = 'v2-resources';\nconst variantClasses = ['magazine'];\n\nexport default async function decorate(block) {\n  variantsClassesToBEM(block.classList, variantClasses, blockName);\n  const isMagazineVariant = block.classList.contains(`${blockName}--magazine`);\n\n  if (isMagazineVariant) {\n    block.closest('.section').classList.add(`${blockName}-wrapper__magazine`);\n  }\n\n  const contentWrapper = block.querySelector(':scope > div');\n  contentWrapper.classList.add(`${blockName}__content-wrapper`);\n\n  const columns = [...block.querySelectorAll(':scope > div > div')];\n\n  const [headerCol, contentCol] = columns;\n\n  headerCol.classList.add(`${blockName}__header`);\n  contentCol.classList.add(`${blockName}__content`);\n\n  const header = [...headerCol.querySelectorAll('h1, h2, h3, h4, h5, h6')];\n  header[0].classList.add(`${blockName}__heading`);\n\n  const subtitles = [...contentCol.querySelectorAll('h1, h2, h3, h4, h5, h6')];\n  subtitles.forEach((subt) => subt.classList.add(`${blockName}__subtitle`));\n\n  [...contentCol.children].forEach((el) => {\n    const link = el.querySelector('a');\n    const buttonClasses = isMagazineVariant ? ['button', 'button--primary', 'button--large'] : ['standalone-link'];\n    link?.classList.add(...buttonClasses);\n  });\n}\n","import { createElement } from '../../scripts/common.js';\n\nconst blockName = 'v2-slider';\n\nfunction handleSlider(block) {\n  const clippingSlider = block.querySelector(`.${blockName}__input`);\n\n  clippingSlider.addEventListener('input', (event) => {\n    const newValue = `${event.target.value}%`;\n    block.style.setProperty('--exposure', newValue);\n  });\n}\n\nexport default async function decorate(block) {\n  const contentWrapper = block.querySelector(':scope > div');\n  contentWrapper.classList.add(`${blockName}__content-wrapper`);\n\n  const content = block.querySelector(':scope > div > div');\n  content.classList.add(`${blockName}__content`);\n\n  const images = [...content.querySelectorAll('p > picture')];\n  const has2Images = images.length === 2;\n\n  if (has2Images) {\n    block.classList.add('two-images');\n  }\n\n  const header = createElement('div', { classes: `${blockName}__header` });\n  const heading = [...content.querySelectorAll('h1, h2, h3, h4, h5, h6')][0];\n  heading.classList.add(`${blockName}__title`, 'with-marker');\n\n  const nextElement = heading.nextElementSibling;\n  const isImage = nextElement.querySelector('picture');\n\n  header.append(heading);\n  if (!isImage) {\n    nextElement.classList.add(`${blockName}__subtitle`);\n    header.append(nextElement);\n  }\n  content.prepend(header);\n\n  const slider = createElement('div', { classes: `${blockName}__images` });\n  const models = createElement('div', { classes: `${blockName}__models` });\n\n  if (has2Images) {\n    images.forEach((img, idx) => {\n      img.classList.add('image', `image-${idx + 1}`);\n\n      const model = img.parentElement;\n      if (model.textContent.trim().length > 0) {\n        model.classList.add('model', `model-${idx + 1}`);\n        models.appendChild(model);\n      }\n      slider.appendChild(img);\n    });\n\n    const divider = createElement('div', { classes: `${blockName}__image-divider` });\n    const label = createElement('label', { classes: `${blockName}__label` });\n    const input = createElement('input', { classes: `${blockName}__input` });\n    input.type = 'range';\n    input.min = '0';\n    input.max = '100';\n    label.appendChild(input);\n    slider.append(label, divider);\n\n    content.append(slider, models);\n\n    handleSlider(block);\n  } else {\n    if (images.length >= 1) {\n      slider.appendChild(images[0]);\n    }\n    content.appendChild(slider);\n  }\n\n  const buttons = [...content.querySelectorAll('p.button-container')];\n  if (buttons.length > 0) {\n    buttons.forEach((btn) => content.appendChild(btn));\n  }\n}\n","import { getTextLabel, unwrapDivs, decorateIcons, variantsClassesToBEM } from '../../scripts/common.js';\nimport { getMetadata } from '../../scripts/aem.js';\n\nconst blockName = 'v2-social-block';\nconst variantClasses = ['attribution'];\nconst docRange = document.createRange();\n\nconst LABELS = {\n  COPIED: getTextLabel('v2_social_block:tooltip_copied_text'),\n};\n\nconst CLASSES = {\n  title: `${blockName}__title`,\n  list: `${blockName}__list`,\n  listItem: `${blockName}__list-item`,\n  tooltipTop: ['tooltip', 'tooltip--top'],\n  tooltipShow: 'show',\n  attribution: `${blockName}--attribution`,\n  attributionWrapper: `${blockName}__attribution-wrapper`,\n  attributionDate: `${blockName}__attribution-date`,\n  attributionAuthor: `${blockName}__attribution-author`,\n};\n\nconst TEMPLATE_LINK_CONFIGS = [\n  ['twitter', 'https://twitter.com/intent/tweet?url='],\n  ['linkedin', 'https://www.linkedin.com/cws/share?url='],\n  ['fb', 'https://www.facebook.com/sharer/sharer.php?u='],\n];\n\nconst buildTemplateBlock = (links, hasAttribution) => {\n  const attributionDate = getMetadata('date');\n  const attributionAuthor = getMetadata('author');\n\n  const attributionContent = hasAttribution\n    ? `\n    <div class=\"${CLASSES.attributionWrapper}\">\n      ${attributionDate ? `<p class=\"${CLASSES.attributionDate}\">${attributionDate}</p>` : ''}\n      ${attributionAuthor ? `<p class=\"${CLASSES.attributionAuthor}\">${attributionAuthor}</p>` : ''}\n    </div>\n  `\n    : '';\n\n  const listItems = links\n    .map(\n      ([icon, baseHref]) => `\n    <li class=\"${CLASSES.listItem}\">\n      <a href=\"${baseHref}${window.location.href}\" target=\"_blank\">\n        <span class=\"icon icon-${icon}\"></span>\n      </a>\n    </li>\n  `,\n    )\n    .join('');\n\n  const template = `\n    ${attributionContent}\n    <ul class=\"${CLASSES.list}\">\n      ${listItems}\n    </ul>\n  `;\n\n  const fragment = docRange.createContextualFragment(template);\n  decorateIcons(fragment);\n\n  return fragment;\n};\n\nconst buildDefaultBlock = (heading = undefined, links = []) => {\n  heading?.classList.add(CLASSES.title);\n  const fragment = docRange.createContextualFragment(`\n    ${heading ? heading.outerHTML : ''}\n    <ul class='${CLASSES.list}'>\n      ${links.map((anchor) => `<li class='${CLASSES.listItem}'>${anchor.outerHTML}</li>`).join('')}\n    </ul>\n  `);\n  return fragment;\n};\n\nconst addTooltip = (link) => {\n  const anchorEl = link.parentElement;\n  anchorEl.dataset.tooltip = LABELS.COPIED;\n  anchorEl.addEventListener('click', async (e) => {\n    e.preventDefault();\n    try {\n      await navigator.clipboard.writeText(window.location.href);\n      anchorEl.classList.add(CLASSES.tooltipShow);\n\n      setTimeout(() => {\n        anchorEl.classList.remove(CLASSES.tooltipShow);\n      }, 1000);\n    } catch (err) {\n      console.error('Failed to copy: ', err);\n    }\n  });\n  anchorEl.classList.add(...CLASSES.tooltipTop);\n};\n\nexport default function decorate(block) {\n  let fragment;\n  const isMagazineTemplate = document.body.classList.contains('v2-magazine');\n\n  if (isMagazineTemplate) {\n    variantsClassesToBEM(block.classList, variantClasses, blockName);\n    const hasAttribution = block.classList.contains(CLASSES.attribution);\n    fragment = buildTemplateBlock(TEMPLATE_LINK_CONFIGS, hasAttribution);\n  } else {\n    const heading = block.querySelectorAll('h1, h2, h3, h4, h5, h6')[0];\n    const links = Array.from(block.querySelectorAll('a'));\n\n    fragment = buildDefaultBlock(heading, links);\n\n    const copyIcon = fragment.querySelector('.icon-link');\n    if (copyIcon) {\n      addTooltip(copyIcon);\n    }\n  }\n  block.innerHTML = '';\n  block.appendChild(fragment);\n\n  unwrapDivs(block);\n}\n","import { adjustPretitle, unwrapDivs } from '../../scripts/common.js';\n\nexport default function decorate(block) {\n  const content = block.querySelector(':scope > div > div');\n  adjustPretitle(content);\n  unwrapDivs(block);\n}\n","import { loadBlock } from '../../scripts/aem.js';\nimport { createElement, slugify, removeEmptyTags } from '../../scripts/common.js';\n\nconst blockName = 'v2-specifications';\n\nexport default async function decorate(block) {\n  const accordionId = [...block.classList].find((className) => className.startsWith('id-'));\n\n  const items = block.querySelectorAll(':scope > div');\n\n  let accordion;\n  let accordionContent;\n  let accordionWrapper;\n\n  const accordionBlock = createElement('div', {\n    classes: ['block', 'v2-accordion', ...(accordionId ? [accordionId] : [])],\n    props: { 'data-block-name': 'v2-accordion' },\n  });\n\n  const accordionBlockWrapper = createElement('div', {\n    classes: ['v2-accordion-wrapper'],\n  });\n  accordionBlockWrapper.appendChild(accordionBlock);\n  block.appendChild(accordionBlockWrapper);\n\n  // Hx tag used for the titles of the accordion\n  const titleMeta = block.closest('.section').dataset.header;\n  if (!titleMeta) {\n    console.warn('No %cheader%c tag found in section metadata for v2-specifications block', 'color: red', 'color: inherit');\n    return;\n  }\n\n  const headerTag = titleMeta.charAt(titleMeta.length - 1);\n  const headings = ['h1', 'h2', 'h3', 'h4', 'h5', 'h6'].slice(headerTag);\n\n  // Add subtitle styles to headings inside the accordion, excluding those used as button titles\n  const headingString = headings.join(',');\n  const headingsList = [...block.querySelectorAll(headingString)];\n  headingsList.forEach((heading) => heading.classList.add(`${blockName}__subtitle`, 'h5'));\n\n  [...items].forEach((item) => {\n    const typeTitle = item.querySelector(`h${headerTag}`); // header of the accordion\n    const typePicture = item.querySelector('picture'); // with image\n    const typeDownloads = item.querySelector('.button-container a'); // with downloads\n    const subtitleCounter = item.querySelectorAll(`.${blockName}__subtitle`).length;\n\n    if (typeTitle) {\n      if (accordion) {\n        // close old Accordion content\n        accordionBlock.appendChild(accordion);\n        accordionWrapper.appendChild(accordionContent);\n        block.appendChild(accordionWrapper);\n      }\n\n      // create slug based on title name\n      const name = `id-${slugify(item.textContent.trim())}`;\n\n      // new Accordion content\n      // (accordionWrapper + accordionContent + accordion are needed)\n      accordionWrapper = createElement('div', { classes: [`${blockName}__accordion-wrapper`] });\n      accordionContent = createElement('div', {\n        classes: [`${blockName}__accordion-content`, name],\n        props: { 'data-block-status': 'loaded' },\n      });\n      accordion = createElement('div');\n\n      // Title of the accordion\n      const titleDiv = item.querySelector(':scope > div');\n      titleDiv.classList.add(`${blockName}__title`);\n      accordion.appendChild(titleDiv);\n\n      // Id to be updated in the accordion content\n      const divId = createElement('div');\n      divId.textContent = `#${name}`;\n      accordion.appendChild(divId);\n      item.remove();\n    }\n\n    const classes = [];\n    if (subtitleCounter) {\n      classes.push(`${blockName}__list--subtitle`);\n    }\n\n    // apply classes to the content based on items inside\n    if (typePicture) {\n      classes.push(`${blockName}__list--with-pictures`);\n    }\n\n    if (typeDownloads) {\n      classes.push(`${blockName}__list--with-downloads`);\n\n      const buttons = item.querySelectorAll('.button-container a');\n      buttons.forEach((bt) => {\n        bt.classList.add('standalone-link');\n      });\n    }\n\n    if (!typePicture && !typeDownloads && !typeTitle) {\n      classes.push(`${blockName}__list--with-text`);\n    }\n\n    if (classes.length > 0) {\n      item.classList.add(...classes);\n    }\n\n    if (accordionContent) {\n      accordionContent.appendChild(item);\n    }\n  });\n\n  // close last accordion content\n  if (accordion) {\n    accordionBlock.appendChild(accordion);\n    accordionWrapper.appendChild(accordionContent);\n    block.appendChild(accordionWrapper);\n  }\n\n  removeEmptyTags(block);\n\n  await loadBlock(accordionBlock);\n}\n","import { debounce } from '../../scripts/scripts.js';\nimport { decorateIcons, getTextLabel } from '../../scripts/common.js';\n\nconst blockName = 'v2-stories-carousel';\n\n/**\n * Creates the basic HTML structure for a carousel component.\n * @param {string} title - The title for the carousel.\n * @param {string} baseBlockName - The base class name for the carousel elements.\n * @param {string} [previousLabel=\"Previous\"] - Accessible label for the \"previous\" button.\n * @param {string} [nextLabel=\"Next\"] - Accessible label for the \"next\" button.\n * @returns {string} - The HTML string for the carousel structure.\n */\nconst createCarouselStructure = (title, baseBlockName, previousLabel = 'Previous', nextLabel = 'Next') => `\n  <div class=\"${baseBlockName}-aligner\">\n    <h2 class=\"${baseBlockName}-title\">${title}</h2>\n    <div class=\"${baseBlockName}-content-wrapper\" aria-label=\"Carousel: ${title}\">\n      <button class=\"${baseBlockName}-control prev hidden\" aria-label=\"${previousLabel}\" aria-controls=\"${baseBlockName}-track\">\n        <span class=\"${baseBlockName}__icon icon icon-chevron-left-thin\" aria-hidden=\"true\"></span>\n      </button>\n      <div class=\"${baseBlockName}-track-container\" role=\"region\" aria-roledescription=\"carousel\">\n        <ul id=\"${baseBlockName}-track\" class=\"${baseBlockName}-track\" aria-live=\"polite\" aria-atomic=\"true\"></ul>\n      </div>\n      <button class=\"${baseBlockName}-control next\" aria-label=\"${nextLabel}\" aria-controls=\"${baseBlockName}-track\">\n        <span class=\"${baseBlockName}__icon icon icon-chevron-right-thin\" aria-hidden=\"true\"></span>\n      </button>\n    </div>\n  </div>\n`;\n\n/**\n * Creates the HTML for a single carousel card.\n * @param {Object} item - The data for the carousel item.\n * @param {HTMLElement} item.picture - The picture element for the card.\n * @param {string} item.text - The text content for the card.\n * @param {string} item.linkText - The link text for the card.\n * @param {string} item.linkHref - The URL for the card link.\n * @param {string} baseBlockName - The base class name for the carousel elements.\n * @returns {string} - The HTML string for the carousel card.\n */\nconst createCarouselCard = ({ picture, text, linkText, linkHref }, baseBlockName) => `\n  <li class=\"${baseBlockName}-card\">\n    <a href=\"${linkHref}\" class=\"${baseBlockName}-image-link\">${picture.outerHTML}</a>\n    <p class=\"${baseBlockName}-tag\">${text}</p>\n    <a href=\"${linkHref}\" class=\"${baseBlockName}-link\">${linkText}</a>\n  </li>\n`;\n\n/**\n * Updates the visibility of the prev and next buttons based on the scroll position.\n * @param {Object} elements - An object containing carousel elements.\n */\nconst updateButtonVisibility = (elements) => {\n  const { trackContainer, prevButton, nextButton } = elements;\n  const { scrollLeft, scrollWidth, offsetWidth } = trackContainer;\n  const isAtStart = scrollLeft <= 0;\n  const isAtEnd = Math.ceil(scrollLeft + offsetWidth) >= scrollWidth;\n  prevButton.classList.toggle('hidden', isAtStart);\n  nextButton.classList.toggle('hidden', isAtEnd);\n};\n\n/**\n * Scrolls to the specified slide based on direction and updates button visibility.\n * @param {Object} elements - An object containing carousel elements.\n * @param {HTMLElement} elements.trackContainer - The container element that holds\n * the carousel track.\n * @param {HTMLElement[]} elements.slides - An array of slide elements within the carousel.\n * @param {number} elements.currentSlideIndex - The index of the currently active slide.\n * @param {number} [direction=1] - The scroll direction, positive for next and\n * negative for previous.\n * @param {boolean} [debounced=false] - Whether to apply debouncing to the scroll action.\n */\nconst scrollToSlide = (elements, direction = 1, debounced = false) => {\n  const { trackContainer, currentSlideIndex } = elements;\n  elements.slides = elements.slides || Array.from(trackContainer.querySelectorAll(`.${blockName}-card`));\n  const { slides } = elements;\n\n  const newSlideIndex = Math.max(0, Math.min(currentSlideIndex + direction, slides.length - 1));\n  elements.currentSlideIndex = newSlideIndex;\n  const targetScrollPosition = slides[newSlideIndex].offsetLeft;\n\n  const performScroll = () => {\n    if (Math.abs(trackContainer.scrollLeft - targetScrollPosition) < 1) {\n      return;\n    }\n\n    trackContainer.scrollTo({\n      left: targetScrollPosition,\n      behavior: 'smooth',\n    });\n    updateButtonVisibility(elements);\n  };\n\n  if (debounced) {\n    debounce(performScroll, 100)();\n  } else {\n    performScroll();\n  }\n};\n\n/**\n * Initializes the carousel by setting its structure and populating items.\n * @param {HTMLElement} block - The carousel container element.\n */\nconst createCarousel = (block) => {\n  const [header, ...items] = block.children;\n  const title = header?.querySelector('h2')?.textContent || '';\n  const previousLabel = getTextLabel('v2_stories_carousel:previous');\n  const nextLabel = getTextLabel('v2_stories_carousel:next');\n  block.innerHTML = createCarouselStructure(title, blockName, previousLabel, nextLabel);\n  const carouselTrack = block.querySelector(`.${blockName}-track`);\n\n  carouselTrack.innerHTML = items\n    .map((item) => {\n      const picture = item.querySelector('picture');\n      const text = item.querySelectorAll('p')[1]?.textContent || '';\n      const link = item.querySelector('a');\n      const linkText = link?.textContent || '';\n      const linkHref = link?.href || '#';\n\n      return createCarouselCard(\n        {\n          picture,\n          text,\n          linkText,\n          linkHref,\n        },\n        blockName,\n      );\n    })\n    .join('');\n};\n\n/**\n * Calculates and caches the width of each slide.\n * @param {Array<HTMLElement>} slides - An array of slide elements.\n * @returns {number} - The width of each slide.\n */\nlet cachedSlideWidth;\nconst calculateSlideWidth = (slides) => {\n  if (!cachedSlideWidth) {\n    cachedSlideWidth = slides[0].getBoundingClientRect().width;\n  }\n  return cachedSlideWidth;\n};\n\n/**\n * Adds swipe gesture support for touch devices.\n * @param {HTMLElement} trackContainer - The track container element.\n * @param {Object} elements - An object containing carousel elements.\n * @param {number} [swipeThreshold=50] - Minimum swipe distance to trigger a slide change.\n */\nconst addSwipeSupport = (trackContainer, elements, swipeThreshold = 50) => {\n  let startX = 0;\n\n  const handleTouchStart = (e) => {\n    startX = e.touches[0].clientX;\n  };\n\n  const handleTouchEnd = (e) => {\n    const endX = e.changedTouches[0].clientX;\n    const swipeDistance = endX - startX;\n    if (Math.abs(swipeDistance) > swipeThreshold) {\n      const direction = swipeDistance < 0 ? 1 : -1;\n      scrollToSlide(elements, direction, true);\n    }\n    startX = 0;\n  };\n\n  trackContainer.addEventListener('touchstart', handleTouchStart, { passive: true });\n  trackContainer.addEventListener('touchend', handleTouchEnd, { passive: true });\n};\n\n/**\n * Adds event listeners for carousel navigation, scroll, and resize handling.\n * @param {Object} elements - An object containing carousel elements.\n */\nconst addEventListeners = (elements) => {\n  const { trackContainer, nextButton, prevButton } = elements;\n\n  elements.currentSlideIndex = 0;\n  elements.slides = elements.slides || Array.from(trackContainer.querySelectorAll(`.${blockName}-card`));\n\n  const updateCarouselState = () => {\n    const slideWidth = calculateSlideWidth(elements.slides);\n    elements.currentSlideIndex = Math.round(trackContainer.scrollLeft / slideWidth);\n    updateButtonVisibility(elements);\n    cachedSlideWidth = null;\n  };\n\n  const debouncedUpdateCarouselState = debounce(updateCarouselState, 100);\n  const handleNextClick = () => scrollToSlide(elements, 1, true);\n  const handlePrevClick = () => scrollToSlide(elements, -1, true);\n\n  nextButton.addEventListener('click', handleNextClick);\n  prevButton.addEventListener('click', handlePrevClick);\n  trackContainer.addEventListener('scroll', debouncedUpdateCarouselState, { passive: true });\n  window.addEventListener('resize', debouncedUpdateCarouselState);\n\n  addSwipeSupport(trackContainer, elements);\n};\n\n/**\n * Main function to set up and initialize the carousel.\n * @param {HTMLElement} block - The carousel container element.\n */\nexport default function decorate(block) {\n  createCarousel(block);\n  const elements = {\n    trackContainer: block.querySelector(`.${blockName}-track-container`),\n    nextButton: block.querySelector(`.${blockName}-control.next`),\n    prevButton: block.querySelector(`.${blockName}-control.prev`),\n  };\n  addEventListeners(elements);\n  block.parentElement.classList.add('full-width');\n  decorateIcons(block);\n}\n","import { createElement, decorateIcons } from '../../scripts/common.js';\nimport { getMetadata } from '../../scripts/aem.js';\n\nconst blockName = 'v2-sub-navigation';\n\n/**\n * Toggles the dropdown menu.\n * @param {HTMLElement} dropdownWrapper - The wrapper element of the dropdown.\n * @returns {Function} Event handler function.\n */\nconst toggleDropdown = (dropdownWrapper) => (e) => {\n  if (e.target.closest(`.${blockName}__active-item-wrapper`)) {\n    dropdownWrapper.classList.toggle(`${blockName}__dropdown--open`);\n  } else {\n    dropdownWrapper.classList.remove(`${blockName}__dropdown--open`);\n  }\n};\n\n/**\n * Fetches the sub-navigation HTML content.\n * @param {string} content - The content path.\n * @returns {Promise<DocumentFragment>} The fetched HTML content as a DocumentFragment.\n */\nconst fetchSubNavHtml = async (content) => {\n  const response = await fetch(`${content}.plain.html`);\n  if (!response.ok) {\n    throw new Error('Failed to fetch sub-navigation content');\n  }\n  return document.createRange().createContextualFragment(await response.text());\n};\n\n/**\n * Sets up navigation items with appropriate classes.\n * @param {HTMLElement} list - The list element containing the navigation items.\n * @returns {NodeList} The list of navigation items.\n */\nconst setupNavItems = (list) => {\n  const items = list.querySelectorAll('li');\n\n  items.forEach((item) => {\n    item.className = `${blockName}__item`;\n  });\n\n  return items;\n};\n\n/**\n * Creates a wrapper for the active navigation item.\n * @param {HTMLElement} activeItem - The active item element.\n * @returns {HTMLElement} The created wrapper element.\n */\nconst createActiveItemWrapper = (activeItem) => {\n  const activeItemWrapper = createElement('div', { classes: `${blockName}__active-item-wrapper` });\n  const dropdownIcon = createElement('span', { classes: [`${blockName}__icon`, 'icon', 'icon-dropdown-caret'] });\n  activeItemWrapper.append(activeItem, dropdownIcon);\n  return activeItemWrapper;\n};\n\n/**\n * Creates a dropdown container element.\n * @param {HTMLElement} activeItem - The active item element.\n * @param {HTMLElement} list - The list element containing the navigation items.\n * @returns {HTMLElement} The created dropdown container element.\n */\nconst createDropdownContainer = (activeItem, list) => {\n  const container = createElement('div', { classes: `${blockName}__dropdown` });\n  container.append(createActiveItemWrapper(activeItem), list);\n  return container;\n};\n\n/**\n * Extracts anchor attributes from the given fragment.\n * @param {DocumentFragment} fragment - The HTML fragment.\n * @returns {Object|null} The extracted anchor attributes or null if not found.\n */\nconst extractAnchorAttributes = (fragment) => {\n  const [mobileAnchor, desktopAnchor] = [...fragment.querySelectorAll('p a')];\n\n  return mobileAnchor && desktopAnchor\n    ? {\n        mobileAnchorText: mobileAnchor.textContent,\n        desktopAnchorText: desktopAnchor.textContent,\n        anchorHref: mobileAnchor.href || desktopAnchor.href,\n        anchorTitle: desktopAnchor.title,\n      }\n    : null;\n};\n\n/**\n * Creates a navigation anchor element.\n * @param {Object} anchorsAttributes - The attributes for the anchor.\n * @returns {HTMLElement} The created anchor element.\n */\nconst createSubNavAnchor = (anchorsAttributes) => {\n  const anchor = createElement('a', {\n    classes: ['button', 'button--large', 'button--red', `${blockName}__cta`],\n    props: { href: anchorsAttributes.anchorHref, title: anchorsAttributes.anchorTitle },\n  });\n\n  const mobileSpan = createElement('span', { classes: [`${blockName}__cta--mobile`] });\n  const desktopSpan = createElement('span', { classes: [`${blockName}__cta--desktop`] });\n\n  mobileSpan.textContent = anchorsAttributes.mobileAnchorText;\n  desktopSpan.textContent = anchorsAttributes.desktopAnchorText;\n\n  anchor.append(mobileSpan, desktopSpan);\n\n  return anchor;\n};\n\n/**\n * Finds and sets the active item based on the current URL.\n * If no item's href matches the current URL, sets the first item's anchor as active.\n * @param {NodeList} items - The list of navigation items.\n * @param {string} className - The class name to set on the active item.\n * @returns {string|null} The text content of the active item\n * or the text content of the first anchor if no match is found.\n */\nconst findAndSetActiveItem = (items, className) => {\n  const currentUrl = window.location.href;\n  let firstAnchor = null;\n\n  for (const item of items) {\n    const anchor = item.querySelector('a');\n    if (anchor) {\n      const anchorHref = new URL(anchor.getAttribute('href'), window.location.origin).href;\n\n      if (!firstAnchor) {\n        firstAnchor = anchor;\n      }\n\n      if (anchorHref === currentUrl) {\n        item.classList.add(className);\n        return anchor.textContent;\n      }\n    }\n  }\n\n  if (firstAnchor) {\n    firstAnchor.closest('li').classList.add(className);\n    return firstAnchor.textContent;\n  }\n\n  return null;\n};\n\n/**\n * Updates the --v2-sub-navigation-height CSS variable based on the viewport width.\n */\nconst updateSubNavigationHeight = () => {\n  const width = document.documentElement.clientWidth;\n  const height = width < 1200 ? '168px' : '218px';\n  document.documentElement.style.setProperty('--v2-sub-navigation-height', height);\n};\n\n/**\n * Initializes the ResizeObserver to monitor changes in the viewport width\n * and update the --v2-sub-navigation-height CSS variable accordingly.\n */\nconst initializeResizeObserver = () => {\n  const resizeObserver = new ResizeObserver(() => updateSubNavigationHeight());\n  resizeObserver.observe(document.documentElement);\n  updateSubNavigationHeight();\n};\n\n/**\n * Applies custom styles to the block's parent elements.\n * @param {HTMLElement} block - The block element to apply styles to.\n * @param {string} style - The custom style to apply.\n */\nconst applyCustomStyles = (block, style) => {\n  if (style) {\n    const twoUp = block.parentElement.parentElement;\n    twoUp.classList.add(`${blockName}__custom--${style}`);\n  }\n};\n\n/**\n * Sets up the sub-navigation block by fetching the sub-navigation HTML,\n * setting up the list and items, and managing the dropdown and picture elements.\n * @param {HTMLElement} block - The block element where the sub-navigation will be appended.\n * @param {string} content - The URL or content to fetch the sub-navigation HTML from.\n * @returns {Promise<void>} - A promise that resolves when the sub-navigation is set up.\n */\nconst setupSubNavigation = async (block, content) => {\n  try {\n    const fragment = await fetchSubNavHtml(content);\n    const list = fragment.querySelector('ul');\n    if (!list) {\n      return;\n    }\n\n    list.className = `${blockName}__items`;\n    const items = setupNavItems(list);\n    const activeItem = createElement('div', { classes: `${blockName}__active-item` });\n    const activeText = findAndSetActiveItem(items, `${blockName}__item--active`);\n    activeItem.textContent = activeText || '';\n\n    const subNavWrapper = createElement('div', { classes: `${blockName}__wrapper` });\n    const dropdownWrapper = createDropdownContainer(activeItem, list);\n    const anchorsAttributes = extractAnchorAttributes(fragment);\n    if (!anchorsAttributes) {\n      return;\n    }\n\n    const anchor = createSubNavAnchor(anchorsAttributes);\n    subNavWrapper.append(dropdownWrapper, anchor);\n\n    const picture = fragment.querySelector('picture');\n\n    if (picture) {\n      const subNavImageWrapper = createElement('div', { classes: `${blockName}__image-wrapper` });\n      subNavImageWrapper.append(picture);\n      block.append(subNavImageWrapper, subNavWrapper);\n      initializeResizeObserver();\n    } else {\n      block.append(subNavWrapper);\n    }\n\n    const customStyles = getMetadata('custom-subnav-style');\n    applyCustomStyles(block, customStyles);\n\n    document.addEventListener('click', toggleDropdown(dropdownWrapper));\n  } catch (error) {\n    console.error(error.message);\n  }\n};\n\n/**\n * Decorates the sub-navigation block.\n * @param {HTMLElement} block - The navigation block element.\n */\nconst decorate = async (block) => {\n  const metaContent = document.head.querySelector('meta[name=\"v2-sub-navigation\"]');\n\n  if (metaContent) {\n    await setupSubNavigation(block, metaContent.content);\n    decorateIcons(block);\n  }\n};\n\nexport default decorate;\n","import { createElement, unwrapDivs, variantsClassesToBEM } from '../../scripts/common.js';\nimport { setCarouselPosition, listenScroll } from '../../scripts/carousel-helper.js';\n\nconst blockName = 'v2-tabbed-carousel';\nconst variantClasses = ['fade-in', 'small-tabs'];\n// transform variantClasses to an object with keys and values are equal to the variant classes\nconst variants = variantClasses.reduce((acc, variant) => {\n  // variant name to camelCase\n  const variantName = variant.replace(/-([a-z])/g, (g) => g[1].toUpperCase());\n  acc[variantName] = variant;\n  return acc;\n}, {});\n\nconst moveNavigationLine = (navigationLine, activeTab, tabNavigation) => {\n  const { x: navigationX } = tabNavigation.getBoundingClientRect();\n  const { x, width } = activeTab.getBoundingClientRect();\n  Object.assign(navigationLine.style, {\n    left: `${x + tabNavigation.scrollLeft - navigationX}px`,\n    width: `${width}px`,\n  });\n};\n\nconst updateActiveItem = (elements, entry) => {\n  elements.forEach((el, index) => {\n    if (el === entry.target && entry.intersectionRatio >= 0.75) {\n      const carouselItems = el.parentElement;\n      const navigation = el.parentElement.nextElementSibling;\n      const navigationLine = navigation.querySelector(`.${blockName}__navigation-line`);\n\n      [carouselItems, navigation].forEach((c) => c.querySelectorAll('.active').forEach((i) => i.classList.remove('active')));\n      carouselItems.children[index].classList.add('active');\n      navigation.children[index].classList.add('active');\n\n      const activeNavigationItem = navigation.children[index];\n      moveNavigationLine(navigationLine, activeNavigationItem, navigation);\n\n      // Center navigation item\n      const navigationActiveItem = navigation.querySelector('.active');\n\n      if (navigation && navigationActiveItem) {\n        const { clientWidth: itemWidth, offsetLeft } = navigationActiveItem;\n        // Calculate the scroll position to center the active item\n        const scrollPosition = offsetLeft - (navigation.clientWidth - itemWidth) / 2;\n        navigation.scrollTo({\n          left: scrollPosition,\n          behavior: 'smooth',\n        });\n      }\n    }\n  });\n};\n\nconst jumpToCarouselItem = (carousel, index, navigation) => {\n  const { width } = carousel.firstElementChild.getBoundingClientRect();\n  const navigationLine = navigation.querySelector(`.${blockName}__navigation-line`);\n\n  // remove active class from activeItem and activeNavigationItem\n  carousel.querySelector('.active').classList.remove('active');\n  navigation.querySelector('.active').classList.remove('active');\n\n  // add active class to the item and navigation item at the index\n  carousel.children[index].classList.add('active');\n  navigation.children[index].classList.add('active');\n\n  // move the navigation line to the active navigation item\n  moveNavigationLine(navigationLine, navigation.children[index], navigation);\n\n  // translate carousel to the active item and center it based in the width of the first item\n  carousel.style.transform = `translateX(-${index * width}px)`;\n};\n\nexport default function decorate(block) {\n  const currentVariant = variantClasses.find((variant) => block.classList.contains(variant)) || null;\n  variantsClassesToBEM(block.classList, variantClasses, blockName);\n  const carouselContainer = createElement('div', { classes: `${blockName}__container` });\n  const carouselItems = createElement('ul', { classes: `${blockName}__items` });\n  carouselContainer.append(carouselItems);\n\n  const tabNavigation = createElement('ul', { classes: `${blockName}__navigation` });\n  const navigationLine = createElement('li', { classes: `${blockName}__navigation-line` });\n  let timeout;\n\n  function buildTabNavigation(buttonContent, index) {\n    const listItem = createElement('li', { classes: `${blockName}__navigation-item` });\n    const button = createElement('button');\n    const moveCarousel =\n      !currentVariant || currentVariant !== variants.fadeIn\n        ? () => setCarouselPosition(carouselItems, index - 1)\n        : () => jumpToCarouselItem(carouselItems, index - 1, tabNavigation);\n    button.addEventListener('click', moveCarousel);\n    button.addEventListener('mouseover', (e) => {\n      clearTimeout(timeout);\n      moveNavigationLine(navigationLine, e.currentTarget, tabNavigation);\n    });\n\n    button.addEventListener('mouseout', () => {\n      timeout = setTimeout(() => {\n        const activeItem = block.querySelector(`.${blockName}__navigation-item.active`);\n        moveNavigationLine(navigationLine, activeItem, tabNavigation);\n      }, 600);\n    });\n\n    button.innerHTML = buttonContent;\n    listItem.append(button);\n\n    return listItem;\n  }\n\n  const tabItems = block.querySelectorAll(':scope > div');\n  tabItems.forEach((tabItem, index) => {\n    const picture = tabItem.querySelector('picture');\n    if (picture) {\n      const liItem = createElement('li', { classes: `${blockName}__item` });\n      const figure = createElement('figure', { classes: `${blockName}__figure` });\n      const tabContent = tabItem.querySelector('p');\n\n      figure.append(tabContent.querySelector('picture'));\n\n      const figCaptionNodes = [...tabContent.childNodes].filter(\n        (node) => (node.nodeType === Node.TEXT_NODE || node.nodeName === 'SUP') && node.textContent.trim() !== '',\n      );\n      if (figCaptionNodes) {\n        const figureCaption = createElement('figcaption');\n        figureCaption.append(...figCaptionNodes);\n        figure.append(figureCaption);\n      }\n\n      liItem.append(figure);\n      carouselItems.appendChild(liItem);\n\n      // navigation item\n      const tabTitle = tabItem.querySelector('h3');\n      const navItem = buildTabNavigation(tabTitle.innerHTML, index);\n      tabNavigation.append(navItem);\n      tabTitle.remove();\n      tabItem.innerHTML = '';\n    } else {\n      const carouselTitle = tabItem.querySelector('h2');\n      carouselTitle?.classList.add(`${blockName}__title`);\n      const carouselText = tabItem.querySelector('p');\n      carouselText?.classList.add(`${blockName}__text`);\n      tabItem.classList.add(`${blockName}__heading-wrapper`);\n    }\n  });\n\n  tabNavigation.append(navigationLine);\n  carouselContainer.append(tabNavigation);\n\n  block.append(carouselContainer);\n\n  // update the button indicator on scroll\n  const elements = carouselItems.querySelectorAll(':scope > *');\n  listenScroll(carouselItems, elements, updateActiveItem, 0.75);\n  unwrapDivs(block);\n}\n","import { isVideoLink, selectVideoLink } from '../../scripts/video-helper.js';\nimport { removeEmptyTags, unwrapDivs, variantsClassesToBEM } from '../../scripts/common.js';\n\nconst blockName = 'v2-testimonial';\nconst variantClasses = ['media-left', 'media-right', 'overlap'];\n\nconst handleVideoLinks = (videoLinks) => {\n  const selectedVideo = selectVideoLink(videoLinks);\n\n  videoLinks.forEach((link) => {\n    if (link !== selectedVideo) {\n      link.parentElement.remove();\n    }\n  });\n\n  if (selectedVideo) {\n    selectedVideo.classList.add(`${blockName}__video-link`);\n    return;\n  }\n\n  console.warn(`[${blockName}]: No proper video link provided for current cookie settings!`);\n};\n\nconst createVideoSection = (col) => {\n  const videoLinks = [...col.querySelectorAll('a')].filter(isVideoLink);\n\n  if (videoLinks.length === 0) {\n    return;\n  }\n\n  handleVideoLinks(videoLinks);\n  const videoSection = col.querySelector('p');\n  videoSection.classList.add(`${blockName}__video-section`);\n  videoSection.setAttribute('data-theme', 'gold');\n  videoSection.append(col.querySelector(`.${blockName}__video-link`));\n};\n\nconst handleBlockquotes = (block, firstHeading) => {\n  let blockquotes = block.querySelectorAll('blockquote');\n  if (blockquotes.length === 0) {\n    console.warn(`[${blockName}]: No blockquote found in the column! Will try to create a blockquote from the text.`);\n\n    const blockquoteCol = block.querySelector(`.${blockName}__blockquote-container`);\n    const paragraphs = blockquoteCol.querySelectorAll('p:only-child, p:not(:last-child)');\n\n    if (paragraphs.length === 0) {\n      console.error(`[${blockName}]: No paragraphs found in the column!`);\n      return;\n    }\n\n    const blockquote = document.createElement('blockquote');\n\n    paragraphs.forEach((p) => {\n      blockquote.append(p);\n    });\n\n    firstHeading.insertAdjacentElement('afterend', blockquote);\n  }\n  blockquotes = block.querySelectorAll('blockquote');\n  blockquotes.forEach((bq) => {\n    const em = bq.querySelector('em');\n\n    if (em) {\n      em.outerHTML = em.innerHTML;\n    }\n\n    bq.classList.add(`${blockName}__blockquote`);\n  });\n};\n\nexport default async function decorate(block) {\n  variantsClassesToBEM(block.classList, variantClasses, blockName);\n  block.parentElement.classList.add('full-width');\n\n  const columns = block.querySelectorAll(':scope > div > div');\n  const headings = block.querySelectorAll('h1, h2, h3, h4, h5, h6');\n  const firstHeading = headings[0];\n\n  columns.forEach((col) => {\n    if (col.contains(firstHeading)) {\n      col.parentElement.classList.add(`${blockName}__column`, `${blockName}__column--text`);\n      col.classList.add(`${blockName}__blockquote-container`);\n      headings.forEach((h) => {\n        h.classList.add(`${blockName}__heading`);\n      });\n      firstHeading.classList.add('with-marker');\n    }\n\n    const images = [...col.querySelectorAll('img')];\n    images.forEach((img) => {\n      img.classList.add(`${blockName}__image`);\n      img.parentElement.classList.add(`${blockName}__column`, `${blockName}__column--media`);\n    });\n\n    createVideoSection(col);\n  });\n\n  handleBlockquotes(block, firstHeading);\n  unwrapDivs(block, { ignoreDataAlign: true });\n  removeEmptyTags(block);\n}\n","import { createElement, removeEmptyTags, unwrapDivs, variantsClassesToBEM } from '../../scripts/common.js';\n\nconst windowBreakpoint = 1200;\nconst getDevice = () => window.innerWidth >= windowBreakpoint;\nconst blockName = 'v2-truck-builder';\nconst variantClasses = ['hide-description', 'media-right'];\n\nconst addAccordionClass = (item) => {\n  const hasPicture = item.querySelector('picture');\n  if (hasPicture) {\n    hasPicture.classList.add(`${blockName}__item-image`);\n  } else {\n    const header = item.querySelector(':is(h1, h2, h3, h4, h5, h6)');\n    if (header) {\n      header.classList.add(`${blockName}__item-title`);\n    }\n    item.querySelectorAll('p').forEach((p) => p.classList.add(`${blockName}__item-description`));\n  }\n};\n\nconst watchScroll = (container) => {\n  const items = container.querySelectorAll(`.${blockName}__item`);\n  const observer = new IntersectionObserver(\n    (entries) => {\n      entries.forEach((entry) => {\n        const intersecting = entry.isIntersecting;\n        if (intersecting && !getDevice()) {\n          entry.target.classList.add('active');\n        } else if (!getDevice()) {\n          entry.target.classList.remove('active');\n        }\n      });\n    },\n    { threshold: 0.5 },\n  );\n  items.forEach((item) => {\n    if (!getDevice()) {\n      observer.observe(item);\n    } else {\n      observer.disconnect();\n    }\n  });\n};\n\nconst getIdxNumber = (item) => {\n  const selectedItem = item.closest('button').parentElement;\n  let num;\n  const classes = [...selectedItem.classList];\n  classes.forEach((el) => {\n    if (el.substring(0, 7) === 'number-') {\n      num = el.split('-').pop();\n    }\n  });\n  return Number(num);\n};\n\nconst handleResize = (container) => {\n  if (getDevice()) {\n    const allItems = container.querySelectorAll(`.${blockName}__item`);\n    allItems.forEach((item) => {\n      item.classList.remove('active');\n    });\n    allItems[0].classList.add('active');\n  } else {\n    watchScroll(container);\n  }\n};\n\nexport default function decorate(block) {\n  variantsClassesToBEM(block.classList, variantClasses, blockName);\n\n  const header = block.querySelector(':scope > div:first-child > div > :first-child');\n  const button = block.querySelector(':scope > div:nth-child(2) > div > :last-child');\n  const buttonContainer = block.querySelector(':scope > div:nth-child(2) > div');\n  const backgroundImage = block.querySelector(':scope > div:nth-child(3) > div > :last-child');\n\n  backgroundImage.classList.add(`${blockName}__bg-image`);\n\n  const accordionItems = [...block.querySelectorAll(':scope > div:nth-child(n+4)')];\n\n  const accordionContainer = createElement('div', { classes: `${blockName}__accordion-container` });\n  const itemsContainer = createElement('div', { classes: `${blockName}__items-container` });\n  block.parentElement.classList.add('full-width');\n  header.parentElement.classList.add(`${blockName}__header-wrapper`);\n  header.parentElement.parentElement.classList.add(`${blockName}__header-container`);\n\n  // style the header as an h2 with red marker over it\n  header.classList.add(`${blockName}__header`, 'with-marker');\n\n  // is responsibility of the author to add the proper amount of images and text\n  accordionItems.forEach((item, i) => {\n    const colBtnTitle = createElement('button', {\n      classes: `${blockName}__item-header-button`,\n      props: { type: 'button' },\n    });\n    const colItems = [...item.querySelectorAll(':scope > div')];\n\n    // add the proper classes to each accordion item\n    item.classList.add(`${blockName}__item`, `number-item-${i + 1}`);\n    if (i === 0 && getDevice()) {\n      item.classList.add('active');\n    }\n    colItems.forEach((col) => addAccordionClass(col, i));\n    colBtnTitle.prepend(item.querySelector(`.${blockName}__item-title`), item.querySelector(`.${blockName}__item-description`));\n    colBtnTitle.onclick = (e) => {\n      if (!getDevice()) {\n        const clickedNum = getIdxNumber(e.target);\n        const selectedItem = itemsContainer.querySelector(`.${blockName}__item.number-item-${clickedNum}`);\n        const { x: itemWidth } = selectedItem.getBoundingClientRect();\n        itemsContainer.scrollLeft += itemWidth;\n      } else {\n        const active = accordionContainer.querySelector('.active');\n        if (active && active !== item) {\n          active.classList.remove('active');\n        }\n        item.classList.add('active');\n      }\n    };\n\n    item.prepend(colBtnTitle);\n    itemsContainer.appendChild(item);\n  });\n  button.classList.add('button--large', `${blockName}__builder-button`);\n\n  itemsContainer.append(buttonContainer);\n  accordionContainer.append(backgroundImage, itemsContainer);\n  block.appendChild(accordionContainer);\n\n  window.addEventListener('resize', () => handleResize(itemsContainer));\n  watchScroll(itemsContainer);\n\n  unwrapDivs(block, { ignoreDataAlign: true });\n  removeEmptyTags(block);\n}\n","import { createElement, unwrapDivs, variantsClassesToBEM } from '../../scripts/common.js';\nimport { getAllElWithChildren } from '../../scripts/scripts.js';\n\nconst blockName = 'v2-truck-features';\nconst desktopMQ = window.matchMedia('(min-width: 1200px)');\nconst DESKTOP_SCROLL_PADDING = 200;\nconst MOBILE_SCROLL_PADDING = 400;\nlet slideScrollPaddingInPx = desktopMQ.matches ? DESKTOP_SCROLL_PADDING : MOBILE_SCROLL_PADDING;\n\ndesktopMQ.addEventListener('change', (event) => {\n  slideScrollPaddingInPx = event.matches ? DESKTOP_SCROLL_PADDING : MOBILE_SCROLL_PADDING;\n});\n\nconst selectImagesList = (slide) => {\n  const imagesLists = [...getAllElWithChildren(slide.querySelectorAll('ul'), ':scope > li > picture')];\n\n  if (imagesLists === 0) {\n    return;\n  }\n\n  imagesLists.forEach((el) => {\n    el.style.display = 'none';\n  });\n\n  const selectedImagesListIndex = desktopMQ.matches ? '-1' : '0';\n\n  imagesLists.at(selectedImagesListIndex).style.display = 'block';\n  imagesLists.at(selectedImagesListIndex).classList.add(`${blockName}__images-list`);\n};\n\nconst setContentWrapperHeight = (wrapper, slidesCount) => {\n  const navHeight = getComputedStyle(document.documentElement).getPropertyValue('--nav-height');\n  const navHeightInPx = Number.parseInt(navHeight, 10); // assuming that the --nav-height is in px\n  const inPageNav = getComputedStyle(document.documentElement).getPropertyValue('--inpage-navigation-height');\n  // assuming that the --inpage-navigation-height is in px\n  const inPageNavInPx = Number.parseInt(inPageNav, 10);\n  const windowHeightInPx = window.innerHeight;\n  const availableViewportInPx = windowHeightInPx - navHeightInPx - inPageNavInPx;\n  // wrapper height is the viewport height without navigations\n  // (to make sure that the slide will fit inside the block) + scroll padding for every slide\n  const wrapperHeight = slideScrollPaddingInPx * slidesCount + availableViewportInPx;\n  wrapper.style.height = `${wrapperHeight}px`;\n};\n\nexport default async function decorate(block) {\n  const activeSlideClass = `${blockName}__slide--active`;\n  const activeSlideImageClass = `${blockName}__slide-image--active`;\n  const variantClasses = ['image-left', 'image-shadow'];\n  variantsClassesToBEM(block.classList, variantClasses, blockName);\n\n  [...block.querySelectorAll(':scope > div')].forEach(unwrapDivs);\n\n  const heading = block.querySelector(':scope > div > :is(h1, h2, h3, h4, h5, h6)');\n  const rows = [...block.querySelectorAll(':scope > div')].slice(1);\n  const list = createElement('ul', { classes: `${blockName}__slides` });\n  const contentEl = createElement('div', { classes: `${blockName}__content` });\n\n  heading.parentElement.replaceWith(heading);\n  heading.classList.add(`${blockName}__heading`);\n\n  contentEl.append(heading, list);\n  block.append(contentEl);\n\n  // moving the rows to list\n  rows.forEach((el) => {\n    const newEl = createElement('li', { classes: `${blockName}__slide` });\n    const textWrapper = createElement('div', { classes: `${blockName}__text-wrapper` });\n\n    newEl.innerHTML = el.innerHTML;\n\n    const descriptionHeading = newEl.querySelector(':scope > :is(h1, h2, h3, h4, h5, h6)');\n    const description = newEl.querySelector(':scope > p');\n\n    descriptionHeading.replaceWith(textWrapper);\n    textWrapper.append(descriptionHeading, description);\n\n    el.remove();\n    list.append(newEl);\n    selectImagesList(newEl);\n  });\n\n  const slidesCount = list.querySelectorAll(`.${blockName}__images-list picture`).length;\n  setContentWrapperHeight(block, slidesCount);\n\n  // setting the first slide as active\n  let activeSlide = list.children[0];\n  activeSlide.classList.add(activeSlideClass);\n  // setting the first image in the first slide active\n  let activePicListItem = activeSlide.querySelector(`.${blockName}__images-list li`);\n  activePicListItem.classList.add(activeSlideImageClass);\n\n  const showNextSlide = () => {\n    const nextImageInSlide = block.querySelector(`.${activeSlideImageClass} + li`);\n    let hasNextSlide = true;\n\n    // if there is a next image in the same slide just switch image\n    if (nextImageInSlide) {\n      activePicListItem.classList.remove(activeSlideImageClass);\n      nextImageInSlide.classList.add(activeSlideImageClass);\n      activePicListItem = nextImageInSlide;\n    } else {\n      // if no next image in slide switch to next slide\n      const nextSlide = block.querySelector(`.${activeSlideClass} + li`);\n\n      if (nextSlide) {\n        activeSlide.classList.remove(activeSlideClass);\n        nextSlide.classList.add(activeSlideClass);\n        activeSlide = nextSlide;\n\n        activePicListItem.classList.remove(activeSlideImageClass);\n        activePicListItem = nextSlide.querySelector(`.${blockName}__images-list li`);\n        activePicListItem.classList.add(activeSlideImageClass);\n      } else {\n        hasNextSlide = false;\n      }\n    }\n\n    return hasNextSlide;\n  };\n\n  const showPrevSlide = () => {\n    const prevImageInSlide = block.querySelector(`.${activeSlideImageClass}`).previousElementSibling;\n    let hasPrevSlide = true;\n\n    // if there is a prev image in the same slide just switch image\n    if (prevImageInSlide) {\n      activePicListItem.classList.remove(activeSlideImageClass);\n      prevImageInSlide.classList.add(activeSlideImageClass);\n      activePicListItem = prevImageInSlide;\n    } else {\n      // if no prev image in slide switch to prev slide\n      const prevSlide = block.querySelector(`.${activeSlideClass}`).previousElementSibling;\n\n      if (prevSlide) {\n        activeSlide.classList.remove(activeSlideClass);\n        prevSlide.classList.add(activeSlideClass);\n        activeSlide = prevSlide;\n\n        activePicListItem.classList.remove(activeSlideImageClass);\n        activePicListItem = prevSlide.querySelector(`.${blockName}__images-list li:last-of-type`);\n        activePicListItem.classList.add(activeSlideImageClass);\n      } else {\n        hasPrevSlide = false;\n      }\n    }\n\n    return hasPrevSlide;\n  };\n\n  let slideIndex = 0;\n\n  window.addEventListener('scroll', () => {\n    const navHeight = getComputedStyle(document.documentElement).getPropertyValue('--nav-height');\n    const navHeightInPx = Number.parseInt(navHeight, 10); // assuming that the --nav-height is in px\n    const inPageNav = getComputedStyle(document.documentElement).getPropertyValue('--inpage-navigation-height');\n    // assuming that the --inpage-navigation-height is in px\n    const inPageNavInPx = Number.parseInt(inPageNav, 10);\n    const { top: blockTopPosition, bottom: blockBottomPosition } = block.getBoundingClientRect();\n\n    if (blockTopPosition < navHeightInPx + inPageNavInPx && blockBottomPosition > navHeightInPx + inPageNavInPx) {\n      const blockScrollInPx = Math.abs(blockTopPosition - navHeightInPx - inPageNavInPx);\n      const newSlideIndex = Math.floor(blockScrollInPx / slideScrollPaddingInPx);\n\n      if (newSlideIndex > slidesCount) {\n        return;\n      }\n\n      if (newSlideIndex > slideIndex) {\n        showNextSlide();\n      }\n\n      if (newSlideIndex < slideIndex) {\n        showPrevSlide();\n      }\n\n      slideIndex = newSlideIndex;\n    }\n  });\n}\n","import { createElement, decorateIcons, getTextLabel } from '../../scripts/common.js';\nimport { createArrowControls, listenScroll, setCarouselPosition } from '../../scripts/carousel-helper.js';\n\nconst blockName = 'v2-truck-lineup';\nconst tabContentClass = `.${blockName}__content`;\n\nfunction stripEmptyTags(main, child) {\n  if (child && child !== main && child.innerHTML.trim() === '') {\n    const parent = child.parentNode;\n    child.remove();\n    stripEmptyTags(main, parent);\n  }\n}\n\nconst moveNavigationLine = (navigationLine, activeTab, tabNavigation) => {\n  const { x: navigationX } = tabNavigation.getBoundingClientRect();\n  const { x, width } = activeTab.getBoundingClientRect();\n  Object.assign(navigationLine.style, {\n    left: `${x + tabNavigation.scrollLeft - navigationX}px`,\n    width: `${width}px`,\n  });\n};\n\nconst setNavigationLine = (tabNavigation) => {\n  const navWidth = tabNavigation.offsetWidth;\n  const viewportWidth = document.documentElement.clientWidth;\n  const listItems = tabNavigation.querySelectorAll(`.${blockName}__navigation-item`);\n  let totalWidth = 0;\n\n  [...listItems].forEach((listItem) => {\n    totalWidth += listItem.getBoundingClientRect().width;\n  });\n\n  let borderScale = totalWidth;\n  if (totalWidth + 32 <= navWidth) {\n    borderScale = navWidth === 1040 && viewportWidth >= 1200 ? navWidth : navWidth - 32;\n  }\n  tabNavigation.style.setProperty('--truck-lineup-border-scale', `${borderScale}`);\n};\n\nfunction buildTabNavigation(tabItems, clickHandler) {\n  const tabNavigationContainer = createElement('div', { classes: `${blockName}__navigation-container` });\n  const tabNavigation = createElement('ul', { classes: `${blockName}__navigation` });\n  const navigationLine = createElement('li', { classes: `${blockName}__navigation-line` });\n  let timeout;\n\n  [...tabItems].forEach((tabItem, i) => {\n    const listItem = createElement('li', { classes: `${blockName}__navigation-item` });\n    const button = createElement('button');\n    button.addEventListener('click', () => clickHandler(i));\n    button.addEventListener('mouseover', (e) => {\n      clearTimeout(timeout);\n      moveNavigationLine(navigationLine, e.currentTarget, tabNavigation);\n    });\n\n    button.addEventListener('mouseout', () => {\n      timeout = setTimeout(() => {\n        const activeItem = document.querySelector(`.${blockName}__navigation-item.active button`);\n        moveNavigationLine(navigationLine, activeItem, tabNavigation);\n      }, 600);\n    });\n\n    const tabContent = tabItem.querySelector(tabContentClass);\n    const icon = tabContent && tabContent?.dataset.truckCarouselIcon;\n    const svgIcon = icon ? `<span class=\"icon icon-${icon}\"></span>` : '';\n    button.innerHTML = `${tabContent.dataset.truckCarousel}${svgIcon}`;\n    listItem.append(button);\n    tabNavigation.append(listItem);\n  });\n\n  tabNavigation.append(navigationLine);\n  tabNavigationContainer.append(tabNavigation);\n\n  return tabNavigationContainer;\n}\n\nconst updateActiveItem = (index) => {\n  const images = document.querySelector(`.${blockName}__images-container`);\n  const descriptions = document.querySelector(`.${blockName}__description-container`);\n  const navigation = document.querySelector(`.${blockName}__navigation`);\n  const navigationLine = document.querySelector(`.${blockName}__navigation-line`);\n  const tabNavigation = document.querySelector(`.${blockName}__navigation`);\n\n  [images, descriptions, navigation].forEach((c) => c.querySelectorAll('.active').forEach((i) => i.classList.remove('active')));\n  images.children[index].classList.add('active');\n  descriptions.children[index].classList.add('active');\n  navigation.children[index].classList.add('active');\n\n  const activeNavigationItem = navigation.children[index].querySelector('button');\n  moveNavigationLine(navigationLine, activeNavigationItem, navigation);\n  setNavigationLine(tabNavigation);\n\n  // Center navigation item\n  const navigationActiveItem = navigation.querySelector('.active');\n\n  if (navigation && navigationActiveItem) {\n    const { clientWidth: itemWidth, offsetLeft } = navigationActiveItem;\n    // Calculate the scroll position to center the active item\n    const scrollPosition = offsetLeft - (navigation.clientWidth - itemWidth) / 2;\n    navigation.scrollTo({\n      left: scrollPosition,\n      behavior: 'smooth',\n    });\n  }\n\n  // Update description position\n  const descriptionWidth = descriptions.offsetWidth;\n\n  descriptions.scrollTo({\n    left: descriptionWidth * index,\n    behavior: 'smooth',\n  });\n};\n\nconst scrollObserverFunction = (elements, entry) => {\n  // in case the block has a featured item, scroll to it\n  const featuredItem = [...elements].find((el) => el.classList.contains('featured'));\n  const targetElement = featuredItem || entry.target;\n  if (!targetElement) {\n    return;\n  }\n  let idx = 0;\n\n  elements.forEach((el, index) => {\n    if (el === targetElement && entry.intersectionRatio >= 0.9) {\n      if (featuredItem) {\n        idx = index;\n      }\n      updateActiveItem(index);\n    }\n  });\n\n  if (featuredItem) {\n    featuredItem.classList.remove('featured');\n    setCarouselPosition(targetElement.parentNode, idx);\n  }\n};\n\nconst arrowFragment = document.createRange().createContextualFragment(`<li>\n  <button aria-label=\"${getTextLabel('v2_truck_lineup:previous')}\">\n    <span class=\"icon icon-arrow-left\" />\n  </button>\n</li>\n<li>\n  <button aria-label=\"${getTextLabel('v2_truck_lineup:next')}\">\n    <span class=\"icon icon-arrow-right\" />\n  </button>\n</li>`);\n\nexport default async function decorate(block) {\n  const descriptionContainer = block.querySelector(':scope > div');\n  const tabItems = block.querySelectorAll(':scope > div > div');\n\n  const imagesWrapper = createElement('div', { classes: `${blockName}__slider-wrapper` });\n  const imagesContainer = createElement('div', { classes: `${blockName}__images-container` });\n  imagesWrapper.appendChild(imagesContainer);\n  descriptionContainer.classList.add(`${blockName}__description-container`);\n  block.prepend(imagesWrapper);\n\n  const tabNavigation = buildTabNavigation(tabItems, (index) => {\n    setCarouselPosition(imagesContainer, index);\n  });\n\n  // Arrows\n  createArrowControls(imagesContainer, `.${blockName}__image-item.active`, [`${blockName}__arrow-controls`], arrowFragment);\n  let arrowControls = imagesContainer.querySelector(`.${blockName}__arrow-controls`);\n\n  if (!arrowControls && imagesContainer.parentElement) {\n    const arrowControlsContainer = imagesContainer.parentElement?.querySelector(`.${blockName}__arrow-controls`);\n    if (arrowControlsContainer) {\n      arrowControls = arrowControlsContainer;\n    }\n  }\n  if (arrowControls) {\n    // move arrows to the end of the images container\n    imagesWrapper.append(arrowControls);\n  } else {\n    console.warn('%cArrow controls not found. %cplease refresh the page', 'color:red', 'color:default', { arrowControls, imagesContainer });\n  }\n\n  block.append(tabNavigation);\n\n  tabItems.forEach((tabItem) => {\n    tabItem.classList.add(`${blockName}__desc-item`);\n    const tabContent = tabItem.querySelector(tabContentClass);\n\n    const headings = tabContent ? tabContent.querySelectorAll('h1, h2, h3, h4, h5, h6') : [];\n    [...headings].forEach((heading) => heading.classList.add(`${blockName}__title`));\n\n    // create div for images and append inside image div container\n    const pictures = tabItem.querySelectorAll('picture');\n    // adds the featured class only to the first featured item even if there are more than one\n    const tabFeatured = tabContent.dataset.truckCarouselFeatured;\n    const hasImageFeatured = imagesContainer.querySelector('.featured');\n    const imageItem = createElement('div', {\n      classes: [`${blockName}__image-item`, ...(tabFeatured && !hasImageFeatured ? ['featured'] : [])],\n    });\n\n    pictures.forEach((pic, idx) => {\n      if (pictures.length > 1) {\n        pic.classList.add(`${blockName}__picture-${idx === 0 ? 'mobile' : 'desktop'}`);\n      }\n      imageItem.appendChild(pic);\n    });\n    imagesContainer.appendChild(imageItem);\n\n    // remove empty tags\n    tabContent.querySelectorAll('p, div').forEach((item) => {\n      stripEmptyTags(tabContent, item);\n    });\n\n    const descriptions = tabContent.querySelectorAll('p:not(.button-container)');\n    [...descriptions].forEach((description) => description.classList.add(`${blockName}__description`));\n\n    if (!descriptions || descriptions.length === 0) {\n      const buttonContainer = tabContent.querySelector('.button-container:has(:not(.button))');\n      if (buttonContainer) {\n        buttonContainer.className = `${blockName}__description`;\n      }\n    }\n\n    // Wrap text in container\n    const textContainer = createElement('div', { classes: `${blockName}__text` });\n    const text = tabContent.querySelector('.default-content-wrapper')?.querySelectorAll(':scope > *:not(.button-container)');\n    if (text.length) {\n      const parentTextContainer = text[0].parentNode;\n      textContainer.append(...text);\n      parentTextContainer.appendChild(textContainer);\n    }\n\n    // Wrap links in container\n    const buttonContainer = createElement('div', { classes: `${blockName}__buttons-container` });\n    const buttons = tabContent.querySelectorAll('.button-container');\n\n    if (buttons.length) {\n      const parentButtonContainer = buttons[0].parentNode;\n      buttonContainer.append(...buttons);\n      parentButtonContainer.appendChild(buttonContainer);\n    }\n  });\n\n  // update the button indicator on scroll\n  const elements = imagesContainer.querySelectorAll(':scope > *');\n  listenScroll(imagesContainer, elements, scrollObserverFunction, 0.9);\n\n  // Update text position + navigation line when page is resized\n  window.addEventListener('resize', () => {\n    const activeItem = imagesContainer.querySelector(`.${blockName}__image-item.active`);\n    if (!activeItem || !activeItem?.parentNode) {\n      return;\n    }\n\n    const index = [...activeItem.parentNode.children].indexOf(activeItem);\n    updateActiveItem(index);\n    setTimeout(() => {\n      setNavigationLine(tabNavigation);\n    }, 100);\n  });\n\n  decorateIcons(block);\n}\n","import { removeEmptyTags, variantsClassesToBEM } from '../../scripts/common.js';\nimport { createVideo, cleanupVideoLink } from '../../scripts/video-helper.js';\n\nconst extractAspectRatio = (block) => {\n  const aspectRatioRegex = /aspect-ratio-(\\d+)-(\\d+)/;\n  const aspectRatioClass = Array.from(block.classList).find((className) => aspectRatioRegex.test(className));\n\n  const match = aspectRatioClass?.match(aspectRatioRegex);\n\n  return match\n    ? {\n        width: parseInt(match[1], 10),\n        height: parseInt(match[2], 10),\n      }\n    : null;\n};\n\nconst retrieveVideoConfig = (block, aspectRatio) => {\n  const image = block.querySelector('img');\n  const poster = image ? new URL(image.getAttribute('src'), window.location.href).href : undefined;\n\n  return {\n    ...(aspectRatio ? { aspectRatio: `${aspectRatio.width}:${aspectRatio.height}` } : {}),\n    ...(poster ? { poster } : {}),\n    autoplay: block.classList.contains('autoplay'),\n    muted: block.classList.contains('autoplay') || block.classList.contains('muted'),\n    loop: block.classList.contains('loop'),\n    controls: block.classList.contains('controls'),\n    disablePictureInPicture: block.classList.contains('disable-picture-in-picture'),\n    language: document.documentElement.lang,\n    playsinline: true,\n  };\n};\n\nconst variantClasses = ['expanding'];\n\nexport default async function decorate(block) {\n  const blockName = 'v2-video';\n  const videoLink = block.querySelector('a');\n\n  variantsClassesToBEM(block.classList, variantClasses, blockName);\n\n  if (!videoLink) {\n    console.warn('Video for v2-video block is required and not provided. The block will not render!');\n    block.innerHTML = '';\n    return;\n  }\n\n  const aspectRatio = extractAspectRatio(block);\n  if (aspectRatio) {\n    block.style.setProperty('--video-aspect-ratio', `${aspectRatio.width}/${aspectRatio.height}`);\n  }\n\n  const config = retrieveVideoConfig(block, aspectRatio);\n  const video = createVideo(\n    videoLink,\n    `${blockName}__video`,\n    {\n      ...config,\n      fill: true,\n    },\n    {\n      usePosterAutoDetection: true,\n      addMuteToggle: config.controls === false, // Only add mute toggle when custom controls are enabled\n    },\n  );\n\n  cleanupVideoLink(block, videoLink, true);\n  removeEmptyTags(block, true);\n  block.prepend(video);\n}\n","import { readBlockConfig } from '../../scripts/aem.js';\nimport { getTextLabel, createElement, getJsonFromUrl, getPlaceholders, getLocale } from '../../scripts/common.js';\n\n// Only these 3 variables are brand-specific\nconst BRAND = 'mack';\nconst formValidationPattern = '^[1,4][M,m][1,2,4,5][A,G,L,P,T,M,a,g,l,p,t,m][A-Za-z0-9]{13}$';\nconst brandBtnClasses = 'button button--primary';\n\nconst docRange = document.createRange();\nconst blockName = 'vin-number';\nconst refreshDateUniqueKey = `refresh-date-${BRAND}`;\nlet configUrl;\n\n// All placeholder label values\nconst LABELS = {\n  resultText: 'vin_number:result_text',\n  modelYear: 'vin_number:model_year',\n  make: 'vin_number:make',\n  model: 'vin_number:model',\n  recalls: 'vin_number:recalls',\n  oldestInfo: 'vin_number:recall_oldest_info',\n  format: 'vin_number:format',\n  formatLength: 'vin_number:format_length',\n  availableInfo: 'vin_number:recall_available_info',\n  loadingRecalls: 'vin_number:loading_recalls',\n  noRecalls: 'vin_number:no_recalls',\n  publishedInfo: 'vin_number:published_info',\n  label: 'vin_number:label',\n  submit: 'vin_number:submit',\n};\n\nconst apiConfig = {\n  dev: {\n    url: 'https://vinlookup-dev-euw-ase-01.azurewebsites.net/v1/api/',\n    key: '0e13506b59674706ad9bae72d94fc83c',\n  },\n  qa: {\n    url: 'https://vinlookup-qa-euw-ase-01.azurewebsites.net/v1/api/',\n    key: '0e13506b59674706ad9bae72d94fc83c',\n  },\n  prod: {\n    url: 'https://vinlookup-prod-euw-ase-01.azurewebsites.net/v1/api/',\n    key: '0e13506b59674706ad9bae72d94fc83c',\n  },\n};\n\n// For the 'mfr_recall_status' field, these are the 3 possible responses\nconst recallStatusCodes = {\n  0: { arrayPosition: 0, status: 'complete' },\n  11: { arrayPosition: 1, status: 'incomplete' },\n  12: { arrayPosition: 2, status: 'incomplete-no-remedy' },\n};\n\n/**\n * Fetches configuration data for recall fields from a remote JSON file.\n * This function assumes 'configUrl' is a string variable defined in the outer scope\n * which holds the URL to the block's configuration file.\n *\n * @async\n * @function fetchRecallFields\n * @returns {Promise<Object|undefined>} A Promise that resolves with the parsed JSON object\n * @throws {Error} Errors are logged to the console.\n */\nconst fetchRecallFields = async () => {\n  try {\n    const { pathname } = new URL(configUrl);\n    const response = await fetch(pathname);\n\n    if (response.ok) {\n      return response.json();\n    } else {\n      console.error('Error fetching recall fields file', response.statusText);\n    }\n  } catch (error) {\n    console.error('Error with recall fields file', error);\n  }\n};\n\n/**\n * Formats a date string into a localized format (e.g., \"Aug 25, 2023\").\n * Uses language variable to determine the current locale like 'en' or 'fr'.\n *\n * @param {string | Date} date - The date value to format (e.g., \"2023-08-25\" or a Date object).\n * @returns {string} The formatted date string in the local format (e.g., 'en' or 'fr').\n */\nconst formatDateWithLocale = (date) => {\n  const language = getLocale().split('-')[0] || 'en';\n  const formattedDate = new Date(date).toLocaleDateString(language, { year: 'numeric', month: 'short', day: 'numeric' });\n  return formattedDate;\n};\n\n/**\n * Determines the appropriate API configuration based on the current hostname\n * environment (dev, qa, or prod).\n * @function getAPIConfig\n * @returns {Object} The configuration object corresponding to the current environment.\n */\nconst getAPIConfig = () => {\n  const host = window.location.host;\n\n  if (host.includes('aem.page')) {\n    return apiConfig['qa'];\n  }\n\n  if (host.includes('localhost')) {\n    return apiConfig['dev'];\n  }\n\n  return apiConfig['prod'];\n};\n\n/**\n * Retrieves an item from localStorage, checks for expiration, removes it if expired,\n * and formats the data using the utility function formatDateWithLocale.\n *\n * It is assumed that items are stored as JSON objects with the structure:\n * { data: '...', expireTime: <timestamp> }.\n *\n * @function getStorageItem\n * @param {string} key - The localStorage key to look up.\n * @returns {string | null} The formatted date string if the item is found and not expired,\n * otherwise returns null.\n */\nconst getStorageItem = (key) => {\n  const storedValue = window.localStorage.getItem(key);\n  if (!storedValue) {\n    return null;\n  }\n\n  try {\n    const result = JSON.parse(storedValue);\n\n    if (result.expireTime <= Date.now()) {\n      window.localStorage.removeItem(key);\n      return null;\n    }\n\n    return formatDateWithLocale(result.data);\n  } catch (error) {\n    console.error(`Error parsing localStorage key: \"${key}\"`, error);\n    window.localStorage.removeItem(key);\n    return null;\n  }\n};\n\n/**\n * Saves a value to the browser's localStorage, wrapping it in a structure\n * that includes an expiration timestamp.\n *\n * The stored object structure is: { data: value, expireTime: <timestamp> }.\n * The expiration time is currently set to 1 hour (60 * 60 * 1000 milliseconds)\n * from the time the function is called.\n *\n * @function setStorageItem\n * @param {string} key - The key under which to store the item in localStorage.\n * @param {*} value - The data to be stored. This value will be JSON stringified.\n * @returns {void}\n */\nconst setStorageItem = (key, value) => {\n  const result = {\n    data: value,\n    expireTime: Date.now() + 60 * 60 * 1000,\n  };\n  window.localStorage.setItem(key, JSON.stringify(result));\n};\n\n/**\n * Fetches the latest data refresh date, prioritizing a cached version from\n * localStorage that has not yet expired.\n * * If the cached item is missing or expired, it fetches the date from the API,\n * stores it in localStorage with a new expiration time, and then formats it.\n * @async\n * @function fetchRefreshDate\n * @returns {Promise<string|undefined>} A promise that resolves with the formatted\n * date string (e.g., \"Aug 25, 2023\"). Returns undefined if the API call fails.\n */\nconst fetchRefreshDate = async () => {\n  const refreshDate = getStorageItem(refreshDateUniqueKey);\n  if (!refreshDate) {\n    const { url, key } = getAPIConfig();\n    const response = await getJsonFromUrl(`${url}refreshdate?api_key=${key}`);\n    setStorageItem(refreshDateUniqueKey, response.refresh_date);\n\n    return formatDateWithLocale(response.refresh_date);\n  }\n  return refreshDate;\n};\n\n/**\n * Checks if a value is a valid date string (e.g., 'Aug 25, 2023', '9/11/2024', '17 févr. 2016')\n * This function explicitly excludes simple numeric inputs (like 0, 11, or 12)\n * which could be the value for 'mfr_recall_status' field\n *\n * * @param {string} value - The value to test. Expected to be a date string.\n * @returns {boolean} True if the value is a valid date string, false otherwise.\n */\nfunction isValidDateString(value) {\n  if (typeof value !== 'string' || value.trim() === '') {\n    return false;\n  }\n  const date = new Date(value);\n  return !isNaN(date.getTime());\n}\n\n/**\n * Processes and transforms field values based on the field key and a configurable\n * text string.\n * It handles two major transformations:\n * - Mapping 'mfr_recall_status' numeric code to descriptive text\n * - Formatting/labeling 'recall_effective_date'\n *\n * @function handleConfigurableFields\n * @param {string} key - The key identifying the field being processed (e.g., 'mfr_recall_status').\n * @param {*} value - The raw value of the field (e.g., a number for status, or a date string).\n * @param {string} text - A configurable string containing delimited text labels (expected to use '//' as delimiter).\n * @returns {string | * | undefined} The transformed string (status text or date label), the original\n * value (if lookup fails or input is invalid), or undefined if the key is unmatched.\n */\nconst handleConfigurableFields = (key, value, text) => {\n  const textArray = text?.split('//');\n\n  // MFR RECALL STATUS\n  if (key === 'mfr_recall_status') {\n    if (!textArray || textArray.length < 3) {\n      console.warn(`Recall configurable text format invalid or inexistent. Input: \"${text}\"`);\n      return value;\n    }\n    const statusObject = recallStatusCodes[value];\n    const recallStatus = textArray[statusObject.arrayPosition];\n    if (recallStatus !== undefined) {\n      return recallStatus;\n    }\n    console.warn(`Recall status code \"${value}\" not found in map.`);\n    return value;\n  }\n\n  // RECALL EFFECTIVE DATE\n  if (key === 'recall_effective_date') {\n    const recallDate = new Date(value).setHours(0, 0, 0, 0);\n    const today = new Date().setHours(0, 0, 0, 0);\n    return recallDate > today ? `${textArray[1]} ${formatDateWithLocale(value)}.` : textArray[0];\n  }\n\n  return undefined;\n};\n\nconst renderRecalls = async (recallsData, recal