onst orderedOptions = [...options.slice(startIndex), ...options.slice(0, startIndex)];\n  const firstMatch = filterOptions(orderedOptions, filter)[0];\n  const allSameLetter = (array) => array.every((letter) => letter === array[0]);\n\n  // first check if there is an exact match for the typed string\n  if (firstMatch) {\n    return options.indexOf(firstMatch);\n  }\n\n  // if the same letter is being repeated, cycle through first-letter matches\n  else if (allSameLetter(filter.split(''))) {\n    const matches = filterOptions(orderedOptions, filter[0]);\n    return options.indexOf(matches[0]);\n  }\n\n  // if no matches, return -1\n  else {\n    return -1;\n  }\n}\n\n/**\n * Get the updated index of an option after performing an action.\n *\n * @param {number} currentIndex - The current index of the option.\n * @param {number} maxIndex - The maximum index of the options.\n * @param {SelectActions} action - The action to perform.\n * @returns {number} - The updated index of the option.\n * @example\n * const currentIndex = 0;\n * const maxIndex = 2;\n * const action = SelectActions.Next;\n * const updatedIndex = getUpdatedIndex(currentIndex, maxIndex, action);\n * // expected output: 1\n */\nfunction getUpdatedIndex(currentIndex, maxIndex, action) {\n  const pageSize = 10; // used for pageup/pagedown\n\n  switch (action) {\n    case SelectActions.First:\n      return 0;\n    case SelectActions.Last:\n      return maxIndex;\n    case SelectActions.Previous:\n      return Math.max(0, currentIndex - 1);\n    case SelectActions.Next:\n      return Math.min(maxIndex, currentIndex + 1);\n    case SelectActions.PageUp:\n      return Math.max(0, currentIndex - pageSize);\n    case SelectActions.PageDown:\n      return Math.min(maxIndex, currentIndex + pageSize);\n    default:\n      return currentIndex;\n  }\n}\n\n/**\n * Check if an element is currently in the view port.\n *\n * @param {HTMLElement} element - The element to check if it is in the view port.\n * @returns {boolean} - Returns true if the element is in the view port, otherwise false.\n */\nfunction isElementInView(element) {\n  const bounding = element.getBoundingClientRect();\n\n  return (\n    bounding.top >= 0 &&\n    bounding.left >= 0 &&\n    bounding.bottom <= (window.innerHeight || document.documentElement.clientHeight) &&\n    bounding.right <= (window.innerWidth || document.documentElement.clientWidth)\n  );\n}\n\n/**\n * check if an element is currently scrollable\n *\n * @param {HTMLElement} element - The element to check if it is scrollable.\n * @returns {boolean} - Returns true if the element is scrollable, otherwise false.\n */\nfunction isScrollable(element) {\n  return element && element.clientHeight < element.scrollHeight;\n}\n\n/**\n * Ensure a given child element is within the parent's visible scroll area.\n * If the child is not visible, scroll the parent.\n *\n * @param {HTMLElement} activeElement - The child element to ensure is visible.\n * @param {HTMLElement} scrollParent - The parent element to scroll if the child is not visible.\n */\nfunction maintainScrollVisibility(activeElement, scrollParent) {\n  const { offsetHeight, offsetTop } = activeElement;\n  const { offsetHeight: parentOffsetHeight, scrollTop } = scrollParent;\n\n  const isAbove = offsetTop < scrollTop;\n  const isBelow = offsetTop + offsetHeight > scrollTop + parentOffsetHeight;\n\n  if (isAbove) {\n    scrollParent.scrollTo(0, offsetTop);\n  } else if (isBelow) {\n    scrollParent.scrollTo(0, offsetTop - parentOffsetHeight + offsetHeight);\n  }\n}\n\n/**\n * Select Component\n * Accepts a clickable element and an array of string options\n *\n * @param {HTMLElement} el - The element to attach the select component to.\n * @param {string[]} options - The list of options to display in the select.\n * @param {string} placeholder - The placeholder text for the select.\n * @param {function} onChangeCallback - The callback function to be called when the value changes.\n */\nconst Select = function (el, options = [], placeholder, onChangeCallback) {\n  // element refs\n  this.el = el;\n  this.labelEl = el.querySelector(`.${componentName}__label`);\n  this.buttonEl = el.querySelector('[role=button]');\n  this.listEl = el.querySelector('[role=listbox]');\n  this.initialState = true;\n\n  // data\n  this.idBase = this.buttonEl.id || componentName;\n  this.placeholder = placeholder;\n  this.options = options;\n  this.onChangeCallback = onChangeCallback;\n\n  // state\n  this.activeIndex = 0;\n  this.open = false;\n  this.searchString = '';\n  this.searchTimeout = null;\n\n  // init\n  if (el && this.buttonEl && this.listEl) {\n    this.init();\n  }\n};\n\n/**\n * Initialize the select component.\n */\nSelect.prototype.init = function init() {\n  // select first option by default\n  this.buttonEl.innerHTML = getOptionLabel(this.placeholder || this.options[0]);\n\n  // add event listeners\n  this.buttonEl.addEventListener('blur', this.onButtonBlur.bind(this));\n  this.listEl.addEventListener('focusout', this.onButtonBlur.bind(this));\n  this.buttonEl.addEventListener('click', this.onButtonClick.bind(this));\n  this.buttonEl.addEventListener('keydown', this.onButtonKeyDown.bind(this));\n\n  // create options\n  this.options.map((option, index) => {\n    const optionEl = this.createOption(option, index);\n    this.listEl.appendChild(optionEl);\n  });\n};\n\n/**\n * Create an option element.\n *\n * @param {string} option - The option to create an element for.\n * @param {number} index - The index of the option in the list.\n * @returns {HTMLElement} - The option element.\n */\nSelect.prototype.createOption = function createOption(option, index) {\n  const optionEl = createElement('div');\n  optionEl.setAttribute('role', 'option');\n  optionEl.id = `${this.idBase}-${index}`;\n\n  if (this.placeholder) {\n    optionEl.className = `${componentName}__option`;\n  } else {\n    optionEl.className = index === 0 ? `${componentName}__option option-current` : `${componentName}__option`;\n    optionEl.setAttribute('aria-selected', `${index === 0}`);\n  }\n\n  let normalizedOption = option;\n\n  if (typeof option === 'string' && option.includes(':')) {\n    // first value in the array is the translated label\n    // second value is the actual information sent to the server\n    const [value, label] = option.split(':');\n    value.trim();\n    normalizedOption = { label, value };\n  }\n\n  this.options[index] = normalizedOption;\n  optionEl.innerText = getOptionLabel(normalizedOption);\n\n  optionEl.addEventListener('click', (event) => {\n    event.stopPropagation();\n    this.onOptionClick(index);\n  });\n  optionEl.addEventListener('mousedown', this.onOptionMouseDown.bind(this));\n\n  return optionEl;\n};\n\n/**\n * Get the search string by adding the most recent letter to the saved search string.\n *\n * @param {string} char - The most recent letter to add to the search string.\n * @returns {string} - The search string.\n */\nSelect.prototype.getSearchString = function getSearchString(char) {\n  // reset typing timeout and start new timeout\n  // this allows us to make multiple-letter matches, like a native select\n  if (typeof this.searchTimeout === 'number') {\n    window.clearTimeout(this.searchTimeout);\n  }\n\n  this.searchTimeout = window.setTimeout(() => {\n    this.searchString = '';\n  }, 500);\n\n  // add most recent letter to saved search string\n  this.searchString += char;\n  return this.searchString;\n};\n\n/**\n * Handle the blur event on the button.\n *\n * @param {FocusEvent} event - The blur event.\n */\nSelect.prototype.onButtonBlur = function onButtonBlur(event) {\n  // do nothing if relatedTarget is contained within listEl\n  if (this.listEl.contains(event.relatedTarget)) {\n    return;\n  }\n\n  // select current option and close\n  if (this.open) {\n    this.updateMenuState(false, false);\n  }\n};\n\n/**\n * Handle the click event on the button.\n */\nSelect.prototype.onButtonClick = function onButtonClick() {\n  this.updateMenuState(!this.open, false);\n};\n\n/**\n * Handle the keydown event on the button.\n *\n * @param {KeyboardEvent} event - The keydown event.\n */\nSelect.prototype.onButtonKeyDown = function onButtonKeyDown(event) {\n  const { key } = event;\n  const max = this.options.length - 1;\n\n  const action = getActionFromKey(event, this.open);\n\n  switch (action) {\n    case SelectActions.Last:\n    case SelectActions.First:\n      this.updateMenuState(true);\n    // intentional fallthrough\n    case SelectActions.Next:\n    case SelectActions.Previous:\n    case SelectActions.PageUp:\n    case SelectActions.PageDown:\n      event.preventDefault();\n      return this.onOptionChange(getUpdatedIndex(this.activeIndex, max, action));\n    case SelectActions.CloseSelect:\n      event.preventDefault();\n      this.selectOption(this.activeIndex);\n    // intentional fallthrough\n    case SelectActions.Close:\n      event.preventDefault();\n      return this.updateMenuState(false);\n    case SelectActions.Type:\n      return this.onButtonType(key);\n    case SelectActions.Open:\n      event.preventDefault();\n      return this.updateMenuState(true);\n  }\n};\n\n/**\n * Handle the type event on the button.\n *\n * @param {string} letter - The letter to type.\n */\nSelect.prototype.onButtonType = function onButtonType(letter) {\n  // open the listbox if it is closed\n  this.updateMenuState(true);\n\n  // find the index of the first matching option\n  const searchString = this.getSearchString(letter);\n  const searchIndex = getIndexByLetter(this.options, searchString, this.activeIndex + 1);\n\n  // if a match was found, go to it\n  if (searchIndex >= 0) {\n    this.onOptionChange(searchIndex);\n  }\n  // if no matches, clear the timeout and search string\n  else {\n    window.clearTimeout(this.searchTimeout);\n    this.searchString = '';\n  }\n};\n\n/**\n * Handle the change event on an option.\n *\n * @param {number} index - The index of the option that changed.\n */\nSelect.prototype.onOptionChange = function onOptionChange(index) {\n  // update state\n  this.activeIndex = index;\n\n  // update aria-activedescendant\n  this.buttonEl.setAttribute('aria-activedescendant', `${this.idBase}-${index}`);\n\n  // update active option styles\n  const optionsElements = this.el.querySelectorAll('[role=option]');\n  [...optionsElements].forEach((optionEl) => {\n    optionEl.classList.remove('option-current');\n  });\n  optionsElements[index].classList.add('option-current');\n\n  // ensure the new option is in view\n  if (isScrollable(this.listEl)) {\n    maintainScrollVisibility(optionsElements[index], this.listEl);\n  }\n\n  // ensure the new option is visible on screen\n  // ensure the new option is in view\n  if (!isElementInView(optionsElements[index])) {\n    optionsElements[index].scrollIntoView({ behavior: 'smooth', block: 'nearest' });\n  }\n};\n\n/**\n * Handle the click event on an option.\n *\n * @param {number} index - The index of the option that was clicked.\n * @param {MouseEvent} event - The click event.\n */\nSelect.prototype.onOptionClick = function onOptionClick(index) {\n  this.onOptionChange(index);\n  this.selectOption(index);\n  this.updateMenuState(false);\n};\n\n/**\n * Handle the mousedown event on an option.\n */\nSelect.prototype.onOptionMouseDown = function onOptionMouseDown() {\n  // Clicking an option will cause a blur event,\n  // but we don't want to perform the default keyboard blur action\n  this.ignoreBlur = true;\n};\n\n/**\n * create an option item from the select element.\n *\n * @param {number} index - The index of the option to select.\n */\nSelect.prototype.selectOption = function selectOption(index) {\n  // update state\n  this.activeIndex = index;\n\n  // update displayed value\n  const selected = this.options[index];\n  this.buttonEl.innerHTML = getOptionLabel(selected);\n\n  // this updates the value of the select that gets inputed in the forms\n  const selectHtml = this.el.closest(`.${componentName}`).querySelector('select');\n  selectHtml.selectedIndex = this.placeholder ? index + 1 : index;\n\n  // update aria-selected\n  const optionsElements = this.el.querySelectorAll('[role=option]');\n  [...optionsElements].forEach((optionEl) => {\n    optionEl.setAttribute('aria-selected', 'false');\n  });\n  optionsElements[index].setAttribute('aria-selected', 'true');\n\n  // call the onChangeCallback if provided\n  if (this.onChangeCallback) {\n    this.onChangeCallback({\n      label: getOptionLabel(selected),\n      value: getOptionValue(selected),\n    });\n  }\n};\n\n/**\n * Update the state of the dropdown menu.\n *\n * @param {boolean} open - If the dropdown menu is open or not.\n * @param {boolean} [callFocus=true] - If the focus should be called on the button.\n */\nSelect.prototype.updateMenuState = function updateMenuState(open, callFocus = true) {\n  if (this.open === open) {\n    return;\n  }\n\n  // change placeholder text color\n  if (this.placeholder !== this.buttonEl.textContent) {\n    this.buttonEl.classList.remove('placeholder-state');\n  }\n\n  // update state\n  this.open = open;\n\n  // update aria-expanded and styles\n  this.buttonEl.setAttribute('aria-expanded', `${open}`);\n  open ? this.el.classList.add('open') : this.el.classList.remove('open');\n\n  // update activedescendant\n  const activeID = open ? `${this.idBase}-${this.activeIndex}` : '';\n  this.buttonEl.setAttribute('aria-activedescendant', activeID);\n\n  if (activeID === '' && !isElementInView(this.buttonEl)) {\n    this.buttonEl.scrollIntoView({ behavior: 'smooth', block: 'nearest' });\n  }\n\n  // move focus back to the button, if needed\n  callFocus && this.buttonEl.focus();\n};\n\n/**\n * Generates the markup for an HTML option element.\n *\n * @param {number} idx - The index of the option in the list.\n * @param {string|Object} option - The option data, which can be a string or an object with `value` and `label` properties.\n * @returns {string} The HTML markup for the option element.\n */\nconst createOptionMarkup = (idx, option, hasPlaceholder) => {\n  return `\n      <option\n        value=\"${getOptionValue(option)}\"\n        ${idx === 0 && !hasPlaceholder ? 'selected' : ''}>\n          ${getOptionLabel(option)}\n      </option>`;\n};\n\n/**\n * Generates the markup for a list of HTML option elements.\n *\n * @param {string[]|Object[]} list - The list of options to generate the markup for.\n * @param {boolean} hasPlaceholder - If the list has a placeholder option.\n * @returns {string} The HTML markup for the list of option elements.\n */\nconst createSelectHtml = (list, hasPlaceholder) => {\n  return list.map((item, idx) => createOptionMarkup(idx, item, hasPlaceholder)).join('');\n};\n\n/**\n * Get the variant classes for the dropdown.\n *\n * @param {Object} options - The options to configure the dropdown.\n * @param {string[]} options.variants - The list of variants to apply to the dropdown.\n * @returns {string} The variant classes for the dropdown.\n */\nfunction getVariantClasses(options) {\n  const { variants = [] } = options;\n  if (!Array.isArray(variants)) {\n    return [];\n  }\n  return variants.map((variant) => `${componentName}--variant-${variant}`).join(' ');\n}\n\n/**\n * Get the custom dropdown component asynchronously because it requires a CSS file to be loaded.\n *\n * @param {Object} options - The options to configure the dropdown.\n * @param {string[] | Object[]} options.optionList - The list of options to display in the dropdown. Each option can be a string or an object with `value` and `label` properties.\n * @param {string} options.label - The label to grab from the placeholder file using getTextLabel function.\n * @param {boolean} options.mandatory - If the dropdown is required or not.\n * @param {string} options.id - The id of the dropdown.\n * @param {string} options.placeholder - The placeholder text for the dropdown to be used as the default option.\n * @param {string} options.name - The name of the hidden select element that will be submitted in the form.\n * @param {string} options.formName - The name of the form that contains the dropdown.\n * @param {function} [options.onChangeCallback] - The callback function to be called when the value changes.\n * @param {string[]} options.variants - \"thick\", \"adjust-width-to-content\".\n *\n * Variants:\n * - \"thick\": Adds thicker appearance.\n * - \"adjust-width-to-content\": By default the dropdown will have a width of 100% of the container. If this option is set to true, the dropdown will adjust its width to the content.\n *\n * @returns {Promise<HTMLElement>} - The custom dropdown component as an HTMLElement.\n */\nexport const getCustomDropdown = async (options = {}) => {\n  const baseUrl = window.location.origin !== 'null' ? window.location.origin : window.location.ancestorOrigins && window.location.ancestorOrigins[0];\n  const { optionList = [], label = '', mandatory = false, id = '', placeholder = '', name = '', formName = '' } = options;\n  const dropdownCSS = `${baseUrl}/common/${componentName}/${componentName}.css`;\n  const className = options.variants ? [componentName, getVariantClasses(options)] : componentName;\n  const el = createElement('div', { classes: className });\n\n  if (formName) {\n    el.classList.add(`${formName}__field-wrapper`);\n  }\n\n  try {\n    await loadCSS(dropdownCSS);\n    const labelClass = label ? `${componentName}__label` : 'field-label';\n    const innerContent = `\n\n        ${label ? `<label id=\"${labelClass} class=\"${labelClass}\">${getTextLabel(label)}${mandatory ? '*' : ''}</label>` : ''}\n        <div\n          ${id ? `id=\"${id}\"` : ''}\n          ${labelClass ? `aria-labelledby=\"${labelClass}\"` : ''}\n          aria-controls=\"options\"\n          aria-expanded=\"false\"\n          aria-haspopup=\"${componentName}\"\n          class=\"${componentName}__button placeholder-state\"\n          role=\"button\"\n          tabindex=\"0\"\n        ></div>\n        <div\n          ${labelClass ? `aria-labelledby=\"${labelClass}\"` : ''}\n          id=\"options\"\n          class=\"${componentName}__option-list\"\n          role=\"listbox\"\n          tabindex=\"-1\"\n        ></div>\n        <select\n          ${name ? `name=\"${name}\"` : ''}\n          aria-hidden=\"true\"\n          class=\"native-select\"\n          autocomplete=\"off\"\n          ${mandatory ? 'required' : ''}>\n          ${placeholder ? `<option value=\"\" selected disabled>${placeholder}</option>` : ''}\n          ${createSelectHtml(optionList, !!placeholder)}\n        </select>\n    `;\n\n    el.appendChild(document.createRange().createContextualFragment(innerContent));\n\n    new Select(el, optionList, placeholder, options.onChangeCallback);\n    return el;\n  } catch (error) {\n    console.error(`Failed to load CSS from ${dropdownCSS}:`, error);\n    return '';\n  }\n};\n","/* global YT */\nimport { loadCSS } from '../../scripts/aem.js';\nimport {\n  createIframe,\n  createVideo,\n  handleVideoMessage,\n  getYoutubeVideoId,\n  loadYouTubeIframeAPI,\n  isAEMVideoUrl,\n  isLowResolutionVideoUrl,\n  isYoutubeVideoUrl,\n  VideoEventManager,\n  AEM_ASSETS,\n} from '../../scripts/video-helper.js';\nimport { createElement, decorateIcons, getTextLabel, isSocialAllowed } from '../../scripts/common.js';\n\nconst { videoIdRegex } = AEM_ASSETS;\nconst videoEventManager = new VideoEventManager();\n\nclass VideoComponent {\n  constructor(videoId) {\n    this.videoId = videoId;\n    this.blockName = 'modal';\n\n    videoEventManager.register(this.videoId, this.blockName, (event) => handleVideoMessage(event, this.videoId, this.blockName));\n  }\n\n  unregister() {\n    videoEventManager.unregister(this.videoId, this.blockName);\n  }\n}\n\nconst HIDE_MODAL_CLASS = 'modal-hidden';\n\nasync function addVideo(block, videoId) {\n  const cookieMsgContainer = block.querySelector('.modal-cookie-message');\n  if (cookieMsgContainer) {\n    cookieMsgContainer.remove();\n  }\n\n  const iframeSrc = `https://www.youtube.com/embed/${videoId}?color=white&amp;rel=0&amp;playsinline=1&amp;enablejsapi=1&amp;autoplay=1`;\n\n  const iframeYT = createIframe(iframeSrc, {\n    parentEl: block,\n    classes: 'modal-video',\n    props: { id: 'modal-youtube-iframe', allow: 'autoplay', allowfullscreen: 'true' },\n  });\n\n  block.append(...iframeYT.childNodes);\n\n  await loadYouTubeIframeAPI();\n\n  window.onYouTubeIframeAPIReady = function onYouTubeIframeAPIReadyInit() {\n    if (!YT) {\n      throw new Error('YouTube API not loaded');\n    }\n    new YT.Player('modal-youtube-iframe', {\n      events: {\n        onReady: onPlayerReady,\n        onError: onPlayerError,\n        onAutoplayBlocked: onPlayerAutoplayBlocked,\n      },\n    });\n  };\n}\n\nfunction onPlayerReady(event) {\n  event.target.playVideo();\n}\n\nfunction onPlayerError(event) {\n  console.warn(event.data);\n}\n\nfunction onPlayerAutoplayBlocked(event) {\n  console.warn(event.data);\n}\n\nconst createModal = () => {\n  const modalBackground = createElement('div', { classes: ['modal-background', HIDE_MODAL_CLASS] });\n\n  modalBackground.addEventListener('click', () => {\n    hideModal();\n  });\n\n  const keyDownAction = (event) => {\n    if (event.key === 'Escape') {\n      hideModal();\n    }\n  };\n\n  const modalContent = createElement('div', { classes: 'modal-content' });\n  modalBackground.appendChild(modalContent);\n  // preventing initial animation when added to DOM\n  modalBackground.style = 'height: 0; opacity: 0;';\n  document.body.appendChild(modalBackground);\n\n  // adding close modal button\n  const closeModalLabel = getTextLabel('modal_component:close_modal_label');\n  const closeButton = createElement('button', { classes: 'modal-close-button', props: { 'aria-label': `${closeModalLabel}` } });\n  const closeIcon = createElement('span', { classes: ['icon', 'icon-close'] });\n  closeButton.append(closeIcon);\n  modalBackground.appendChild(closeButton);\n\n  closeButton.addEventListener('click', () => hideModal());\n\n  decorateIcons(closeButton);\n\n  const clearModalContent = () => {\n    modalContent.innerHTML = '';\n    modalContent.className = 'modal-content';\n  };\n\n  async function showModal(newContent, { beforeBanner, beforeIframe, classes = [] } = {}) {\n    const shouldVideoSocialCheck = classes.includes('modal-video-social-cookie-check');\n\n    await loadCSS(`${window.hlx.codeBasePath}/common/modal/modal-component.css`);\n    modalBackground.style = '';\n    modalBackground.classList.add(...classes);\n    window.addEventListener('keydown', keyDownAction);\n\n    if (newContent && typeof newContent !== 'string') {\n      // opening modal\n      clearModalContent();\n      modalContent.classList.add(...classes);\n      modalContent.append(newContent);\n      modalContent.appendChild(closeButton);\n    } else if (newContent) {\n      clearModalContent();\n      let videoWrapper = null;\n      if (isLowResolutionVideoUrl(newContent)) {\n        videoWrapper = createVideo(\n          newContent,\n          'modal-video',\n          {\n            autoplay: 'autoplay',\n            playsinline: true,\n            controls: false,\n            loop: false,\n            language: document.documentElement.lang,\n          },\n          {\n            addMuteToggle: true,\n            usePosterAutoDetection: false,\n          },\n        );\n        modalContent.append(videoWrapper);\n      } else if (isAEMVideoUrl(newContent)) {\n        let videoId;\n        const match = newContent.match(videoIdRegex);\n        if (match) {\n          [videoId] = match;\n        }\n\n        new VideoComponent(videoId);\n\n        videoWrapper = createVideo(\n          newContent,\n          'modal-video',\n          {\n            autoplay: 'any',\n            muted: false,\n            playsinline: true,\n            controls: false,\n            loop: false,\n            disablePictureInPicture: true,\n            title: 'video',\n            language: document.documentElement.lang,\n          },\n          {\n            addMuteToggle: true,\n            usePosterAutoDetection: false,\n          },\n        );\n        modalContent.append(videoWrapper);\n      } else if (isYoutubeVideoUrl(newContent) && shouldVideoSocialCheck) {\n        const videoId = getYoutubeVideoId(newContent);\n\n        if (!videoId) {\n          console.warn('V2 Video block: There is no video link. Please check the provided URL.');\n          return;\n        }\n        window.isSingleVideo = true;\n\n        if (isSocialAllowed()) {\n          addVideo(modalContent, videoId);\n        } else {\n          const cookieMsgContainer = createElement('div', {\n            classes: 'modal-cookie-message',\n          });\n          cookieMsgContainer.style.background = 'linear-gradient(180deg, rgba(0, 0, 0, 0.00) 0%, rgba(0, 0, 0, 0.80) 100%) center / cover no-repeat';\n\n          const cookieMessage = document.createRange().createContextualFragment(`\n            <h3 class=\"modal-cookie-message__title\">${getTextLabel('modal_component:cookie_message_title')}</h3>\n            ${getTextLabel('modal_component:cookie_message_text')}\n            <div class=\"modal-cookie-message__button-container\">\n              <button class=\"button primary button--large button--red\">${getTextLabel('modal_component:cookie_accept_button')}</button>\n              <button class=\"button secondary button--large\">${getTextLabel('modal_component:cookie_reject_button')}</button>\n            </div>\n          `);\n\n          cookieMsgContainer.append(cookieMessage);\n          modalContent.append(cookieMsgContainer);\n\n          modalContent.querySelector('.modal-cookie-message__button-container .primary')?.addEventListener('click', () => {\n            if (window.OneTrust) {\n              window.OneTrust.AllowAll();\n            }\n\n            addVideo(modalContent, videoId);\n          });\n\n          modalContent.querySelector('.modal-cookie-message__button-container .secondary')?.addEventListener('click', () => {\n            hideModal();\n          });\n        }\n      } else {\n        // otherwise load it as iframe\n        videoWrapper = createIframe(newContent, { parentEl: modalContent, classes: 'modal-video' });\n      }\n\n      if (beforeBanner) {\n        const bannerWrapper = createElement('div', { classes: 'modal-before-banner' });\n        bannerWrapper.addEventListener('click', (event) => event.stopPropagation());\n        bannerWrapper.appendChild(beforeBanner);\n\n        videoWrapper.parentElement.insertBefore(bannerWrapper, videoWrapper);\n      }\n\n      if (beforeIframe) {\n        const wrapper = createElement('div', { classes: 'modal-before-iframe' });\n        wrapper.appendChild(beforeIframe);\n        videoWrapper.parentElement.insertBefore(wrapper, videoWrapper);\n      }\n\n      if (videoWrapper) {\n        videoWrapper.parentElement.insertBefore(closeButton, videoWrapper);\n      } else {\n        modalContent.insertBefore(closeButton, modalContent.firstChild);\n      }\n    }\n\n    modalBackground.classList.remove(HIDE_MODAL_CLASS);\n\n    // disable page scrolling\n    document.body.classList.add('disable-scroll');\n\n    modalContent.addEventListener('click', (event) => {\n      event.stopPropagation();\n    });\n  }\n\n  function hideModal() {\n    modalBackground.classList.add(HIDE_MODAL_CLASS);\n    window.removeEventListener('keydown', keyDownAction);\n    document.body.classList.remove('disable-scroll');\n\n    // stop playing video if the modal contains one\n    document.querySelector('.modal-content video')?.pause();\n    document.querySelector('.modal-content iframe')?.setAttribute('src', '');\n\n    const onHideTransitionCancel = (event) => {\n      if (event.target === modalBackground) {\n        modalBackground.removeEventListener('transitionend', onHideTransitionEnd);\n      }\n    };\n\n    const onHideTransitionEnd = (event) => {\n      if (event.target === modalBackground) {\n        clearModalContent();\n\n        if (onHideTransitionCancel) {\n          modalBackground.removeEventListener('transitioncancel', onHideTransitionCancel);\n        }\n      }\n    };\n\n    modalBackground.addEventListener('transitionend', onHideTransitionEnd, { once: true });\n    modalBackground.addEventListener('transitioncancel', onHideTransitionCancel, { once: true });\n  }\n\n  return {\n    showModal,\n    hideModal,\n  };\n};\n\nconst { showModal, hideModal } = createModal();\n\nexport { showModal, hideModal };\n","import { sampleRUM } from './aem.js';\nimport { getTextLabel } from './common.js';\nimport './scripts.js';\n\n// TODO: Verify why this is needed and also present in the Adobe eds boilerplate:\n// https://github.com/adobe/aem-boilerplate/blob/main/404.html\nwindow.isErrorPage = true;\nwindow.errorCode = '404';\n\nsampleRUM('404', { source: document.referrer, target: window.location.href });\n\nif (document.referrer) {\n  const { origin, pathname } = new URL(document.referrer);\n  if (origin === window.location.origin) {\n    const main = document.querySelector('main.error');\n\n    const observer = new MutationObserver((mutations, observer) => {\n      const fragmentContainer = document.querySelector('.fragment-wrapper');\n      if (fragmentContainer) {\n        const backLinkTitle = getTextLabel('404:back_link_title');\n        const btnContainer = document.createElement('p');\n        const backBtn = document.createElement('a');\n        backBtn.classList.add('button', 'button--primary');\n        backBtn.href = pathname;\n        backBtn.textContent = backLinkTitle;\n        backBtn.title = backLinkTitle;\n        btnContainer.append(backBtn);\n        fragmentContainer.append(btnContainer);\n        observer.disconnect();\n      }\n    });\n\n    observer.observe(main, {\n      childList: true,\n      subtree: true,\n    });\n  }\n}\n","/*\n * Copyright 2024 Adobe. All rights reserved.\n * This file is licensed to you under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License. You may obtain a copy\n * of the License at http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software distributed under\n * the License is distributed on an \"AS IS\" BASIS, WITHOUT WARRANTIES OR REPRESENTATIONS\n * OF ANY KIND, either express or implied. See the License for the specific language\n * governing permissions and limitations under the License.\n */\n\n// eslint-disable-next-line no-undef\nconst context = require.context(\n  '../blocks/', // Relative to this file\n  true,\n  /^[^/]+\\/[^/]+\\.js$/, // Adjust as needed\n);\n\nfunction sampleRUM(checkpoint, data) {\n  const timeShift = () => (window.performance ? window.performance.now() : Date.now() - window.hlx.rum.firstReadTime);\n  try {\n    window.hlx = window.hlx || {};\n    sampleRUM.enhance = () => {};\n    if (!window.hlx.rum) {\n      const param = new URLSearchParams(window.location.search).get('rum');\n      const weight =\n        (window.SAMPLE_PAGEVIEWS_AT_RATE === 'high' && 10) || (window.SAMPLE_PAGEVIEWS_AT_RATE === 'low' && 1000) || (param === 'on' && 1) || 100;\n      const id = Math.random().toString(36).slice(-4);\n      const isSelected = param !== 'off' && Math.random() * weight < 1;\n\n      window.hlx.rum = {\n        weight,\n        id,\n        isSelected,\n        firstReadTime: window.performance ? window.performance.timeOrigin : Date.now(),\n        sampleRUM,\n        queue: [],\n        collector: (...args) => window.hlx.rum.queue.push(args),\n      };\n      if (isSelected) {\n        const dataFromErrorObj = (error) => {\n          const errData = { source: 'undefined error' };\n          try {\n            errData.target = error.toString();\n            errData.source = error.stack\n              .split('\\n')\n              .filter((line) => line.match(/https?:\\/\\//))\n              .shift()\n              .replace(/at ([^ ]+) \\((.+)\\)/, '$1@$2')\n              .replace(/ at /, '@')\n              .trim();\n          } catch (err) {\n            /* error structure was not as expected */\n            console.error(err);\n          }\n          return errData;\n        };\n\n        window.addEventListener('error', ({ error }) => {\n          const errData = dataFromErrorObj(error);\n          sampleRUM('error', errData);\n        });\n\n        window.addEventListener('unhandledrejection', ({ reason }) => {\n          let errData = {\n            source: 'Unhandled Rejection',\n            target: reason || 'Unknown',\n          };\n          if (reason instanceof Error) {\n            errData = dataFromErrorObj(reason);\n          }\n          sampleRUM('error', errData);\n        });\n\n        sampleRUM.baseURL = sampleRUM.baseURL || new URL(window.RUM_BASE || '/', new URL('https://rum.hlx.page'));\n        sampleRUM.collectBaseURL = sampleRUM.collectBaseURL || sampleRUM.baseURL;\n        sampleRUM.sendPing = (ck, time, pingData = {}) => {\n          const rumData = JSON.stringify({\n            weight,\n            id,\n            referer: window.location.href,\n            checkpoint: ck,\n            t: time,\n            ...pingData,\n          });\n          const urlParams = window.RUM_PARAMS ? `?${new URLSearchParams(window.RUM_PARAMS).toString()}` : '';\n          const { href: url, origin } = new URL(`.rum/${weight}${urlParams}`, sampleRUM.collectBaseURL);\n          const body = origin === window.location.origin ? new Blob([rumData], { type: 'application/json' }) : rumData;\n          navigator.sendBeacon(url, body);\n\n          console.debug(`ping:${ck}`, pingData);\n        };\n        sampleRUM.sendPing('top', timeShift());\n\n        sampleRUM.enhance = () => {\n          // only enhance once\n          if (document.querySelector('script[src*=\"rum-enhancer\"]')) {\n            return;\n          }\n          const { enhancerVersion, enhancerHash } = sampleRUM.enhancerContext || {};\n          const script = document.createElement('script');\n          if (enhancerHash) {\n            script.integrity = enhancerHash;\n            script.setAttribute('crossorigin', 'anonymous');\n          }\n          script.src = new URL(`.rum/@adobe/helix-rum-enhancer@${enhancerVersion || '^2'}/src/index.js`, sampleRUM.baseURL).href;\n          document.head.appendChild(script);\n        };\n        if (!window.hlx.RUM_MANUAL_ENHANCE) {\n          sampleRUM.enhance();\n        }\n      }\n    }\n    if (window.hlx.rum && window.hlx.rum.isSelected && checkpoint) {\n      window.hlx.rum.collector(checkpoint, data, timeShift());\n    }\n    document.dispatchEvent(new CustomEvent('rum', { detail: { checkpoint, data } }));\n  } catch (error) {\n    // something went awry\n    console.error(error);\n  }\n}\n\n/**\n * Setup block utils.\n */\nfunction setup() {\n  window.hlx = window.hlx || {};\n  window.hlx.RUM_MASK_URL = 'full';\n  window.hlx.RUM_MANUAL_ENHANCE = true;\n  window.hlx.codeBasePath = '';\n  window.hlx.lighthouse = new URLSearchParams(window.location.search).get('lighthouse') === 'on';\n\n  const scriptEl = document.querySelector('script[src$=\"/scripts/scripts.js\"]');\n  if (scriptEl) {\n    try {\n      [window.hlx.codeBasePath] = new URL(scriptEl.src).pathname.split('/scripts/scripts.js');\n    } catch (error) {\n      console.log(error);\n    }\n  }\n}\n\n/**\n * Auto initializiation.\n */\n\nfunction init() {\n  setup();\n  sampleRUM();\n}\n\n/**\n * Sanitizes a string for use as class name.\n * @param {string} name The unsanitized string\n * @returns {string} The class name\n */\nfunction toClassName(name) {\n  return typeof name === 'string'\n    ? name\n        .toLowerCase()\n        .replace(/[^0-9a-z]/gi, '-')\n        .replace(/-+/g, '-')\n        .replace(/^-|-$/g, '')\n    : '';\n}\n\n/**\n * Sanitizes a string for use as a js property name.\n * @param {string} name The unsanitized string\n * @returns {string} The camelCased name\n */\nfunction toCamelCase(name) {\n  return toClassName(name).replace(/-([a-z])/g, (g) => g[1].toUpperCase());\n}\n\n/**\n * Extracts the config from a block.\n * @param {Element} block The block element\n * @returns {object} The block config\n */\nfunction readBlockConfig(block) {\n  const config = {};\n  block.querySelectorAll(':scope > div').forEach((row) => {\n    if (row.children) {\n      const cols = [...row.children];\n      if (cols[1]) {\n        const col = cols[1];\n        const name = toClassName(cols[0].textContent);\n        let value = '';\n        if (col.querySelector('a')) {\n          const as = [...col.querySelectorAll('a')];\n          if (as.length === 1) {\n            value = as[0].href;\n          } else {\n            value = as.map((a) => a.href);\n          }\n        } else if (col.querySelector('img')) {\n          const imgs = [...col.querySelectorAll('img')];\n          if (imgs.length === 1) {\n            value = imgs[0].src;\n          } else {\n            value = imgs.map((img) => img.src);\n          }\n        } else if (col.querySelector('p')) {\n          const ps = [...col.querySelectorAll('p')];\n          if (ps.length === 1) {\n            value = ps[0].textContent;\n          } else {\n            value = ps.map((p) => p.textContent);\n          }\n        } else {\n          value = row.children[1].textContent;\n        }\n        config[name] = value;\n      }\n    }\n  });\n  return config;\n}\n\n/**\n * Loads a CSS file.\n * @param {string} href URL to the CSS file\n */\nasync function loadCSS(href) {\n  return new Promise((resolve, reject) => {\n    if (!document.querySelector(`head > link[href=\"${href}\"]`)) {\n      const link = document.createElement('link');\n      link.rel = 'stylesheet';\n      link.href = href;\n      link.onload = resolve;\n      link.onerror = reject;\n      document.head.append(link);\n    } else {\n      resolve();\n    }\n  });\n}\n\n/**\n * Loads a non module JS file.\n * @param {string} src URL to the JS file\n * @param {Object} attrs additional optional attributes\n */\nasync function loadScript(src, attrs) {\n  return new Promise((resolve, reject) => {\n    if (!document.querySelector(`head > script[src=\"${src}\"]`)) {\n      const script = document.createElement('script');\n      script.src = src;\n      if (attrs) {\n        for (const attr in attrs) {\n          script.setAttribute(attr, attrs[attr]);\n        }\n      }\n      script.onload = resolve;\n      script.onerror = reject;\n      document.head.append(script);\n    } else {\n      resolve();\n    }\n  });\n}\n\n/**\n * Retrieves the content of metadata tags.\n * @param {string} name The metadata name (or property)\n * @param {Document} doc Document object to query for metadata. Defaults to the window's document\n * @returns {string} The metadata value(s)\n */\nfunction getMetadata(name, doc = document) {\n  const attr = name && name.includes(':') ? 'property' : 'name';\n  const meta = [...doc.head.querySelectorAll(`meta[${attr}=\"${name}\"]`)].map((m) => m.content).join(', ');\n  return meta || '';\n}\n\n/**\n * Returns a picture element with webp and fallbacks\n * @param {string} src The image URL\n * @param {string} [alt] The image alternative text\n * @param {boolean} [eager] Set loading attribute to eager\n * @param {Array} [breakpoints] Breakpoints and corresponding params (eg. width)\n * @returns {Element} The picture element\n */\nfunction createOptimizedPicture(src, alt = '', eager = false, breakpoints = [{ media: '(min-width: 600px)', width: '2000' }, { width: '750' }]) {\n  const url = new URL(src, window.location.href);\n  const picture = document.createElement('picture');\n  const { pathname } = url;\n  const ext = pathname.substring(pathname.lastIndexOf('.') + 1);\n\n  // webp\n  breakpoints.forEach((br) => {\n    const source = document.createElement('source');\n    if (br.media) {\n      source.setAttribute('media', br.media);\n    }\n    source.setAttribute('type', 'image/webp');\n    source.setAttribute('srcset', `${pathname}?width=${br.width}&format=webply&optimize=medium`);\n    picture.appendChild(source);\n  });\n\n  // fallback\n  breakpoints.forEach((br, i) => {\n    if (i < breakpoints.length - 1) {\n      const source = document.createElement('source');\n      if (br.media) {\n        source.setAttribute('media', br.media);\n      }\n      source.setAttribute('srcset', `${pathname}?width=${br.width}&format=${ext}&optimize=medium`);\n      picture.appendChild(source);\n    } else {\n      const img = document.createElement('img');\n      img.setAttribute('loading', eager ? 'eager' : 'lazy');\n      img.setAttribute('alt', alt);\n      picture.appendChild(img);\n      img.setAttribute('src', `${pathname}?width=${br.width}&format=${ext}&optimize=medium`);\n    }\n  });\n\n  return picture;\n}\n\n/**\n * Set template (page structure) and theme (page styles).\n */\nfunction decorateTemplateAndTheme() {\n  const addClasses = (element, classes) => {\n    classes.split(',').forEach((c) => {\n      element.classList.add(toClassName(c.trim()));\n    });\n  };\n  const template = getMetadata('template');\n  if (template) {\n    addClasses(document.body, template);\n  }\n  const theme = getMetadata('theme');\n  if (theme) {\n    addClasses(document.body, theme);\n  }\n}\n\n/**\n * Wrap inline text content of block cells within a <p> tag.\n * @param {Element} block the block element\n */\nfunction wrapTextNodes(block) {\n  const validWrappers = ['P', 'PRE', 'UL', 'OL', 'PICTURE', 'TABLE', 'H1', 'H2', 'H3', 'H4', 'H5', 'H6'];\n\n  const wrap = (el) => {\n    const wrapper = document.createElement('p');\n    wrapper.append(...el.childNodes);\n    el.append(wrapper);\n  };\n\n  block.querySelectorAll(':scope > div > div').forEach((blockColumn) => {\n    if (blockColumn.hasChildNodes()) {\n      const hasWrapper = !!blockColumn.firstElementChild && validWrappers.some((tagName) => blockColumn.firstElementChild.tagName === tagName);\n      if (!hasWrapper) {\n        wrap(blockColumn);\n      } else if (blockColumn.firstElementChild.tagName === 'PICTURE' && (blockColumn.children.length > 1 || !!blockColumn.textContent.trim())) {\n        wrap(blockColumn);\n      }\n    }\n  });\n}\n\n/**\n * Decorates paragraphs containing a single link as buttons.\n * @param {Element} element container element\n */\nfunction decorateButtons(element) {\n  element.querySelectorAll('a').forEach((a) => {\n    a.title = a.title || a.textContent;\n    if (a.href !== a.textContent) {\n      const up = a.parentElement;\n      const twoup = a.parentElement.parentElement;\n      if (!a.querySelector('img')) {\n        if (up.childNodes.length === 1 && (up.tagName === 'P' || up.tagName === 'DIV')) {\n          a.className = 'button'; // default\n          up.classList.add('button-container');\n        }\n        if (up.childNodes.length === 1 && up.tagName === 'STRONG' && twoup.childNodes.length === 1 && twoup.tagName === 'P') {\n          a.className = 'button primary';\n          twoup.classList.add('button-container');\n        }\n        if (up.childNodes.length === 1 && up.tagName === 'EM' && twoup.childNodes.length === 1 && twoup.tagName === 'P') {\n          a.className = 'button secondary';\n          twoup.classList.add('button-container');\n        }\n      }\n    }\n  });\n}\n\n/**\n * Add <img> for icon, prefixed with codeBasePath and optional prefix.\n * @param {Element} [span] span element with icon classes\n * @param {string} [prefix] prefix to be added to icon src\n * @param {string} [alt] alt text to be added to icon\n */\nfunction decorateIcon(span, prefix = '', alt = '') {\n  const iconName = Array.from(span.classList)\n    .find((c) => c.startsWith('icon-'))\n    .substring(5);\n  const img = document.createElement('img');\n  img.dataset.iconName = iconName;\n  img.src = `${window.hlx.codeBasePath}${prefix}/icons/${iconName}.svg`;\n  img.alt = alt;\n  img.loading = 'lazy';\n  span.append(img);\n}\n\n/**\n * Add <img> for icons, prefixed with codeBasePath and optional prefix.\n * @param {Element} [element] Element containing icons\n * @param {string} [prefix] prefix to be added to icon the src\n */\nfunction decorateIcons(element, prefix = '') {\n  const icons = [...element.querySelectorAll('span.icon')];\n  icons.forEach((span) => {\n    decorateIcon(span, prefix);\n  });\n}\n\n/**\n * Decorates all sections in a container element.\n * @param {Element} main The container element\n */\nfunction decorateSections(main) {\n  main.querySelectorAll(':scope > div').forEach((section) => {\n    const wrappers = [];\n    let defaultContent = false;\n    [...section.children].forEach((e) => {\n      if (e.tagName === 'DIV' || !defaultContent) {\n        const wrapper = document.createElement('div');\n        wrappers.push(wrapper);\n        defaultContent = e.tagName !== 'DIV';\n        if (defaultContent) {\n          wrapper.classList.add('default-content-wrapper');\n        }\n      }\n      wrappers[wrappers.length - 1].append(e);\n    });\n    wrappers.forEach((wrapper) => section.append(wrapper));\n    section.classList.add('section');\n    section.dataset.sectionStatus = 'initialized';\n    section.style.display = 'none';\n\n    // Process section metadata\n    const sectionMeta = section.querySelector('div.section-metadata');\n    if (sectionMeta) {\n      const meta = readBlockConfig(sectionMeta);\n      Object.keys(meta).forEach((key) => {\n        if (key === 'style') {\n          const styles = meta.style\n            .split(',')\n            .filter((style) => style)\n            .map((style) => toClassName(style.trim()));\n          styles.forEach((style) => section.classList.add(style));\n        } else {\n          section.dataset[toCamelCase(key)] = meta[key];\n        }\n      });\n      sectionMeta.parentNode.remove();\n    }\n  });\n}\n\n/**\n * Builds a block DOM Element from a two dimensional array, string, or object\n * @param {string} blockName name of the block\n * @param {*} content two dimensional array or string or object of content\n */\nfunction buildBlock(blockName, content) {\n  const table = Array.isArray(content) ? content : [[content]];\n  const blockEl = document.createElement('div');\n  // build image block nested div structure\n  blockEl.classList.add(blockName);\n  table.forEach((row) => {\n    const rowEl = document.createElement('div');\n    row.forEach((col) => {\n      const colEl = document.createElement('div');\n      const vals = col.elems ? col.elems : [col];\n      vals.forEach((val) => {\n        if (val) {\n          if (typeof val === 'string') {\n            colEl.innerHTML += val;\n          } else {\n            colEl.appendChild(val);\n          }\n        }\n      });\n      rowEl.appendChild(colEl);\n    });\n    blockEl.appendChild(rowEl);\n  });\n  return blockEl;\n}\n\n/**\n * Loads JS and CSS for a block.\n * @param {Element} block The block element\n */\nasync function loadBlock(block) {\n  const status = block.dataset.blockStatus;\n  if (status !== 'loading' && status !== 'loaded') {\n    block.dataset.blockStatus = 'loading';\n    const { blockName } = block.dataset;\n    try {\n      const cssLoaded = loadCSS(`${window.hlx.codeBasePath}/blocks/${blockName}/${blockName}.css`);\n      const decorationComplete = new Promise((resolve) => {\n        (async () => {\n          try {\n            const blockPath = `${blockName}/${blockName}.js`;\n            const mod = await context(blockPath);\n            if (mod.default) {\n              await mod.default(block);\n            }\n          } catch (error) {\n            console.error(`Failed to load block ${blockName}`, error);\n          }\n          resolve();\n        })();\n      });\n      await Promise.all([cssLoaded, decorationComplete]);\n    } catch (error) {\n      console.log(`failed to load block ${blockName}`, error);\n    }\n    block.dataset.blockStatus = 'loaded';\n  }\n  return block;\n}\n\n/**\n * Decorates a block.\n * @param {Element} block The block element\n */\nfunction decorateBlock(block) {\n  const shortBlockName = block.classList[0];\n  if (shortBlockName) {\n    block.classList.add('block');\n    block.dataset.blockName = shortBlockName;\n    block.dataset.blockStatus = 'initialized';\n    wrapTextNodes(block);\n    const blockWrapper = block.parentElement;\n    blockWrapper.classList.add(`${shortBlockName}-wrapper`);\n    const section = block.closest('.section');\n    if (section) {\n      section.classList.add(`${shortBlockName}-container`);\n    }\n  }\n}\n\n/**\n * Decorates all blocks in a container element.\n * @param {Element} main The container element\n */\nfunction decorateBlocks(main) {\n  main.querySelectorAll('div.section > div > div').forEach(decorateBlock);\n}\n\n/**\n * Loads a block named 'header' into header\n * @param {Element} header header element\n * @returns {Promise}\n */\nasync function loadHeader(header) {\n  const headerBlock = buildBlock('header', '');\n  header.append(headerBlock);\n  decorateBlock(headerBlock);\n  return loadBlock(headerBlock);\n}\n\n/**\n * Loads a block named 'footer' into footer\n * @param footer footer element\n * @returns {Promise}\n */\nasync function loadFooter(footer) {\n  const footerBlock = buildBlock('footer', '');\n  footer.append(footerBlock);\n  decorateBlock(footerBlock);\n  return loadBlock(footerBlock);\n}\n\n/**\n * Wait for Image.\n * @param {Element} section section element\n */\nasync function waitForFirstImage(section) {\n  const lcpCandidate = section.querySelector('img');\n  await new Promise((resolve) => {\n    if (lcpCandidate && !lcpCandidate.complete) {\n      lcpCandidate.setAttribute('loading', 'eager');\n      lcpCandidate.addEventListener('load', resolve);\n      lcpCandidate.addEventListener('error', resolve);\n    } else {\n      resolve();\n    }\n  });\n}\n\n/**\n * Loads all blocks in a section.\n * @param {Element} section The section element\n */\n\nasync function loadSection(section, loadCallback) {\n  if (!section) {\n    return;\n  }\n\n  const status = section.dataset.sectionStatus;\n  if (!status || status === 'initialized') {\n    section.dataset.sectionStatus = 'loading';\n    const blocks = [...section.querySelectorAll('div.block')];\n    for (let i = 0; i < blocks.length; i += 1) {\n      await loadBlock(blocks[i]);\n    }\n    if (loadCallback) {\n      await loadCallback(section);\n    }\n    section.dataset.sectionStatus = 'loaded';\n    section.style.display = null;\n  }\n}\n\n/**\n * Loads all sections.\n * @param {Element} element The parent element of sections to load\n */\n\nasync function loadSections(element) {\n  const sections = [...element.querySelectorAll('div.section')];\n  for (let i = 0; i < sections.length; i += 1) {\n    await loadSection(sections[i]);\n    if (i === 0 && sampleRUM.enhance) {\n      sampleRUM.enhance();\n    }\n  }\n}\n\ninit();\n\nexport {\n  buildBlock,\n  createOptimizedPicture,\n  decorateBlock,\n  decorateBlocks,\n  decorateButtons,\n  decorateIcons,\n  decorateSections,\n  decorateTemplateAndTheme,\n  getMetadata,\n  loadBlock,\n  loadCSS,\n  loadFooter,\n  loadHeader,\n  loadScript,\n  loadSection,\n  loadSections,\n  readBlockConfig,\n  sampleRUM,\n  setup,\n  toCamelCase,\n  toClassName,\n  waitForFirstImage,\n  wrapTextNodes,\n};\n","import { createElement, formatStringToArray } from './common.js';\nimport { loadScript, loadCSS, getMetadata } from './aem.js';\nimport { validateCountries } from './validate-countries.js';\n\n/**\n * Convert metadata or comma-separated lists into clean arrays.\n */\nconst parseUrlList = (list) =>\n  formatStringToArray(list || '')\n    .map((u) => u?.trim())\n    .filter(Boolean);\n\n/**\n * Create the mount container and replace main content with it.\n */\nconst mountContainer = (main, appId) => {\n  const container = createElement('div', { props: { id: appId } });\n  main.replaceChildren(container);\n  return container;\n};\n\n/**\n * Load JS and CSS assets safely.\n */\nconst loadAssets = (urls = {}, loadedScripts = new Set()) => {\n  const jsUrls = parseUrlList(urls.JS);\n  const cssUrls = parseUrlList(urls.CSS);\n\n  jsUrls.forEach((url) => {\n    if (!loadedScripts.has(url)) {\n      loadedScripts.add(url);\n      loadScript(url, { defer: 'defer', type: 'text/javascript', charset: 'UTF-8' });\n    }\n  });\n\n  cssUrls.forEach((url) => loadCSS(url));\n};\n\n/**\n * Handle single metadata-based hash routing.\n */\nconst applyInitialRoute = (metadataPageKey) => {\n  if (!metadataPageKey) {\n    return;\n  }\n\n  const page = getMetadata(metadataPageKey)?.toLowerCase();\n  if (!page) {\n    return;\n  }\n\n  if (location.hash && location.hash !== '#' && location.hash !== '#/') {\n    return;\n  }\n\n  location.hash = `#/${page}`;\n};\n\n/**\n * Move the app class from <main> to <html>.\n */\nconst normalizeAppClass = (html, main, appClass) => {\n  if (main.classList.contains(appClass)) {\n    main.classList.remove(appClass);\n    html.classList.add(appClass);\n  }\n};\n\n/**\n * Optional country validation helper.\n */\nconst handleCountryRestrictions = () => {\n  const allowed = getMetadata('allowed-countries');\n  const redirectUrl = getMetadata('redirect-url');\n  if (allowed && redirectUrl) {\n    validateCountries(allowed, redirectUrl);\n  }\n};\n\n/**\n * Main entry point for embedding an app.\n */\nexport const initEmbeddedApp = ({ appClass, appId, urls = {}, metadataPageKey, shouldDisableHeader = false, headerDetailClass = null }) => {\n  const html = document.documentElement;\n  const main = document.querySelector('main');\n\n  if (!html.classList.contains(appClass) && !main.classList.contains(appClass)) {\n    return;\n  }\n\n  normalizeAppClass(html, main, appClass);\n  handleCountryRestrictions();\n  mountContainer(main, appId);\n  loadAssets(urls);\n  applyInitialRoute(metadataPageKey);\n\n  if (shouldDisableHeader && headerDetailClass) {\n    html.classList.add(headerDetailClass);\n  }\n};\n","import { createElement } from './common.js';\n\nexport const listenScroll = (carousel, elements, updateFn, threshold = 1) => {\n  const io = new IntersectionObserver(\n    (entries) => {\n      entries.forEach((entry) => {\n        if (entry.isIntersecting) {\n          updateFn(elements, entry);\n        }\n      });\n    },\n    {\n      root: carousel,\n      threshold,\n    },\n  );\n\n  elements.forEach((el) => {\n    io.observe(el);\n  });\n};\n\nexport const setCarouselPosition = (carousel, index) => {\n  const firstEl = carousel.firstElementChild;\n  const scrollOffset = firstEl.getBoundingClientRect().width;\n  const style = window.getComputedStyle(firstEl);\n  const marginleft = parseFloat(style.marginLeft);\n\n  carousel.scrollTo({\n    left: index * scrollOffset + marginleft,\n    behavior: 'smooth',\n  });\n};\n\nexport const createArrowControls = (carousel, scrollSelector, controlClasses, arrowFragment) => {\n  function navigate(direction) {\n    const activeItem = carousel.querySelector(scrollSelector);\n    let index = [...activeItem.parentNode.children].indexOf(activeItem);\n    if (direction === 'left') {\n      index -= 1;\n      if (index === -1) {\n        // Go to the last item if at the start\n        index = carousel.childElementCount;\n      }\n    } else {\n      index += 1;\n      if (index > carousel.childElementCount - 1) {\n        index = 0; // Go to the first item if at the end\n      }\n    }\n\n    setCarouselPosition(carousel, index);\n  }\n\n  const arrowControls = createElement('ul', { classes: controlClasses });\n  arrowControls.append(...arrowFragment.children);\n  carousel.insertAdjacentElement('beforebegin', arrowControls);\n  const [prevButton, nextButton] = arrowControls.querySelectorAll(':scope button');\n  prevButton.addEventListener('click', () => navigate('left'));\n  nextButton.addEventListener('click', () => navigate('right'));\n};\n","import { loadCSS, getMetadata } from './aem.js';\n\nconst DEFAULT_PLACEHOLDER_LOCALE = 'en';\nlet placeholders = null;\nlet placeholdersPromise = null;\n\nconst formatValues = (values) => {\n  const obj = {};\n  if (values) {\n    values.forEach(({ name, value }) => (obj[name] = value));\n  }\n  return obj;\n};\n\n// The `key` key MUST exist in the object\n// The rest of the params will be key-value pairs of the main key\nconst formatValuesByKey = (values) =>\n  (values &&\n    values.reduce((acc, { key, ...rest }) => {\n      acc[key] = rest;\n      return acc;\n    }, {})) ||\n  {};\n\nconst getLanguagePath = () => {\n  const { pathname } = new URL(window.location.href);\n  const langCodeMatch = pathname.match('^(/[a-z]{2}(-[a-z]{2})?/).*');\n  return langCodeMatch ? langCodeMatch[1] : '/';\n};\n\n/**\n * loads the constants file where configuration values are stored\n */\nasync function getConstantValues() {\n  const constantsUrl = `${getLanguagePath()}constants.json`;\n\n  try {\n    const response = await fetch(constantsUrl);\n\n    if (!response.ok) {\n      console.error('[constants] Failed to fetch constants:', response.status, response.statusText, constantsUrl);\n      return {};\n    }\n\n    return await response.json();\n  } catch (error) {\n    console.error('[constants] Error fetching constants file:', constantsUrl, error);\n    return {};\n  }\n}\n\nconst CONSTANTS = (await getConstantValues()) || {};\nconst {\n  searchConfig,\n  cookieValues,\n  magazineConfig,\n  headerConfig,\n  tools,\n  truckConfiguratorUrls,\n  myGarageUrls,\n  newsFeedConfig,\n  feeds,\n  holidays,\n  placeholdersConfig,\n} = CONSTANTS;\n\n// This data comes from the sharepoint 'constants.xlsx' file\nconst SEARCH_CONFIGS = formatValues(searchConfig?.data);\nconst COOKIE_CONFIGS = formatValues(cookieValues?.data);\nconst MAGAZINE_CONFIGS = formatValues(magazineConfig?.data);\nconst HEADER_CONFIGS = formatValues(headerConfig?.data);\nconst TOOLS_CONFIGS = formatValues(tools?.data);\nconst TRUCK_CONFIGURATOR_URLS = formatValues(truckConfiguratorUrls?.data);\nconst NEWS_FEED_CONFIGS = formatValues(newsFeedConfig?.data);\nconst FEEDS = formatValuesByKey(feeds?.data);\nconst MY_GARAGE_URLS = formatValues(myGarageUrls?.data);\nconst HOLIDAYS = formatValues(holidays?.data);\nconst PLACEHOLDERS_URL = formatValues(placeholdersConfig?.data)?.PLACEHOLDERS_URL;\n\n/**\n * Resolves the localized text for a single placeholder row.\n *\n * Fallback order:\n * 1. Exact locale (e.g. \"fr-ca\")\n * 2. Base language (e.g. \"fr\")\n * 3. Any matching language variant (e.g. \"fr-*\", deterministic)\n * 4. Default locale (DEFAULT_PLACEHOLDER_LOCALE)\n *\n * @param {Object} placeholderRow\n * @param {string} pageLocale\n * @returns {string}\n */\nfunction resolveTextForLocale(placeholderRow, pageLocale) {\n  if (!placeholderRow || typeof placeholderRow !== 'object') {\n    return '';\n  }\n\n  const pageLocaleNormalized = String(pageLocale || '')\n    .toLowerCase()\n    .trim();\n  const languageCode = pageLocaleNormalized ? pageLocaleNormalized.split('-')[0] : '';\n\n  const readText = (value) => {\n    if (typeof value !== 'string') {\n      return '';\n    }\n    return value.trim() || '';\n  };\n\n  if (pageLocaleNormalized) {\n    const exactLocaleText = readText(placeholderRow[pageLocaleNormalized]);\n    if (exactLocaleText) {\n      return exactLocaleText;\n    }\n  }\n\n  if (languageCode) {\n    const baseLanguageText = readText(placeholderRow[languageCode]);\n    if (baseLanguageText) {\n      return baseLanguageText;\n    }\n\n    const languageVariantPrefix = `${languageCode}-`;\n    let bestVariantColumnKey = '';\n    let bestVariantColumnKeyNormalized = '';\n\n    for (const columnKey of Object.keys(placeholderRow)) {\n      const columnKeyNormalized = String(columnKey).toLowerCase();\n      if (!columnKeyNormalized.startsWith(languageVariantPrefix)) {\n        continue;\n      }\n      if (!bestVariantColumnKey || columnKeyNormalized < bestVariantColumnKeyNormalized) {\n        bestVariantColumnKey = columnKey;\n        bestVariantColumnKeyNormalized = columnKeyNormalized;\n      }\n    }\n\n    if (bestVariantColumnKey) {\n      const variantText = readText(placeholderRow[bestVariantColumnKey]);\n      if (variantText) {\n        return variantText;\n      }\n    }\n  }\n\n  return readText(placeholderRow[DEFAULT_PLACEHOLDER_LOCALE]);\n}\n\n/**\n * Builds a map of placeholder keys to resolved localized values.\n *\n * Rows without a valid key or resolved text are ignored.\n * Duplicate keys overwrite previous values and log a warning.\n *\n * @param {Object} placeholdersPayload\n * @param {string} pageLocale\n * @returns {Map<string, string>}\n */\nfunction buildPlaceholdersMap(placeholdersPayload, pageLocale) {\n  const dataRows = Array.isArray(placeholdersPayload?.data) ? placeholdersPayload.data : [];\n  const placeholdersByKey = new Map();\n\n  for (const dataRow of dataRows) {\n    const authoredKey = dataRow?.Key ?? dataRow?.key;\n    if (authoredKey === undefined || authoredKey === null) {\n      continue;\n    }\n\n    const placeholderKey = String(authoredKey).trim();\n    if (!placeholderKey) {\n      continue;\n    }\n\n    const resolvedText = resolveTextForLocale(dataRow, pageLocale);\n    if (!resolvedText) {\n      continue;\n    }\n\n    if (placeholdersByKey.has(placeholderKey)) {\n      console.warn('[placeholders] Duplicate placeholder key:', placeholderKey);\n    }\n\n    placeholdersByKey.set(placeholderKey, resolvedText);\n  }\n\n  return placeholdersByKey;\n}\n\n/**\n * Loads and caches the placeholders map for the current locale.\n * Ensures a single in-flight request. On failure, an empty map is stored.\n *\n * @returns {Promise<void>}\n */\nasync function getPlaceholders() {\n  if (placeholders) {\n    return Promise.resolve();\n  }\n\n  if (placeholdersPromise) {\n    return placeholdersPromise;\n  }\n\n  const locale = getLocale();\n  const pageLocale = locale ? locale.toLowerCase().trim() : DEFAULT_PLACEHOLDER_LOCALE;\n  const placeholdersUrl = typeof PLACEHOLDERS_URL === 'string' ? PLACEHOLDERS_URL.trim() : '';\n\n  if (!placeholdersUrl) {\n    console.error('[placeholders] Missing PLACEHOLDERS_URL.');\n    placeholders = new Map();\n    return Promise.resolve();\n  }\n\n  placeholdersPromise = (async () => {\n    try {\n      const response = await fetch(placeholdersUrl);\n      if (!response.ok) {\n        throw new Error(`Failed to fetch placeholders (${response.status} ${response.statusText})`);\n      }\n\n      const placeholdersPayload = await response.json();\n      const dataRows = Array.isArray(placeholdersPayload?.data) ? placeholdersPayload.data : [];\n\n      if (dataRows.length) {\n        const hasLocaleColumn = dataRows.some((dataRow) => {\n          return dataRow && typeof dataRow === 'object' && pageLocale in dataRow;\n        });\n\n        if (!hasLocaleColumn) {\n          console.warn('[placeholders] Locale column missing in placeholder file:', pageLocale);\n        }\n      }\n\n      placeholders = buildPlaceholdersMap(placeholdersPayload, pageLocale);\n    } catch (error) {\n      console.error('[placeholders] Fetch failed:', { url: placeholdersUrl, error });\n      placeholders = new Map();\n    } finally {\n      placeholdersPromise = null;\n    }\n  })();\n\n  return placeholdersPromise;\n}\n\n/**\n * Return the resolved placeholder text for a key.\n *\n * @param {string} key\n * @returns {string}\n */\nfunction getTextLabel(key) {\n  return placeholders?.get(key) ?? key;\n}\n\n/**\n * Returns the true origin of the current page in the browser.\n * If the page is running in a iframe with srcdoc, the ancestor origin is returned.\n * @returns {String} The true origin\n */\nfunction getOrigin() {\n  return window.location.href === 'about:srcdoc' ? window.parent.location.origin : window.location.origin;\n}\n\n/**\n * Returns the true of the current page in the browser.mac\n * If the page is running in a iframe with srcdoc,